INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('955a7b77-6e29-550e-8490-8c96dfd92bd6', 'math-8eme', 'المعادلات من الدرجة الأولى بمجهول واحد', 'حلُّ معادلةٍ من الشكل ax + b = c بمعاملاتٍ جذريّةٍ نسبيّة (أعدادٌ سالبة وكسريّة وعشريّة)، وجمعُ الحدود المتشابهة قبل الحلّ، ووضعُ مسألةٍ في معادلة، والتحقّقُ من صحّة الحلّ عدديًّا ومنطقيًّا', '# ⚔️ المعادلات من الدرجة الأولى — فكُّ شيفرة المجهول

> 💡 «كلُّ مسألةٍ في الحياة يمكن ترجمتُها إلى معادلة؛ ومن يتقن حلَّ المعادلة يملك مفتاحَ الجواب.»

في السنة السابعة تعلّمتَ حلَّ معادلاتٍ بسيطة بأعدادٍ موجبة. في هذا الفصل ترفع المستوى: تحلّ معادلاتٍ من الشكل ax + b = c بمعاملاتٍ **جذريّةٍ نسبيّة** (سالبة، كسريّة، عشريّة)، وتتعلّم جمعَ الحدود المتشابهة قبل الحلّ، ثمّ تترجم مسائلَ أعقدَ إلى معادلاتٍ تحلّها بثقة.

## 🏰 تذكيرٌ سريع: المعادلة والمجهول والحلّ

**المعادلة** مساواةٌ بين **طرفَين** (يمينَ الإشارة = ويسارَها) تحتوي على **مجهول**، حرفٌ (غالبًا x) يرمز إلى عددٍ غيرِ معروف. في الطرف ax + b نميّز:

- **الحدّ الحرفيّ** ax: يضمّ المجهول، والعددُ a هو **معامل** المجهول.
- **الحدّ العدديّ** b: عددٌ ثابتٌ بلا مجهول.

**حلُّ المعادلة** هو العددُ الذي، إذا عوّضنا به x، يجعل الطرفَين متساويَين.

> 🗡️ في 8ème صار المعامل a والحدّ b قد يكونان **سالبَين أو كسريَّين أو عشريَّين**. القاعدةُ لا تتغيّر، لكن انتبِه جيّدًا للإشارات.

## ✅ التحقّقُ من أنّ عددًا ما حلٌّ لمعادلة

نعوّض العددَ المقترَح مكانَ x في **كلا الطرفَين**، نحسب كلَّ طرفٍ كاملًا، ثمّ نقارن.

**مثال محسوب**: هل x = −2 حلٌّ للمعادلة 3x + 10 = 4؟

- الطرفُ الأوّل: 3 × (−2) + 10 = −6 + 10 = 4
- الطرفُ الثاني: 4
- الطرفان متساويان (4 = 4) ✓ إذن x = −2 حلٌّ للمعادلة.

> ⚠️ الفخّ الشائع مع الأعداد السالبة: نسيانُ أنّ 3 × (−2) = −6 (سالب)، أو حسابُ طرفٍ واحدٍ فقط. احسب الطرفَين كاملَين قبل الحكم.

## ⚖️ مبدأُ توازن المعادلة

المعادلةُ ميزانٌ متوازن. **القاعدةُ الذهبيّة**: إذا أجرينا **العمليّةَ نفسَها على الطرفَين معًا** (جمعٌ، طرحٌ، ضربٌ، أو قسمةٌ على عددٍ غيرِ الصفر)، يبقى الميزانُ متوازنًا ولا يتغيّر الحلّ.

$$ إذا كان a = b فإنّ a + k = b + k وa − k = b − k $$

هذا المبدأ هو أساسُ كلِّ طرق الحلّ التالية.

## 🧮 حلّ ax + b = c بمعاملاتٍ صحيحةٍ نسبية

نتّبع خطوتَين ثابتتَين:

**1 — نعزل الحدّ الحرفيّ**: ننقل الحدّ العدديّ b إلى الطرف الآخر **مع تغيير إشارته** (لأنّنا نطرحه من الطرفَين).

**2 — نعزل x**: نقسم الطرفَين على المعامل a (حتّى إن كان a سالبًا).

**مثال محسوب**: حلّ المعادلة −3x + 2 = 11

- نعزل الحدّ الحرفيّ: −3x = 11 − 2 = 9
- نقسم على −3: x = 9 ÷ (−3) = −3

**التحقّق**: −3 × (−3) + 2 = 9 + 2 = 11 ✓

> ⚠️ الفخّان الأشهر هنا: (1) نسيانُ تغيير إشارة الحدّ عند نقله (+2 يصبح −2)؛ (2) نسيانُ إشارة القسمة على معاملٍ سالب (9 ÷ (−3) = −3، لا +3).

## 🔢 معاملٌ كسريّ أو عشريّ: نضرب في المقلوب

إذا كان المعامل **كسرًا** من الشكل (a/b)، نعزل الحدّ الحرفيّ أوّلًا، ثمّ نضرب الطرفَين في **مقلوب المعامل** (b/a). وإذا كان المجهولُ مقسومًا (x/b)، نضرب الطرفَين في المقام b.

**مثال محسوب (معاملٌ كسريّ)**: حلّ المعادلة (3/4)x + 2 = 8

- نعزل الحدّ الحرفيّ: (3/4)x = 8 − 2 = 6
- نضرب في المقلوب (4/3): x = 6 × 4/3 = 8

**التحقّق**: (3/4) × 8 + 2 = 6 + 2 = 8 ✓

**مثال محسوب (المجهولُ مقسوم)**: حلّ المعادلة x/2 − 3 = 4 → x/2 = 7 → x = 7 × 2 = 14

**مثال محسوب (معاملٌ عشريّ)**: حلّ المعادلة 1,2x − 5 = 7 → 1,2x = 12 → x = 12 ÷ 1,2 = 10

> 🗡️ الفخّ الكسريّ: الضربُ في المعامل نفسِه بدل مقلوبه. حلُّ (3/4)x = 6 يكون بالضرب في **4/3** (فنحصل على 8)، لا في 3/4 (الذي يعطي 4,5 خطأً).

## ➕ جمعُ الحدود المتشابهة قبل الحلّ

أحيانًا يظهر المجهولُ أكثرَ من مرّة (خاصّةً عند وضع مسألة). نجمع أوّلًا الحدودَ المتشابهة لنعود إلى الشكل القياسيّ ax + b = c، ثمّ نحلّ.

**مثال محسوب**: مجموعُ ثلثِ عددٍ ورُبعِه يساوي 14: (1/3)x + (1/4)x = 14

- نوحّد المقامات: (4/12)x + (3/12)x = (7/12)x = 14
- نضرب في المقلوب (12/7): x = 14 × 12/7 = 24

**التحقّق**: (1/3) × 24 + (1/4) × 24 = 8 + 6 = 14 ✓

> ⚠️ لا تجمع المقامات! (1/3) + (1/4) = 7/12، لا 2/7 ولا 1/7. وحِّد المقامَ دائمًا قبل الجمع.

## 📐 وضعُ مسألةٍ في معادلة والتحقّق

**المنهجيّة**: (1) نسمّي المجهولَ x ونوضّح ماذا يمثّل؛ (2) نترجم المعطيات إلى معادلة؛ (3) نحلّ؛ (4) نتحقّق من الحلّ في المعادلة **وفي سياق المسألة** (طولٌ موجب، عمرٌ منطقيّ…)، ثمّ نصوغ الجواب بجملة.

**مثال محسوب**: مستطيلٌ طولُه يساوي 3 أمثال عرضِه ناقصَ 2 متر، ومحيطُه 44 مترًا. ما عرضُه؟

- نسمّي x العرضَ (بالمتر)، فالطولُ 3x − 2.
- المحيطُ = 2 × (الطول + العرض): 2 × ((3x − 2) + x) = 2 × (4x − 2) = 8x − 4
- المعادلة: 8x − 4 = 44 → 8x = 48 → x = 6
- **التحقّق**: العرض 6 م، الطول 3 × 6 − 2 = 16 م، المحيط 2 × (16 + 6) = 44 ✓
- الجواب: عرضُ المستطيل 6 أمتار.

> ⚠️ الفخّ عند الترجمة: الخلطُ بين "زيادة" (+) و"نقصان" (−)، ونسيانُ صيغة المحيط، والإجابةُ بالكمّيّة الخاطئة (الطول بدل العرض). اقرأ السؤالَ جيّدًا وتحقّق دائمًا.

> 🏆 أتقنتَ الآن حلَّ المعادلات بمعاملاتٍ نسبيّة وكسريّة وعشريّة، وجمعَ الحدود المتشابهة، ووضعَ المسائل في معادلات. هذه الأدواتُ ستفتح لك في السنة التاسعة أبوابَ المتراجحات والجُمل بمجهولَين.', '# 📜 ملخّص: المعادلات من الدرجة الأولى بمجهول واحد

- **المعادلة والمجهول والحلّ:** مساواةٌ بين طرفَين تحتوي مجهولًا x؛ في ax + b نميّز الحدّ الحرفيّ ax (وa معامله) والحدّ العدديّ b؛ الحلُّ هو العددُ الذي يجعل الطرفَين متساويَين عند التعويض.
- **التحقّقُ من حلّ:** نعوّض العددَ في كلا الطرفَين، نحسبُهما كاملَين — مع الانتباه لإشارات الأعداد السالبة — ثمّ نقارن.
- **مبدأُ التوازن:** إجراءُ العمليّة نفسِها (جمع/طرح/ضرب/قسمة على غير الصفر) على الطرفَين معًا لا يغيّر الحلّ.
- **حلّ ax + b = c (معاملٌ صحيحٌ نسبيّ):** ننقل b إلى الطرف الآخر مع **تغيير إشارته** (ax = c − b)، ثمّ نقسم على a — حتّى إن كان a سالبًا (فقد يكون الحلُّ سالبًا).
- **معاملٌ كسريّ أو عشريّ:** نعزل الحدّ الحرفيّ، ثمّ نضرب الطرفَين في **مقلوب المعامل** (b/a)؛ وإن كان المجهولُ مقسومًا x/b نضرب في المقام b.
- **جمعُ الحدود المتشابهة:** إذا تكرّر المجهول، نوحّد المقامات ونجمع الحدودَ للعودة إلى الشكل ax + b = c قبل الحلّ (لا تُجمع المقامات).
- **وضعُ مسألةٍ في معادلة:** نسمّي المجهولَ x، نترجم المعطيات إلى معادلة، نحلّها، ثمّ نتحقّق من الحلّ عدديًّا وفي سياق المسألة، ونصوغ الجواب بجملة.', 4, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('1d21b8df-e861-538d-a71a-2137f9397422', 'math-8eme', 'التناسبية والنسبة المئوية', 'التعرّفُ على السلاسل المتناسبة وحسابُ معامل التناسب، وإيجادُ الرابع المتناسب بالجداء التبادليّ، والنسبةُ المئوية (حسابُ نسبةٍ من كمّية، والزيادةُ والتخفيضُ بنسبةٍ مئوية بمعامل الضرب، وحسابُ نسبة التغيّر انطلاقًا من قيمتَين)، وقراءةُ السلّم على مخطّط، وحسابُ السرعة المتوسّطة مع التحويلات بين الساعة والدقيقة', '# ⚔️ التناسبية والنسبة المئوية — لغةُ التخفيضات والأسفار والخرائط

> 💡 «كلّ تخفيضٍ في السوق، كلّ ترقيةٍ في راتب، كلّ مسافةٍ على خريطة… هي في الحقيقة نسبةٌ مئويّةٌ أو تناسبٌ ينتظر من يقرؤه.»

أنت تعرف من السنة الماضية جدولَ التناسب ومعاملَه، وحسابَ نسبةٍ مئويّةٍ من كمّية. في هذا الفصل نرفع المستوى: نتعرّف على **السلاسل المتناسبة**، ونُتقن **الزيادةَ والتخفيضَ بنسبةٍ مئوية بمعامل ضربٍ واحد**، ونتعلّم **كيف نحسب نسبةَ التغيّر انطلاقًا من قيمتَين**، ثمّ نطبّق كلّ ذلك على السلّم والسرعة المتوسّطة. هذه الأدواتُ هي لغةُ الاقتصاد والجغرافيا والفيزياء.

## 🏰 السلاسل المتناسبة ومعاملُ التناسب

نقول إنّ سلسلتَي أعدادٍ **متناسبتان** إذا حصلنا على كلّ حدٍّ من السلسلة الثانية بضرب الحدّ المقابل له في السلسلة الأولى في **عددٍ ثابتٍ واحد** يُسمّى **معاملَ التناسب k**. نتحقّق من ذلك بحساب نسبة **كلّ عمود** (الحدّ الثاني ÷ الحدّ الأوّل): إن كانت النسبةُ **ثابتةً في كلّ الأعمدة**، فالسلسلتان متناسبتان.

| الكمّية 1 | 3   | 5   | 8   |
| --------- | --- | --- | --- |
| الكمّية 2 | 12  | 20  | 32  |

نحسب النسب: 12 ÷ 3 = 4، و20 ÷ 5 = 4، و32 ÷ 8 = 4. النسبةُ ثابتةٌ (4)، إذن السلسلتان متناسبتان ومعاملُ التناسب k = 4.

$$ الكمّيّةُ الثانية = k × الكمّيّةُ الأولى $$

> ⚠️ الفخّ الشائع: مقارنةُ عمودَين فقط. سلسلتان قد تتّفقان في عمودَين وتختلفان في الثالث؛ افحص **كلّ** الأعمدة قبل الحكم بالتناسب.

## 🧮 الرابعُ المتناسب: الجداءُ التبادليّ

إذا نقص حدٌّ واحد في سلسلةٍ متناسبةٍ من عمودَين، نسمّيه **الرابعَ المتناسب** ونحسبه بـ **الجداء التبادليّ (الضرب التقاطعيّ)**: نضرب الحدَّين المتقاطعَين المعلومَين ونقسم على الحدّ الثالث المعلوم.

| الكمّية 1 | 6   | 15  |
| --------- | --- | --- |
| الكمّية 2 | 8   | x   |

$$ x = (15 × 8) ÷ 6 = 120 ÷ 6 = 20 $$

> ⚠️ الفخّ الأشهر: ضربُ حدَّين من **العمود نفسه** بدل الحدَّين المتقاطعَين، أو القسمةُ على الحدّ الخطأ. اكتب السلسلةَ دائمًا قبل الحساب.

## 💰 حسابُ نسبةٍ مئوية من كمّية

**النسبةُ المئوية** t % هي معاملُ تناسبٍ قيمتُه t ÷ 100. لحساب t % من كمّيّةٍ Q:

$$ t % من Q = (t × Q) ÷ 100 $$

**مثال محسوب**: 15 % من 240 دينارًا = (15 × 240) ÷ 100 = 3600 ÷ 100 = 36 دينارًا.

كلّ نسبةٍ مئوية تُكتب أيضًا كسرًا مقامُه 100، أو عددًا عشريًّا (قسمة t على 100): 15 % = 15/100 = 0,15.

## 📈 الزيادةُ والتخفيضُ بنسبةٍ مئوية: معاملُ الضرب

الجديدُ هذا العام هو حسابُ القيمة **بعد** زيادةٍ أو تخفيض بمعامل ضربٍ واحد، بدل خطوتَين:

- **الزيادةُ بـ t %**: القيمةُ الجديدة = القيمةُ الأصليّة × (1 + t/100).
- **التخفيضُ بـ t %**: القيمةُ الجديدة = القيمةُ الأصليّة × (1 − t/100).

$$ زيادة t %: × (1 + t/100) — تخفيض t %: × (1 − t/100) $$

**مثال محسوب (تخفيض)**: قميصٌ ثمنُه 90 دينارًا، عليه تخفيضٌ 20 %. الثمنُ بعد التخفيض = 90 × (1 − 20/100) = 90 × 0,8 = 72 دينارًا.

**مثال محسوب (زيادة)**: راتبٌ 500 دينار، زِيد بنسبة 10 %. الراتبُ الجديد = 500 × (1 + 10/100) = 500 × 1,1 = 550 دينارًا.

**الاتّجاهُ العكسيّ** (نعرف القيمة الجديدة ونطلب الأصليّة): نقسم على معامل الضرب. إذا أصبح ثمنٌ بعد تخفيض 20 % يساوي 72 دينارًا، فالأصليّ = 72 ÷ 0,8 = 90 دينارًا.

> ⚠️ الفخّ القاتل: بعد تخفيض 20 %، **لا** يعود الثمنُ إلى أصله بزيادة 20 % عليه — لأنّ 20 % تُحسب على قيمةٍ أصغر. استعمل القسمةَ على معامل الضرب، لا الزيادةَ العكسيّة.

## 🎯 حسابُ نسبة التغيّر انطلاقًا من قيمتَين

إذا عرفنا القيمةَ الأصليّة والقيمةَ الجديدة وأردنا **نسبةَ الزيادة أو التخفيض**:

$$ نسبةُ التغيّر % = (القيمةُ الجديدة − القيمةُ الأصليّة) ÷ القيمةُ الأصليّة × 100 $$

**مثال محسوب**: ارتفع ثمنُ سلعةٍ من 80 دينارًا إلى 100 دينار. نسبةُ الزيادة = (100 − 80) ÷ 80 × 100 = 20 ÷ 80 × 100 = 25 %.

> ⚠️ الفخّ الأخطر: القسمةُ على القيمة **الجديدة** بدل الأصليّة (20 ÷ 100 = 20 %). نسبةُ التغيّر تُحسب دائمًا بالنسبة إلى **القيمة الأصليّة** (المرجع).

## 🗺️ السلّم: من المخطّط إلى الواقع

**السلّمُ** معاملُ تناسبٍ يُكتب على الصورة 1/n، يربط مسافةً على مخطّطٍ بالمسافة الحقيقيّة بالوحدة نفسها: 1 سم على المخطّط يمثّل n سم في الواقع.

**مثال محسوب**: على خريطةٍ سلّمُها 1/50000، المسافةُ بين قريتَين 7 سم. الحقيقيّة = 7 × 50000 = 350000 سم = 3500 م = 3,5 كم.

> 🗡️ حوّل الوحدتَين إلى الوحدة نفسها (السنتيمتر غالبًا) قبل استعمال السلّم، ثمّ عامله كمعامل تناسب عاديّ: الحقيقيّة = المخطّط × n، والمخطّط = الحقيقيّة ÷ n.

## 🚗 السرعةُ المتوسّطة والتحويلات

**السرعةُ المتوسّطةُ** تربط المسافةَ المقطوعة بالزمن المستغرق:

$$ السرعة = المسافة ÷ الزمن $$

بمسافةٍ بالكيلومتر وزمنٍ بالساعة تكون السرعةُ بـ كم/سا. ومن هذه العلاقة نستنتج: المسافة = السرعة × الزمن، والزمن = المسافة ÷ السرعة.

**تحويلُ الدقائق إلى ساعات**: بما أنّ الساعة = 60 دقيقة، فإنّ m دقيقة = m ÷ 60 ساعة. مثلًا 30 د = 0,5 سا، و1 سا 15 د = 1,25 سا، و45 د = 0,75 سا.

**مثال محسوب**: قطع قطارٌ 120 كم في 1 سا 30 د. نحوّل الزمن: 1 سا 30 د = 1,5 سا. السرعة = 120 ÷ 1,5 = 80 كم/سا.

> ⚠️ الفخّ الأشهر: القسمةُ على عدد الدقائق مباشرةً (120 ÷ 90) بدل تحويلها إلى ساعات أوّلًا (120 ÷ 1,5). حوّل الزمنَ إلى ساعاتٍ قبل القسمة كلّما كانت الوحدةُ المطلوبة كم/سا.

> 🏆 أتقنتَ الآن التناسبيةَ والنسبةَ المئوية بكلّ وجوهها: السلاسلَ المتناسبة، الرابعَ المتناسب، الزيادةَ والتخفيضَ بمعامل ضرب، نسبةَ التغيّر، السلّم، والسرعةَ المتوسّطة. هذه الأدواتُ ستقودك في الإحصاء والهندسة، وستمهّد لك الدوالَّ الخطّية والتآلفية في السنة القادمة.', '# 📜 ملخّص: التناسبية والنسبة المئوية

- **السلاسلُ المتناسبة ومعاملُها:** سلسلتان متناسبتان إذا كانت نسبةُ كلّ عمود (الثانية ÷ الأولى) **ثابتة** عبر كلّ الأعمدة؛ هذه النسبةُ الثابتة هي معاملُ التناسب k، و«الثانية = k × الأولى».
- **الرابعُ المتناسب:** حدٌّ ناقصٌ في سلسلةٍ من عمودَين يُحسب بالجداء التبادليّ: نضرب الحدَّين المتقاطعَين المعلومَين ونقسم على الحدّ الثالث.
- **نسبةٌ مئوية من كمّية:** t % من Q تساوي (t × Q) ÷ 100؛ وتُكتب كسرًا مقامُه 100 أو عددًا عشريًّا (t ÷ 100).
- **الزيادةُ والتخفيضُ بمعامل ضرب:** زيادةٌ بـ t %: × (1 + t/100)؛ تخفيضٌ بـ t %: × (1 − t/100)؛ لإيجاد القيمة الأصليّة نقسم القيمةَ الجديدة على معامل الضرب (لا نعكس النسبة).
- **نسبةُ التغيّر من قيمتَين:** النسبة % = (الجديدة − الأصليّة) ÷ الأصليّة × 100؛ القسمةُ دائمًا على القيمة **الأصليّة** لا الجديدة.
- **السلّم:** معاملُ تناسبٍ 1/n بين مسافةٍ على مخطّطٍ ومسافةٍ حقيقيّة بالوحدة نفسها؛ الحقيقيّة = المخطّط × n، والمخطّط = الحقيقيّة ÷ n.
- **السرعةُ المتوسّطة:** السرعة = المسافة ÷ الزمن (كم/سا)؛ المسافة = السرعة × الزمن، والزمن = المسافة ÷ السرعة؛ تُحوَّل الدقائقُ إلى ساعات بقسمتها على 60 قبل الحساب.', 5, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
