INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('dc069921-eb84-505a-94b2-025b1413186e', 'math-8eme', 'الزوايا والمستقيمات المتوازية', 'الزوايا المتكوّنة من مستقيمَين وقاطعٍ (المتقابلتان بالرأس، المتناظرتان، المتبادلتان داخليًّا والمتحالفتان داخليًّا)، والعلاقة بين هذه الزوايا والتوازي مع شروط التوازي، ومجموعُ زوايا المثلّث (180°) والمضلّع ((n − 2)×180°)', '# ⚔️ الزوايا والمستقيمات المتوازية

> 💡 «مستقيمٌ واحدٌ يعبر مستقيمَين فيولّد ثمانيَ زوايا؛ ومَن يعرف أيّها متساوٍ وأيّها متكاملٌ يقرأ الشكلَ كلَّه من زاويةٍ واحدة.»

في السنوات الماضية تعلّمتَ قيسَ الزاوية وأنواعَها (حادّة، قائمة، منفرجة). اليوم تربط الزوايا بالتوازي: تتعرّف على الزوايا التي يكوّنها مستقيمان وقاطعٌ، وتكتشف متى يكون المستقيمان متوازيَين، ثمّ تحسب مجموعَ زوايا المثلّث وأيّ مضلّع. هذه الأدواتُ هي لغةُ الهندسة كلِّها.

## 🔁 زاويتان متقابلتان بالرأس

عندما يتقاطع مستقيمان في نقطة، يتكوّن أربعُ زوايا. الزاويتان **المتقابلتان بالرأس** هما اللتان تشتركان في الرأس ويقع كلٌّ منهما مقابلَ الأخرى (ضلعاهما امتدادان لضلعَي الأخرى). القاعدة:

$$ \text{الزاويتان المتقابلتان بالرأس متساويتان} $$

_مثال:_ إذا تقاطع مستقيمان وكانت إحدى الزوايا 50°، فالزاوية المقابلة لها بالرأس تساوي 50° أيضًا.

## ➕ زاويتان متكاملتان وزاويتان متتامّتان

- **زاويتان متكاملتان** (متجاورتان على استقامة واحدة): مجموعهما 180°.
- **زاويتان متتامّتان**: مجموعهما 90°.

$$ \text{متكاملتان: } a + b = 180° \qquad \text{متتامّتان: } a + b = 90° $$

_مثال:_ إذا كانت إحدى زاويتَين متكاملتَين 110°، فالأخرى 180° − 110° = 70°.

> ⚠️ الفخّ الشائع: خلطُ **المتكاملتين** (180°) بـ **المتتامّتين** (90°). زاويةٌ متمّمها إلى 90 غيرُ مكمّلها إلى 180.

## ✂️ مستقيمان وقاطع: الأزواج الثلاثة

عندما يقطع مستقيمٌ ثالثٌ (نسمّيه **القاطع**) مستقيمَين (d) و(d'')، تتكوّن ثمانيُ زوايا نصنّفها في أزواج حسب موقعها:

- **الزاويتان المتناظرتان**: تحتلّان **الموقع نفسه** عند كلّ تقاطع (مثلًا: أعلى-يمين عند الأولى وأعلى-يمين عند الثانية).
- **الزاويتان المتبادلتان داخليًّا**: تقعان **بين** المستقيمَين (d) و(d'')، على **جهتَين متقابلتَين** من القاطع.
- **الزاويتان المتحالفتان داخليًّا** (الداخليّتان على نفس الجهة): تقعان **بين** المستقيمَين، على **الجهة نفسها** من القاطع.

هذا التصنيفُ لا يعتمد على التوازي بعدُ؛ إنّه مجرّدُ تسميةٍ حسب الموقع.

## 📐 الزوايا والتوازي (الخاصيات)

إذا كان **(d) و(d'') متوازيَين**، فإنّ القاطع يولّد هذه العلاقات:

| نوع الزاويتَين           | العلاقة عند التوازي       |
| ------------------------ | ------------------------- |
| **المتناظرتان**          | متساويتان                 |
| **المتبادلتان داخليًّا** | متساويتان                 |
| **المتحالفتان داخليًّا** | متكاملتان (مجموعهما 180°) |

_مثال محسوب:_ إذا كان (d)//(d'') وكانت إحدى زاويتَين متبادلتَين داخليًّا 65°، فالأخرى 65°. لكن إذا كانت إحدى زاويتَين **متحالفتَين** داخليًّا 65°، فالأخرى 180° − 65° = 115°.

> ⚠️ أخطرُ فخٍّ في الدرس: اعتبارُ **المتحالفتَين داخليًّا متساويتَين**. المتبادلتان داخليًّا متساويتان، أمّا المتحالفتان (على نفس الجهة) فـ **متكاملتان** — مجموعهما 180°، لا متساويتان.

> 🗡️ حيلةُ التمييز: المتبادلتان تُرسمان على شكل حرفَي **Z** (متساويتان)، والمتحالفتان على شكل حرف **U/C** (متكاملتان، مجموعهما 180°).

## 🔓 شروط التوازي (القاعدة العكسية)

الخاصياتُ السابقة تعمل في الاتجاه العكسيّ أيضًا، وهذا ما يُثبت التوازي:

> إذا قطع قاطعٌ مستقيمَين وكوّن **زاويتَين متبادلتَين داخليًّا متساويتَين** (أو **متناظرتَين متساويتَين**، أو **متحالفتَين داخليًّا متكاملتَين**)، فإنّ المستقيمَين **متوازيان**.

_مثال:_ إذا كوّن قاطعٌ زاويتَين متناظرتَين قيسهما 70° و70°، فالمستقيمان متوازيان. أمّا لو كانتا 70° و80° فليسا متوازيَين.

## 🔺 مجموع زوايا المثلّث

في **أيّ** مثلّث، مجموعُ الزوايا الثلاث ثابتٌ:

$$ \hat{A} + \hat{B} + \hat{C} = 180° $$

نستنتج منه:

- **المثلّث المتساوي الأضلاع**: كلّ زاوية 180° ÷ 3 = 60°.
- **المثلّث القائم**: الزاويتان الحادّتان متتامّتان (مجموعهما 90°).
- **المثلّث المتساوي الساقَين**: زاويتا القاعدة متساويتان.
- **الزاوية الخارجية** لمثلّث تساوي مجموعَ الزاويتَين الداخليّتَين غير المجاورتَين لها.

_مثال محسوب:_ مثلّثٌ زاويتاه 40° و75°؛ الثالثة = 180° − (40° + 75°) = 180° − 115° = 65°.

> ⚠️ الفخّ الشائع: نسيانُ أنّ المجموع 180° وجمعُ زاويتَين فقط، أو طرحُ خطأ (180 − 40 = 140 دون طرح الثانية).

## ⬡ مجموع زوايا مضلّع

المضلّعُ ذو n ضلعًا يُقسَّم إلى (n − 2) مثلّثًا انطلاقًا من رأسٍ واحد، فيكون مجموعُ زواياه الداخلية:

$$ \text{المجموع} = (n − 2)×180° $$

| المضلّع | n   | المجموع             |
| ------- | --- | ------------------- |
| مثلّث   | 3   | (3 − 2)×180° = 180° |
| رباعي   | 4   | (4 − 2)×180° = 360° |
| خماسي   | 5   | (5 − 2)×180° = 540° |
| سداسي   | 6   | (6 − 2)×180° = 720° |

في **المضلّع المنتظم** (كلّ أضلاعه وزواياه متساوية)، قيسُ كلّ زاوية داخلية:

$$ \text{الزاوية الواحدة} = \frac{(n − 2)×180°}{n} $$

_مثال:_ السداسي المنتظم: كلّ زاوية = 720° ÷ 6 = 120°.

> ⚠️ الفخّ الأشهر: استعمالُ n×180° بدل (n − 2)×180° (فيُكتب مجموعُ الخماسي 900° بدل 540°). لا تنسَ طرحَ 2. وفخٌّ ثانٍ: الخلطُ بين **مجموع** زوايا المنتظم والزاوية **الواحدة** (720° مجموعُ السداسي، لكنّ الزاوية الواحدة 120°).

> 🏆 أصبحتَ الآن تقرأ أيّ شكلٍ من زاويةٍ واحدة: تعرف المتساويَ من المتكامل، وتُثبت التوازيَ من الزوايا، وتحسب مجموعَ زوايا أيّ مثلّثٍ أو مضلّع. هذه الأدواتُ سلاحُك في البراهين الهندسية القادمة.', '# 📜 ملخّص: الزوايا والمستقيمات المتوازية

- **المتقابلتان بالرأس:** متساويتان دائمًا عند تقاطع مستقيمَين.
- **المتكاملتان:** مجموعهما 180° (على استقامة واحدة)؛ **المتتامّتان:** مجموعهما 90°.
- **مستقيمان وقاطع:** ثلاثةُ أزواج حسب الموقع — المتناظرتان، المتبادلتان داخليًّا، المتحالفتان داخليًّا.
- **عند التوازي (d)//(d''):** المتناظرتان **متساويتان**، المتبادلتان داخليًّا **متساويتان**، المتحالفتان داخليًّا **متكاملتان** (180°). ⚠️ المتحالفتان ليستا متساويتَين.
- **شروط التوازي:** إذا كانت المتبادلتان داخليًّا متساويتَين (أو المتناظرتان متساويتَين، أو المتحالفتان متكاملتَين) فالمستقيمان متوازيان.
- **مجموع زوايا مثلّث:** Â + B̂ + Ĉ = 180°؛ متساوي الأضلاع كلّ زاوية 60°، القائم زاويتاه الحادّتان مجموعهما 90°.
- **مجموع زوايا مضلّع:** (n − 2)×180° (رباعي 360°، خماسي 540°، سداسي 720°)؛ الزاوية الواحدة في المنتظم = (n − 2)×180° ÷ n. ⚠️ لا تنسَ طرحَ 2.', 9, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('c8c10e2d-2106-59cb-b4a1-05920b7c30c6', 'math-8eme', 'تقايس المثلثات', 'معنى تقايس مثلثين (الانطباق التامّ وتناظر الأضلاع والزوايا)، وحالات التقايس الثلاث: الحالة الأولى (ضلعان والزاوية المحصورة بينهما)، الحالة الثانية (ضلعٌ والزاويتان المجاورتان له)، الحالة الثالثة (الأضلاع الثلاثة)، مع تطبيقاتٍ وبراهينَ بسيطة', '# ⚔️ تقايس المثلثات

> 💡 «مثلثان متقايسان توأمان في الشكل والحجم؛ ولا يلزمك قياسُ كلّ شيء لتتأكّد من ذلك، بل يكفيك ثلاثةُ معطياتٍ مختارةٍ بذكاء.»

في الدرس الماضي رأيتَ أنّ التناظرَ المركزيّ والانسحابَ يحفظان الأطوالَ والزوايا. اليوم نستعمل هذه الفكرة: مثلثان **متقايسان** (isométriques) إذا أمكن أن ينطبق أحدهما على الآخر تمامًا. لكنْ ليس علينا قياسُ الأضلاع الثلاثة والزوايا الثلاث في كلّ مرّة؛ سنتعلّم **ثلاثَ حالات** تُثبت التقايسَ من ثلاثة معطياتٍ فقط. هذه الحالاتُ هي سلاحُ البراهين في الهندسة.

## 🎯 ما معنى «مثلثان متقايسان»؟

مثلثان **متقايسان** لهما نفسُ الشكل ونفسُ الحجم: ينطبق أحدهما على الآخر بالتمام. نكتب مثلًا: المثلث ABC يقايس المثلث A''B''C''، ونحترم **ترتيبَ الرؤوس** لأنّه يحدّد التناظر:

$$ A ↔ A'' \quad ; \quad B ↔ B'' \quad ; \quad C ↔ C'' $$

ويترتّب على هذا التناظر أنّ **الأضلاع المتناظرة متقايسة** و**الزوايا المتناظرة متقايسة**:

$$ AB = A''B'' \quad ; \quad BC = B''C'' \quad ; \quad CA = C''A'' $$

$$ \widehat{A} = \widehat{A''} \quad ; \quad \widehat{B} = \widehat{B''} \quad ; \quad \widehat{C} = \widehat{C''} $$

> ⚠️ لا تخلط بين **متقايسَين** و**متشابهَين**: المتشابهان لهما نفسُ الشكل لكنْ قد يختلف الحجم (مثلثٌ صغيرٌ وآخرُ كبيرٌ بنفس الزوايا). المتقايسان متشابهان **وبنفس الحجم** أيضًا. التقايسُ أقوى من التشابه.

## 📐 الزاوية المحصورة بين ضلعين

قبل الحالات، نحتاج مصطلحًا واحدًا: **الزاوية المحصورة** بين ضلعين هي الزاويةُ التي **رأسُها هو الرأسُ المشترك** بين الضلعين.

- الزاويةُ المحصورةُ بين [AB] و[AC] هي الزاوية A (الرأسُ المشترك A).
- الزاويةُ المحصورةُ بين [BA] و[BC] هي الزاوية B (الرأسُ المشترك B).

> 🗡️ حيلةٌ سريعة: انظر إلى الحرف الذي يتكرّر في اسمَي الضلعين — هو رأسُ الزاوية المحصورة. في [AB] و[BC] الحرفُ المتكرّر هو B.

## 🔺 الحالة الأولى: ضلعان والزاوية المحصورة بينهما (ض ـ ز ـ ض)

> إذا كان لمثلثين **ضلعان متقايسان** و**الزاويةُ المحصورةُ بينهما** متقايسةً، فالمثلثان متقايسان.

_مثال محسوب:_ في المثلثين ABC و A''B''C'':

$$ AB = A''B'' = 5 \text{ cm} \quad ; \quad AC = A''C'' = 4 \text{ cm} \quad ; \quad \widehat{A} = \widehat{A''} = 50° $$

الزاوية A محصورةٌ بين الضلعين [AB] و[AC]، فتنطبق الحالةُ الأولى ⇐ المثلثان متقايسان، ونستنتج مثلًا أنّ BC = B''C''.

> ⚠️ الفخّ الأخطر في هذه الحالة: أن تكون الزاويةُ المتقايسةُ **غيرَ محصورةٍ** بين الضلعين. لو عرفنا AB = A''B'' و AC = A''C'' لكنّ الزاويةَ المتقايسةَ هي B (لا A)، فهذه حالةُ «ضلعان وزاويةٌ غيرُ محصورة» و**لا تضمن التقايس**. لا بدّ أن تكون الزاويةُ **بين** الضلعين المتقايسين.

## 🔺 الحالة الثانية: ضلعٌ والزاويتان المجاورتان له (ز ـ ض ـ ز)

> إذا كان لمثلثين **ضلعٌ متقايس** و**الزاويتان الواقعتان على طرفيه** متقايستين، فالمثلثان متقايسان.

_مثال محسوب:_ في المثلثين ABC و A''B''C'':

$$ \widehat{B} = \widehat{B''} = 60° \quad ; \quad BC = B''C'' = 6 \text{ cm} \quad ; \quad \widehat{C} = \widehat{C''} = 55° $$

الضلع [BC] محصورٌ بين الزاويتين B و C، فتنطبق الحالةُ الثانية ⇐ المثلثان متقايسان.

> 🗡️ لماذا يكفي ضلعٌ وزاويتان؟ لأنّ مجموعَ زوايا المثلث 180°؛ فمتى عرفتَ زاويتين عرفتَ الثالثة. المهمّ أن يكون الضلعُ المتقايسُ **محصورًا بين** الزاويتين المتقايستين.

## 🔺 الحالة الثالثة: الأضلاع الثلاثة (ض ـ ض ـ ض)

> إذا كانت **الأضلاعُ الثلاثة** لمثلثٍ متقايسةً مع الأضلاع الثلاثة لمثلثٍ آخرَ **مثنى مثنى**، فالمثلثان متقايسان.

_مثال محسوب:_ في المثلثين ABC و A''B''C'':

$$ AB = A''B'' = 7 \text{ cm} \quad ; \quad BC = B''C'' = 6 \text{ cm} \quad ; \quad CA = C''A'' = 5 \text{ cm} $$

الأضلاعُ متقايسةٌ مثنى مثنى ⇐ المثلثان متقايسان، وتتساوى تِبعًا لذلك زواياهما المتناظرة.

## 📋 جدولُ الحالات الثلاث

| الحالة      | الرمز     | المعطيات الثلاثة                              |
| ----------- | --------- | --------------------------------------------- |
| **الأولى**  | ض ـ ز ـ ض | ضلعان متقايسان + الزاوية **المحصورة** بينهما  |
| **الثانية** | ز ـ ض ـ ز | ضلعٌ متقايس + الزاويتان **المجاورتان** لطرفيه |
| **الثالثة** | ض ـ ض ـ ض | الأضلاع الثلاثة متقايسة مثنى مثنى             |

## 🚫 ما لا يكفي للتقايس

انتبه إلى «حالتين مزيّفتين» يقع فيهما كثيرٌ من التلاميذ:

- **الزوايا الثلاث فقط (ز ـ ز ـ ز):** تساوي الزوايا مثنى مثنى يعطي **التشابهَ** لا التقايس؛ فقد يكون أحدُ المثلثين أكبرَ من الآخر بنفس الزوايا. لا بدّ من معطًى واحدٍ على الأقلّ عن **طول** ضلع.
- **ضلعان وزاويةٌ غيرُ محصورة:** كما رأينا في الحالة الأولى، إن لم تكن الزاويةُ محصورةً بين الضلعين المتقايسين فالمعطياتُ **لا تضمن** التقايس.

> ⚠️ تذكّر: كلُّ حالةٍ تحتاج بالضبط إلى **ثلاثة** معطياتٍ من النوع الصحيح وفي الموضع الصحيح. لا يكفي «ضلعان وزاوية» أو «ثلاث زوايا» بأيّ ترتيب.

## ✍️ كيف نكتب التناظر بترتيبٍ صحيح

عندما نكتب «ABC يقايس A''B''C''»، فإنّ الترتيبَ يقرأ التناظرَ: أوّلٌ مع أوّل، ثانٍ مع ثانٍ، ثالثٌ مع ثالث. لذلك:

$$ AB = A''B'' \quad \text{لكنْ} \quad AB \neq B''C'' $$

> 🗡️ عند استنتاج طولٍ أو زاويةٍ من التقايس، اكتب أوّلًا التناظرَ (A↔A''...) ثمّ اقرأ منه المتناظرَين. هذا يحميك من مطابقةٍ خاطئة.

## 🧩 تطبيقٌ: برهانٌ بسيط في المثلث المتساوي الساقين

المثلثُ المتساوي الساقين ABC حيث AB = AC، ولتكن M منتصفَ [BC]. **نُثبت أنّ الزاوية B = الزاوية C.**

نقارن المثلثين ABM و ACM:

- AB = AC (معطى، الساقان)،
- BM = CM (لأنّ M منتصفُ [BC])،
- [AM] ضلعٌ مشتركٌ بينهما.

الأضلاعُ الثلاثة متقايسةٌ مثنى مثنى ⇐ بالحالة الثالثة (ض ـ ض ـ ض) المثلثان متقايسان. ومن تناظر الزوايا نستنتج:

$$ \widehat{B} = \widehat{C} $$

وأكثرُ من ذلك: الزاويتان AMB و AMC متناظرتان ومتقايستان، ومجموعُهما 180° (زاويةٌ مستقيمة)، فكلٌّ منهما 90°؛ إذنْ [AM] عموديٌّ على [BC]. هكذا يكون المتوسّطُ من الرأس في المثلث المتساوي الساقين ارتفاعًا أيضًا. 🎯

> 🏆 أتقنتَ الآن معنى التقايس والحالاتِ الثلاث (ض ـ ز ـ ض ، ز ـ ض ـ ز ، ض ـ ض ـ ض)، وميّزتَ ما لا يكفي (الزوايا وحدها، أو زاويةٌ غيرُ محصورة)، وبدأتَ توظيفَها في البراهين. هذه الأدواتُ ستُرافقك في فيثاغور والدائرة وفي كلّ هندسة السنوات القادمة.', '# 📜 ملخّص: تقايس المثلثات

- **معنى التقايس:** مثلثان متقايسان ينطبق أحدهما على الآخر تمامًا (نفسُ الشكل ونفسُ الحجم)؛ الأضلاعُ المتناظرة متقايسة والزوايا المتناظرة متقايسة. نحترم ترتيبَ الرؤوس: ABC يقايس A''B''C'' يعني A↔A''، B↔B''، C↔C''.
- **متقايس ≠ متشابه:** المتشابهان لهما نفسُ الشكل مع إمكان اختلاف الحجم؛ المتقايسان متشابهان **وبنفس الحجم**.
- **الزاوية المحصورة:** بين ضلعين هي الزاويةُ التي رأسُها الرأسُ المشترك بينهما (بين [AB] و[BC] ⇐ الزاوية B).
- **الحالة الأولى (ض ـ ز ـ ض):** ضلعان متقايسان + الزاوية **المحصورة** بينهما ⇐ تقايس.
- **الحالة الثانية (ز ـ ض ـ ز):** ضلعٌ متقايس + الزاويتان **المجاورتان** لطرفيه ⇐ تقايس.
- **الحالة الثالثة (ض ـ ض ـ ض):** الأضلاع الثلاثة متقايسة مثنى مثنى ⇐ تقايس.
- **ما لا يكفي:** الزوايا الثلاث وحدها (ز ـ ز ـ ز) تعطي التشابهَ لا التقايس؛ وضلعان وزاويةٌ **غيرُ محصورة** لا يضمنان التقايس.
- **التطبيق في البراهين:** لإثبات تساوي ضلعين أو زاويتين، ابحث عن مثلثين متقايسين يحتويانهما كعنصرين متناظرين (مثل المثلث المتساوي الساقين: AB=AC وM منتصفُ [BC] ⇐ ABM و ACM متقايسان بالحالة الثالثة ⇐ الزاوية B = الزاوية C و[AM] عموديّ على [BC]).', 10, NULL)
ON CONFLICT (id) DO UPDATE SET
