INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dbf04301-8bcf-5e35-b229-e8ea3c2ae70c', '7945f775-aa19-5d28-91ed-554e190bd5b2', 'ما ناتجُ (−6) + (+10)؟', '[{"id":"a","text":"−16"},{"id":"b","text":"−4"},{"id":"c","text":"4"},{"id":"d","text":"16"}]'::jsonb, 'c', 'الإشارتان مختلفتان، فنطرح الأصغرَ قيمةً مطلقةً من الأكبر: 10 − 6 = 4، ونأخذ إشارةَ الأكبر قيمةً مطلقة (+10)؛ إذن الناتجُ +4.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fdfcb91c-f4f3-51cc-bc6b-18049ef3df26', '7945f775-aa19-5d28-91ed-554e190bd5b2', 'ما ناتجُ (−7) − (−3)؟', '[{"id":"a","text":"−10"},{"id":"b","text":"−4"},{"id":"c","text":"4"},{"id":"d","text":"10"}]'::jsonb, 'b', 'الطرحُ هو جمعُ المعاكس: (−7) − (−3) = (−7) + (+3) = −4 (لأنّ 7 > 3 والإشارةُ للأكبر قيمةً مطلقة). الخطأُ الشائع: (−7) − (−3) = −10 بجمع القيمتَين دون تحويل الطرح إلى جمع المعاكس.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a709bbe-0e6d-5773-87d5-5f5f79cfcc52', '7945f775-aa19-5d28-91ed-554e190bd5b2', 'رتّب تصاعديًا (من الأصغر إلى الأكبر) الكسور: 5/6 ، 7/8 ، 2/3.', '[{"id":"a","text":"2/3 < 5/6 < 7/8"},{"id":"b","text":"2/3 < 7/8 < 5/6"},{"id":"c","text":"5/6 < 2/3 < 7/8"},{"id":"d","text":"7/8 < 5/6 < 2/3"}]'::jsonb, 'a', 'بالكتابة العشريّة: 2/3 ≈ 0,667 و5/6 ≈ 0,833 و7/8 = 0,875. أو بجداء الطرفين والوسطين بين 5/6 و7/8: 5×8 = 40 و6×7 = 42، وبما أنّ 40 < 42 فإنّ 5/6 < 7/8. الترتيبُ الصحيح: 2/3 < 5/6 < 7/8.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fcdb379b-32ac-59a0-9072-f9ee0bd75a62', '7945f775-aa19-5d28-91ed-554e190bd5b2', 'ما ناتجُ (−2/3) × (9/4)؟', '[{"id":"a","text":"3/2"},{"id":"b","text":"−3/4"},{"id":"c","text":"−6/7"},{"id":"d","text":"−3/2"}]'::jsonb, 'd', 'بقاعدة الإشارات جداءُ سالبٍ في موجبٍ سالب؛ نضرب بسطًا في بسط ومقامًا في مقام: −(2×9)/(3×4) = −18/12 = −3/2 ✓. الخطأُ الشائع: نسيانُ الإشارة والحصولُ على 3/2 موجبًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('139a766e-a993-5028-8980-a02a0703c607', '7945f775-aa19-5d28-91ed-554e190bd5b2', 'ما ناتجُ (−8/9) ÷ (4/3)؟', '[{"id":"a","text":"−2/3"},{"id":"b","text":"2/3"},{"id":"c","text":"−3/2"},{"id":"d","text":"−32/27"}]'::jsonb, 'a', 'القسمةُ على كسرٍ هي الضربُ في مقلوبه: (−8/9) ÷ (4/3) = (−8/9) × (3/4) = −24/36 = −2/3 ✓. الخطأُ الشائع: الضربُ مباشرةً دون قلبٍ فنحصل على −32/27، أو نسيانُ الإشارة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
