  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9600b5c-a190-5102-983f-3d512bb73af2', '7945f775-aa19-5d28-91ed-554e190bd5b2', 'ما ناتجُ (−3) + (−4) × 2؟', '[{"id":"a","text":"−14"},{"id":"b","text":"−11"},{"id":"c","text":"−5"},{"id":"d","text":"2"}]'::jsonb, 'b', 'نبدأ بالضرب قبل الجمع: (−4) × 2 = −8، ثمّ (−3) + (−8) = −11 ✓. الخطأُ الشائع: حسابُ (−3) + (−4) = −7 أوّلًا ثمّ × 2 = −14، وهذا يخالف أولويّةَ الضرب على الجمع.', 6)
