INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3976ab3b-8de7-5cd4-993b-a381184a6407', 'c2b6def3-a4ae-5c50-98f3-9852973524af', 'ما معاكسُ العدد −6؟', '[{"id":"a","text":"−6"},{"id":"b","text":"−1/6"},{"id":"c","text":"1/6"},{"id":"d","text":"6"}]'::jsonb, 'd', 'معاكسُ عددٍ هو العددُ الذي يكون مجموعُه معه صفرًا؛ معاكسُ −6 هو +6 لأنّ (−6) + (+6) = 0. الجوابُ −1/6 هو المقلوبُ لا المعاكس.', 2)
