INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c27c022-3284-5d0c-98ad-d88ad883f4ba', 'c2b6def3-a4ae-5c50-98f3-9852973524af', 'ما ناتجُ (+9) + (−15)؟', '[{"id":"a","text":"−24"},{"id":"b","text":"−6"},{"id":"c","text":"6"},{"id":"d","text":"24"}]'::jsonb, 'b', 'الإشارتان مختلفتان، فنطرح: 15 − 9 = 6، ونأخذ إشارةَ الأكبر قيمةً مطلقة (−15)؛ إذن الناتجُ −6. الجوابُ −24 خطأٌ من جمع القيمتَين بإشارةٍ سالبة.', 3)
