INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0745daff-c6e6-5f4c-bd7a-0bbae6482595', 'c2b6def3-a4ae-5c50-98f3-9852973524af', 'ما ناتجُ (−12) − (−20)؟', '[{"id":"a","text":"−32"},{"id":"b","text":"−8"},{"id":"c","text":"8"},{"id":"d","text":"32"}]'::jsonb, 'c', 'الطرحُ جمعُ المعاكس: (−12) − (−20) = (−12) + (+20) = +8 (لأنّ 20 > 12 والإشارةُ للأكبر). الخطأُ الشائع: −32 بجمع القيمتَين دون تحويل الطرح.', 4)
