INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('98bdcdff-f011-5268-bcb8-19d79d039d25', 'c2b6def3-a4ae-5c50-98f3-9852973524af', 'رتّب تصاعديًا (من الأصغر إلى الأكبر): −1/2 ، −3/4 ، −4/5.', '[{"id":"a","text":"−1/2 < −3/4 < −4/5"},{"id":"b","text":"−4/5 < −3/4 < −1/2"},{"id":"c","text":"−3/4 < −4/5 < −1/2"},{"id":"d","text":"−4/5 < −1/2 < −3/4"}]'::jsonb, 'b', 'بالكتابة العشريّة: −1/2 = −0,5 و−3/4 = −0,75 و−4/5 = −0,8. بين السوالب الأكبرُ قيمةً مطلقةً هو الأصغر، فالترتيب: −4/5 < −3/4 < −1/2. الخطأُ الشائع: اختيارُ −1/2 < −3/4 كأنّ رقمًا أكبرَ يعني عددًا أكبر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f23d2ca-b50e-5159-8fe0-cbba42e2f542', 'c2b6def3-a4ae-5c50-98f3-9852973524af', 'ما ناتجُ (−2/5) × 10؟', '[{"id":"a","text":"−4"},{"id":"b","text":"−2/5"},{"id":"c","text":"2/5"},{"id":"d","text":"4"}]'::jsonb, 'a', '(−2/5) × 10 = −(2 × 10)/5 = −20/5 = −4 ✓. بقاعدة الإشارات جداءُ سالبٍ في موجبٍ سالب. الجوابُ 4 خطأٌ في الإشارة.', 6)
