INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6292455c-bcd8-5a4a-ac6a-1466e2c997cd', '11f08802-5735-5acd-8a80-388e358b90d8', 'في مدينة عين دراهم بلغت درجةُ الحرارة −5°C ليلًا، ثمّ ارتفعت بمقدار 8 درجات نهارًا، ثمّ انخفضت 3 درجات مساءً. ما درجةُ الحرارة مساءً؟', '[{"id":"a","text":"−16"},{"id":"b","text":"−8"},{"id":"c","text":"−5"},{"id":"d","text":"0"}]'::jsonb, 'd', 'نجمع التغيّرات بترتيبها: −5 + 8 − 3 = 3 − 3 = 0 ✓. الدرجةُ مساءً 0°C. الخطأُ الشائع: جمعُ الأعداد كلِّها بإشارةٍ سالبة (−5 − 8 − 3 = −16)، أو إهمالُ ارتفاع النهار.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('597d0647-918d-500f-b7af-463cbb038648', '11f08802-5735-5acd-8a80-388e358b90d8', 'غوّاصٌ نزل إلى العمق −30 م تحت سطح البحر (نأخذ السطحَ مرجعًا 0)، ثمّ صعد 12 م، ثمّ نزل 7 م. على أيّ عمقٍ استقرّ؟', '[{"id":"a","text":"−25"},{"id":"b","text":"−18"},{"id":"c","text":"−11"},{"id":"d","text":"25"}]'::jsonb, 'a', 'الصعودُ يُضاف موجبًا والنزولُ سالبًا: −30 + 12 − 7 = −18 − 7 = −25 ✓. استقرّ على العمق −25 م. الخطأُ الشائع: −30 + 12 + 7 = −11 بجعل النزول الأخير موجبًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90170c37-355d-5f99-bae5-397bf48419cc', '11f08802-5735-5acd-8a80-388e358b90d8', 'سجّل حسابُ فتحي عند بائعٍ ما يلي: دَينٌ 12 د (يُكتب −12)، ثمّ سدّد 20 د (+20)، ثمّ اشترى بدَينٍ قدرُه 15 د (−15). ما رصيدُ حسابه بالدينار؟', '[{"id":"a","text":"−47"},{"id":"b","text":"−27"},{"id":"c","text":"−7"},{"id":"d","text":"8"}]'::jsonb, 'c', 'نجمع الحركات: −12 + 20 − 15 = 8 − 15 = −7 ✓. الرصيدُ −7 د (أي دَينٌ قدرُه 7 د). الخطأُ الشائع: إهمالُ التسديد (+20) والحصولُ على −27، أو جمعُ كلِّ شيءٍ سالبًا (−47).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5eee08af-7356-597f-829c-9b0d374961a2', '11f08802-5735-5acd-8a80-388e358b90d8', 'انطلقت درجةُ حرارة سائلٍ من 8°C، ثمّ أخذت تنخفض بمقدار 5 درجات كلَّ ساعة طيلة ساعتين. ما درجةُ الحرارة بعد الساعتين؟', '[{"id":"a","text":"−10"},{"id":"b","text":"−2"},{"id":"c","text":"6"},{"id":"d","text":"18"}]'::jsonb, 'b', 'الانخفاضُ الكلّيّ = (−5) × 2 = −10، ثمّ 8 + (−10) = −2 ✓. الدرجةُ بعد ساعتين −2°C. الخطأُ الشائع: (8 − 5) × 2 = 6 بإجراء الطرح قبل الضرب، أو 8 + 5 × 2 = 18 بنسيان الإشارة السالبة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5badea6b-d1bc-525b-bf53-0507a1482df1', '11f08802-5735-5acd-8a80-388e358b90d8', 'ما ناتجُ (−3/4) + (5/6) − (1/2)؟', '[{"id":"a","text":"−5/12"},{"id":"b","text":"5/12"},{"id":"c","text":"−1/12"},{"id":"d","text":"−25/12"}]'::jsonb, 'a', 'نوحّد المقامات على 12: −9/12 + 10/12 − 6/12 = (−9 + 10 − 6)/12 = −5/12 ✓. الخطأُ الشائع: جمعُ البسوط دون توحيد المقامات، أو الخطأُ في إشارة أحد الكسور.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c491342-1a8f-523f-8c2d-f117d9a6d1b2', '11f08802-5735-5acd-8a80-388e358b90d8', 'عددٌ جذريّ x يحقّق x + (−3/5) = 2/5. ما قيمةُ x؟', '[{"id":"a","text":"−1"},{"id":"b","text":"−1/5"},{"id":"c","text":"1/5"},{"id":"d","text":"1"}]'::jsonb, 'd', 'نعزل x بجمع المعاكس +3/5 إلى الطرفين: x = 2/5 − (−3/5) = 2/5 + 3/5 = 5/5 = 1 ✓. الخطأُ الشائع: x = 2/5 + (−3/5) = −1/5 بعدم عكس إشارة المنقول.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

