INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad4032c4-550e-5347-8433-fe7405237681', 'b015f379-245d-54fe-89dd-fd4db6f58b0f', 'ما ناتجُ (−8) + (+3) + (−5)؟', '[{"id":"a","text":"−16"},{"id":"b","text":"−10"},{"id":"c","text":"−6"},{"id":"d","text":"0"}]'::jsonb, 'b', 'نحسب خطوةً خطوة: (−8) + (+3) = −5، ثمّ (−5) + (−5) = −10 ✓. أو نجمع السوالب −8 − 5 = −13 والموجب +3، فالناتج −10.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('76b3e887-61a4-5e49-96f0-af034f29e558', 'b015f379-245d-54fe-89dd-fd4db6f58b0f', 'ما ناتجُ (−2/3) − (1/6)؟', '[{"id":"a","text":"−5/6"},{"id":"b","text":"−1/6"},{"id":"c","text":"1/2"},{"id":"d","text":"5/6"}]'::jsonb, 'a', 'نوحّد المقامات على 6: −2/3 = −4/6، ثمّ −4/6 − 1/6 = −5/6 ✓. الخطأُ الشائع: طرحُ البسطَين دون توحيد المقامات، أو نسيانُ الإشارة السالبة فنحصل على 5/6.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90f853d7-b030-5561-a8b0-e0ea892bff4b', 'b015f379-245d-54fe-89dd-fd4db6f58b0f', 'ما ناتجُ (−3/4) × (8/9)؟', '[{"id":"a","text":"−6/13"},{"id":"b","text":"2/3"},{"id":"c","text":"3/2"},{"id":"d","text":"−2/3"}]'::jsonb, 'd', 'بقاعدة الإشارات جداءُ سالبٍ في موجبٍ سالب: −(3 × 8)/(4 × 9) = −24/36 = −2/3 ✓. الخطأُ الشائع: جمعُ البسوط والمقامات (−6/13)، أو نسيانُ الإشارة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83564b0c-e2c4-5a7b-a0a2-2e974f136ce3', 'b015f379-245d-54fe-89dd-fd4db6f58b0f', 'ما ناتجُ (−15) ÷ (−6)؟', '[{"id":"a","text":"−5/2"},{"id":"b","text":"2/5"},{"id":"c","text":"5/2"},{"id":"d","text":"90"}]'::jsonb, 'c', 'بقاعدة الإشارات خارجُ قسمة سالبٍ على سالبٍ موجب: (−15) ÷ (−6) = +15/6 = 5/2 ✓. الجوابُ −5/2 خطأٌ في الإشارة، و90 = 15 × 6 ناتجُ ضربٍ بدل القسمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a556e12-2614-5051-9ebe-81b5af41f324', 'b015f379-245d-54fe-89dd-fd4db6f58b0f', 'ما ناتجُ (−2) × (−3) + (−4) × 2؟', '[{"id":"a","text":"−14"},{"id":"b","text":"−2"},{"id":"c","text":"4"},{"id":"d","text":"10"}]'::jsonb, 'b', 'نُجري الضربَين قبل الجمع: (−2) × (−3) = +6 و(−4) × 2 = −8، ثمّ 6 + (−8) = −2 ✓. الخطأُ الشائع: حسابُ 6 − 4 = 2 ثمّ × 2 = 4 بإهمال أولويّة الضرب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

