  ('a1d41c4e-bfc7-5fe4-8c37-f71b3454f0c8', '9d3bf956-8c48-58da-be03-a90180c87d33', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: الإتقانُ الكامل للأعداد الجذرية', 4, 300, 60, 'challenge', 'admin', 6)
