INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f55ae338-e3b8-5c61-82b6-4cf663bbd8f7', 'a1d41c4e-bfc7-5fe4-8c37-f71b3454f0c8', 'عددان جذريّان متعاكسان مجموعُهما 0، وأحدُهما −7. ما العددُ الآخر؟', '[{"id":"a","text":"−7"},{"id":"b","text":"−1/7"},{"id":"c","text":"1/7"},{"id":"d","text":"7"}]'::jsonb, 'd', 'معاكسُ العدد −7 هو +7 لأنّ (−7) + (+7) = 0 ✓. الجوابُ −1/7 هو المقلوبُ لا المعاكس، والفرقُ بين المفهومَين شائعٌ في هذا الفصل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2755689b-ed9f-5737-9cbe-412d4bb059f6', 'a1d41c4e-bfc7-5fe4-8c37-f71b3454f0c8', 'رتّب تصاعديًا (من الأصغر إلى الأكبر): −2/3 ، −5/8 ، −3/4.', '[{"id":"a","text":"−3/4 < −2/3 < −5/8"},{"id":"b","text":"−5/8 < −2/3 < −3/4"},{"id":"c","text":"−2/3 < −3/4 < −5/8"},{"id":"d","text":"−3/4 < −5/8 < −2/3"}]'::jsonb, 'a', 'بالكتابة العشريّة: −2/3 ≈ −0,667 و−5/8 = −0,625 و−3/4 = −0,75. الأكبرُ قيمةً مطلقةً بين السوالب هو الأصغر، فالأصغرُ −3/4 والأكبرُ −5/8؛ الترتيب: −3/4 < −2/3 < −5/8 ✓. الخطأُ الشائع: عكسُ الترتيب لأنّ 0,75 يبدو أكبر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('15e2cf5c-e5f6-5cd5-9afa-ec3c13efa2ed', 'a1d41c4e-bfc7-5fe4-8c37-f71b3454f0c8', 'أرادت سلمى حسابَ (−6) − (−4) × 2 فكتبت: (−6) − (−4) = −2، ثمّ −2 × 2 = −4. أين الخطأُ وما الناتجُ الصحيح؟', '[{"id":"a","text":"لا خطأ؛ الناتجُ −4"},{"id":"b","text":"الخطأُ في قاعدة الإشارات؛ الناتجُ −8"},{"id":"c","text":"أجرت الطرحَ قبل الضرب؛ الناتجُ الصحيح 2"},{"id":"d","text":"لم تعكس إشارةَ الطرح؛ الناتجُ −10"}]'::jsonb, 'c', 'الضربُ له الأولويّة على الطرح: نحسب أوّلًا (−4) × 2 = −8، ثمّ (−6) − (−8) = (−6) + (+8) = +2 ✓. خطأُ سلمى أنّها بدأت بالطرح قبل الضرب. (السؤالُ من نوع تصحيح الخطأ، فالجوابُ الصحيح يصف الخطأ.)', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('104c48d8-fbbb-5871-bc45-97a6d4c6bf1a', 'a1d41c4e-bfc7-5fe4-8c37-f71b3454f0c8', 'ما ناتجُ (−3/5) × (10/9) + (−1/2)؟', '[{"id":"a","text":"−7/6"},{"id":"b","text":"−1/6"},{"id":"c","text":"7/6"},{"id":"d","text":"−2/3"}]'::jsonb, 'a', 'نبدأ بالضرب: (−3/5) × (10/9) = −30/45 = −2/3. ثمّ نوحّد المقامات على 6: −2/3 + (−1/2) = −4/6 − 3/6 = −7/6 ✓. الخطأُ الشائع: التوقّفُ عند −2/3 بإهمال الحدّ −1/2.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('456548db-948d-5d7b-9a1a-44177aeedea3', 'a1d41c4e-bfc7-5fe4-8c37-f71b3454f0c8', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"−5 > −2"},{"id":"b","text":"|−7| = −7"},{"id":"c","text":"(−9) + (+9) = 0"},{"id":"d","text":"(−4) × (−3) = −12"}]'::jsonb, 'c', 'الصحيحُ هو (−9) + (+9) = 0 لأنّ العددين متعاكسان ✓. أمّا −5 > −2 فخطأ (−5 أصغر)، و|−7| = 7 لا −7 (القيمةُ المطلقة موجبة)، و(−4) × (−3) = +12 لا −12 (جداءُ سالبَين موجب).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80f48a2f-b40e-5336-a937-eaa906e84f5e', 'a1d41c4e-bfc7-5fe4-8c37-f71b3454f0c8', 'في تجربةٍ علميّة انطلقت درجةُ حرارة سائلٍ من 12°C، وتناقصت بمقدار 3,5 درجة كلَّ دقيقة. ما درجةُ الحرارة بعد 4 دقائق؟', '[{"id":"a","text":"−14"},{"id":"b","text":"−2"},{"id":"c","text":"2"},{"id":"d","text":"26"}]'::jsonb, 'b', 'التناقصُ الكلّيّ = (−3,5) × 4 = −14، ثمّ 12 + (−14) = −2 ✓. الدرجةُ بعد 4 دقائق −2°C. الخطأُ الشائع: 12 + 3,5 × 4 = 26 بنسيان الإشارة السالبة، أو 14 − 12 = 2 بعكس الطرح.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

