INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d5147a2-930d-5322-b5d5-8553e0412f5c', '78af02ef-808a-5643-bfce-a5093ac839c5', 'ما قيمة a⁰ إذا كان a عددًا غيرَ معدوم؟', '[{"id":"a","text":"1"},{"id":"b","text":"0"},{"id":"c","text":"a"},{"id":"d","text":"غيرُ معرّفٍ"}]'::jsonb, 'a', 'كلُّ عددٍ غيرِ معدومٍ مرفوعٍ إلى الأُسّ 0 يساوي 1؛ إذن a⁰ = 1 (مثلًا 5⁰ = 1).', 1)
