INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44d1e581-de7a-58b1-8d51-e5db1c3e8ff2', '78af02ef-808a-5643-bfce-a5093ac839c5', 'ما الكتابة العلمية للعدد 3 400؟', '[{"id":"a","text":"34 × 10²"},{"id":"b","text":"3,4 × 10²"},{"id":"c","text":"3,4 × 10³"},{"id":"d","text":"0,34 × 10⁴"}]'::jsonb, 'c', 'الكتابة العلمية تكون a × 10ⁿ مع 1 ≤ a < 10؛ إذن 3 400 = 3,4 × 10³. (34 × 10² و0,34 × 10⁴ ترفضهما لأنّ a خارج المجال [1 ; 10[.)', 4)
