INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e3e3a77-d418-5f8d-a4f7-e6407f70a2ae', 'a69bea3d-99cc-55c1-91dc-e4f8741f2f4e', 'ما ناتج 4⁰ + 4¹؟', '[{"id":"a","text":"4"},{"id":"b","text":"8"},{"id":"c","text":"2"},{"id":"d","text":"5"}]'::jsonb, 'd', '4⁰ = 1 و4¹ = 4، إذن 4⁰ + 4¹ = 1 + 4 = 5. (الخطأ الشائع: اعتبار 4⁰ = 0 فيُحصَل على 4، أو 4⁰ = 4 فيُحصَل على 8.)', 6)
ON CONFLICT (id) DO UPDATE SET
