INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b773787f-a733-5864-8939-56375d185139', 'ec73e405-dab4-5f2b-955e-1f8915b8bf6d', 'بسّط الكتابة 3⁵ × 3⁻²، ثمّ اذكر ناتجها.', '[{"id":"a","text":"3³ = 27"},{"id":"b","text":"3⁷ = 2187"},{"id":"c","text":"3⁻¹⁰"},{"id":"d","text":"3¹⁰"}]'::jsonb, 'a', 'في الجُداء نجمع الأُسّين: 3⁵ × 3⁻² = 3⁵⁺⁽⁻²⁾ = 3³ = 27. الخطأ الشائع: طرحُ الأُسّين (5 − 2 = 3 يصادف الصحيح لكن بالمنطق الخاطئ) أو ضربُهما (5 × (−2) = −10) بدل جمعِهما.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7bce8d03-e881-54a9-ad6f-a82ad576b0d9', 'ec73e405-dab4-5f2b-955e-1f8915b8bf6d', 'ما ناتج 10⁻³ × 10⁵ ÷ 10⁻¹؟', '[{"id":"a","text":"10¹"},{"id":"b","text":"10³"},{"id":"c","text":"10⁷"},{"id":"d","text":"10⁹"}]'::jsonb, 'b', 'نجمع أُسّي الجُداء: 10⁻³ × 10⁵ = 10⁻³⁺⁵ = 10²، ثمّ نطرح أُسّ الخارج: 10² ÷ 10⁻¹ = 10²⁻⁽⁻¹⁾ = 10³. الخطأ الشائع: كتابة 10²⁻¹ = 10¹ بنسيان أنّ طرح عددٍ سالبٍ زيادة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('70185d8d-bd89-5d78-9324-250bf0f9b5e4', 'ec73e405-dab4-5f2b-955e-1f8915b8bf6d', 'ما الكتابة العلمية للعدد 0,00047؟', '[{"id":"a","text":"4,7 × 10⁻³"},{"id":"b","text":"47 × 10⁻⁵"},{"id":"c","text":"4,7 × 10⁻⁴"},{"id":"d","text":"4,7 × 10⁴"}]'::jsonb, 'c', 'نحرّك الفاصلة 4 مواضعَ نحو اليمين لنحصل على 4,7، فالأُسّ سالبٌ يساوي −4: 0,00047 = 4,7 × 10⁻⁴. الخطأ الشائع: خطأُ موضعٍ واحدٍ في العدّ (10⁻³) أو ترك a = 47 خارج المجال [1 ; 10[.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb79efff-e46b-57e1-aca6-923f07173ed8', 'ec73e405-dab4-5f2b-955e-1f8915b8bf6d', 'ما قيمة (2⁻²)³؟', '[{"id":"a","text":"1/32"},{"id":"b","text":"64"},{"id":"c","text":"−64"},{"id":"d","text":"1/64"}]'::jsonb, 'd', 'في قوّة القوّة نضرب الأُسّين: (2⁻²)³ = 2⁻²×³ = 2⁻⁶ = 1/2⁶ = 1/64. الخطأ الشائع: جمعُ الأُسّين (−2 + 3 = 1) بدل ضربِهما، أو نسيانُ أنّ الأُسّ السالب يعطي المقلوب لا عددًا سالبًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9a48384-ab57-5b5e-b71e-6ce187294906', 'ec73e405-dab4-5f2b-955e-1f8915b8bf6d', 'ما العدد الأكبر بين 2⁻² و 2⁻³؟', '[{"id":"a","text":"هما متساويان"},{"id":"b","text":"2⁻³"},{"id":"c","text":"2⁻²"},{"id":"d","text":"كلاهما يساوي 0"}]'::jsonb, 'c', '2⁻² = 1/4 = 0,25 و 2⁻³ = 1/8 = 0,125، إذن 2⁻² هو الأكبر. الخطأ الشائع: ظنُّ أنّ الأُسّ الأكبر في القيمة المطلقة (3) يعطي عددًا أكبر، بينما كلّما كبُر أُسُّ المقام صغُرت القيمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39826938-9f76-5d68-9ad5-7e67bf05c2ed', 'ec73e405-dab4-5f2b-955e-1f8915b8bf6d', 'ما ناتج (5³ × 5⁻⁵) ÷ 5⁻¹؟', '[{"id":"a","text":"5⁻³"},{"id":"b","text":"5⁻¹"},{"id":"c","text":"5⁻⁷"},{"id":"d","text":"5¹"}]'::jsonb, 'b', 'نجمع أُسّي البسط: 5³ × 5⁻⁵ = 5³⁺⁽⁻⁵⁾ = 5⁻²، ثمّ نطرح أُسّ المقام: 5⁻² ÷ 5⁻¹ = 5⁻²⁻⁽⁻¹⁾ = 5⁻¹ = 1/5. الخطأ الشائع: طرحُ 5⁻² − 5⁻¹ بجمع الأُسّين خطأً (−2 + (−1) = −3) بدل طرحِهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

