INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c22beea-cc29-5fd9-9703-f227da12cb6f', '2fc835a3-2761-5f0a-a687-4a58c223b2e4', 'ما ناتج 7⁻³ × 7³؟', '[{"id":"a","text":"7⁶"},{"id":"b","text":"0"},{"id":"c","text":"7⁻⁹"},{"id":"d","text":"1"}]'::jsonb, 'd', 'نجمع الأُسّين: 7⁻³ × 7³ = 7⁻³⁺³ = 7⁰ = 1. فالقوّةُ ومقلوبُها حاصلُ ضربهما يساوي 1 دائمًا. الخطأ الشائع: ضربُ الأُسّين (−9) أو ظنُّ أنّ الناتج 0.', 6)
