INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3249b3ef-bdf9-51f5-8ba1-d1ec1d67c34d', '7ee286db-fda1-5e83-b6ff-4e3160160dd6', 'ما ناتج (10⁴ × 10⁻⁶) ÷ 10⁻³؟', '[{"id":"a","text":"10⁻⁷"},{"id":"b","text":"10¹"},{"id":"c","text":"10⁻¹"},{"id":"d","text":"10⁵"}]'::jsonb, 'b', 'نجمع أُسّي البسط: 10⁴ × 10⁻⁶ = 10⁴⁺⁽⁻⁶⁾ = 10⁻²، ثمّ نطرح أُسّ المقام: 10⁻² ÷ 10⁻³ = 10⁻²⁻⁽⁻³⁾ = 10¹ = 10. الخطأ الشائع: كتابة 10⁻²⁻³ = 10⁻⁵ بنسيان أنّ طرح عددٍ سالبٍ زيادة.', 1)
