INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b3ea4966-3ba9-5825-b80d-3b45e816190f', '7ee286db-fda1-5e83-b6ff-4e3160160dd6', 'إذا كان 10ⁿ = 0,001، فما قيمة n؟', '[{"id":"a","text":"3"},{"id":"b","text":"−2"},{"id":"c","text":"−3"},{"id":"d","text":"−4"}]'::jsonb, 'c', '0,001 = 1/1 000 = 1/10³ = 10⁻³، إذن n = −3. الخطأ الشائع: عدُّ الأصفار الثلاثة فيُكتب n = −4، أو نسيانُ الإشارة السالبة فيُكتب n = 3.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9e8ce023-f464-5196-a0af-8257422b5691', '7ee286db-fda1-5e83-b6ff-4e3160160dd6', 'أيّ عبارةٍ من العبارات الأربع صحيحةٌ؟', '[{"id":"a","text":"2⁻³ × 2⁵ = 2⁻¹⁵"},{"id":"b","text":"10⁶ ÷ 10⁻² = 10⁴"},{"id":"c","text":"3⁰ = 0"},{"id":"d","text":"(5⁻²)⁻¹ = 5²"}]'::jsonb, 'd', '(5⁻²)⁻¹ = 5⁽⁻²⁾×⁽⁻¹⁾ = 5² (صحيح). أمّا الباقي فخاطئ: 2⁻³ × 2⁵ = 2² (نجمع لا نضرب)، 10⁶ ÷ 10⁻² = 10⁸ (6 − (−2) = 8 لا 4)، و3⁰ = 1 لا 0.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b34ab56-0cf7-59bf-92e9-cb869b902fbd', '7ee286db-fda1-5e83-b6ff-4e3160160dd6', 'ما الخطأ في الحلّ التالي؟ «الكتابة العلمية للعدد 0,00036 هي 3,6 × 10⁻³».', '[{"id":"a","text":"الخطأ في الأُسّ: يجب أن يكون 10⁻⁴ لا 10⁻³، فالكتابة الصحيحة 3,6 × 10⁻⁴"},{"id":"b","text":"لا يوجد خطأٌ، الحلُّ صحيحٌ"},{"id":"c","text":"الخطأ أنّ a يجب أن يساوي 36 لا 3,6"},{"id":"d","text":"الخطأ في الإشارة: الأُسّ يجب أن يكون موجبًا 10³"}]'::jsonb, 'a', 'لنحصل على 3,6 من 0,00036 نحرّك الفاصلة 4 مواضعَ نحو اليمين، فالأُسّ يساوي −4: 0,00036 = 3,6 × 10⁻⁴. الحلُّ المعروضُ عدَّ 3 مواضعَ فقط خطأً فكتب 10⁻³. (تحقّق: 3,6 × 10⁻⁴ = 3,6 ÷ 10 000 = 0,00036 ✓)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e93661e7-7f34-540f-8a3b-9e45a6c551cd', '7ee286db-fda1-5e83-b6ff-4e3160160dd6', 'اكتب حاصل الضرب (3 × 10⁴) × (2 × 10⁻⁷) بالكتابة العلمية.', '[{"id":"a","text":"6 × 10⁻²⁸"},{"id":"b","text":"5 × 10⁻³"},{"id":"c","text":"6 × 10⁻¹¹"},{"id":"d","text":"6 × 10⁻³"}]'::jsonb, 'd', 'نضرب المعاملين ونجمع أُسّي 10: (3 × 2) × 10⁴⁺⁽⁻⁷⁾ = 6 × 10⁻³، والمعامل 6 ضمن المجال [1 ; 10[ فالكتابة علميّةٌ صحيحة. الخطأ الشائع: ضربُ أُسّي 10 (4 × (−7) = −28) أو جمعُ المعاملين (3 + 2 = 5).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
