INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33577ae6-fb49-5a9b-8bea-109930a30c70', '7ee286db-fda1-5e83-b6ff-4e3160160dd6', 'قارن العددين 3,5 × 10⁵ و 2,8 × 10⁶: أيّهما أكبر؟', '[{"id":"a","text":"3,5 × 10⁵ أكبر"},{"id":"b","text":"2,8 × 10⁶ أكبر"},{"id":"c","text":"هما متساويان"},{"id":"d","text":"لا يمكن المقارنة لاختلاف المعاملين"}]'::jsonb, 'b', 'نقارن أُسَّي 10 أوّلًا: 10⁶ أكبر من 10⁵، ويكفي فرقُ مرتبةٍ ليَغلب رغم أنّ 2,8 < 3,5. فعلًا 3,5 × 10⁵ = 350 000 و 2,8 × 10⁶ = 2 800 000، إذن الثاني أكبر. الخطأ الشائع: مقارنة المعاملين (3,5 > 2,8) وإهمالُ الأُسّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

