INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('294af9b5-ecda-50c4-88c7-835a324d12c4', 'cfa0c9fe-eaa7-5fc4-907f-4433c7eb36ce', 'ما الكتابة العلمية للعدد 6 500 000؟', '[{"id":"a","text":"6,5 × 10⁶"},{"id":"b","text":"65 × 10⁵"},{"id":"c","text":"6,5 × 10⁵"},{"id":"d","text":"0,65 × 10⁷"}]'::jsonb, 'a', 'نحرّك الفاصلة 6 مواضعَ نحو اليسار لنحصل على 6,5 ضمن المجال [1 ; 10[: 6 500 000 = 6,5 × 10⁶. (65 × 10⁵ و0,65 × 10⁷ مرفوضتان لأنّ a خارج المجال.)', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe01ca4c-226d-567b-b398-6ffad6cb65cf', 'cfa0c9fe-eaa7-5fc4-907f-4433c7eb36ce', 'ما ناتج 9⁻² × 9²؟', '[{"id":"a","text":"9⁴"},{"id":"b","text":"1"},{"id":"c","text":"0"},{"id":"d","text":"9⁻⁴"}]'::jsonb, 'b', 'نجمع الأُسّين: 9⁻² × 9² = 9⁻²⁺² = 9⁰ = 1. القوّةُ ومقلوبُها حاصلُ ضربهما يساوي 1 دائمًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('87fc2166-e214-5972-948c-4de0574fd2cc', 'cfa0c9fe-eaa7-5fc4-907f-4433c7eb36ce', 'أيّ عددٍ عشريّ يساوي 10⁻⁴؟', '[{"id":"a","text":"0,001"},{"id":"b","text":"0,00001"},{"id":"c","text":"−10000"},{"id":"d","text":"0,0001"}]'::jsonb, 'd', '10⁻⁴ = 1/10⁴ = 1/10 000 = 0,0001 (ثلاثةُ أصفارٍ بعد الفاصلة قبل الـ1). الخطأ الشائع: خطأُ موضعٍ واحدٍ في عدّ الأصفار (0,001 أو 0,00001).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03c5d076-e98e-5cb2-a834-03e104873c0d', 'cfa0c9fe-eaa7-5fc4-907f-4433c7eb36ce', 'ما قيمة (3⁻¹)⁻²؟', '[{"id":"a","text":"1/9"},{"id":"b","text":"3⁻³"},{"id":"c","text":"9"},{"id":"d","text":"−9"}]'::jsonb, 'c', 'في قوّة القوّة نضرب الأُسّين: (3⁻¹)⁻² = 3⁽⁻¹⁾×⁽⁻²⁾ = 3² = 9. الخطأ الشائع: جمعُ الأُسّين (−1 + (−2) = −3) بدل ضربِهما، فيُظنّ الناتجُ 3⁻³ = 1/27.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c65c96d9-b3f6-513f-9bf1-b6c85dcee773', 'cfa0c9fe-eaa7-5fc4-907f-4433c7eb36ce', 'ما ناتج (2⁶ × 2⁻⁴) ÷ 2³؟', '[{"id":"a","text":"2⁵"},{"id":"b","text":"2⁻¹"},{"id":"c","text":"2⁻⁵"},{"id":"d","text":"2⁷"}]'::jsonb, 'b', 'نجمع أُسّي البسط: 2⁶ × 2⁻⁴ = 2⁶⁺⁽⁻⁴⁾ = 2²، ثمّ نطرح أُسّ المقام: 2² ÷ 2³ = 2²⁻³ = 2⁻¹ = 1/2 = 0,5. الخطأ الشائع: الخلطُ بين الجمع والطرح في الأُسُس.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5881f4e7-5b93-50d3-b5e5-9c35739da15b', 'cfa0c9fe-eaa7-5fc4-907f-4433c7eb36ce', 'اكتب العدد 47 × 10³ بالكتابة العلمية.', '[{"id":"a","text":"47 × 10³"},{"id":"b","text":"4,7 × 10³"},{"id":"c","text":"4,7 × 10²"},{"id":"d","text":"4,7 × 10⁴"}]'::jsonb, 'd', 'المعامل 47 خارج المجال [1 ; 10[، فنكتبه 4,7 × 10¹ ونعوّض: 47 × 10³ = 4,7 × 10¹ × 10³ = 4,7 × 10⁴. الخطأ الشائع: ترك 47 × 10³ كأنّه كتابةٌ علميّةٌ، أو نسيانُ زيادة الأُسّ عند تصغير المعامل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3149ac8e-46b8-58f4-a5da-252870ac27ec', 'd270ebef-a2db-5fb5-a15f-13265020bb60', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّد الكون العدديّ', 4, 300, 60, 'challenge', 'admin', 6)
