INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31397481-af2b-582d-93cd-4b7c051705c2', '3149ac8e-46b8-58f4-a5da-252870ac27ec', 'أيّ عبارةٍ صحيحةٌ بخصوص الكتابة العلمية؟', '[{"id":"a","text":"يكون a عددًا صحيحًا دائمًا"},{"id":"b","text":"12 × 10³ كتابةٌ علميّةٌ صحيحةٌ"},{"id":"c","text":"الكتابة العلمية لعددٍ هي a × 10ⁿ حيث 1 ≤ a < 10"},{"id":"d","text":"لا تُستعمل الكتابة العلمية إلّا للأعداد الكبيرة"}]'::jsonb, 'c', 'الكتابة العلمية هي a × 10ⁿ مع 1 ≤ a < 10 وn نسبيّ. فـ a قد يكون عشريًّا (3,6) لا صحيحًا فقط، و12 × 10³ مرفوضةٌ لأنّ a = 12 ≥ 10، وتُستعمل الكتابة للأعداد الصغيرة أيضًا (0,0067 = 6,7 × 10⁻³).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8afd637f-0833-59b2-bf4c-b88464ea3517', '3149ac8e-46b8-58f4-a5da-252870ac27ec', 'اكتب حاصل الضرب (4 × 10⁻³) × (5 × 10⁶) بالكتابة العلمية.', '[{"id":"a","text":"20 × 10³"},{"id":"b","text":"2 × 10⁴"},{"id":"c","text":"9 × 10³"},{"id":"d","text":"2 × 10⁻¹⁸"}]'::jsonb, 'b', 'نضرب المعاملين ونجمع أُسّي 10: (4 × 5) × 10⁻³⁺⁶ = 20 × 10³. لكنّ 20 ≥ 10، فنصحّح: 20 × 10³ = 2 × 10¹ × 10³ = 2 × 10⁴. الخطأ الشائع: ترك 20 × 10³ دون تصحيح، أو ضربُ أُسّي 10 (−3 × 6 = −18)، أو جمعُ المعاملين (4 + 5 = 9).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cc1dc17-1eae-5cb4-91c0-3cca4c8ec759', '3149ac8e-46b8-58f4-a5da-252870ac27ec', 'ما الخطأ في الحلّ التالي؟ الخطوة: (5⁻²)³ = 5⁻²⁺³ = 5¹ = 5.', '[{"id":"a","text":"الخطأ في الخطوة الأولى: يجب ضربُ الأُسّين لا جمعُهما، فالناتج الصحيح 5⁻⁶ = 1/15 625"},{"id":"b","text":"لا يوجد خطأٌ، الحلُّ صحيحٌ"},{"id":"c","text":"الخطأ في حساب 5¹، فهو يساوي 1 لا 5"},{"id":"d","text":"الخطأ أنّ الأساس يجب أن يصير موجبًا"}]'::jsonb, 'a', 'في قوّة القوّة نضرب الأُسّين لا نجمعُهما: (5⁻²)³ = 5⁻²×³ = 5⁻⁶ = 1/5⁶ = 1/15 625. الحلُّ المعروضُ جمع الأُسّين خطأً (−2 + 3 = 1) فحصل على 5 بدل الناتج الصحيح.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba6c7de3-f98f-5003-af70-b1992930c41f', '3149ac8e-46b8-58f4-a5da-252870ac27ec', 'إذا كان 2ⁿ = 1/32، فما قيمة n؟', '[{"id":"a","text":"5"},{"id":"b","text":"−5"},{"id":"c","text":"−6"},{"id":"d","text":"−4"}]'::jsonb, 'b', 'بما أنّ 32 = 2⁵، فإنّ 1/32 = 1/2⁵ = 2⁻⁵، إذن n = −5. الخطأ الشائع: نسيانُ الإشارة السالبة (n = 5 يعطي 2⁵ = 32 لا مقلوبَه)، أو خطأُ موضعٍ في حساب 2⁵.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55ebaddb-d0bf-5d6f-8ea3-2aeabfde27ad', '3149ac8e-46b8-58f4-a5da-252870ac27ec', 'بسّط الكتابة (10⁻² × 10⁵)³ ÷ 10⁴.', '[{"id":"a","text":"10⁶"},{"id":"b","text":"10¹³"},{"id":"c","text":"10⁹"},{"id":"d","text":"10⁵"}]'::jsonb, 'd', 'داخل القوس: 10⁻² × 10⁵ = 10⁻²⁺⁵ = 10³، ثمّ قوّة القوّة: (10³)³ = 10³×³ = 10⁹، ثمّ الخارج: 10⁹ ÷ 10⁴ = 10⁹⁻⁴ = 10⁵. الخطأ الشائع: نسيانُ خطوة القسمة (10⁹)، أو جمعُ أُسُس القوس بدل ضربها في قوّة القوّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('97509018-1226-5dfd-b0ec-da663a2e1d9c', '3149ac8e-46b8-58f4-a5da-252870ac27ec', 'أيُّ هذه الأعداد هو الأصغر؟', '[{"id":"a","text":"5 × 10⁻³"},{"id":"b","text":"2 × 10⁻²"},{"id":"c","text":"8 × 10⁻⁴"},{"id":"d","text":"1 × 10⁻²"}]'::jsonb, 'c', 'نحوّل إلى الكتابة العشرية: 5 × 10⁻³ = 0,005 و2 × 10⁻² = 0,02 و8 × 10⁻⁴ = 0,0008 و1 × 10⁻² = 0,01. الأصغر هو 8 × 10⁻⁴. الخطأ الشائع: اختيارُ العدد ذي المعامل الأكبر (8) ظنًّا أنّه الأكبر، بينما الأُسّ الأكثر سلبيّةً (−4) يجعل العددَ أصغر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

