INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7354b7b-b7f6-56d4-8c34-85c979910dac', 'b7f89252-e4dc-58ed-88ed-04dcfdaab2bb', 'انشر العبارة: 3×(x + 4).', '[{"id":"a","text":"3x + 12"},{"id":"b","text":"3x + 7"},{"id":"c","text":"3x + 4"},{"id":"d","text":"7x"}]'::jsonb, 'a', 'نوزّع 3 على كلّ حدٍّ داخل القوسين: 3×x + 3×4 = 3x + 12 ✓. الخطأُ الشائع: جمعُ 3+4=7 بدل توزيع الضرب (3x+7)، أو نسيانُ ضرب الحدّ الثاني (3x+4).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08ced735-decf-5365-bffc-8b2b709bbb34', 'b7f89252-e4dc-58ed-88ed-04dcfdaab2bb', 'عمِّل بإخراج العامل المشترك: 5x + 10.', '[{"id":"a","text":"5(x + 10)"},{"id":"b","text":"5(x + 2)"},{"id":"c","text":"x(5 + 10)"},{"id":"d","text":"5(x + 5)"}]'::jsonb, 'b', 'العاملُ المشترك للحدّين 5x و10 هو 5؛ 5x÷5 = x و10÷5 = 2، فالتعميلُ هو 5(x + 2) ✓. الخطأُ الشائع: إخراجُ 5 من الحدّ الأوّل فقط دون قسمة 10 (فتُكتب 5(x+10))، أو اختيارُ عاملٍ لا يقسم العددَ 10.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('744a0a8d-efd6-5e2c-84ba-e84405f54401', 'b7f89252-e4dc-58ed-88ed-04dcfdaab2bb', 'انشر بالتوزيعية المضاعفة: (x + 2)(x + 3).', '[{"id":"a","text":"x² + 6"},{"id":"b","text":"x² + 5x + 6"},{"id":"c","text":"x² + 6x + 6"},{"id":"d","text":"x² + 5x + 5"}]'::jsonb, 'b', 'نضرب كلّ حدٍّ في كلّ حدّ: x×x + x×3 + 2×x + 2×3 = x² + 3x + 2x + 6 = x² + 5x + 6 ✓. الخطأُ الشائع: ضربُ الأوّل في الأوّل والثاني في الثاني فقط ونسيانُ الجُداءين الأوسطين (x²+6).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e5e6a81-9857-5b1b-9397-3a77027da1f8', 'b7f89252-e4dc-58ed-88ed-04dcfdaab2bb', 'اختزل العبارة: 2x² + 3x + x² − x.', '[{"id":"a","text":"3x² + 2x"},{"id":"b","text":"6x³"},{"id":"c","text":"3x² + 4x"},{"id":"d","text":"4x²"}]'::jsonb, 'a', 'نجمع المتشابهات: (2x²+x²) = 3x² و(3x−x) = 2x، فالنتيجة 3x² + 2x ✓. الخطأُ الشائع: ضمُّ حدود x² إلى حدود x وجمعُها كلَّها معًا (4x² أو 6x³)؛ الحدودُ المختلفةُ القوّةِ لا تُجمع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b31707f2-5b86-5734-bc2c-b5027228d786', 'b7f89252-e4dc-58ed-88ed-04dcfdaab2bb', 'انشر المتطابقة: (x + 3)².', '[{"id":"a","text":"x² + 9"},{"id":"b","text":"x² + 3x + 9"},{"id":"c","text":"x² + 6x + 9"},{"id":"d","text":"x² + 6x + 6"}]'::jsonb, 'c', '(x+3)² = (x+3)(x+3) = x² + 3x + 3x + 9 = x² + 6x + 9 ✓. الخطأُ الأشهر: نسيانُ الحدّ الأوسط 2ab وكتابةُ x²+9.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
