INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdcb4053-1722-5cb5-8d44-7336106ba367', '2b2e7d52-bc3b-54b5-a439-24e37fc3d310', 'عمِّل بإخراج العامل المشترك: 6x + 9.', '[{"id":"a","text":"3(2x + 9)"},{"id":"b","text":"2(3x + 9)"},{"id":"c","text":"3(2x + 3)"},{"id":"d","text":"6(x + 9)"}]'::jsonb, 'c', 'العاملُ المشترك للعددين 6 و9 هو 3؛ 6x÷3 = 2x و9÷3 = 3، فالتعميلُ هو 3(2x + 3) ✓. الخطأُ الشائع: عدمُ قسمة الحدّ الثاني على العامل (3(2x+9))، أو اختيارُ عاملٍ لا يقسم 9 كاملًا (2(3x+9)).', 6)
