INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f12aef7-0bc8-53fa-bd54-00e40fbefbb6', '13559988-10fe-5be5-bc36-fec80d7e8cac', 'انشر بالتوزيعية المضاعفة: (x − 3)(x + 2).', '[{"id":"a","text":"x² − 6"},{"id":"b","text":"x² + x − 6"},{"id":"c","text":"x² − x − 6"},{"id":"d","text":"x² − 5x − 6"}]'::jsonb, 'c', 'نضرب كلّ حدٍّ في كلّ حدّ مع الإشارات: x² + 2x − 3x − 6 = x² − x − 6 ✓. الخطأُ الشائع: جمعُ 2 و3 بدل طرحهما في الحدّ الأوسط (x²+x−6 أو x²−5x−6)، أو نسيانُ الحدّين الأوسطين (x²−6).', 3)
