INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('036e3fcf-d4f8-5826-9293-793c420c0ffa', '13559988-10fe-5be5-bc36-fec80d7e8cac', 'عمِّل بإخراج العامل المشترك: x² + 7x.', '[{"id":"a","text":"x(x − 7)"},{"id":"b","text":"7(x + x)"},{"id":"c","text":"x²(1 + 7)"},{"id":"d","text":"x(x + 7)"}]'::jsonb, 'd', 'العاملُ المشترك بين x² و7x هو x؛ x²÷x = x و7x÷x = 7، فالتعميلُ هو x(x + 7) ✓. الخطأُ الشائع: الخطأُ في الإشارة (x(x−7))، أو إخراجُ عاملٍ عدديّ لا يشترك فيه الحدّان (7(x+x)).', 4)
