INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59694735-6192-56e0-a4b8-e8a093a1c96b', '13559988-10fe-5be5-bc36-fec80d7e8cac', 'انشر ثمّ اختزل: 2(x + 3) + 3(x − 1).', '[{"id":"a","text":"5x + 3"},{"id":"b","text":"5x + 9"},{"id":"c","text":"5x − 3"},{"id":"d","text":"6x + 3"}]'::jsonb, 'a', 'ننشر أوّلًا: 2x + 6 + 3x − 3، ثمّ نختزل: (2x+3x) + (6−3) = 5x + 3 ✓. الخطأُ الشائع: نسيانُ توزيع 3 على −1 فيبقى الثابتُ 6 (5x+9)، أو الخطأُ في جمع الثوابت (5x−3).', 5)
