INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d04934e2-e3e2-51d8-bf87-d92eef1f8449', '13559988-10fe-5be5-bc36-fec80d7e8cac', 'انشر بالتوزيعية المضاعفة: (2x + 1)(x + 3).', '[{"id":"a","text":"2x² + 6x + 3"},{"id":"b","text":"2x² + 7x + 3"},{"id":"c","text":"2x² + 7x + 4"},{"id":"d","text":"2x² + 3"}]'::jsonb, 'b', 'نضرب كلّ حدٍّ في كلّ حدّ: 2x×x + 2x×3 + 1×x + 1×3 = 2x² + 6x + x + 3 = 2x² + 7x + 3 ✓. الخطأُ الشائع: نسيانُ جُداء 1×x فيصبح الحدّ الأوسط 6x (2x²+6x+3)، أو نسيانُ الحدّين الأوسطين معًا (2x²+3).', 6)
