INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f31b014-b43d-57e8-87f2-6e62fcef69ee', '934c97b1-b838-5c6b-a1ae-cd55d7573b0c', 'انشر المتطابقة: (x + 4)².', '[{"id":"a","text":"x² + 16"},{"id":"b","text":"x² + 8x + 16"},{"id":"c","text":"x² + 8x + 8"},{"id":"d","text":"x² + 4x + 16"}]'::jsonb, 'b', '(x+4)² = (x+4)(x+4) = x² + 4x + 4x + 16 = x² + 8x + 16 ✓. الحدُّ الأوسط هو 2×4×x = 8x. الخطأُ الأشهر: نسيانُ الحدّ الأوسط (x²+16)، أو أخذُ الحدّ الأوسط 4x فقط بدل 8x (x²+4x+16).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f6216ff-f58f-5ef7-9d51-03e452c905b1', '934c97b1-b838-5c6b-a1ae-cd55d7573b0c', 'انشر المتطابقة: (x + 5)(x − 5).', '[{"id":"a","text":"x² − 25"},{"id":"b","text":"x² + 25"},{"id":"c","text":"x² − 25x"},{"id":"d","text":"x² − 10x + 25"}]'::jsonb, 'a', 'جُداءُ مجموعٍ في فرقٍ: (x+5)(x−5) = x² − 5x + 5x − 25 = x² − 25؛ يتلاشى الحدّان الأوسطان ✓. الخطأُ الشائع: الخلطُ مع (x−5)² فيُكتب x²−10x+25، أو الخطأُ في إشارة الحدّ الثابت (x²+25).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25d74b64-fb11-59d6-bfd4-1151259b17f7', '934c97b1-b838-5c6b-a1ae-cd55d7573b0c', 'بسِّط إلى أبسط صورة: (x + 2)(x + 3) − x².', '[{"id":"a","text":"x² + 5x + 6"},{"id":"b","text":"5x² + 6"},{"id":"c","text":"6x"},{"id":"d","text":"5x + 6"}]'::jsonb, 'd', 'ننشر أوّلًا: (x+2)(x+3) = x² + 5x + 6، ثمّ نطرح x²: (x²−x²) + 5x + 6 = 5x + 6 ✓. الخطأُ الشائع: نسيانُ طرح x² فيبقى x²+5x+6، أو طرحُ x² من كلّ حدٍّ خطأً فيُكتب 5x²+6.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96b85486-80a1-5621-aa4e-9c50bc74c9b3', '934c97b1-b838-5c6b-a1ae-cd55d7573b0c', 'كتب تلميذٌ الحلّ التالي: (x + 3)(x + 4) = x² + 7x + 7. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، الحلُّ صحيح"},{"id":"b","text":"الخطأ في معامل x: الصحيح x² + 12x + 7"},{"id":"c","text":"الخطأ في الحدّ الثابت: 3×4 = 12 وليس 7، الصحيح x² + 7x + 12"},{"id":"d","text":"الخطأ في الإشارة داخل القوسين"}]'::jsonb, 'c', 'النشرُ الصحيح: (x+3)(x+4) = x² + 4x + 3x + 12 = x² + 7x + 12. معاملُ x صحيحٌ (4+3=7)، لكنّ الحدّ الثابت يجب أن يكون جُداءَ 3×4 = 12 لا مجموعَهما 7 ✓. (سؤالُ اكتشاف خطأ: الخيارُ الصحيح يصف موضعَ الخطأ لا حلًّا بديلًا.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a642f45-79c6-5b4b-a114-450d7adcffc5', '934c97b1-b838-5c6b-a1ae-cd55d7573b0c', 'بعد النشر تساوي العبارة (x + 3)(x + a) الصورةَ x² + 8x + 15. ما قيمة a؟', '[{"id":"a","text":"8"},{"id":"b","text":"5"},{"id":"c","text":"15"},{"id":"d","text":"2"}]'::jsonb, 'b', 'بالنشر: (x+3)(x+a) = x² + (3+a)x + 3a. نطابق مع x²+8x+15: من الحدّ الثابت 3a = 15 فـ a = 5، ونتحقّق من المعامل 3+5 = 8 ✓. الخطأُ الشائع: أخذُ a = 8 من معامل x مباشرةً بنسيان الحدّ 3، أو a = 15 من الحدّ الثابت دون قسمةٍ على 3.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a739c692-11ec-5155-b6c2-60ebd97953f7', '934c97b1-b838-5c6b-a1ae-cd55d7573b0c', 'مستطيلٌ طولُه (x + 5) وعرضُه (x + 2). عبّر عن مساحته منشورةً ومختزَلة.', '[{"id":"a","text":"x² + 10"},{"id":"b","text":"2x + 7"},{"id":"c","text":"x² + 7x + 10"},{"id":"d","text":"x² + 10x + 7"}]'::jsonb, 'c', 'المساحةُ = الطول × العرض = (x+5)(x+2) = x² + 2x + 5x + 10 = x² + 7x + 10 ✓. الخطأُ الشائع: حسابُ المحيط بدل المساحة (2x+7)، أو نسيانُ الحدّين الأوسطين (x²+10)، أو الخلطُ بين المعامل 7 والثابت 10 (x²+10x+7).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

