INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bef5b155-08aa-5434-b00f-c2f68c680ce9', '82604f58-1e97-5a36-9864-8b02b0f47f8c', 'انشر العبارة: −(x − 3).', '[{"id":"a","text":"−x + 3"},{"id":"b","text":"−x − 3"},{"id":"c","text":"x − 3"},{"id":"d","text":"x + 3"}]'::jsonb, 'a', 'الطرحُ أمام القوس يقلب إشارةَ كلّ حدّ: −(x − 3) = −x + 3 ✓. الخطأُ الأخطر: قلبُ إشارة الحدّ الأوّل فقط ونسيانُ قلب الثاني (−x−3).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf98edc6-4515-55d3-ae5c-ffe51f821660', '82604f58-1e97-5a36-9864-8b02b0f47f8c', 'انشر العبارة: 2×(3x − 4).', '[{"id":"a","text":"6x + 8"},{"id":"b","text":"5x − 8"},{"id":"c","text":"6x − 4"},{"id":"d","text":"6x − 8"}]'::jsonb, 'd', 'نوزّع 2 على الحدّين: 2×3x − 2×4 = 6x − 8 ✓. الخطأُ الشائع: نسيانُ ضرب الحدّ الثاني (6x−4)، أو الخطأُ في إشارة الحدّ الثاني (6x+8).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55830d8d-0d91-5d08-a14f-35e1b52781f6', '82604f58-1e97-5a36-9864-8b02b0f47f8c', 'انشر بالتوزيعية المضاعفة: (2x − 1)(x + 4).', '[{"id":"a","text":"2x² − 4"},{"id":"b","text":"2x² + 7x − 4"},{"id":"c","text":"2x² + 7x + 4"},{"id":"d","text":"2x² + 9x − 4"}]'::jsonb, 'b', 'نضرب كلّ حدٍّ في كلّ حدّ: 2x×x + 2x×4 − 1×x − 1×4 = 2x² + 8x − x − 4 = 2x² + 7x − 4 ✓. الخطأُ الشائع: الخطأُ في إشارة الحدّ الثابت (2x²+7x+4)، أو جمعُ 8x مع x بدل طرحها (2x²+9x−4).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e979eb1-840f-53e4-bcbe-7b64a96104a1', '82604f58-1e97-5a36-9864-8b02b0f47f8c', 'عمِّل بإخراج العامل المشترك: 12x + 8.', '[{"id":"a","text":"4(3x + 8)"},{"id":"b","text":"3(4x + 2)"},{"id":"c","text":"4(3x + 2)"},{"id":"d","text":"6(2x + 8)"}]'::jsonb, 'c', 'العاملُ المشترك الأكبر للعددين 12 و8 هو 4؛ 12x÷4 = 3x و8÷4 = 2، فالتعميلُ الكامل هو 4(3x + 2) ✓. الخطأُ الشائع: عدمُ قسمة 8 على العامل (4(3x+8))، أو اختيارُ عاملٍ لا يقسم العددَين معًا (3(4x+2) = 12x+6 ≠ 12x+8).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8b29a8a1-4123-5111-a156-61581ed1bcf8', '82604f58-1e97-5a36-9864-8b02b0f47f8c', 'انشر ثمّ اختزل: 5(x + 2) − (x − 3).', '[{"id":"a","text":"4x + 7"},{"id":"b","text":"4x − 13"},{"id":"c","text":"6x + 13"},{"id":"d","text":"4x + 13"}]'::jsonb, 'd', 'ننشر: 5x + 10، والقوسُ الثاني بإشارةٍ سالبة: −(x−3) = −x + 3. نجمع: (5x − x) + (10 + 3) = 4x + 13 ✓. الخطأُ الأخطر: نسيانُ قلب إشارة −3 فيصبح −x−3 والنتيجةُ 4x+7.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31353829-2d46-5d70-b62c-481a7db6e9c2', '82604f58-1e97-5a36-9864-8b02b0f47f8c', 'انشر المتطابقة: (2x + 3)².', '[{"id":"a","text":"4x² + 9"},{"id":"b","text":"4x² + 12x + 9"},{"id":"c","text":"2x² + 12x + 9"},{"id":"d","text":"4x² + 6x + 9"}]'::jsonb, 'b', '(2x+3)² = (2x+3)(2x+3) = 4x² + 6x + 6x + 9 = 4x² + 12x + 9؛ الحدّ الأوسط 2×(2x)×3 = 12x ✓. الخطأُ الشائع: نسيانُ الحدّ الأوسط (4x²+9)، أو عدمُ تربيع المعامل 2 فيُكتب 2x²، أو أخذُ الحدّ الأوسط 6x بدل 12x.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

