  ('dfb1bf66-a7bf-5ae0-bff0-01cf67f6701f', '851ce498-e499-5f5a-97b2-91ddceda5ca0', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: المتطابقات والتعميل المتقدّم', 4, 300, 60, 'challenge', 'admin', 6)
