INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e70ecde2-d503-5c89-a951-4a0e013b66a6', 'dfb1bf66-a7bf-5ae0-bff0-01cf67f6701f', 'انشر المتطابقة: (x − 6)².', '[{"id":"a","text":"x² − 36"},{"id":"b","text":"x² − 12x − 36"},{"id":"c","text":"x² − 12x + 36"},{"id":"d","text":"x² − 36x + 36"}]'::jsonb, 'c', '(x−6)² = x² − 6x − 6x + 36 = x² − 12x + 36؛ الحدّ الأوسط 2×6×x = 12x والحدّ الثابت (−6)×(−6) = +36 ✓. الخطأُ الأشهر: نسيانُ الحدّ الأوسط (x²−36)، أو الخطأُ في إشارة الحدّ الثابت (x²−12x−36).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e7abbe9-ca7b-52f6-b80b-b61d0b94710d', 'dfb1bf66-a7bf-5ae0-bff0-01cf67f6701f', 'انشر المتطابقة: (3x + 2)(3x − 2).', '[{"id":"a","text":"9x² − 4"},{"id":"b","text":"9x² + 4"},{"id":"c","text":"3x² − 4"},{"id":"d","text":"9x² − 12x − 4"}]'::jsonb, 'a', 'جُداءُ مجموعٍ في فرقٍ: (3x+2)(3x−2) = (3x)² − 2² = 9x² − 4؛ يتلاشى الحدّان الأوسطان ✓. الخطأُ الشائع: عدمُ تربيع المعامل 3 فيُكتب 3x²، أو الخطأُ في إشارة الحدّ الثابت (9x²+4).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0590fe2b-7c2e-5bea-be94-b277fbb381f6', 'dfb1bf66-a7bf-5ae0-bff0-01cf67f6701f', 'بسِّط إلى أبسط صورة: (x + 4)(x − 1) − (x − 2)(x + 3).', '[{"id":"a","text":"2x² + 2"},{"id":"b","text":"4x − 2"},{"id":"c","text":"2x − 10"},{"id":"d","text":"2x + 2"}]'::jsonb, 'd', 'ننشر كلَّ جُداء: (x+4)(x−1) = x² + 3x − 4، و(x−2)(x+3) = x² + x − 6. نطرح مع قلب إشارات القوس الثاني: (x²+3x−4) − (x²+x−6) = 2x + 2 ✓. الخطأُ الأخطر: نسيانُ قلب إشارة −6 عند الطرح فتظهر نتيجةٌ ثابتُها خاطئ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b0bd0177-fe60-5d2e-94f7-7c8820d54dad', 'dfb1bf66-a7bf-5ae0-bff0-01cf67f6701f', 'أيُّ المتطابقات التالية صحيحةٌ مهما تكن قيمة x؟', '[{"id":"a","text":"(x + 2)² = x² + 4"},{"id":"b","text":"(x + 3)(x − 3) = x² − 9"},{"id":"c","text":"(x − 1)² = x² − 1"},{"id":"d","text":"(x + 5)² = x² + 10x + 5"}]'::jsonb, 'b', '(x+3)(x−3) = x² − 9 صحيحةٌ دائمًا (مجموعٌ في فرق) ✓. الباقي خاطئ: (x+2)² = x²+4x+4 لا x²+4 (نسيانُ الأوسط)؛ (x−1)² = x²−2x+1 لا x²−1؛ (x+5)² = x²+10x+25 لا …+5 (الثابتُ 5² = 25).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fac2d2b-e044-5277-9735-c5bfd1697848', 'dfb1bf66-a7bf-5ae0-bff0-01cf67f6701f', 'أيُّ الصور التالية تساوي العبارة x² + 10x + 25؟', '[{"id":"a","text":"(x + 10)²"},{"id":"b","text":"(x + 25)²"},{"id":"c","text":"(x + 5)²"},{"id":"d","text":"(x + 5)(x − 5)"}]'::jsonb, 'c', 'نتعرّف على مربّعٍ كامل: الحدّ الثابت 25 = 5² والحدّ الأوسط 10x = 2×5×x، فالعبارة هي (x + 5)² ✓. الخطأُ الشائع: أخذُ نصف معامل x خطأً أو الحدّ الثابت مباشرةً ((x+10)² أو (x+25)²)، أو الخلطُ مع الفرق (x+5)(x−5) = x²−25.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('705d6c89-dee7-58d9-ae59-7cc04bb5e2a7', 'dfb1bf66-a7bf-5ae0-bff0-01cf67f6701f', 'عمِّل تعميلًا كاملًا بإخراج العامل المشترك الأكبر: 6x² + 9x.', '[{"id":"a","text":"3(2x² + 3x)"},{"id":"b","text":"3x(2x + 3)"},{"id":"c","text":"x(6x + 9)"},{"id":"d","text":"3x(2x + 9)"}]'::jsonb, 'b', 'العددُ المشترك بين 6 و9 هو 3، والحرفُ المشترك بين x² وx هو x، فالعاملُ الأكبر 3x؛ 6x²÷3x = 2x و9x÷3x = 3، فالتعميلُ الكامل هو 3x(2x + 3) ✓. الخياران 3(2x²+3x) وx(6x+9) صحيحان قيمةً لكنّهما غيرُ مكتملَين (لم يُخرَج العاملُ الأكبر)؛ والخيار 3x(2x+9) = 6x²+27x خاطئٌ قيمةً.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
