INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d38db7bd-88a8-5815-8219-39dc73765fad', '6afe2dde-e1af-59a5-9f38-629a5ea72d6e', 'للتحقّق من أنّ عددًا هو حلٌّ لمعادلة، ماذا نفعل؟', '[{"id":"a","text":"نعوّضه مكانَ المجهول في كلا الطرفَين ونقارن الناتجَين"},{"id":"b","text":"نعوّضه في الطرف الأوّل فقط"},{"id":"c","text":"نضربه في معامل المجهول"},{"id":"d","text":"نجمعه مع الحدّ العدديّ"}]'::jsonb, 'a', 'الحلُّ هو العددُ الذي يجعل الطرفَين متساويَين، لذا نعوّضه في كلا الطرفَين ونحسبُهما كاملَين ثمّ نقارن؛ حسابُ طرفٍ واحدٍ فقط لا يكفي للحكم.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85ea0bba-ff88-5f47-8c69-d0002b2e45e6', '6afe2dde-e1af-59a5-9f38-629a5ea72d6e', 'ما حلُّ المعادلة 2x − 3 = 7؟', '[{"id":"a","text":"−2"},{"id":"b","text":"2"},{"id":"c","text":"5"},{"id":"d","text":"10"}]'::jsonb, 'c', 'نعزل الحدّ الحرفيّ: 2x = 7 + 3 = 10، ثمّ نقسم على 2: x = 10 ÷ 2 = 5. التحقّق: 2 × 5 − 3 = 7 ✓. الخطأُ الشائع: نسيانُ تغيير إشارة −3 يعطي 2x = 7 − 3 = 4 → x = 2، أو نسيانُ القسمة يعطي 10.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d519f89-5c0e-5014-a5f0-b3248d1b99fb', '6afe2dde-e1af-59a5-9f38-629a5ea72d6e', 'ما حلُّ المعادلة 2x + 7 = 1؟', '[{"id":"a","text":"−6"},{"id":"b","text":"−3"},{"id":"c","text":"3"},{"id":"d","text":"4"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ: 2x = 1 − 7 = −6، ثمّ نقسم على 2: x = −6 ÷ 2 = −3. التحقّق: 2 × (−3) + 7 = −6 + 7 = 1 ✓. الخطأُ الشائع: نقلُ +7 دون تغيير إشارته يعطي 2x = 1 + 7 = 8 → x = 4، أو نسيانُ القسمة يعطي −6.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f88b8d74-8792-5a1f-9b79-0f66b1e82805', '6afe2dde-e1af-59a5-9f38-629a5ea72d6e', 'ما حلُّ المعادلة x/3 + 2 = 6؟', '[{"id":"a","text":"4"},{"id":"b","text":"12"},{"id":"c","text":"18"},{"id":"d","text":"24"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ: x/3 = 6 − 2 = 4، ثمّ نضرب في المقام 3: x = 4 × 3 = 12. التحقّق: 12/3 + 2 = 4 + 2 = 6 ✓. الخطأُ الشائع: نسيانُ الضرب في 3 يعطي 4، أو نقلُ +2 بإشارةٍ خاطئة (x/3 = 8) يعطي 24، أو تجاهلُ الحدّ العدديّ (x/3 = 6) يعطي 18.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8625719-e0fb-51e8-8f99-30521e0096c5', '6afe2dde-e1af-59a5-9f38-629a5ea72d6e', 'ما حلُّ المعادلة −2x + 5 = 11؟', '[{"id":"a","text":"−8"},{"id":"b","text":"−6"},{"id":"c","text":"−3"},{"id":"d","text":"3"}]'::jsonb, 'c', 'نعزل الحدّ الحرفيّ: −2x = 11 − 5 = 6، ثمّ نقسم على −2: x = 6 ÷ (−2) = −3. التحقّق: −2 × (−3) + 5 = 6 + 5 = 11 ✓. الخطأُ الشائع: تجاهلُ الإشارة السالبة عند القسمة يعطي 3، أو نقلُ +5 بإشارةٍ خاطئة (−2x = 16) يعطي −8، أو نسيانُ القسمة يعطي −6.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

