INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('726d7f5b-db63-5e9e-a0c0-143ab4e37485', 'f5a30bab-b176-5023-99b4-ffa0bb144f9d', 'في المعادلة −4x + 9 = 5، ما هو معاملُ المجهول؟', '[{"id":"a","text":"−4"},{"id":"b","text":"4"},{"id":"c","text":"5"},{"id":"d","text":"9"}]'::jsonb, 'a', 'معاملُ المجهول هو العددُ الذي يضربه في الحدّ الحرفيّ، أي −4 (بإشارته السالبة). أمّا 9 فهو الحدّ العدديّ، و5 هو الطرفُ الثاني.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
