INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cebb35b6-fcce-5341-a96b-eeeb413974f3', 'f5a30bab-b176-5023-99b4-ffa0bb144f9d', 'هل x = −2 حلٌّ للمعادلة 3x + 10 = 4؟', '[{"id":"a","text":"نعم، لأنّ 3 × (−2) + 10 = 4"},{"id":"b","text":"لا، لأنّ 3 × (−2) + 10 = 16"},{"id":"c","text":"لا، لأنّ 3 × (−2) + 10 = −16"},{"id":"d","text":"لا، لأنّ المعادلة ليس لها حلّ"}]'::jsonb, 'a', 'نعوّض x = −2: الطرفُ الأوّل 3 × (−2) + 10 = −6 + 10 = 4، وهو يساوي الطرفَ الثاني (4)، فـ x = −2 حلٌّ للمعادلة ✓. الخطأُ الشائع: حسابُ 3 × (−2) = 6 بدل −6 يعطي 16.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2cd70e56-68a5-5aa4-90b4-bf4efd5cc292', 'f5a30bab-b176-5023-99b4-ffa0bb144f9d', 'ما حلُّ المعادلة x + 6 = 2؟', '[{"id":"a","text":"−8"},{"id":"b","text":"−4"},{"id":"c","text":"4"},{"id":"d","text":"8"}]'::jsonb, 'b', 'نطرح 6 من الطرفَين: x = 2 − 6 = −4. التحقّق: −4 + 6 = 2 ✓. الخطأُ الشائع: عكسُ ترتيب الطرح (6 − 2 = 4)، أو جمعُ 6 بدل طرحه (2 + 6 = 8).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
