  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d4ec1cf-d54a-5bd7-90b6-390a96bf8401', 'f5a30bab-b176-5023-99b4-ffa0bb144f9d', 'ما حلُّ المعادلة 4x = −20؟', '[{"id":"a","text":"−80"},{"id":"b","text":"−16"},{"id":"c","text":"−5"},{"id":"d","text":"5"}]'::jsonb, 'c', 'نقسم الطرفَين على 4: x = −20 ÷ 4 = −5. التحقّق: 4 × (−5) = −20 ✓. الخطأُ الشائع: تجاهلُ الإشارة السالبة يعطي 5، أو الطرحُ بدل القسمة (−20 − 4 = −16)، أو الضربُ بدل القسمة (−20 × 4 = −80).', 4)
