INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71a334ca-c3e8-5b3f-a138-7111a3c614c8', 'f5a30bab-b176-5023-99b4-ffa0bb144f9d', 'ما حلُّ المعادلة 2x − 6 = 8؟', '[{"id":"a","text":"−1"},{"id":"b","text":"1"},{"id":"c","text":"7"},{"id":"d","text":"14"}]'::jsonb, 'c', 'نعزل الحدّ الحرفيّ: 2x = 8 + 6 = 14، ثمّ نقسم على 2: x = 14 ÷ 2 = 7. التحقّق: 2 × 7 − 6 = 8 ✓. الخطأُ الشائع: نسيانُ تغيير إشارة −6 يعطي 2x = 8 − 6 = 2 → x = 1، أو نسيانُ القسمة يعطي 14.', 5)
