INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed06bcd2-dfd0-5ebc-890c-d40fd2994427', 'f5a30bab-b176-5023-99b4-ffa0bb144f9d', 'ما حلُّ المعادلة x/2 − 3 = 4؟', '[{"id":"a","text":"2"},{"id":"b","text":"7"},{"id":"c","text":"8"},{"id":"d","text":"14"}]'::jsonb, 'd', 'نعزل الحدّ الحرفيّ: x/2 = 4 + 3 = 7، ثمّ نضرب في المقام 2: x = 7 × 2 = 14. التحقّق: 14/2 − 3 = 7 − 3 = 4 ✓. الخطأُ الشائع: نسيانُ الضرب في 2 يعطي 7، أو تجاهلُ الحدّ العدديّ (x/2 = 4) يعطي 8، أو نقلُ 3 بإشارةٍ خاطئة (x/2 = 1) يعطي 2.', 6)
