INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fdad9e55-54ed-5d02-9f25-e29373acbcb2', 'b1a25f8f-475b-5d0c-9595-d4b6cbc1348f', 'ما حلُّ المعادلة 3x − 6 = 9؟', '[{"id":"a","text":"1"},{"id":"b","text":"5"},{"id":"c","text":"15"},{"id":"d","text":"45"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ بنقل −6 مع تغيير إشارته: 3x = 9 + 6 = 15، ثمّ نقسم على 3: x = 15 ÷ 3 = 5. التحقّق: 3 × 5 − 6 = 9 ✓. الخطأُ الشائع: نسيانُ تغيير إشارة −6 يعطي 3x = 9 − 6 = 3 → x = 1، أو نسيانُ القسمة يعطي 15، أو الضربُ بدل القسمة (15 × 3 = 45).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('edd7c195-004f-5d77-ba83-a8dc1ff12fac', 'b1a25f8f-475b-5d0c-9595-d4b6cbc1348f', 'ما حلُّ المعادلة −2x + 3 = 9؟', '[{"id":"a","text":"−3"},{"id":"b","text":"3"},{"id":"c","text":"−6"},{"id":"d","text":"6"}]'::jsonb, 'a', 'نعزل الحدّ الحرفيّ: −2x = 9 − 3 = 6، ثمّ نقسم على −2: x = 6 ÷ (−2) = −3. التحقّق: −2 × (−3) + 3 = 6 + 3 = 9 ✓. الخطأُ الشائع: تجاهلُ الإشارة السالبة عند القسمة يعطي 3، أو نقلُ +3 دون تغيير إشارته (−2x = 12) يعطي −6، أو نسيانُ القسمة يعطي 6.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34b43924-324f-57c9-bf59-6af0f1685a2e', 'b1a25f8f-475b-5d0c-9595-d4b6cbc1348f', 'ما حلُّ المعادلة 0,5x + 1 = 4؟', '[{"id":"a","text":"3"},{"id":"b","text":"1,5"},{"id":"c","text":"10"},{"id":"d","text":"6"}]'::jsonb, 'd', 'نعزل الحدّ الحرفيّ: 0,5x = 4 − 1 = 3، ثمّ نقسم على المعامل: x = 3 ÷ 0,5 = 6 (القسمةُ على 0,5 تُكافئ الضربَ في 2). التحقّق: 0,5 × 6 + 1 = 3 + 1 = 4 ✓. الخطأُ الشائع: الضربُ في 0,5 بدل القسمة (3 × 0,5 = 1,5)، أو تجاهلُ المعامل واعتبارُ الناتج 3، أو نقلُ +1 بإشارةٍ خاطئة (0,5x = 5) يعطي 10.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d81d132c-354c-56d8-a10c-7516c8387920', 'b1a25f8f-475b-5d0c-9595-d4b6cbc1348f', 'ما حلُّ المعادلة (1/4)x + 2 = 5؟', '[{"id":"a","text":"28"},{"id":"b","text":"0,75"},{"id":"c","text":"12"},{"id":"d","text":"3"}]'::jsonb, 'c', 'نعزل الحدّ الحرفيّ: (1/4)x = 5 − 2 = 3، ثمّ نضرب في المقلوب 4: x = 3 × 4 = 12. التحقّق: (1/4) × 12 + 2 = 3 + 2 = 5 ✓. الخطأُ الشائع: الضربُ في المعامل 1/4 بدل مقلوبه (3 × 1/4 = 0,75)، أو التوقّفُ عند 3 بنسيان الضرب في 4، أو نقلُ +2 بإشارةٍ خاطئة ((1/4)x = 7) يعطي 28.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8fd14b2f-0024-5b5d-9cd4-95c8c1a6bd05', 'b1a25f8f-475b-5d0c-9595-d4b6cbc1348f', 'ما حلُّ المعادلة 5x − 2x + 3 = 15؟', '[{"id":"a","text":"4"},{"id":"b","text":"5"},{"id":"c","text":"6"},{"id":"d","text":"12"}]'::jsonb, 'a', 'نجمع الحدود المتشابهة أوّلًا: 5x − 2x = 3x فتصير المعادلة 3x + 3 = 15، ثمّ 3x = 12 و x = 4. التحقّق: 5 × 4 − 2 × 4 + 3 = 20 − 8 + 3 = 15 ✓. الخطأُ الشائع: تجاهلُ الحدّ +3 (3x = 15 → x = 5)، أو نسيانُ تغيير إشارة +3 (3x = 18 → x = 6)، أو نسيانُ القسمة يعطي 12.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d4aa889-cd81-5b2b-ab35-946f3ab8dd95', 'b1a25f8f-475b-5d0c-9595-d4b6cbc1348f', 'اشترى وليدٌ قميصَين متماثلَين وحزامًا بـ 4 دنانير، فبلغ مجموعُ ما دفعه 20 دينارًا. ما ثمنُ القميص الواحد؟', '[{"id":"a","text":"16 دينارًا"},{"id":"b","text":"8 دنانير"},{"id":"c","text":"10 دنانير"},{"id":"d","text":"12 دينارًا"}]'::jsonb, 'b', 'نسمّي x ثمنَ القميص، فالمعادلة 2x + 4 = 20. نعزل: 2x = 20 − 4 = 16، ثمّ x = 16 ÷ 2 = 8 دنانير. التحقّق: 2 × 8 + 4 = 20 ✓. الخطأُ الشائع: تجاهلُ ثمن الحزام (2x = 20 → x = 10)، أو نسيانُ تغيير إشارة 4 (2x = 24 → x = 12)، أو نسيانُ القسمة يعطي 16.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('fc147fd2-f83e-5fb1-8aa3-d64d3d3a9e01', '955a7b77-6e29-550e-8490-8c96dfd92bd6', 'math-8eme', '⭐⭐ تمرين مراجعة (نمط امتحان): معادلاتٌ وتحقّقٌ من الحلّ', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
