INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cb79caf0-f512-53f3-a540-4a85799b0f34', 'fc147fd2-f83e-5fb1-8aa3-d64d3d3a9e01', 'ما حلُّ المعادلة x − 5 = 3؟', '[{"id":"a","text":"2"},{"id":"b","text":"−2"},{"id":"c","text":"8"},{"id":"d","text":"15"}]'::jsonb, 'c', 'نضيف 5 إلى الطرفَين لعزل x: x = 3 + 5 = 8. التحقّق: 8 − 5 = 3 ✓. الخطأُ الشائع: طرحُ 5 من 3 بدل إضافته (3 − 5 = −2)، أو عكسُ الترتيب (5 − 3 = 2)، أو ضربُ العددين (5 × 3 = 15).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0cb1f4f-9e9b-5bb1-9048-9115c0f079ac', 'fc147fd2-f83e-5fb1-8aa3-d64d3d3a9e01', 'ما حلُّ المعادلة 3x = 21؟', '[{"id":"a","text":"7"},{"id":"b","text":"18"},{"id":"c","text":"24"},{"id":"d","text":"63"}]'::jsonb, 'a', 'نقسم الطرفَين على 3: x = 21 ÷ 3 = 7. التحقّق: 3 × 7 = 21 ✓. الخطأُ الشائع: طرحُ 3 بدل القسمة (21 − 3 = 18)، أو إضافتُه (21 + 3 = 24)، أو ضربُه (21 × 3 = 63).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d92a357e-98ac-5b73-b55e-bb6ab722e3ac', 'fc147fd2-f83e-5fb1-8aa3-d64d3d3a9e01', 'ما حلُّ المعادلة 2x + 5 = 13؟', '[{"id":"a","text":"18"},{"id":"b","text":"4"},{"id":"c","text":"8"},{"id":"d","text":"9"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ: 2x = 13 − 5 = 8، ثمّ نقسم على 2: x = 8 ÷ 2 = 4. التحقّق: 2 × 4 + 5 = 13 ✓. الخطأُ الشائع: نسيانُ القسمة يعطي 8، أو نسيانُ تغيير إشارة 5 (2x = 18 → x = 9)، أو التوقّفُ عند 18.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('968768dd-e8fb-558e-b416-29da016ead87', 'fc147fd2-f83e-5fb1-8aa3-d64d3d3a9e01', 'هل x = −4 حلٌّ للمعادلة −x + 2 = 6؟', '[{"id":"a","text":"نعم، لأنّ −(−4) + 2 = 6"},{"id":"b","text":"لا، لأنّ −(−4) + 2 = −2"},{"id":"c","text":"لا، لأنّ −(−4) + 2 = 2"},{"id":"d","text":"لا، لأنّ المعادلة ليس لها حلّ"}]'::jsonb, 'a', 'نعوّض x = −4 في الطرف الأوّل: −(−4) + 2 = 4 + 2 = 6، وهو يساوي الطرفَ الثاني (6)، فـ x = −4 حلٌّ للمعادلة ✓. الخطأُ الشائع: اعتبارُ −(−4) = −4 يعطي −4 + 2 = −2، أو اعتبارُ −(−4) = 0 يعطي 2؛ تذكّر أنّ عكسَ عددٍ سالبٍ موجب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('548bd724-6319-593e-8c39-325e05edcd21', 'fc147fd2-f83e-5fb1-8aa3-d64d3d3a9e01', 'ما حلُّ المعادلة 0,2x = 6؟', '[{"id":"a","text":"1,2"},{"id":"b","text":"3"},{"id":"c","text":"12"},{"id":"d","text":"30"}]'::jsonb, 'd', 'نقسم على المعامل: x = 6 ÷ 0,2 = 30 (القسمةُ على 0,2 تُكافئ الضربَ في 5). التحقّق: 0,2 × 30 = 6 ✓. الخطأُ الشائع: الضربُ في 0,2 بدل القسمة (6 × 0,2 = 1,2)، أو القسمةُ على 2 بدل 0,2 (6 ÷ 2 = 3).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8072d34a-ca89-58d9-ac09-87e4c0df94ad', 'fc147fd2-f83e-5fb1-8aa3-d64d3d3a9e01', 'ما حلُّ المعادلة 4x + 2x = 18؟', '[{"id":"a","text":"4,5"},{"id":"b","text":"3"},{"id":"c","text":"9"},{"id":"d","text":"18"}]'::jsonb, 'b', 'نجمع الحدّين المتشابهَين: 4x + 2x = 6x، فتصير المعادلة 6x = 18 و x = 18 ÷ 6 = 3. التحقّق: 4 × 3 + 2 × 3 = 12 + 6 = 18 ✓. الخطأُ الشائع: اعتبارُ الحدّ 2x فقط (2x = 18 → x = 9)، أو الحدّ 4x فقط (4x = 18 → x = 4,5)، أو نسيانُ القسمة يعطي 18.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

