INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89a625d9-f8b2-56dd-b067-a7dbce2b22b4', 'f3aceac4-8daf-52c8-b66b-ba78f16f1432', 'ما حلُّ المعادلة (2/3)x − 1 = 5؟', '[{"id":"a","text":"6"},{"id":"b","text":"9"},{"id":"c","text":"4"},{"id":"d","text":"3"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ: (2/3)x = 5 + 1 = 6، ثمّ نضرب في المقلوب (3/2): x = 6 × 3/2 = 9. التحقّق: (2/3) × 9 − 1 = 6 − 1 = 5 ✓. الخطأُ الشائع: نسيانُ تغيير إشارة −1 ((2/3)x = 4 → x = 6)، أو الضربُ في المعامل 2/3 بدل مقلوبه (6 × 2/3 = 4)، أو القسمةُ على البسط فقط (6 ÷ 2 = 3).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed945d96-f61b-5d1b-bac4-0d845c94b625', 'f3aceac4-8daf-52c8-b66b-ba78f16f1432', 'ما حلُّ المعادلة 7x − 3x + 2 = 14؟', '[{"id":"a","text":"3"},{"id":"b","text":"3,5"},{"id":"c","text":"4"},{"id":"d","text":"12"}]'::jsonb, 'a', 'نجمع الحدود المتشابهة: 7x − 3x = 4x فتصير المعادلة 4x + 2 = 14، ثمّ 4x = 12 و x = 3. التحقّق: 7 × 3 − 3 × 3 + 2 = 21 − 9 + 2 = 14 ✓. الخطأُ الشائع: تجاهلُ الحدّ +2 (4x = 14 → x = 3,5)، أو نسيانُ تغيير إشارته (4x = 16 → x = 4)، أو نسيانُ القسمة يعطي 12.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('567232a9-721b-5606-a571-72768cbcf968', 'f3aceac4-8daf-52c8-b66b-ba78f16f1432', 'عُمرُ أمينة يفوق عُمرَ أخيها بـ 5 سنوات، ومجموعُ عُمرَيهما 27 سنة. كم عُمرُ أخيها؟', '[{"id":"a","text":"16 سنة"},{"id":"b","text":"13,5 سنة"},{"id":"c","text":"11 سنة"},{"id":"d","text":"22 سنة"}]'::jsonb, 'c', 'نسمّي x عُمرَ الأخ، فعُمرُ أمينة x + 5، والمجموع x + (x + 5) = 27، أي 2x + 5 = 27. نعزل: 2x = 22 و x = 11 سنة. التحقّق: 11 + 16 = 27 ✓. الخطأُ الشائع: الإجابةُ بعُمر أمينة بدل الأخ (16)، أو تجاهلُ الفارق 5 (2x = 27 → x = 13,5)، أو نسيانُ القسمة يعطي 22.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9cc699a4-e271-5635-8d73-be3cc7b17008', 'f3aceac4-8daf-52c8-b66b-ba78f16f1432', 'حلَّ تلميذٌ المعادلة −2x + 6 = 10 كالتالي: −2x = 10 − 6 = 4، ثمّ x = 4 ÷ 2 = 2. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، x = 2 صحيح"},{"id":"b","text":"الخطأ في نقل 6: الصحيح −2x = 16"},{"id":"c","text":"الخطأ أنّ المعادلة ليس لها حلّ"},{"id":"d","text":"الخطأ في القسمة: قسم على 2 بدل −2، والصحيح x = −2"}]'::jsonb, 'd', 'عزلُ الحدّ الحرفيّ صحيح: −2x = 4، لكنّ القسمة يجب أن تكون على المعامل بإشارته −2 لا 2؛ فالصحيح x = 4 ÷ (−2) = −2. التحقّق: −2 × (−2) + 6 = 4 + 6 = 10 ✓. (سؤالُ اكتشاف خطأ: الخيارُ الصحيح يصف موضعَ الخطأ لا حلًّا بديلًا.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17d1873b-fa7f-51b5-a45c-343579a518d0', 'f3aceac4-8daf-52c8-b66b-ba78f16f1432', 'دفع حرفيٌّ ثلاثةَ أرباع ثمن مادّةٍ أوّليّة مقدّمًا، وتبقّى عليه أن يدفع رُبعَ الثمن أي 40 دينارًا. ما ثمنُ المادّة كاملًا؟', '[{"id":"a","text":"10 دنانير"},{"id":"b","text":"160 دينارًا"},{"id":"c","text":"36 دينارًا"},{"id":"d","text":"44 دينارًا"}]'::jsonb, 'b', 'نسمّي x الثمنَ الكامل، فالرُّبعُ المتبقّي (1/4)x = 40. نضرب في المقلوب 4: x = 40 × 4 = 160 دينارًا. التحقّق: رُبعُ 160 هو 40 ✓. الخطأُ الشائع: القسمةُ على 4 بدل الضرب (40 ÷ 4 = 10)، أو طرحُ 4 (40 − 4 = 36)، أو جمعُه (40 + 4 = 44).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('762e8ece-7bd2-5b0c-aa44-51f8cbd3fbd2', 'f3aceac4-8daf-52c8-b66b-ba78f16f1432', 'المعادلة 4x + b = 3 لها الحلّ x = 2. ما قيمة b؟', '[{"id":"a","text":"−5"},{"id":"b","text":"5"},{"id":"c","text":"11"},{"id":"d","text":"−11"}]'::jsonb, 'a', 'نعوّض x = 2: 4 × 2 + b = 3، أي 8 + b = 3، فـ b = 3 − 8 = −5. التحقّق: 4 × 2 + (−5) = 8 − 5 = 3 ✓. الخطأُ الشائع: عكسُ الطرح (8 − 3 = 5)، أو جمعُ العددَين (3 + 8 = 11)، أو الخطأُ في الإشارة (−11).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

