INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ef031cf-a624-515c-97fd-6faf713cf63b', '6286991c-9921-59e8-96c0-6a8a256dcd1b', 'في حديقةٍ عددُ أشجار الزيتون يساوي ضِعفَ عدد أشجار اللوز زائدَ 3، وعددُ أشجار الزيتون 17. كم عددُ أشجار اللوز؟', '[{"id":"a","text":"14"},{"id":"b","text":"8,5"},{"id":"c","text":"10"},{"id":"d","text":"7"}]'::jsonb, 'd', 'نسمّي x عددَ أشجار اللوز، فعددُ الزيتون 2x + 3 = 17. نعزل: 2x = 17 − 3 = 14، ثمّ x = 14 ÷ 2 = 7. التحقّق: 2 × 7 + 3 = 17 ✓. الخطأُ الشائع: تجاهلُ الزيادة 3 (2x = 17 → x = 8,5)، أو نسيانُ تغيير إشارة 3 (2x = 20 → x = 10)، أو نسيانُ القسمة يعطي 14.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d9526ba3-8737-5535-9e24-20588de78b4b', '955a7b77-6e29-550e-8490-8c96dfd92bd6', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مجهولٌ على الطرفَين ومسائلُ مركّبة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
