  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f9b93fc-e7de-5039-94db-37987a8ee65f', 'd9526ba3-8737-5535-9e24-20588de78b4b', 'ما حلُّ المعادلة 5x + 2 = 3x + 10؟', '[{"id":"a","text":"4"},{"id":"b","text":"1"},{"id":"c","text":"6"},{"id":"d","text":"8"}]'::jsonb, 'a', 'نجمع الحدود الحرفيّة في طرفٍ والعدديّة في الآخر: 5x − 3x = 10 − 2، أي 2x = 8، فـ x = 4. التحقّق: 5 × 4 + 2 = 22 و 3 × 4 + 10 = 22 ✓. الخطأُ الشائع: جمعُ 5x و 3x بدل طرحهما (8x = 8 → x = 1)، أو الخطأُ في نقل الحدود (2x = 12 → x = 6)، أو نسيانُ القسمة يعطي 8.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f27b66fd-66d9-5feb-a9f0-6bf7647c4605', 'd9526ba3-8737-5535-9e24-20588de78b4b', 'ما حلُّ المعادلة 0,4x − 1,5 = 2,5؟', '[{"id":"a","text":"10"},{"id":"b","text":"1,6"},{"id":"c","text":"4"},{"id":"d","text":"2,5"}]'::jsonb, 'a', 'نعزل الحدّ الحرفيّ: 0,4x = 2,5 + 1,5 = 4، ثمّ نقسم على المعامل: x = 4 ÷ 0,4 = 10. التحقّق: 0,4 × 10 − 1,5 = 4 − 1,5 = 2,5 ✓. الخطأُ الشائع: الضربُ في 0,4 بدل القسمة (4 × 0,4 = 1,6)، أو التوقّفُ عند 4، أو نسيانُ تغيير إشارة −1,5 (0,4x = 1 → x = 2,5).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('09cfd16d-92f3-58e4-9779-1169b0adbdc7', 'd9526ba3-8737-5535-9e24-20588de78b4b', 'مستطيلٌ طولُه يفوق عرضَه بـ 4 أمتار، ومحيطُه 36 مترًا. ما عرضُه؟', '[{"id":"a","text":"16 مترًا"},{"id":"b","text":"9 أمتار"},{"id":"c","text":"7 أمتار"},{"id":"d","text":"11 مترًا"}]'::jsonb, 'c', 'نسمّي x العرضَ (بالمتر)، فالطولُ x + 4. المحيطُ = 2 × (الطول + العرض) = 2 × ((x + 4) + x) = 2 × (2x + 4) = 4x + 8 = 36. نعزل: 4x = 28 و x = 7 أمتار. التحقّق: العرض 7 والطول 11، والمحيط 2 × (11 + 7) = 36 ✓. الخطأُ الشائع: نسيانُ الضرب في 2 (2x + 4 = 36 → x = 16)، أو تجاهلُ الزيادة 4 (4x = 36 → x = 9)، أو الإجابةُ بالطول بدل العرض (11).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed1252eb-00cf-57a6-b2a5-3cbbd2c1a6d3', 'd9526ba3-8737-5535-9e24-20588de78b4b', 'مجموعُ نصفِ عددٍ وثُلثِه يساوي 15. ما هو العدد؟', '[{"id":"a","text":"37,5"},{"id":"b","text":"18"},{"id":"c","text":"12,5"},{"id":"d","text":"30"}]'::jsonb, 'b', 'المعادلة (1/2)x + (1/3)x = 15. نوحّد المقامات: (3/6)x + (2/6)x = (5/6)x = 15، ثمّ نضرب في المقلوب (6/5): x = 15 × 6/5 = 18. التحقّق: (1/2) × 18 + (1/3) × 18 = 9 + 6 = 15 ✓. الخطأُ الشائع: جمعُ الكسرَين خطأً (1/2 + 1/3 = 2/5) يعطي 37,5، أو الضربُ في المعامل 5/6 بدل مقلوبه (15 × 5/6 = 12,5)، أو اعتبارُ النصف يعني الضربَ في 2 (30).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ae72427-f890-5f8d-a217-823b70da53de', 'd9526ba3-8737-5535-9e24-20588de78b4b', 'لحلّ المعادلة (2/5)x = 8، كتب تلميذٌ: x = 8 × 2/5 = 3,2. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، x = 3,2 صحيح"},{"id":"b","text":"الخطأ في ضرب 8 في المعامل 2/5 بدل مقلوبه 5/2، والصحيح x = 20"},{"id":"c","text":"الخطأ أنّه يجب جمع 2/5 إلى 8"},{"id":"d","text":"الخطأ أنّ المعادلة ليس لها حلّ"}]'::jsonb, 'b', 'لعزل x نضرب في مقلوب المعامل لا في المعامل نفسِه؛ مقلوبُ 2/5 هو 5/2، فالصحيح x = 8 × 5/2 = 20. التحقّق: (2/5) × 20 = 8 ✓. (سؤالُ اكتشاف خطأ: الضربُ في 2/5 يصغّر العدد بينما الحلُّ يجب أن يكبّره.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c75487a5-dc01-570e-815d-6389c6b71bd0', 'd9526ba3-8737-5535-9e24-20588de78b4b', 'إذا كان x = −3 حلًّا للمعادلة ax − 1 = 8، فما قيمة a؟', '[{"id":"a","text":"9"},{"id":"b","text":"−9"},{"id":"c","text":"3"},{"id":"d","text":"−3"}]'::jsonb, 'd', 'نعوّض x = −3: a × (−3) − 1 = 8، أي −3a = 8 + 1 = 9، فـ a = 9 ÷ (−3) = −3. التحقّق: (−3) × (−3) − 1 = 9 − 1 = 8 ✓. الخطأُ الشائع: تجاهلُ الإشارة السالبة في القسمة (3)، أو نسيانُ القسمة على −3 (9 أو −9).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

