INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db40e64a-710f-581f-8515-d18162ce01b6', '01332114-bbf9-5e43-b98f-d223affda1b2', 'سلسلتان متناسبتان: العدد 4 يقابله 20، والعدد 7 يقابله 35. ما معاملُ التناسب؟', '[{"id":"a","text":"1/5"},{"id":"b","text":"5"},{"id":"c","text":"24"},{"id":"d","text":"140"}]'::jsonb, 'b', 'معاملُ التناسب k = الحدّ الثاني ÷ الحدّ الأوّل = 20 ÷ 4 = 5 (وكذلك 35 ÷ 7 = 5).', 1)
