INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99c7b3d8-7f05-5f7f-8cb0-93c6f7d35bb4', '01332114-bbf9-5e43-b98f-d223affda1b2', 'في سلسلةٍ متناسبة، العدد 3 يقابله 12. بنفس معامل التناسب، ما الذي يقابل 5؟', '[{"id":"a","text":"15"},{"id":"b","text":"17"},{"id":"c","text":"20"},{"id":"d","text":"60"}]'::jsonb, 'c', 'معاملُ التناسب k = 12 ÷ 3 = 4، إذن الحدُّ المقابل لـ 5 هو 5 × 4 = 20 (أو بالجداء التبادليّ: (5 × 12) ÷ 3 = 20).', 2)
