INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d54d14a-4a5b-549a-bec8-067e2d7f9cbc', '01332114-bbf9-5e43-b98f-d223affda1b2', 'ثمنُ سلعةٍ 200 دينار. زِيد بنسبة 10 %. ما الثمنُ الجديد؟', '[{"id":"a","text":"180"},{"id":"b","text":"200"},{"id":"c","text":"210"},{"id":"d","text":"220"}]'::jsonb, 'd', 'الزيادةُ بـ 10 % تعني الضربَ في (1 + 10/100) = 1,1، فالثمنُ الجديد = 200 × 1,1 = 220 دينارًا.', 4)
