INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8acbde40-bbb5-5b40-992c-454f404501be', '01332114-bbf9-5e43-b98f-d223affda1b2', 'قطعت درّاجةٌ ناريّة مسافةَ 30 كم في 30 دقيقة. ما سرعتُها المتوسّطة؟', '[{"id":"a","text":"1 كم/سا"},{"id":"b","text":"15 كم/سا"},{"id":"c","text":"60 كم/سا"},{"id":"d","text":"900 كم/سا"}]'::jsonb, 'c', 'نحوّل الزمن: 30 دقيقة = 30 ÷ 60 = 0,5 سا. السرعةُ = المسافة ÷ الزمن = 30 ÷ 0,5 = 60 كم/سا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
