INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21c40461-030d-507e-a0b4-ee6dd1820ef3', 'a5fa6b20-7025-5ab8-89d0-0c4daf68a200', 'سلسلتان متناسبتان: 2 يقابله 10، و6 يقابله 30. ما معاملُ التناسب k؟', '[{"id":"a","text":"5"},{"id":"b","text":"0,2"},{"id":"c","text":"8"},{"id":"d","text":"20"}]'::jsonb, 'a', 'معاملُ التناسب = الحدّ الثاني ÷ الحدّ الأوّل = 10 ÷ 2 = 5 (ونتحقّق: 30 ÷ 6 = 5) ✓. الخطأُ الشائع: قلبُ القسمة (2 ÷ 10 = 0,2)، أو طرحُ الحدّين (10 − 2 = 8)، أو ضربُهما (2 × 10 = 20).', 1)
