INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f60e7b49-425d-551a-b381-cb522fbd793f', 'a5fa6b20-7025-5ab8-89d0-0c4daf68a200', 'في سلسلةٍ متناسبة، 3 يقابله 21. بنفس المعامل، ما الذي يقابل 5؟', '[{"id":"a","text":"15"},{"id":"b","text":"35"},{"id":"c","text":"105"},{"id":"d","text":"23"}]'::jsonb, 'b', 'معاملُ التناسب = 21 ÷ 3 = 7، إذن الحدُّ المقابل لـ 5 هو 5 × 7 = 35 (أو بالجداء التبادليّ: (5 × 21) ÷ 3 = 35) ✓. الخطأُ الشائع: ضربُ 5 في الحدّ نفسه من العمود (5 × 3 = 15)، أو نسيانُ القسمة على 3 (5 × 21 = 105).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
