INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d0f7697-dd68-5b68-8b90-8d1b89f6047d', 'a5fa6b20-7025-5ab8-89d0-0c4daf68a200', 'ما 40 % من 150؟', '[{"id":"a","text":"6000"},{"id":"b","text":"110"},{"id":"c","text":"3,75"},{"id":"d","text":"60"}]'::jsonb, 'd', '40 % من 150 = (40 × 150) ÷ 100 = 6000 ÷ 100 = 60 ✓. الخطأُ الشائع: نسيانُ القسمة على 100 (6000)، أو طرحُ 40 من 150 مباشرةً (110).', 4)
