INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20184c24-64f6-554e-a29c-ce7ec556cb71', 'a5fa6b20-7025-5ab8-89d0-0c4daf68a200', 'على مخطّطٍ سلّمُه 1/200، طولُ قطعةٍ على المخطّط 5 سم. ما طولُها الحقيقيّ؟', '[{"id":"a","text":"0,025 سم"},{"id":"b","text":"1000 سم"},{"id":"c","text":"205 سم"},{"id":"d","text":"40 سم"}]'::jsonb, 'b', 'الطولُ الحقيقيّ = طولُ المخطّط × n = 5 × 200 = 1000 سم (= 10 م) ✓. الخطأُ الشائع: القسمةُ بدل الضرب فيُعكس السلّم (5 ÷ 200 = 0,025)، أو جمعُ العددين (5 + 200 = 205)، أو قسمةُ السلّم على الطول (200 ÷ 5 = 40).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
