  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf953c88-731d-5a4f-8175-a3e570c36d66', 'a5fa6b20-7025-5ab8-89d0-0c4daf68a200', 'قطع درّاجٌ 45 كم في 3 ساعات. ما سرعتُه المتوسّطة؟', '[{"id":"a","text":"135 كم/سا"},{"id":"b","text":"15 كم/سا"},{"id":"c","text":"42 كم/سا"},{"id":"d","text":"48 كم/سا"}]'::jsonb, 'b', 'السرعةُ المتوسّطة = المسافة ÷ الزمن = 45 ÷ 3 = 15 كم/سا ✓. الخطأُ الشائع: ضربُ المسافة في الزمن بدل قسمتها (45 × 3 = 135)، أو طرحُ الزمن من المسافة (45 − 3 = 42)، أو جمعُهما (45 + 3 = 48).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9c14bd1f-6198-5a6a-96dd-40e4f97bee14', '1d21b8df-e861-538d-a71a-2137f9397422', 'math-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: النسب المئوية والسرعة', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
