INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2fb7fd22-4057-584e-b9bc-bfe6f4ec906d', '9c14bd1f-6198-5a6a-96dd-40e4f97bee14', 'السلسلةُ الأولى: 4 ثمّ 6، والسلسلةُ الثانية: 12 ثمّ 18. هل هما متناسبتان، وما المعامل؟', '[{"id":"a","text":"غير متناسبتَين"},{"id":"b","text":"متناسبتان، k = 3"},{"id":"c","text":"متناسبتان، k = 8"},{"id":"d","text":"متناسبتان، k = 2"}]'::jsonb, 'b', 'نفحص كلّ عمود: 12 ÷ 4 = 3 و18 ÷ 6 = 3؛ النسبةُ ثابتة في العمودين، فالسلسلتان متناسبتان ومعاملُهما k = 3 ✓. الخطأُ الشائع: طرحُ الحدّين بدل قسمتهما (12 − 4 = 8)، أو الاكتفاءُ بفحص عمودٍ واحد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2639d63a-109e-5005-af98-8d9b5eb7be28', '9c14bd1f-6198-5a6a-96dd-40e4f97bee14', 'جدولُ تناسب: 8 يقابله 20، و x يقابله 45. ما x؟', '[{"id":"a","text":"45"},{"id":"b","text":"112,5"},{"id":"c","text":"18"},{"id":"d","text":"57"}]'::jsonb, 'c', 'بالجداء التبادليّ: 20 ÷ 8 = 45 ÷ x، إذن x = (8 × 45) ÷ 20 = 360 ÷ 20 = 18 ✓. الخطأُ الشائع: ضربُ الحدّين من الصفّ نفسه والقسمةُ على الحدّ الخطأ ((20 × 45) ÷ 8 = 112,5)، أو جمعُ الأعداد (45 + 20 − 8 = 57).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f8ce1c7a-5f95-58ba-9b57-fa7f973fa8e8', '9c14bd1f-6198-5a6a-96dd-40e4f97bee14', 'ثمنُ سلعةٍ 400 دينار، زِيد بنسبة 15 %. ما الثمنُ الجديد؟', '[{"id":"a","text":"415"},{"id":"b","text":"340"},{"id":"c","text":"400,15"},{"id":"d","text":"460"}]'::jsonb, 'd', 'الزيادةُ بـ 15 % تعني الضربَ في معامل الضرب (1 + 15/100) = 1,15، فالثمنُ الجديد = 400 × 1,15 = 460 دينارًا ✓. الخطأُ الشائع: جمعُ 15 مباشرةً (415)، أو الضربُ في 0,85 (تخفيضًا بدل زيادة → 340)، أو جمعُ 0,15 (400,15).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5be21665-555a-500f-9ae7-2512ba7a92f1', '9c14bd1f-6198-5a6a-96dd-40e4f97bee14', 'ثوبٌ ثمنُه 80 دينارًا، عليه تخفيضٌ 25 %. ما الثمنُ بعد التخفيض؟', '[{"id":"a","text":"60"},{"id":"b","text":"100"},{"id":"c","text":"55"},{"id":"d","text":"20"}]'::jsonb, 'a', 'التخفيضُ بـ 25 % يعني الضربَ في (1 − 25/100) = 0,75، فالثمنُ الجديد = 80 × 0,75 = 60 دينارًا ✓. الخطأُ الشائع: الزيادةُ بدل التخفيض (80 × 1,25 = 100)، أو طرحُ 25 مباشرةً (80 − 25 = 55)، أو حسابُ مقدار التخفيض وحده (80 × 0,25 = 20) لا الثمن الجديد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af225d14-1478-5b16-9a33-c9d7d00b2661', '9c14bd1f-6198-5a6a-96dd-40e4f97bee14', 'ارتفع ثمنُ كتابٍ من 20 دينارًا إلى 25 دينارًا. ما نسبةُ الزيادة؟', '[{"id":"a","text":"5 %"},{"id":"b","text":"25 %"},{"id":"c","text":"20 %"},{"id":"d","text":"5 دنانير"}]'::jsonb, 'b', 'نسبةُ التغيّر = (الجديدة − الأصليّة) ÷ الأصليّة × 100 = (25 − 20) ÷ 20 × 100 = 5 ÷ 20 × 100 = 25 % ✓. الخطأُ الشائع: القسمةُ على القيمة الجديدة (5 ÷ 25 × 100 = 20 %)، أو الاكتفاءُ بمقدار الفرق دون نسبة (5)، أو الخلطُ بين المقدار بالدينار والنسبة المئوية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f9498d1-119d-5e63-8ff0-32f5576a53cc', '9c14bd1f-6198-5a6a-96dd-40e4f97bee14', 'قطع قطارٌ 150 كم في ساعتَين ونصف. ما سرعتُه المتوسّطة؟', '[{"id":"a","text":"75 كم/سا"},{"id":"b","text":"300 كم/سا"},{"id":"c","text":"60 كم/سا"},{"id":"d","text":"375 كم/سا"}]'::jsonb, 'c', 'نحوّل الزمن: ساعتان ونصف = 2,5 سا. السرعة = المسافة ÷ الزمن = 150 ÷ 2,5 = 60 كم/سا ✓. الخطأُ الشائع: القسمةُ على 2 وإهمالُ النصف (150 ÷ 2 = 75)، أو الضربُ بدل القسمة (150 × 2 = 300 أو 150 × 2,5 = 375).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

