INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19b13094-56d7-53b7-8074-daa9db94cab2', '9d721103-84db-56c5-9862-d761df7441ad', 'سلسلتان متناسبتان: 5 يقابله 15. ما معاملُ التناسب؟', '[{"id":"a","text":"10"},{"id":"b","text":"75"},{"id":"c","text":"3"},{"id":"d","text":"0,33"}]'::jsonb, 'c', 'معاملُ التناسب = 15 ÷ 5 = 3 ✓. الخطأُ الشائع: طرحُ الحدّين (15 − 5 = 10)، أو ضربُهما (15 × 5 = 75)، أو قلبُ القسمة (5 ÷ 15 ≈ 0,33).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
