INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9cc2584e-bc63-5890-9a8e-7d1c2ac8cddd', '9d721103-84db-56c5-9862-d761df7441ad', 'ما 50 % من 240؟', '[{"id":"a","text":"12000"},{"id":"b","text":"190"},{"id":"c","text":"50"},{"id":"d","text":"120"}]'::jsonb, 'd', '50 % من 240 = (50 × 240) ÷ 100 = 120، وهو نصفُ الكمّية ✓. الخطأُ الشائع: نسيانُ القسمة على 100 (12000)، أو طرحُ 50 من 240 (190)، أو نقلُ النسبة كما هي (50).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e025ac6-f04f-594c-ba11-f47ec60c8fce', '9d721103-84db-56c5-9862-d761df7441ad', 'جدولُ تناسب: 6 يقابله 9. ما الذي يقابل 14 بنفس المعامل؟', '[{"id":"a","text":"21"},{"id":"b","text":"126"},{"id":"c","text":"84"},{"id":"d","text":"17"}]'::jsonb, 'a', 'بالجداء التبادليّ: الحدُّ = (14 × 9) ÷ 6 = 126 ÷ 6 = 21 (المعامل 9 ÷ 6 = 1,5 و14 × 1,5 = 21) ✓. الخطأُ الشائع: نسيانُ القسمة على 6 (14 × 9 = 126)، أو الضربُ في الحدّ الخطأ (14 × 6 = 84)، أو جمعٌ خاطئ (14 + 3 = 17).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a3c4441-5b33-5bfd-a3af-6220d543f5ec', '9d721103-84db-56c5-9862-d761df7441ad', 'عددُ منخرطي نادٍ 200، ازداد بنسبة 20 %. كم صار العدد؟', '[{"id":"a","text":"220"},{"id":"b","text":"240"},{"id":"c","text":"160"},{"id":"d","text":"40"}]'::jsonb, 'b', 'الزيادةُ بـ 20 % = ضربٌ في (1 + 20/100) = 1,2، فالعددُ الجديد = 200 × 1,2 = 240 ✓. الخطأُ الشائع: جمعُ 20 مباشرةً (220)، أو التخفيضُ بدل الزيادة (200 × 0,8 = 160)، أو حسابُ مقدار الزيادة وحده (200 × 0,2 = 40).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ec1fd4b-2512-50b7-9a5d-9e93f1bc05a3', '9d721103-84db-56c5-9862-d761df7441ad', 'خريطةٌ سلّمُها 1/50000. المسافةُ الحقيقيّة بين مدينتَين 3 كم. كم تمثّلها على الخريطة؟', '[{"id":"a","text":"0,06 سم"},{"id":"b","text":"60 سم"},{"id":"c","text":"6 سم"},{"id":"d","text":"1,5 سم"}]'::jsonb, 'c', 'نحوّل إلى الوحدة نفسها: 3 كم = 3 × 100000 = 300000 سم. طولُ المخطّط = الحقيقيّة ÷ n = 300000 ÷ 50000 = 6 سم ✓. الخطأُ الشائع: نسيانُ تحويل الكيلومتر إلى سنتيمتر (3 ÷ 50000 = 0,00006)، أو خطأٌ في عدد الأصفار عند التحويل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1208d46d-a934-5c11-a5a8-412136cea884', '9d721103-84db-56c5-9862-d761df7441ad', 'قطعت حافلةٌ 80 كم في ساعةٍ وربع. ما سرعتُها المتوسّطة؟', '[{"id":"a","text":"100 كم/سا"},{"id":"b","text":"80 كم/سا"},{"id":"c","text":"53,3 كم/سا"},{"id":"d","text":"64 كم/سا"}]'::jsonb, 'd', 'نحوّل الزمن: ساعةٌ وربع = 1 سا 15 د = 1,25 سا. السرعة = 80 ÷ 1,25 = 64 كم/سا ✓. الخطأُ الشائع: الضربُ بدل القسمة (80 × 1,25 = 100)، أو اعتبارُ الربع نصفًا والقسمةُ على 1,5 (80 ÷ 1,5 ≈ 53,3)، أو إهمالُ الزمن (80).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

