INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d237a4c6-47de-582c-b1f9-4745599d2abf', '9f1052bd-6a53-5f82-84f7-e48a6f951b68', 'بعد تخفيضٍ 20 % أصبح ثمنُ حقيبةٍ 72 دينارًا. ما ثمنُها الأصليّ؟', '[{"id":"a","text":"86,4"},{"id":"b","text":"92"},{"id":"c","text":"57,6"},{"id":"d","text":"90"}]'::jsonb, 'd', 'التخفيضُ بـ 20 % ضربٌ في 0,8، وللعودة إلى الأصليّ نقسم على معامل الضرب: 72 ÷ 0,8 = 90 دينارًا (نتحقّق: 90 × 0,8 = 72) ✓. الفخّ القاتل: زيادةُ 20 % على 72 (72 × 1,2 = 86,4) — لا تُعيد السعرَ لأنّ 20 % تُحسب على قيمةٍ أصغر. الخطأُ الآخر: 72 × 0,8 = 57,6، أو 72 + 20 = 92.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b1ee418-b3ea-5205-abab-ce3ad10aac5d', '9f1052bd-6a53-5f82-84f7-e48a6f951b68', 'انخفض ثمنُ هاتفٍ من 500 دينارًا إلى 400 دينار. ما نسبةُ التخفيض؟', '[{"id":"a","text":"20 %"},{"id":"b","text":"25 %"},{"id":"c","text":"100 %"},{"id":"d","text":"80 %"}]'::jsonb, 'a', 'نسبةُ التغيّر = (400 − 500) ÷ 500 × 100 = −100 ÷ 500 × 100 = −20 %، أي تخفيضٌ بـ 20 % ✓. الخطأُ الشائع: القسمةُ على القيمة الجديدة (100 ÷ 400 × 100 = 25 %)، أو الاكتفاءُ بالفرق (100)، أو حسابُ نسبة ما تبقّى من الثمن (400 ÷ 500 = 80 %).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47d4290d-3c94-5789-8e54-834fac1bb602', '9f1052bd-6a53-5f82-84f7-e48a6f951b68', 'اشترى تاجرٌ 8 أمتارٍ من قماشٍ بـ 60 دينارًا. كم يدفع مقابل 20 مترًا بنفس السعر؟', '[{"id":"a","text":"165"},{"id":"b","text":"150"},{"id":"c","text":"24"},{"id":"d","text":"7,5"}]'::jsonb, 'b', 'بالجداء التبادليّ: الثمن = (20 × 60) ÷ 8 = 1200 ÷ 8 = 150 دينارًا (سعرُ المتر = 60 ÷ 8 = 7,5 د، و7,5 × 20 = 150) ✓. الخطأُ الشائع: التوقّفُ عند سعر المتر الواحد (7,5)، أو عكسُ الجداء ((8 × 60) ÷ 20 = 24)، أو جمعٌ خاطئ (165).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb9689c7-3c48-516c-b1e0-24e553e6946d', '9f1052bd-6a53-5f82-84f7-e48a6f951b68', 'حسب تلميذٌ سرعةَ سيّارةٍ قطعت 60 كم في 45 دقيقة فكتب: 60 ÷ 45 ≈ 1,33 كم/سا. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، الحسابُ صحيح"},{"id":"b","text":"الخطأ في القسمة فقط؛ الصحيح 60 ÷ 45 = 1,5"},{"id":"c","text":"لم يحوّل الدقائق إلى ساعات؛ 45 د = 0,75 سا والسرعةُ = 60 ÷ 0,75 = 80 كم/سا"},{"id":"d","text":"الصحيح هو 45 ÷ 60 = 0,75 كم/سا"}]'::jsonb, 'c', 'الوحدةُ المطلوبة كم/سا، فيجب تحويلُ الزمن إلى ساعاتٍ قبل القسمة: 45 د = 45 ÷ 60 = 0,75 سا، والسرعة = 60 ÷ 0,75 = 80 كم/سا ✓. القسمةُ على 45 مباشرةً خطأٌ لأنّ 45 دقيقةً ليست 45 ساعة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd0034c5-2434-5691-8558-243e262cce66', '9f1052bd-6a53-5f82-84f7-e48a6f951b68', 'سعرُ سلعةٍ 100 دينار. زِيد بنسبة 10 %، ثمّ خُفّض الثمنُ الناتج بنسبة 10 %. ما الثمنُ النهائيّ؟', '[{"id":"a","text":"100"},{"id":"b","text":"90"},{"id":"c","text":"110"},{"id":"d","text":"99"}]'::jsonb, 'd', 'أوّلًا الزيادة: 100 × 1,1 = 110، ثمّ التخفيض: 110 × 0,9 = 99 دينارًا ✓. الفخّ: الظنُّ أنّ زيادةً ثمّ تخفيضًا بنفس النسبة يُعيدان السعرَ إلى 100 — لكنّ 10 % الثانية تُحسب على 110 لا على 100، فينقص الثمنُ إلى 99.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
