INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad59602b-5b92-522c-8ea9-79d7caa7e960', '9f1052bd-6a53-5f82-84f7-e48a6f951b68', 'في سلسلةٍ متناسبة معاملُها 2,5، حدٌّ في السلسلة الثانية يساوي 60. ما الحدُّ المقابل له في السلسلة الأولى؟', '[{"id":"a","text":"24"},{"id":"b","text":"150"},{"id":"c","text":"62,5"},{"id":"d","text":"57,5"}]'::jsonb, 'a', 'بما أنّ «الثانية = k × الأولى»، فالأولى = الثانية ÷ k = 60 ÷ 2,5 = 24 ✓. الخطأُ الشائع: الضربُ بدل القسمة (60 × 2,5 = 150)، أو جمعُ المعامل (60 + 2,5 = 62,5)، أو طرحُه (60 − 2,5 = 57,5).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('47e7b880-4a66-5345-abd9-3293a355a229', '1d21b8df-e861-538d-a71a-2137f9397422', 'math-8eme', '📝 تدريب ⭐⭐⭐: مراجعةٌ شاملة (نسبةٌ، تناسبٌ، سرعةٌ، سلّم)', 3, 120, 30, 'boss', 'admin', 5)
