  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('338585b9-3b3c-5969-ba05-ad8100439c3c', '47e7b880-4a66-5345-abd9-3293a355a229', 'ما 20 % من 300؟', '[{"id":"a","text":"60"},{"id":"b","text":"280"},{"id":"c","text":"15"},{"id":"d","text":"6000"}]'::jsonb, 'a', '20 % من 300 = (20 × 300) ÷ 100 = 6000 ÷ 100 = 60 ✓. الخطأُ الشائع: طرحُ 20 من 300 (280)، أو نسيانُ القسمة على 100 (6000).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b2f6f28-a623-5d3f-9335-a118ab338929', '47e7b880-4a66-5345-abd9-3293a355a229', 'جدولُ تناسب: 9 يقابله 6، و15 يقابله x. ما x؟', '[{"id":"a","text":"22,5"},{"id":"b","text":"18"},{"id":"c","text":"10"},{"id":"d","text":"12"}]'::jsonb, 'c', 'بالجداء التبادليّ: x = (15 × 6) ÷ 9 = 90 ÷ 9 = 10 ✓. الخطأُ الشائع: عكسُ الجداء ((15 × 9) ÷ 6 = 22,5)، أو القسمةُ على الحدّ الخطأ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6b28b9c-3559-5874-b14f-ad39ed75cdc1', '47e7b880-4a66-5345-abd9-3293a355a229', 'ساعةٌ ثمنُها 250 دينارًا، خُفّضت بنسبة 12 %. ما الثمنُ الجديد؟', '[{"id":"a","text":"238"},{"id":"b","text":"220"},{"id":"c","text":"280"},{"id":"d","text":"30"}]'::jsonb, 'b', 'التخفيضُ بـ 12 % = ضربٌ في (1 − 12/100) = 0,88، فالثمنُ الجديد = 250 × 0,88 = 220 دينارًا ✓. الخطأُ الشائع: طرحُ 12 مباشرةً (238)، أو الزيادةُ بدل التخفيض (250 × 1,12 = 280)، أو حسابُ مقدار التخفيض وحده (250 × 0,12 = 30).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd0d00b9-ec7f-5ac5-a47a-38d3e1c57bca', '47e7b880-4a66-5345-abd9-3293a355a229', 'سار عدّاءٌ بسرعةٍ متوسّطة 12 كم/سا لمدّة نصف ساعة. ما المسافةُ التي قطعها؟', '[{"id":"a","text":"24 كم"},{"id":"b","text":"12,5 كم"},{"id":"c","text":"0,5 كم"},{"id":"d","text":"6 كم"}]'::jsonb, 'd', 'المسافة = السرعة × الزمن؛ نصفُ ساعة = 0,5 سا، فالمسافة = 12 × 0,5 = 6 كم ✓. الخطأُ الشائع: القسمةُ بدل الضرب (12 ÷ 0,5 = 24)، أو جمعُ الزمن (12 + 0,5 = 12,5)، أو نقلُ الزمن كمسافة (0,5).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aaf65f49-3987-5c29-8f74-f5abc87a22fa', '47e7b880-4a66-5345-abd9-3293a355a229', 'كان راتبُ عاملٍ 900 دينار فأصبح 1080 دينارًا. ما نسبةُ الزيادة؟', '[{"id":"a","text":"20 %"},{"id":"b","text":"16,7 %"},{"id":"c","text":"180 %"},{"id":"d","text":"18 %"}]'::jsonb, 'a', 'نسبةُ التغيّر = (1080 − 900) ÷ 900 × 100 = 180 ÷ 900 × 100 = 20 % ✓. الخطأُ الشائع: القسمةُ على القيمة الجديدة (180 ÷ 1080 × 100 ≈ 16,7 %)، أو الاكتفاءُ بمقدار الفرق (180)، أو خطأٌ في القسمة (18 %).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f39f7f88-8875-50c3-80d2-144bd7acac16', '47e7b880-4a66-5345-abd9-3293a355a229', 'على خريطةٍ سلّمُها 1/25000، طريقٌ طولُه على الخريطة 8 سم. ما طولُه الحقيقيّ بالكيلومتر؟', '[{"id":"a","text":"20 كم"},{"id":"b","text":"0,2 كم"},{"id":"c","text":"2 كم"},{"id":"d","text":"200 كم"}]'::jsonb, 'c', 'الطولُ الحقيقيّ = 8 × 25000 = 200000 سم = 2000 م = 2 كم ✓. الخطأُ الشائع: خطأٌ في تحويل السنتيمتر إلى كيلومتر (÷ 100000)، فينتج 20 كم أو 200 كم أو 0,2 كم بدل 2 كم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8825a2b1-6c6a-517d-ac9e-56c2388e7bba', '1d21b8df-e861-538d-a71a-2137f9397422', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: التناسبُ المركّب والسرعةُ المتوسّطة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
