INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e4f539c-71ec-5ca9-8e51-65fe81b7703e', '8825a2b1-6c6a-517d-ac9e-56c2388e7bba', 'بعد زيادةٍ 25 % أصبح راتبٌ 750 دينارًا. ما الراتبُ الأصليّ؟', '[{"id":"a","text":"562,5"},{"id":"b","text":"600"},{"id":"c","text":"937,5"},{"id":"d","text":"725"}]'::jsonb, 'b', 'الزيادةُ بـ 25 % ضربٌ في 1,25، وللعودة إلى الأصليّ نقسم: 750 ÷ 1,25 = 600 دينارًا (نتحقّق: 600 × 1,25 = 750) ✓. الخطأُ الشائع: تخفيضُ 25 % من 750 (750 × 0,75 = 562,5)، أو زيادةٌ أخرى (750 × 1,25 = 937,5)، أو طرحُ 25 (725).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e3c3dadc-46e4-5ddc-babd-7a3f4eb3a460', '8825a2b1-6c6a-517d-ac9e-56c2388e7bba', 'تحتاج وصفةٌ لِ 4 أشخاصٍ إلى 6 بيضات. كم بيضةً تلزمُ لِ 10 أشخاص بنفس النسبة؟', '[{"id":"a","text":"12"},{"id":"b","text":"2,4"},{"id":"c","text":"60"},{"id":"d","text":"15"}]'::jsonb, 'd', 'بالجداء التبادليّ: العدد = (10 × 6) ÷ 4 = 60 ÷ 4 = 15 بيضة ✓. الخطأُ الشائع: عكسُ الجداء ((4 × 6) ÷ 10 = 2,4)، أو نسيانُ القسمة على 4 (10 × 6 = 60)، أو جمعٌ خاطئ (6 + 6 = 12).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('15cf21db-4cf5-566c-8b79-0e7bc09f279f', '8825a2b1-6c6a-517d-ac9e-56c2388e7bba', 'في مدرسةٍ 400 تلميذ؛ 60 % منهم يمارسون رياضةً، ونصفُ هؤلاء يلعبون كرةَ القدم. كم تلميذًا يلعب كرةَ القدم؟', '[{"id":"a","text":"200"},{"id":"b","text":"60"},{"id":"c","text":"120"},{"id":"d","text":"240"}]'::jsonb, 'c', 'عددُ الممارسين للرياضة = 60 % من 400 = (60 × 400) ÷ 100 = 240، ثمّ نصفُهم = 240 ÷ 2 = 120 تلميذًا ✓. الخطأُ الشائع: التوقّفُ عند عدد الممارسين (240)، أو حسابُ نصف العدد الكلّي (200)، أو الخلطُ في النسبة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd16aced-e02a-52d6-b1fc-709c11c3e671', '8825a2b1-6c6a-517d-ac9e-56c2388e7bba', 'قال تلميذ: «ثوبٌ بعد تخفيض 10 % صار 90 دينارًا، إذن الأصليّ = 90 + 10 % من 90 = 99 دينارًا». هل حسابُه صحيح؟', '[{"id":"a","text":"خطأ؛ الأصليّ = 90 ÷ 0,9 = 100 دينار"},{"id":"b","text":"صحيح، الأصليّ 99 دينارًا"},{"id":"c","text":"خطأ؛ الأصليّ = 90 − 10 % = 81 دينارًا"},{"id":"d","text":"خطأ؛ الأصليّ = 90 × 1,1 = 99 دينارًا"}]'::jsonb, 'a', 'التخفيضُ 10 % حُسب على السعر الأصليّ لا على 90، فلا نستعيده بزيادة 10 % على 90. نقسم على معامل الضرب: 90 ÷ 0,9 = 100 دينار (نتحقّق: 100 × 0,9 = 90) ✓. الخيار d يعطي 99 لأنّه يزيد 10 % على 90، وهو نفسُ فخّ التلميذ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dfa94b20-e353-5b44-80e2-fec761f38450', '8825a2b1-6c6a-517d-ac9e-56c2388e7bba', 'قطعت سيّارةٌ 40 كم في ساعةٍ، ثمّ 90 كم في ساعةٍ ونصف. ما سرعتُها المتوسّطة على كامل الرحلة؟', '[{"id":"a","text":"50 كم/سا"},{"id":"b","text":"52 كم/سا"},{"id":"c","text":"65 كم/سا"},{"id":"d","text":"130 كم/سا"}]'::jsonb, 'b', 'السرعةُ المتوسّطة = المسافةُ الكلّية ÷ الزمنُ الكلّي = (40 + 90) ÷ (1 + 1,5) = 130 ÷ 2,5 = 52 كم/سا ✓. الفخّ: أخذُ المعدّل الحسابيّ لسرعتَي المرحلتَين ((40 + 60) ÷ 2 = 50) خطأٌ لأنّ زمنَي المرحلتَين مختلفان. الخطأُ الآخر: القسمةُ على 2 بدل 2,5 (65)، أو نقلُ المسافة الكلّية كسرعة (130).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7acad45b-a001-5c07-b069-e1313667b330', '8825a2b1-6c6a-517d-ac9e-56c2388e7bba', 'على خريطةٍ سلّمُها 1/200000، المسافةُ بين مدينتَين 6 سم. تسير سيّارةٌ بسرعة 80 كم/سا. كم من الوقت تستغرق الرحلةُ بينهما؟', '[{"id":"a","text":"15 دقيقة"},{"id":"b","text":"0,15 دقيقة"},{"id":"c","text":"12 دقيقة"},{"id":"d","text":"9 دقائق"}]'::jsonb, 'd', 'المسافةُ الحقيقيّة = 6 × 200000 = 1200000 سم = 12000 م = 12 كم. الزمن = المسافة ÷ السرعة = 12 ÷ 80 = 0,15 سا = 0,15 × 60 = 9 دقائق ✓. الخطأُ الشائع: نسيانُ تحويل الساعة إلى دقائق، أو خطأٌ في تحويل وحدات الطول (فينتج 15 أو 12 دقيقة).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

