  ('4db62683-9b85-5168-bc71-b43764bde4b2', 'e39038b4-4633-5971-a4f9-51c9b38a7d92', 'math-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
