INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('127af05d-9c32-5dfa-a67d-7dc7a719c334', '4db62683-9b85-5168-bc71-b43764bde4b2', 'كيف نحسب التواترَ النسبيّ لقيمةٍ في سلسلةٍ إحصائيّة؟', '[{"id":"a","text":"عددُ المرّات التي تظهر فيها القيمة (تعدادُها)"},{"id":"b","text":"تعدادُ القيمة مقسومًا على التعداد الكليّ"},{"id":"c","text":"تعدادُ القيمة مضروبًا في التعداد الكليّ"},{"id":"d","text":"مجموعُ تعدادات كلّ القيم"}]'::jsonb, 'b', 'التواترُ النسبيّ حصّةُ القيمة من المجموع: تعدادُها ÷ التعداد الكليّ ✓. الخيار (أ) هو التعدادُ نفسُه لا التواتر، و(د) هو التعدادُ الكليّ. الفخّ: الخلطُ بين التعداد (عددٌ صحيح) والتواتر النسبيّ (حصّةٌ تُقسَم).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dde54e81-78b7-55ac-bbf1-7c7c50cc9e9b', '4db62683-9b85-5168-bc71-b43764bde4b2', 'في قسمٍ من 25 تلميذًا، يحبّ 10 منهم كرةَ القدم. ما التواترُ النسبيّ لمحبّي كرة القدم بالنسبة المئوية؟', '[{"id":"a","text":"40%"},{"id":"b","text":"10%"},{"id":"c","text":"25%"},{"id":"d","text":"250%"}]'::jsonb, 'a', 'التواتر النسبي = 10 ÷ 25 = 0.4 = 40% ✓. الخطأُ الشائع: أخذُ التعداد 10 كنسبة (10%)، أو التعداد الكليّ 25 (25%)، أو القسمةُ المقلوبة 25 ÷ 10 = 2.5 = 250%.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8fb946b-65a2-5a3c-a6dc-01b133a52d59', '4db62683-9b85-5168-bc71-b43764bde4b2', 'في جدولٍ إحصائيّ، مجموعُ التواترات النسبيّة لكلّ القيم يساوي دائمًا:', '[{"id":"a","text":"360°"},{"id":"b","text":"التعدادَ الكليّ"},{"id":"c","text":"100% (أي 1)"},{"id":"d","text":"قيمةً تختلف حسب البيانات"}]'::jsonb, 'c', 'كلُّ التعدادات مقسومةً على التعداد الكليّ تُعطي في مجموعها التعدادَ الكليّ ÷ نفسِه = 1 = 100% ✓. أمّا مجموعُ التعدادات فيساوي التعدادَ الكليّ (خيار ب)، و360° مجموعُ زوايا القطاعات لا التواترات.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
