INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9f316d06-2c88-5597-93b8-4806e21f0cee', '4db62683-9b85-5168-bc71-b43764bde4b2', 'قيمةٌ تواترُها النسبيّ 25%. ما قياسُ زاويةِ قطاعها في التمثيل الدائريّ؟', '[{"id":"a","text":"25°"},{"id":"b","text":"45°"},{"id":"c","text":"360°"},{"id":"d","text":"90°"}]'::jsonb, 'd', 'زاوية القطاع = التواتر النسبي × 360 = 0.25 × 360 = 90° ✓. الخطأُ الشائع: كتابةُ الزاوية مساويةً للنسبة مباشرةً (25°) بنسيان الضرب في 360.', 4)
