INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('765a60fa-53b3-5152-9245-d31e86958d7d', '4db62683-9b85-5168-bc71-b43764bde4b2', 'ما المعدّلُ الحسابيّ للعلامات التالية: 12؛ 8؛ 10؛ 14؛ 16؟', '[{"id":"a","text":"12"},{"id":"b","text":"60"},{"id":"c","text":"10"},{"id":"d","text":"16"}]'::jsonb, 'a', 'المعدّل = مجموع القيم ÷ عددها = (12+8+10+14+16) ÷ 5 = 60 ÷ 5 = 12 ✓. الخطأُ الشائع: نسيانُ القسمة على العدد والاكتفاءُ بالمجموع 60، أو القسمةُ على عددٍ خاطئ.', 5)
