INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0497cc1f-61e8-597a-973e-e2e687aa0eee', '1a35b13e-27c5-50cd-8b90-fa60f86466b7', 'سلسلةٌ إحصائيّة تعداداتُها: 5؛ 8؛ 4؛ 3. ما التعدادُ الكليّ؟', '[{"id":"a","text":"20"},{"id":"b","text":"8"},{"id":"c","text":"16"},{"id":"d","text":"4"}]'::jsonb, 'a', 'التعدادُ الكليّ هو مجموعُ كلّ التعدادات: 5 + 8 + 4 + 3 = 20 ✓. الخطأُ الشائع: أخذُ أكبر تعدادٍ (8) أو عددِ القيم (4) بدل جمعها كلِّها.', 1)
