INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a87d0ce-ebec-5e97-b35c-cdb66d324e1f', '1a35b13e-27c5-50cd-8b90-fa60f86466b7', 'من بين 20 تلميذًا، اختار 5 مادّةَ الرسم. ما التواترُ النسبيّ لمحبّي الرسم؟', '[{"id":"a","text":"5%"},{"id":"b","text":"25%"},{"id":"c","text":"20%"},{"id":"d","text":"4%"}]'::jsonb, 'b', 'التواتر النسبي = 5 ÷ 20 = 0.25 = 25% ✓. الخطأُ الشائع: أخذُ التعداد 5 كنسبة (5%)، أو التعداد الكليّ 20 (20%)، أو القسمةُ المقلوبة 20 ÷ 5 كنسبةٍ خاطئة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('06ba240c-9012-50c3-b06e-5b3324226af5', '1a35b13e-27c5-50cd-8b90-fa60f86466b7', 'في استطلاعٍ عن نوع الفطور، أجاب 12 شخصًا بـ«قهوة». ماذا يمثّل العددُ 12؟', '[{"id":"a","text":"التواترَ النسبيّ لجواب «قهوة»"},{"id":"b","text":"المعدّلَ الحسابيّ"},{"id":"c","text":"تعدادَ جواب «قهوة» (عددَ من اختاروه)"},{"id":"d","text":"التعدادَ الكليّ للاستطلاع"}]'::jsonb, 'c', 'العددُ 12 هو تعدادُ القيمة «قهوة»: عددُ الأشخاص الذين أجابوا بها ✓. أمّا التواترُ النسبيّ فحصّةٌ مئويّة، والتعدادُ الكليّ مجموعُ كلّ الإجابات لا إجابةً واحدة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47ac7cf2-f9d6-577e-a0b7-33b1e1fbfb44', '1a35b13e-27c5-50cd-8b90-fa60f86466b7', 'ما المعدّلُ الحسابيّ للأعداد: 6؛ 10؛ 8؟', '[{"id":"a","text":"24"},{"id":"b","text":"9"},{"id":"c","text":"6"},{"id":"d","text":"8"}]'::jsonb, 'd', 'المعدّل = مجموع القيم ÷ عددها = (6 + 10 + 8) ÷ 3 = 24 ÷ 3 = 8 ✓. الخطأُ الشائع: نسيانُ القسمة والاكتفاءُ بالمجموع 24، أو القسمةُ على عددٍ خاطئ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
