INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce741c7c-de61-5faf-a393-1d4f3a88f9df', '1a35b13e-27c5-50cd-8b90-fa60f86466b7', 'في قسمٍ من 30 تلميذًا، تواترُ محبّي القراءة النسبيّ 20%. كم عددُهم؟', '[{"id":"a","text":"6"},{"id":"b","text":"20"},{"id":"c","text":"10"},{"id":"d","text":"15"}]'::jsonb, 'a', 'تعدادُ القيمة = التواتر النسبيّ × التعداد الكليّ = 0.20 × 30 = 6 ✓. الخطأُ الشائع: أخذُ النسبة 20 كعددٍ مباشرةً، أو قسمةُ 30 على 2.', 5)
ON CONFLICT (id) DO UPDATE SET
