  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59617934-1848-5ede-9413-84e0a2ab1b26', '1a35b13e-27c5-50cd-8b90-fa60f86466b7', 'سلسلةٌ من 40 عنصرًا بأربع قيم، تعداداتُ ثلاثٍ منها: 12؛ 15؛ 8، والرابعة س. ما قيمةُ س؟', '[{"id":"a","text":"13"},{"id":"b","text":"5"},{"id":"c","text":"35"},{"id":"d","text":"8"}]'::jsonb, 'b', 'مجموعُ التعدادات = التعداد الكليّ: 12 + 15 + 8 + س = 40، أي 35 + س = 40، فـ س = 40 − 35 = 5 ✓. الخطأُ الشائع: نسيانُ الطرح واعتبارُ المجموع الجزئيّ 35 هو الجواب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

