INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c3d0d6d1-c781-5536-82b1-14df5a01a2ad', '5bf1faa9-f11e-5c30-9bd6-c6289f648f79', 'قيمةٌ تواترُها النسبيّ 50%. ما قياسُ زاويةِ قطاعها في التمثيل الدائريّ؟', '[{"id":"a","text":"180°"},{"id":"b","text":"50°"},{"id":"c","text":"90°"},{"id":"d","text":"360°"}]'::jsonb, 'a', 'زاوية القطاع = التواتر النسبيّ × 360 = 0.5 × 360 = 180° ✓. النصفُ من الدائرة الكاملة (360°) هو 180°. الخطأُ الشائع: كتابةُ 50° مباشرةً بنسيان الضرب في 360.', 1)
