INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6bf4363e-8a57-5f72-9879-145619dc1cee', '5bf1faa9-f11e-5c30-9bd6-c6289f648f79', 'في سلسلةٍ تعدادُها الكليّ 50، تعدادُ إحدى القيم 20. ما تواترُها النسبيّ؟', '[{"id":"a","text":"20%"},{"id":"b","text":"40%"},{"id":"c","text":"25%"},{"id":"d","text":"30%"}]'::jsonb, 'b', 'التواتر النسبيّ = 20 ÷ 50 = 0.4 = 40% ✓. الخطأُ الشائع: أخذُ التعداد 20 كنسبة (20%)، أو حسابُ 50 ÷ 20 = 2.5 بدل القسمة الصحيحة.', 2)
