INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5be4594b-bf63-5e8d-afaa-78a8bf6a7a7e', '5bf1faa9-f11e-5c30-9bd6-c6289f648f79', 'في سلسلةٍ تعدادُها الكليّ 40، قيمةٌ تعدادُها 10. ما قياسُ زاويةِ قطاعها الدائريّ؟', '[{"id":"a","text":"10°"},{"id":"b","text":"36°"},{"id":"c","text":"90°"},{"id":"d","text":"100°"}]'::jsonb, 'c', 'الزاوية = (تعداد القيمة ÷ التعداد الكليّ) × 360 = (10 ÷ 40) × 360 = 0.25 × 360 = 90° ✓. الخطأُ الشائع: أخذُ التعداد 10 كأنّه نسبةٌ مئويّة فتُحسب 10% × 360 = 36°، أو كتابةُ 10° مباشرةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68a06906-1d15-51d4-9b94-e63c86a81067', '5bf1faa9-f11e-5c30-9bd6-c6289f648f79', 'علاماتٌ في اختبار: العلامة 10 عند تلميذين، والعلامة 15 عند 3 تلاميذ. ما المعدّلُ الحسابيّ؟', '[{"id":"a","text":"12.5"},{"id":"b","text":"13"},{"id":"c","text":"25"},{"id":"d","text":"11"}]'::jsonb, 'b', 'المعدّل المرجّح = (10×2 + 15×3) ÷ (2+3) = (20 + 45) ÷ 5 = 65 ÷ 5 = 13 ✓. الخطأُ الشائع: القسمةُ على عدد القيم المختلفة (10+15)÷2 = 12.5 بنسيان الترجيح بالتعدادات، أو جمعُ القيمتين فقط (25).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d71ca19-4a90-5837-b851-3ca78683cc27', '5bf1faa9-f11e-5c30-9bd6-c6289f648f79', 'في جدولٍ إحصائيّ، التواترات النسبيّة لثلاث قيم هي: 30%؛ 25%؛ 20%، وهناك قيمةٌ رابعة مجهولةٌ تواترُها. ما تواترُها النسبيّ؟', '[{"id":"a","text":"75%"},{"id":"b","text":"20%"},{"id":"c","text":"25%"},{"id":"d","text":"100%"}]'::jsonb, 'c', 'مجموعُ التواترات النسبيّة يساوي دائمًا 100%: 30 + 25 + 20 + س = 100، أي 75 + س = 100، فـ س = 25% ✓. الخطأُ الشائع: اعتبارُ المجموع الجزئيّ 75% هو الجواب، أو نسيانُ خاصّية الـ100%.', 5)
