INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0050247f-6af4-5966-9d7f-3d50b79ba9f9', '126a97fb-e69b-5ac4-ab28-f424b3b17ac6', 'في سلسلةٍ تعدادُها الكليّ 60، قيمةٌ تعدادُها 9. ما قياسُ زاويةِ قطاعها الدائريّ؟', '[{"id":"a","text":"9°"},{"id":"b","text":"60°"},{"id":"c","text":"54°"},{"id":"d","text":"15°"}]'::jsonb, 'c', 'الزاوية = (9 ÷ 60) × 360 = 0.15 × 360 = 54° ✓. الخطأُ الشائع: كتابةُ 9° مباشرةً، أو التوقّفُ عند التواتر 15% (9÷60) دون ضربه في 360.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61652647-f552-52b4-9fc5-da8a12654ccd', '126a97fb-e69b-5ac4-ab28-f424b3b17ac6', 'في مدرسةٍ من 400 تلميذ، تواترُ الناجحين النسبيّ 90%. كم عددُ الناجحين؟', '[{"id":"a","text":"360 تلميذًا"},{"id":"b","text":"90 تلميذًا"},{"id":"c","text":"40 تلميذًا"},{"id":"d","text":"التعدادُ الكليّ 90"}]'::jsonb, 'a', 'عددُ الناجحين = 0.90 × 400 = 360 تلميذًا ✓. الخطأُ الشائع: أخذُ النسبة 90 كعددٍ من الناجحين، أو حسابُ عدد الراسبين (10% × 400 = 40) بدل الناجحين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

