  ('e4659fcb-3ea7-5abb-81dd-adda3a51733d', 'e39038b4-4633-5971-a4f9-51c9b38a7d92', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: عمقُ الإحصاء والمعدّل', 4, 300, 60, 'challenge', 'admin', 4)
