INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1705c2ae-70fd-51f2-acae-129e52b57904', 'e4659fcb-3ea7-5abb-81dd-adda3a51733d', 'في تمثيلٍ دائريّ، قطاعُ إحدى القيم زاويتُه 72°. ما التواترُ النسبيّ لهذه القيمة؟', '[{"id":"a","text":"72%"},{"id":"b","text":"20%"},{"id":"c","text":"10%"},{"id":"d","text":"36%"}]'::jsonb, 'b', 'التواتر النسبيّ = الزاوية ÷ 360 = 72 ÷ 360 = 0.2 = 20% ✓ (العمليّةُ العكسيّة للضرب في 360). الخطأُ الشائع: أخذُ الزاوية 72 كنسبةٍ مباشرةً (72%).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('15af682b-4bd9-57e6-bcfb-0a1e02326740', 'e4659fcb-3ea7-5abb-81dd-adda3a51733d', 'أعمارُ فريق: 15 سنة (لاعبان)، 16 سنة (3 لاعبين)، 18 سنة (لاعبٌ واحد). ما معدّلُ العمر؟', '[{"id":"a","text":"16.5"},{"id":"b","text":"16.33"},{"id":"c","text":"16"},{"id":"d","text":"96"}]'::jsonb, 'c', 'المعدّل المرجّح = (15×2 + 16×3 + 18×1) ÷ (2+3+1) = (30 + 48 + 18) ÷ 6 = 96 ÷ 6 = 16 ✓. الخطأُ الشائع: القسمةُ على عدد القيم المختلفة (15+16+18)÷3 ≈ 16.33 بنسيان الترجيح بالتعدادات.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8519a67-65fa-5a8f-bf49-4e8e6771153e', 'e4659fcb-3ea7-5abb-81dd-adda3a51733d', 'سلسلةٌ من 50 عنصرًا بأربع قيم، تعداداتُ ثلاثٍ منها: 12؛ 18؛ 11. ما التواترُ النسبيّ للقيمة الرابعة؟', '[{"id":"a","text":"9%"},{"id":"b","text":"22%"},{"id":"c","text":"41%"},{"id":"d","text":"18%"}]'::jsonb, 'd', 'أوّلًا نجد تعداد الرابعة: 50 − (12+18+11) = 50 − 41 = 9. ثمّ تواترُها = 9 ÷ 50 = 0.18 = 18% ✓. الخطأُ الشائع: التوقّفُ عند التعداد 9 وكتابتُه كنسبة (9%)، أو نسيانُ الطرح من التعداد الكليّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('baa2e2f0-d62d-596d-b31f-01ebc303a42a', 'e4659fcb-3ea7-5abb-81dd-adda3a51733d', 'معدّلُ ثلاث علاماتٍ يساوي 12. علامتان منها 10 و11. ما العلامةُ الثالثة؟', '[{"id":"a","text":"15"},{"id":"b","text":"13"},{"id":"c","text":"12"},{"id":"d","text":"14"}]'::jsonb, 'a', 'المعدّل 12 لثلاث علاماتٍ يعني أنّ مجموعها = 12 × 3 = 36. العلامةُ الثالثة = 36 − (10 + 11) = 36 − 21 = 15 ✓. الخطأُ الشائع: نسيانُ ضرب المعدّل في العدد لإيجاد المجموع، أو أخذُ المعدّل 12 كجواب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cecdb6b-b5cb-5ec9-86b0-319a9514e4e3', 'e4659fcb-3ea7-5abb-81dd-adda3a51733d', 'لحساب معدّل العلامات: 8 (عند 3 تلاميذ) و16 (عند تلميذٍ واحد)، كتب تلميذٌ: المعدّل = (8 + 16) ÷ 2 = 12. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، المعدّل 12 صحيح"},{"id":"b","text":"نسي ترجيح كلّ علامةٍ بتعدادها؛ الصحيح (8×3 + 16×1) ÷ 4 = 10"},{"id":"c","text":"كان عليه القسمة على 3 لا على 2"},{"id":"d","text":"المعدّل هو مجموع العلامتين 24"}]'::jsonb, 'b', 'المعدّل المرجّح يضرب كلّ علامةٍ في تعدادها ويقسم على التعداد الكليّ: (8×3 + 16×1) ÷ (3+1) = (24 + 16) ÷ 4 = 40 ÷ 4 = 10 ✓. التلميذُ عامل العلامتين بوزنٍ متساوٍ فأخطأ. (سؤالُ اكتشاف خطأ: الخيارُ الصحيح يصف الخطأ ويعطي القيمة السليمة.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b0736243-caca-50d3-ac20-e961f3c411ff', 'e4659fcb-3ea7-5abb-81dd-adda3a51733d', 'في استطلاعٍ شمل 120 شخصًا، خُصّص للقطاع «راضٍ» في التمثيل الدائريّ زاويةٌ قياسُها 210°. كم عددُ الراضين؟', '[{"id":"a","text":"210"},{"id":"b","text":"58"},{"id":"c","text":"70"},{"id":"d","text":"60"}]'::jsonb, 'c', 'التواتر النسبيّ = 210 ÷ 360 (وهو 7/12)، والعدد = التواتر × التعداد الكليّ = (210 ÷ 360) × 120 = (7/12) × 120 = 70 ✓. الخطأُ الشائع: أخذُ الزاوية 210 كعددٍ مباشرةً، أو الخلطُ بين النصف (60) والقيمة الحقيقية.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

