INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03f7b413-40f4-5f6f-8561-60f7d80f04e9', 'f8b21c7d-f774-5a06-a3b4-489daf88664a', 'من بين 20 كتابًا في رفٍّ، 8 روايات. ما التواترُ النسبيّ للروايات؟', '[{"id":"a","text":"8%"},{"id":"b","text":"40%"},{"id":"c","text":"20%"},{"id":"d","text":"12%"}]'::jsonb, 'b', 'التواتر النسبيّ = 8 ÷ 20 = 0.4 = 40% ✓. الخطأُ الشائع: أخذُ التعداد 8 كنسبة (8%)، أو التعداد الكليّ 20 (20%)، أو حسابُ عدد غير الروايات (12) بدل الروايات.', 1)
