INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2bae698-04ea-52fd-b6fd-c06763a209f9', 'f8b21c7d-f774-5a06-a3b4-489daf88664a', 'قيمةٌ تواترُها النسبيّ 30%. ما قياسُ زاويةِ قطاعها في التمثيل الدائريّ؟', '[{"id":"a","text":"30°"},{"id":"b","text":"36°"},{"id":"c","text":"108°"},{"id":"d","text":"120°"}]'::jsonb, 'c', 'الزاوية = 0.3 × 360 = 108° ✓. الخطأُ الشائع: كتابةُ 30° مباشرةً بنسيان الضرب في 360، أو الخلطُ مع قيمةٍ ربعِ الدائرة (90°) أو ثلثِها (120°).', 2)
