INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3604af69-b459-56b8-ba3a-ae37221d3dc3', 'f8b21c7d-f774-5a06-a3b4-489daf88664a', 'عددُ الأهداف في 5 مباريات: 0؛ 2؛ 1؛ 3؛ 4. ما معدّلُ عدد الأهداف في المباراة؟', '[{"id":"a","text":"2"},{"id":"b","text":"10"},{"id":"c","text":"2.5"},{"id":"d","text":"1.5"}]'::jsonb, 'a', 'المعدّل = (0 + 2 + 1 + 3 + 4) ÷ 5 = 10 ÷ 5 = 2 ✓. الخطأُ الشائع: الاكتفاءُ بالمجموع 10 بلا قسمة، أو القسمةُ على 4 (بإسقاط المباراة صاحبة الصفر) فيصبح 2.5.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
