INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0ef07935-2d7c-5cba-a302-0646a6101561', 'f8b21c7d-f774-5a06-a3b4-489daf88664a', 'من بين 300 ناخب، شارك 60% في التصويت. كم عددُ المصوّتين؟', '[{"id":"a","text":"60"},{"id":"b","text":"1800"},{"id":"c","text":"240"},{"id":"d","text":"180"}]'::jsonb, 'd', 'العدد = 0.60 × 300 = 180 ✓. الخطأُ الشائع: أخذُ النسبة 60 كعدد، أو الضربُ في 300 دون قسمة النسبة على 100 (1800)، أو حسابُ الممتنعين 40% × 300 = 120.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd0a86b7-76bf-5805-b6d4-b8f6922f0d68', 'f8b21c7d-f774-5a06-a3b4-489daf88664a', 'في جدولٍ إحصائيّ، التواترات النسبيّة لثلاث قيم: 45%؛ 30%؛ 15%. ما التواترُ النسبيّ للقيمة الرابعة والأخيرة؟', '[{"id":"a","text":"10%"},{"id":"b","text":"90%"},{"id":"c","text":"15%"},{"id":"d","text":"0%"}]'::jsonb, 'a', 'مجموعُ التواترات = 100%: 45 + 30 + 15 + س = 100، أي 90 + س = 100، فـ س = 10% ✓. الخطأُ الشائع: اعتبارُ المجموع الجزئيّ 90% هو الجواب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f5c8a31-a63f-57ab-86ab-759dbeca9cae', 'f8b21c7d-f774-5a06-a3b4-489daf88664a', 'في جدول: القيمة 5 تعدادُها 4، والقيمة 10 تعدادُها 6. ما المعدّلُ الحسابيّ؟', '[{"id":"a","text":"7.5"},{"id":"b","text":"8"},{"id":"c","text":"15"},{"id":"d","text":"80"}]'::jsonb, 'b', 'المعدّل المرجّح = (5×4 + 10×6) ÷ (4+6) = (20 + 60) ÷ 10 = 80 ÷ 10 = 8 ✓. الخطأُ الشائع: القسمةُ على عدد القيم (5+10)÷2 = 7.5 بنسيان الترجيح، أو نسيانُ القسمة على التعداد الكليّ (80).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

