INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9cee13e0-b5d5-52a6-bb65-67e8fc180984', '02953175-6b30-572c-b224-4439f8fd39d5', 'قطاعٌ في تمثيلٍ دائريّ زاويتُه 45°. ما التواترُ النسبيّ للقيمة التي يمثّلها؟', '[{"id":"a","text":"45%"},{"id":"b","text":"12.5%"},{"id":"c","text":"8%"},{"id":"d","text":"25%"}]'::jsonb, 'b', 'التواتر النسبيّ = 45 ÷ 360 = 0.125 = 12.5% ✓. الخطأُ الشائع: أخذُ الزاوية 45 كنسبةٍ مباشرةً (45%)، أو حسابُ 360 ÷ 45 = 8 كنسبةٍ مقلوبة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
