INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('547b805d-de8e-5787-90da-ff60c40d9fed', '02953175-6b30-572c-b224-4439f8fd39d5', 'درجاتٌ في اختبار: الدرجة 6 (عند تلميذٍ واحد)، الدرجة 12 (عند 4 تلاميذ)، الدرجة 15 (عند 5 تلاميذ). ما المعدّلُ الحسابيّ؟', '[{"id":"a","text":"11"},{"id":"b","text":"12"},{"id":"c","text":"12.9"},{"id":"d","text":"33"}]'::jsonb, 'c', 'المعدّل المرجّح = (6×1 + 12×4 + 15×5) ÷ (1+4+5) = (6 + 48 + 75) ÷ 10 = 129 ÷ 10 = 12.9 ✓. الخطأُ الشائع: القسمةُ على عدد القيم (6+12+15)÷3 = 11 بنسيان الترجيح، أو جمعُ القيم فقط (33).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cfbefcd6-31e5-52cf-8333-86b338bfb217', '02953175-6b30-572c-b224-4439f8fd39d5', 'قيمةٌ تعدادُها 24 وتواترُها النسبيّ 30%. ما التعدادُ الكليّ للسلسلة؟', '[{"id":"a","text":"80"},{"id":"b","text":"72"},{"id":"c","text":"7.2"},{"id":"d","text":"800"}]'::jsonb, 'a', 'بما أنّ التواتر = التعداد ÷ التعداد الكليّ، فالتعداد الكليّ = التعداد ÷ التواتر = 24 ÷ 0.30 = 80 ✓. تحقّق: 24 ÷ 80 = 0.30 = 30% ✓. الخطأُ الشائع: ضربُ 24 × 0.30 = 7.2 بدل القسمة، أو حسابُ 24 × 3 = 72.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46e9e98a-d56e-5db5-9d03-a17096abfdd5', '02953175-6b30-572c-b224-4439f8fd39d5', 'أربعُ علاماتٍ معدّلُها 13. ثلاثٌ منها: 10؛ 14؛ 15. ما العلامةُ الرابعة؟', '[{"id":"a","text":"12"},{"id":"b","text":"14"},{"id":"c","text":"11"},{"id":"d","text":"13"}]'::jsonb, 'd', 'مجموعُ العلامات الأربع = 13 × 4 = 52. العلامةُ الرابعة = 52 − (10 + 14 + 15) = 52 − 39 = 13 ✓. الخطأُ الشائع: نسيانُ ضرب المعدّل في العدد لإيجاد المجموع، أو الخطأُ في جمع الثلاث المعروفة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac15e3cd-61d6-5d38-a4b3-7a5f995d619a', '02953175-6b30-572c-b224-4439f8fd39d5', 'في سلسلةٍ تعدادُها الكليّ 80، قيمةٌ تواترُها النسبيّ 25%. ما قياسُ زاويةِ قطاعها وما تعدادُها؟', '[{"id":"a","text":"90° وتعدادُها 20"},{"id":"b","text":"25° وتعدادُها 25"},{"id":"c","text":"90° وتعدادُها 25"},{"id":"d","text":"25° وتعدادُها 20"}]'::jsonb, 'a', 'الزاوية = 0.25 × 360 = 90°، والتعداد = 0.25 × 80 = 20 ✓. الخطأُ الشائع: كتابةُ الزاوية 25° بنسيان الضرب في 360، أو الخلطُ بين النسبة 25% والتعداد الحقيقيّ 20.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47c9e261-b611-59c2-953e-a1dc1a96fd94', '02953175-6b30-572c-b224-4439f8fd39d5', 'قال تلميذٌ إنّ التواترات النسبيّة لقيمِ سلسلةٍ هي: 50%؛ 30%؛ 25%. هل هذا ممكنٌ إحصائيًّا؟', '[{"id":"a","text":"نعم، ممكنٌ دائمًا"},{"id":"b","text":"لا، لأنّ مجموعها 105% يتجاوز 100%"},{"id":"c","text":"لا، لأنّ التواترات يجب أن تكون متساوية"},{"id":"d","text":"نعم، إذا كان التعدادُ الكليّ كبيرًا"}]'::jsonb, 'b', 'مجموعُ التواترات النسبيّة يجب أن يساوي 100% بالضبط، لكن 50 + 30 + 25 = 105% > 100%، فهذا مستحيلٌ إحصائيًّا ✓. لا علاقة للأمر بتساوي التواترات أو بحجم التعداد الكليّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

