INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e66244d5-12d1-5e47-a244-c34f387a7cb5', 'b19b69c9-513f-5a9e-9fc3-6b1b80d4532d', 'متى تكون النقطة M′ مناظرةَ النقطة M بالنسبة إلى المركز O؟', '[{"id":"a","text":"عندما تكون O منتصفَ القطعة [MM′]"},{"id":"b","text":"عندما يكون المستقيم (OM) عموديًّا على (OM′)"},{"id":"c","text":"عندما تكون M منتصفَ القطعة [OM′]"},{"id":"d","text":"عندما تكون O على مسافةٍ من M ضِعفَ مسافتها من M′"}]'::jsonb, 'a', 'بالتعريف: مناظرُ M بالنسبة إلى المركز O هو M′ حيث تكون O منتصفَ [MM′]، أي OM = OM′ والنقاطُ M, O, M′ على استقامة واحدة ✓. الخطأُ الشائع: الخلطُ بينه وبين التناظر المحوري (تعامد) أو جعلُ نقطةٍ أخرى هي المنتصف.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c00a295-0157-536a-99d0-398e9961bf52', 'b19b69c9-513f-5a9e-9fc3-6b1b80d4532d', 'ما مناظرُ المركز O بالنسبة إلى المركز O نفسِه؟', '[{"id":"a","text":"لا وجود لمناظرٍ للمركز"},{"id":"b","text":"النقطة O نفسُها"},{"id":"c","text":"نقطةٌ تبعد عن O مسافةً ثابتة"},{"id":"d","text":"أيُّ نقطةٍ على المستقيم المارّ بـ O"}]'::jsonb, 'b', 'مناظرُ المركز بالنسبة إلى نفسِه هو المركزُ نفسُه: O منتصفُ [OO] محقّقٌ بداهةً، وهي النقطةُ الوحيدةُ الثابتة في التناظر المركزي ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6baf699c-732b-51cb-b2a6-f41cf1ea586f', 'b19b69c9-513f-5a9e-9fc3-6b1b80d4532d', 'ما مناظرُ مستقيمٍ (d) بالنسبة إلى مركزٍ O لا ينتمي إليه؟', '[{"id":"a","text":"المستقيمُ (d) نفسُه"},{"id":"b","text":"مستقيمٌ عموديٌّ على (d)"},{"id":"c","text":"مستقيمٌ يوازي (d)"},{"id":"d","text":"نقطةٌ واحدة"}]'::jsonb, 'c', 'مناظرُ مستقيمٍ لا يمرّ بالمركز هو مستقيمٌ يوازيه ✓. الخطأُ الشائع: الظنُّ أنّه المستقيمُ نفسُه (هذا يصحّ فقط إذا كان O ينتمي إلى (d))، أو الخلطُ مع التعامد.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a333d23-c9ec-5e5f-b0f9-98dcef1b3fdb', 'b19b69c9-513f-5a9e-9fc3-6b1b80d4532d', 'قطعةٌ [AB] طولُها 5 سم. ما طولُ مناظرتِها [A′B′] بالتناظر المركزي بالنسبة إلى نقطةٍ ما؟', '[{"id":"a","text":"10 سم"},{"id":"b","text":"2.5 سم"},{"id":"c","text":"5 سم"},{"id":"d","text":"لا يمكن تحديدُه دون معرفة المركز"}]'::jsonb, 'c', 'التناظرُ المركزيُّ يحفظ الأطوال: A′B′ = AB = 5 سم، مهما كان موضعُ المركز ✓. الخطأُ الشائع: ظنُّ أنّ الطول يتضاعف (10) أو ينتصف (2.5)؛ الطولُ لا يتغيّر بالتناظر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65aa6850-a52b-5b87-9608-1c3e69e29cae', 'b19b69c9-513f-5a9e-9fc3-6b1b80d4532d', 'أين يقع مركزُ تناظرِ متوازي الأضلاع ABCD؟', '[{"id":"a","text":"في أحد رؤوسه"},{"id":"b","text":"في نقطة تقاطع قطرَيه"},{"id":"c","text":"في منتصف أحد أضلاعه"},{"id":"d","text":"لا مركزَ تناظرَ لمتوازي الأضلاع"}]'::jsonb, 'b', 'مركزُ تناظر متوازي الأضلاع هو نقطةُ تقاطع قطرَيه (وهي منتصفُ كلٍّ من القطرَين) ✓. الخطأُ الشائع: اختيارُ رأسٍ أو منتصفِ ضلعٍ، أو الظنُّ أنّه لا مركزَ له بينما مركزُه موجودٌ ووحيد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

