INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20f0a8e5-ca12-525f-8502-9d39ede1d715', 'cee04ed9-6549-55ee-91b3-8a121f98ce58', 'إذا كانت M′ مناظرةَ M بالنسبة إلى المركز O، فأيُّ العلاقة صحيحة؟', '[{"id":"a","text":"M منتصفُ [OM′]"},{"id":"b","text":"O منتصفُ [MM′] وOM = OM′"},{"id":"c","text":"(OM) عموديٌّ على (OM′)"},{"id":"d","text":"M′ منتصفُ [OM]"}]'::jsonb, 'b', 'بالتعريف: O هي منتصفُ القطعة [MM′]، أي OM = OM′ والنقاطُ M, O, M′ على استقامة واحدة ✓. الخطأُ الشائع: جعلُ نقطةٍ أخرى غيرِ O هي المنتصف، أو الخلطُ مع التعامد (وهو ليس من شروط التناظر المركزي).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c158e10-7afb-5ecf-ab9a-5c11ace7c7bb', 'cee04ed9-6549-55ee-91b3-8a121f98ce58', 'التناظرُ المركزيُّ يكون بالنسبة إلى:', '[{"id":"a","text":"نقطةٍ (المركز)"},{"id":"b","text":"مستقيمٍ (المحور)"},{"id":"c","text":"دائرةٍ"},{"id":"d","text":"زاويةٍ"}]'::jsonb, 'a', 'المرجعُ في التناظر المركزي هو **نقطةٌ** تُسمّى المركز ✓. الخطأُ الأشهر: الخلطُ مع التناظر المحوري (السنة الماضية) الذي يكون بالنسبة إلى **مستقيمٍ** (محور).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('246c3649-d0d3-582d-8a4e-1a7525c1cfbe', 'cee04ed9-6549-55ee-91b3-8a121f98ce58', 'ما مناظرُ المركز O بالنسبة إلى O نفسِه؟', '[{"id":"a","text":"نقطةٌ تبعد عن O مسافةً ثابتة"},{"id":"b","text":"لا وجودَ لمناظرٍ للمركز"},{"id":"c","text":"النقطة O نفسُها"},{"id":"d","text":"أيُّ نقطةٍ في المستوى"}]'::jsonb, 'c', 'المركزُ هو النقطةُ الوحيدةُ الثابتة: مناظرُ O بالنسبة إلى O هو O نفسُه (O منتصفُ [OO]) ✓.', 3)
