INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32862eb5-2658-557a-b8db-43d6594f1bc9', 'cee04ed9-6549-55ee-91b3-8a121f98ce58', 'قطعةٌ [AB] طولُها 7 سم. ما طولُ مناظرتِها [A′B′] بالتناظر المركزي؟', '[{"id":"a","text":"14 سم"},{"id":"b","text":"3.5 سم"},{"id":"c","text":"لا يمكن معرفتُه"},{"id":"d","text":"7 سم"}]'::jsonb, 'd', 'التناظرُ المركزيُّ يحفظ الأطوال: A′B′ = AB = 7 سم مهما كان موضعُ المركز ✓. الخطأُ الشائع: ظنُّ أنّ الطول يتضاعف (14) أو ينتصف (3.5).', 4)
