INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd77bb25-1e47-5c1b-83d3-574fedcd63ea', 'cee04ed9-6549-55ee-91b3-8a121f98ce58', 'ما مناظرُ مستقيمٍ (d) بالنسبة إلى مركزٍ O لا ينتمي إليه؟', '[{"id":"a","text":"المستقيمُ (d) نفسُه"},{"id":"b","text":"مستقيمٌ يوازي (d)"},{"id":"c","text":"مستقيمٌ عموديٌّ على (d)"},{"id":"d","text":"نصفُ مستقيم"}]'::jsonb, 'b', 'مناظرُ مستقيمٍ لا يمرّ بالمركز هو مستقيمٌ يوازيه ✓. الخطأُ الشائع: الظنُّ أنّه المستقيمُ نفسُه (لا يصحّ إلّا إذا مرّ (d) بالمركز)، أو الخلطُ مع التعامد.', 5)
