INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('669409f4-110f-5d64-be4b-ea9eb8f40815', 'cee04ed9-6549-55ee-91b3-8a121f98ce58', 'أين يقع مركزُ تناظرِ دائرةٍ؟', '[{"id":"a","text":"في مركزها"},{"id":"b","text":"في أيّ نقطةٍ من محيطها"},{"id":"c","text":"لا مركزَ تناظرَ للدائرة"},{"id":"d","text":"في نقطتَين متقابلتَين من محيطها"}]'::jsonb, 'a', 'مركزُ تناظر الدائرة هو مركزُها: مناظرُ الدائرة بالنسبة إليه هو الدائرةُ نفسُها ✓. الخطأُ الشائع: اختيارُ نقطةٍ على المحيط، أو الظنُّ أنّه لا مركزَ لها بينما لها مركزٌ وحيد.', 6)
