INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27c773d6-a12d-5ade-b613-b47c37ef6201', 'af24817d-f29d-53b3-82f1-1790f9220019', 'في معلَمٍ متعامد، ما مناظرُ النقطة A(2, 5) بالنسبة إلى المبدأ O(0, 0)؟', '[{"id":"a","text":"(2, −5)"},{"id":"b","text":"(−2, 5)"},{"id":"c","text":"(−2, −5)"},{"id":"d","text":"(5, 2)"}]'::jsonb, 'c', 'مناظرُ A(x, y) بالنسبة إلى المبدأ هو A′(−x, −y): نقلب إشارةَ الإحداثيّتَين معًا، فنحصل على (−2, −5) ✓. الخطأُ الشائع: قلبُ إشارة إحداثيّةٍ واحدة فقط ((2, −5) أو (−2, 5))، أو تبديلُ الإحداثيّتَين ((5, 2)).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

