  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20bcb966-f08b-5160-8d72-d26003bd28a7', 'af24817d-f29d-53b3-82f1-1790f9220019', 'أين يقع مركزُ تناظرِ مستطيلٍ ABCD؟', '[{"id":"a","text":"في منتصف أطول ضلعَيه"},{"id":"b","text":"في الرأس A"},{"id":"c","text":"لا مركزَ تناظرَ للمستطيل"},{"id":"d","text":"في نقطة تقاطع قطرَيه"}]'::jsonb, 'd', 'مركزُ تناظر المستطيل هو نقطةُ تقاطع قطرَيه ✓. الخطأُ الشائع: اختيارُ رأسٍ أو منتصفِ ضلعٍ، أو الخلطُ بين محاور تناظر المستطيل (مستقيمان) ومركزِ تناظره (نقطةٌ واحدة).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae814d51-372d-589c-904b-56c51ecf20c0', 'af24817d-f29d-53b3-82f1-1790f9220019', 'النقاطُ A، B، C على استقامةٍ واحدة. ماذا نقول عن مناظراتها A′، B′، C′ بالتناظر المركزي؟', '[{"id":"a","text":"تشكّل مثلثًا"},{"id":"b","text":"تبقى على استقامةٍ واحدة"},{"id":"c","text":"تصبح رؤوسَ مربّع"},{"id":"d","text":"لا يمكن تحديدُ وضعها"}]'::jsonb, 'b', 'التناظرُ المركزيُّ يحفظ الاستقامية: صورُ نقاطٍ على استقامةٍ واحدة تبقى على استقامةٍ واحدة ✓. الخطأُ الشائع: الظنُّ أنّ نصف الدورة «يبعثر» النقاط بينما هو يحافظ على انتظامها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8cfa1635-b873-5f21-9c97-4ae1298d6472', 'af24817d-f29d-53b3-82f1-1790f9220019', 'M(−1, 4) ونقطةٌ O(2, 1) منتصفُ [MM′]. ما إحداثياتُ مناظرِ M، أي M′؟', '[{"id":"a","text":"(1, 5)"},{"id":"b","text":"(−4, 7)"},{"id":"c","text":"(5, −2)"},{"id":"d","text":"(3, −3)"}]'::jsonb, 'c', 'بما أنّ O منتصفُ [MM′]، فإنّ إحداثيّتَي M′ هما 2×إحداثيّتَي O ناقصَ إحداثيّتَي M: xM′ = 2×2 − (−1) = 5، yM′ = 2×1 − 4 = −2، فـ M′(5, −2) ✓. الخطأُ الشائع: جمعُ الإحداثيّات بدل تطبيق صيغة المنتصف ((1, 5))، أو طرحُ O من M بدل العكس.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da7ba07b-84c4-5c7a-b2dc-0ad09a4f7ed5', 'af24817d-f29d-53b3-82f1-1790f9220019', 'أيُّ الأشكال التالية **ليس** له مركزُ تناظر؟', '[{"id":"a","text":"المربّع"},{"id":"b","text":"الدائرة"},{"id":"c","text":"متوازي الأضلاع"},{"id":"d","text":"المثلّث المتساوي الأضلاع"}]'::jsonb, 'd', 'المثلّثُ المتساوي الأضلاع ليس له مركزُ تناظر (له ثلاثةُ محاورِ تناظرٍ لكن لا مركزَ) ✓. أمّا المربّعُ والدائرةُ ومتوازي الأضلاع فلكلٍّ منها مركزُ تناظر. الخطأُ الشائع: الخلطُ بين وجود محاورِ تناظرٍ ووجود مركزِ تناظر؛ هما مختلفان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

