  ('4ba0528f-fd51-5e59-b11b-a61456e4bafb', '111edeb4-a8c8-52ca-8715-53f7e02b054d', 'math-8eme', '⭐⭐ تمرين مراجعة (نمط امتحان): تعريفٌ وخاصياتٌ ومراكز تناظر', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
