  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ec74a83-a974-53ae-ab9a-92f4937e3356', '4ba0528f-fd51-5e59-b11b-a61456e4bafb', 'N′ مناظرةُ N بالنسبة إلى المركز O. أيُّ التعبير يصف الوضع بدقّة؟', '[{"id":"a","text":"O منتصفُ [NN′] والنقاطُ N, O, N′ على استقامةٍ واحدة"},{"id":"b","text":"المستقيمُ (ON) محورُ تناظرٍ للقطعة [NN′]"},{"id":"c","text":"N منتصفُ [ON′]"},{"id":"d","text":"ON أكبرُ من ON′"}]'::jsonb, 'a', 'التعريفُ الدقيق: O منتصفُ [NN′]، فتكون ON = ON′ والنقاطُ الثلاث على استقامةٍ واحدة ✓. الخطأُ الشائع: استعمالُ لغة التناظر المحوري (محور) بدل المركزي، أو جعلُ نقطةٍ خطأً هي المنتصف.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c6ba3a7-e8a9-5001-b9b6-bb801a32018b', '4ba0528f-fd51-5e59-b11b-a61456e4bafb', 'التناظرُ المركزيُّ يوافق دورانًا (نصفَ دورة) قدرُه:', '[{"id":"a","text":"90 درجة"},{"id":"b","text":"180 درجة"},{"id":"c","text":"360 درجة"},{"id":"d","text":"45 درجة"}]'::jsonb, 'b', 'نصفُ الدورة قدرُه 180 درجة: زاويةٌ مستقيمة حول المركز ✓. الخطأُ الشائع: أخذُ ربع دورةٍ (90) أو دورةٍ كاملة (360 التي تُرجع الشكلَ إلى موضعه دون تغيير).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('480793ba-fdc7-593f-9703-68747ed72bf0', '4ba0528f-fd51-5e59-b11b-a61456e4bafb', 'مستقيمٌ (d) يمرّ بالمركز O. ما مناظرُه بالتناظر المركزي بالنسبة إلى O؟', '[{"id":"a","text":"مستقيمٌ يوازيه ولا ينطبق عليه"},{"id":"b","text":"مستقيمٌ عموديٌّ عليه"},{"id":"c","text":"المستقيمُ (d) نفسُه"},{"id":"d","text":"النقطة O فقط"}]'::jsonb, 'c', 'إذا مرّ المستقيمُ بالمركز فمناظرُه هو المستقيمُ نفسُه (لأنّ مناظرَ كلّ نقطةٍ منه يقع أيضًا عليه) ✓. الخطأُ الشائع: تطبيقُ قاعدة «المستقيمُ يوازي مناظرَه» التي تخصّ فقط مستقيمًا لا يمرّ بالمركز.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('402b98ea-4021-58c1-a2a3-1eef6626b215', '4ba0528f-fd51-5e59-b11b-a61456e4bafb', 'ما مناظرُ النقطة A(−4, 6) بالنسبة إلى المبدأ O(0, 0)؟', '[{"id":"a","text":"(−4, −6)"},{"id":"b","text":"(4, 6)"},{"id":"c","text":"(6, −4)"},{"id":"d","text":"(4, −6)"}]'::jsonb, 'd', 'نقلب إشارةَ الإحداثيّتَين: مناظرُ A(−4, 6) هو (4, −6) ✓. الخطأُ الشائع: قلبُ إشارة إحداثيّةٍ واحدة فقط ((−4, −6) أو (4, 6))، أو تبديلُ مكان الإحداثيّتَين ((6, −4)).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1fc3708-fe2e-5f9a-b345-b7dcf5b4be69', '4ba0528f-fd51-5e59-b11b-a61456e4bafb', 'أين يقع مركزُ تناظرِ القطعة [AB]؟', '[{"id":"a","text":"في منتصفها"},{"id":"b","text":"في الطرف A"},{"id":"c","text":"في الطرف B"},{"id":"d","text":"لا مركزَ تناظرَ للقطعة"}]'::jsonb, 'a', 'مركزُ تناظر القطعة هو منتصفُها: مناظرُ [AB] بالنسبة إلى منتصفها هو القطعةُ نفسُها (يتبادل الطرفان A وB) ✓. الخطأُ الشائع: اختيارُ أحد الطرفَين، أو الظنُّ أنّه لا مركزَ لها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('584f4303-70c3-5f83-ac04-31ce276e1a37', '4ba0528f-fd51-5e59-b11b-a61456e4bafb', 'مستقيمان (d1) و(d2) متوازيان. ماذا نقول عن مناظرَيهما (d1′) و(d2′) بالتناظر المركزي؟', '[{"id":"a","text":"يتقاطعان في نقطة"},{"id":"b","text":"متوازيان أيضًا"},{"id":"c","text":"متعامدان"},{"id":"d","text":"ينطبقان على بعضهما"}]'::jsonb, 'b', 'التناظرُ المركزيُّ يحفظ التوازي: مناظرا مستقيمَين متوازيَين متوازيان ✓. الخطأُ الشائع: الظنُّ أنّ نصف الدورة يجعلهما يتقاطعان أو يتعامدان، بينما يحافظ على العلاقات بين المستقيمات.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

