INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb1a5cc3-fcb6-5277-9982-9de03249bb29', 'ac1c08a5-920f-5250-b387-1800a08988c3', 'ما مناظرُ النقطة A(1, 4) بالنسبة إلى المركز C(3, 3)؟', '[{"id":"a","text":"(−1, −4)"},{"id":"b","text":"(2, −1)"},{"id":"c","text":"(5, 2)"},{"id":"d","text":"(4, 7)"}]'::jsonb, 'c', 'بما أنّ C منتصفُ [AA′]: xA′ = 2×3 − 1 = 5، yA′ = 2×3 − 4 = 2، فـ A′(5, 2) ✓. الخطأُ الشائع: تطبيقُ صيغة المبدأ (−x, −y) رغم أنّ المركز ليس المبدأ ((−1, −4))، أو حسابُ المنتصف بدل المناظر ((2, −1) هو منتصفُ [AC] تقريبًا).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('acd7b679-bea9-5b4b-a296-b9d24413f79c', 'ac1c08a5-920f-5250-b387-1800a08988c3', 'أيُّ الجمل التالية تصف بدقّةٍ الفرقَ بين التناظر المحوري والتناظر المركزي؟', '[{"id":"a","text":"المحوريُّ بالنسبة إلى مستقيم، والمركزيُّ بالنسبة إلى نقطة"},{"id":"b","text":"المحوريُّ يحفظ الأطوال، والمركزيُّ لا يحفظها"},{"id":"c","text":"المحوريُّ بالنسبة إلى نقطة، والمركزيُّ بالنسبة إلى مستقيم"},{"id":"d","text":"لا فرقَ بينهما، مجرّدُ تسميتَين"}]'::jsonb, 'a', 'الفرقُ الجوهريُّ في المرجع: المحوريُّ بالنسبة إلى **مستقيمٍ** (محور، كالمرآة)، والمركزيُّ بالنسبة إلى **نقطةٍ** (مركز، كنصف دورة) ✓. الخطأُ الشائع: عكسُ التعريفَين (c)، أو الظنُّ أنّ المركزيَّ لا يحفظ الأطوال (كلاهما يحفظها).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('133faad6-cea8-5e98-93d2-8c987b6ca49f', 'ac1c08a5-920f-5250-b387-1800a08988c3', 'كتب تلميذٌ: «مناظرُ A(3, −2) بالنسبة إلى المبدأ هو (−3, −2)». أين الخطأ؟', '[{"id":"a","text":"لا خطأ، الحلُّ صحيح"},{"id":"b","text":"الخطأ في تبديل الإحداثيّتَين، الصحيح (−2, 3)"},{"id":"c","text":"يجب ألّا تتغيّر أيُّ إشارة، الصحيح (3, −2)"},{"id":"d","text":"نسيَ قلبَ إشارة الإحداثيّة الثانية، الصحيح (−3, 2)"}]'::jsonb, 'd', 'المناظرُ بالنسبة إلى المبدأ يقلب إشارةَ **كلتا** الإحداثيّتَين: مناظرُ A(3, −2) هو (−3, 2). التلميذُ قلب الأولى ونسيَ قلبَ الثانية ✓. (سؤالُ اكتشاف خطأ: الخيارُ الصحيح يصف موضعَ الخطأ ويعطي التصحيح.)', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('894b64f6-d07d-51eb-a778-281ac303d228', 'ac1c08a5-920f-5250-b387-1800a08988c3', 'أيُّ الأشكال التالية **له** مركزُ تناظر؟', '[{"id":"a","text":"المثلّثُ القائم"},{"id":"b","text":"شبهُ منحرفٍ عام"},{"id":"c","text":"المعيّن"},{"id":"d","text":"المثلّثُ المتساوي الساقَين"}]'::jsonb, 'c', 'المعيّنُ متوازي أضلاعٍ خاصّ، فله مركزُ تناظرٍ هو نقطةُ تقاطع قطرَيه ✓. أمّا المثلّثاتُ (قائم أو متساوي الساقَين) وشبهُ المنحرف العام فلا مركزَ تناظرَ لها. الخطأُ الشائع: الخلطُ بين وجود محورِ تناظرٍ (لبعضها) ووجود مركزِ تناظر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('467234d8-30f0-52d2-bd82-36d3fdb3b929', 'ac1c08a5-920f-5250-b387-1800a08988c3', 'قطعةٌ [AB] طولُها 6 سم ومناظرتُها [A′B′] بالتناظر المركزي. ما طولُ [A′B′] وما علاقةُ المستقيم (A′B′) بالمستقيم (AB)؟', '[{"id":"a","text":"الطولُ 12 سم و(A′B′) عموديٌّ على (AB)"},{"id":"b","text":"الطولُ 6 سم و(A′B′) يوازي (AB)"},{"id":"c","text":"الطولُ 3 سم و(A′B′) ينطبق على (AB)"},{"id":"d","text":"الطولُ 6 سم و(A′B′) عموديٌّ على (AB)"}]'::jsonb, 'b', 'التناظرُ المركزيُّ يحفظ الطول فـ A′B′ = AB = 6 سم، ويحوّل المستقيمَ إلى مستقيمٍ يوازيه (ما لم يمرّ بالمركز) فـ (A′B′) ∥ (AB) ✓. الخطأُ الشائع: مضاعفةُ الطول (12)، أو الظنُّ أنّ المناظرَ عموديٌّ على الأصل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b99703d1-844e-555f-bbbb-95d83f898e25', 'ac1c08a5-920f-5250-b387-1800a08988c3', 'مثلّثٌ ABC محيطُه 12 سم. ما محيطُ مناظرِه A′B′C′ بالتناظر المركزي؟', '[{"id":"a","text":"12 سم"},{"id":"b","text":"24 سم"},{"id":"c","text":"6 سم"},{"id":"d","text":"لا يمكن تحديدُه دون معرفة المركز"}]'::jsonb, 'a', 'التناظرُ المركزيُّ يحفظ الأطوال، فكلُّ ضلعٍ يساوي مناظرَه، ومنه المحيطُ محفوظٌ: محيطُ A′B′C′ = 12 سم مهما كان المركز ✓. الخطأُ الشائع: مضاعفةُ المحيط (24) أو تنصيفُه (6) ظنًّا أنّ نصف الدورة يغيّر الأبعاد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6714716c-67f8-51e3-889e-f70f7f7b59e2', '111edeb4-a8c8-52ca-8715-53f7e02b054d', 'math-8eme', '📝 تدريب ⭐⭐⭐: مراجعةٌ شاملة (تعريفٌ، إحداثياتٌ، خاصياتٌ، مراكز)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
