  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('599af47b-55b0-5055-ad86-9c7dd7d62f2e', '6714716c-67f8-51e3-889e-f70f7f7b59e2', 'هل يحفظ التناظرُ المركزيُّ أطوالَ القطع؟', '[{"id":"a","text":"نعم، القطعةُ ومناظرُها متساويتان طولًا"},{"id":"b","text":"لا، يضاعف الأطوال"},{"id":"c","text":"لا، ينصّف الأطوال"},{"id":"d","text":"يحفظها فقط إذا مرّ المركزُ بالقطعة"}]'::jsonb, 'a', 'من أهمّ خاصيات التناظر المركزي حفظُ الأطوال: A′B′ = AB دائمًا ✓. الخطأُ الشائع: الظنُّ أنّ نصف الدورة يغيّر الأبعاد (يضاعف أو ينصّف)، أو ربطُ الحفظ بموضع المركز.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e681380-3a75-54ea-9b19-6915b0f2054b', '6714716c-67f8-51e3-889e-f70f7f7b59e2', 'ما مناظرُ النقطة B(5, −3) بالنسبة إلى المبدأ O(0, 0)؟', '[{"id":"a","text":"(5, 3)"},{"id":"b","text":"(−3, 5)"},{"id":"c","text":"(−5, 3)"},{"id":"d","text":"(−5, −3)"}]'::jsonb, 'c', 'نقلب إشارةَ الإحداثيّتَين: مناظرُ B(5, −3) هو (−5, 3) ✓. الخطأُ الشائع: قلبُ إشارة إحداثيّةٍ واحدة فقط ((5, 3) أو (−5, −3))، أو تبديلُ الإحداثيّتَين ((−3, 5)).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f414ce1-fc40-571c-b772-c23a24d7d8ad', '6714716c-67f8-51e3-889e-f70f7f7b59e2', 'أين يقع مركزُ تناظرِ مربّعٍ ABCD؟', '[{"id":"a","text":"في الرأس C"},{"id":"b","text":"في نقطة تقاطع قطرَيه"},{"id":"c","text":"في منتصف أحد أضلاعه"},{"id":"d","text":"على أحد محاور تناظره خارج القطرَين"}]'::jsonb, 'b', 'مركزُ تناظر المربّع هو نقطةُ تقاطع قطرَيه (وهي مركزُه) ✓. الخطأُ الشائع: الخلطُ بين محاور تناظر المربّع (أربعةُ مستقيمات) ومركزِ تناظره (نقطةٌ واحدة)، أو اختيارُ رأسٍ أو منتصفِ ضلع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aec50efa-ab52-5bf8-a85d-1fe9467da81f', '6714716c-67f8-51e3-889e-f70f7f7b59e2', 'مستقيمٌ (d) لا يمرّ بالمركز O. ما وضعُ مناظرِه (d′)؟', '[{"id":"a","text":"يتقاطع مع (d) في O"},{"id":"b","text":"عموديٌّ على (d)"},{"id":"c","text":"يوازي (d)"},{"id":"d","text":"ينطبق على (d)"}]'::jsonb, 'c', 'مناظرُ مستقيمٍ لا يمرّ بالمركز مستقيمٌ يوازيه: (d′) ∥ (d) ✓. الخطأُ الشائع: الظنُّ أنّه ينطبق عليه (يصحّ فقط إذا مرّ (d) بالمركز)، أو أنّه يتقاطع معه أو يعامده.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45b21e90-412e-5aae-98d9-9be830cccbd0', '6714716c-67f8-51e3-889e-f70f7f7b59e2', 'O(2, 1) منتصفُ [MM′] وM(−1, 4). ما إحداثياتُ M′؟', '[{"id":"a","text":"(5, −2)"},{"id":"b","text":"(1, 5)"},{"id":"c","text":"(−4, 7)"},{"id":"d","text":"(3, 3)"}]'::jsonb, 'a', 'من صيغة المنتصف: xM′ = 2×2 − (−1) = 5 وyM′ = 2×1 − 4 = −2، فـ M′(5, −2) ✓. الخطأُ الشائع: جمعُ الإحداثيّات مباشرةً ((1, 5))، أو طرحُ O من M بدل تطبيق 2O − M ((−4, 7)).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dda27967-ae97-5104-b934-2b68c7e23e65', '6714716c-67f8-51e3-889e-f70f7f7b59e2', 'أيُّ الجمل التالية **ليست** خاصيّةً من خاصيات التناظر المركزي؟', '[{"id":"a","text":"يحفظ الأطوال"},{"id":"b","text":"يحفظ الزوايا"},{"id":"c","text":"يحفظ التوازي"},{"id":"d","text":"يجعل مناظرَ المستقيم عموديًّا عليه"}]'::jsonb, 'd', 'التناظرُ المركزيُّ يحوّل المستقيمَ إلى مستقيمٍ **يوازيه** لا يعامده، فالجملةُ (d) خاطئةٌ وليست خاصيّة ✓. أمّا حفظُ الأطوال والزوايا والتوازي فكلُّها خاصياتٌ صحيحة. الخطأُ الشائع: الخلطُ بين خاصية التوازي والتعامد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

