  ('d143ca95-f7e1-5197-afab-fc3e5d4f14fa', '111edeb4-a8c8-52ca-8715-53f7e02b054d', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مراكزُ التناظر والإحداثيات المتقدّمة', 4, 300, 60, 'challenge', 'admin', 6)
