INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99d53e17-b9a5-57ac-b3b5-878c30624fb8', 'd143ca95-f7e1-5197-afab-fc3e5d4f14fa', 'ما مناظرُ النقطة A(4, 1) بالنسبة إلى المركز C(1, 2)؟', '[{"id":"a","text":"(−4, −1)"},{"id":"b","text":"(−2, 3)"},{"id":"c","text":"(2, 3)"},{"id":"d","text":"(3, −1)"}]'::jsonb, 'b', 'C منتصفُ [AA′]: xA′ = 2×1 − 4 = −2 وyA′ = 2×2 − 1 = 3، فـ A′(−2, 3) ✓. الخطأُ الشائع: تطبيقُ صيغة المبدأ (−x, −y) رغم أنّ المركز C ليس المبدأ ((−4, −1))، أو نسيانُ مضاعفة إحداثيّة المركز.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c12a7633-aa1c-5751-b7c8-e74ee2ba64fb', 'd143ca95-f7e1-5197-afab-fc3e5d4f14fa', 'أيُّ الأشكال التالية **ليس** له مركزُ تناظر؟', '[{"id":"a","text":"متوازي الأضلاع"},{"id":"b","text":"المعيّن"},{"id":"c","text":"شبهُ المنحرف العام"},{"id":"d","text":"المربّع"}]'::jsonb, 'c', 'شبهُ المنحرف العام ليس متوازيَ أضلاع، فلا مركزَ تناظرَ له ✓. أمّا متوازي الأضلاع والمعيّنُ والمربّعُ فلكلٍّ منها مركزٌ هو تقاطعُ القطرَين. الخطأُ الشائع: افتراضُ أنّ كلّ رباعيٍّ له مركزُ تناظر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe664f2b-a1b1-566d-b327-6f89b3c0614b', 'd143ca95-f7e1-5197-afab-fc3e5d4f14fa', 'أيُّ الجمل التالية **صحيحة**؟', '[{"id":"a","text":"مناظرُ مستقيمٍ بالتناظر المركزي عموديٌّ عليه"},{"id":"b","text":"التناظرُ المركزيُّ يضاعف أطوالَ القطع"},{"id":"c","text":"مناظرُ A(2, −5) بالنسبة إلى المبدأ هو (−2, 5)"},{"id":"d","text":"لكلّ مثلّثٍ عامٍّ مركزُ تناظر"}]'::jsonb, 'c', 'المناظرُ بالنسبة إلى المبدأ يقلب إشارةَ الإحداثيّتَين: مناظرُ (2, −5) هو (−2, 5) ✓. الباقي خاطئ: مناظرُ المستقيم يوازيه لا يعامده؛ التناظرُ يحفظ الأطوال لا يضاعفها؛ المثلّثُ العامُّ لا مركزَ تناظرَ له.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25f2f416-353e-579c-b8f5-f8f1f66eeb44', 'd143ca95-f7e1-5197-afab-fc3e5d4f14fa', 'مثلّثٌ ABC مساحتُه 18 سم². ما مساحةُ مناظرِه A′B′C′ بالتناظر المركزي؟', '[{"id":"a","text":"18 سم²"},{"id":"b","text":"36 سم²"},{"id":"c","text":"9 سم²"},{"id":"d","text":"324 سم²"}]'::jsonb, 'a', 'التناظرُ المركزيُّ يحفظ الأطوالَ والزوايا، فمناظرُ المثلّث يقايسه تمامًا ومساحتُه محفوظة: 18 سم² ✓. الخطأُ الشائع: مضاعفةُ المساحة (36)، أو تربيعُ مُعامِلٍ وهميّ (324)، أو تنصيفُها (9).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('13f5e6dc-08d3-5d6e-b7aa-0fdc4db12234', 'd143ca95-f7e1-5197-afab-fc3e5d4f14fa', 'مناظرُ النقطة A بالنسبة إلى المبدأ هو A′(−6, 8). ما إحداثياتُ A؟', '[{"id":"a","text":"(−6, 8)"},{"id":"b","text":"(8, −6)"},{"id":"c","text":"(−6, −8)"},{"id":"d","text":"(6, −8)"}]'::jsonb, 'd', 'التناظرُ المركزيُّ يعمل في الاتجاهَين: إن كان A′ مناظرَ A فإنّ A مناظرُ A′. نقلب إشارةَ إحداثيّتَي A′(−6, 8) فنحصل على A(6, −8) ✓. الخطأُ الشائع: نسخُ إحداثيّات A′ كما هي ((−6, 8))، أو تبديلُ الإحداثيّتَين ((8, −6)).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77f27d4a-b176-51ea-8f13-fdd1aaa2fed0', 'd143ca95-f7e1-5197-afab-fc3e5d4f14fa', 'كم مركزَ تناظرٍ لمستقيمٍ (d)؟', '[{"id":"a","text":"صفر (لا مركزَ له)"},{"id":"b","text":"عددٌ لا نهائيّ: كلُّ نقطةٍ منه مركزُ تناظر"},{"id":"c","text":"واحدٌ فقط: منتصفه"},{"id":"d","text":"اثنان: طرفاه"}]'::jsonb, 'b', 'مناظرُ المستقيم بالنسبة إلى أيّ نقطةٍ **تنتمي إليه** هو المستقيمُ نفسُه، فكلُّ نقطةٍ من (d) مركزُ تناظرٍ له: العددُ لا نهائيّ ✓. الخطأُ الشائع: معاملةُ المستقيم كقطعةٍ لها منتصفٌ وحيدٌ أو طرفان (المستقيمُ غيرُ منتهٍ ولا طرفَ له).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

