INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e6a7493-f4c5-59c6-9710-4e6016cb9ddd', '6db33607-2209-5b90-a3e1-4a58c78d9e9d', 'أيُّ العبارات التالية تُعرّف متوازيَ الأضلاع تعريفًا صحيحًا؟', '[{"id":"a","text":"رباعيٌّ له زوجٌ واحدٌ من الأضلاع المتوازية"},{"id":"b","text":"رباعيٌّ أضلاعُه المتقابلةُ متوازيةٌ مثنى مثنى"},{"id":"c","text":"رباعيٌّ له أربعُ زوايا قائمة"},{"id":"d","text":"رباعيٌّ قطراه متقايسان"}]'::jsonb, 'b', 'متوازي الأضلاع رباعيٌّ ضلعاه المتقابلان متوازيان في **الزوجَين معًا** ✓. زوجٌ واحدٌ متوازٍ فقط يعطي شبهَ منحرف؛ أربعُ زوايا قائمةٍ تخصّ المستطيل؛ وتقايسُ القطرَين خاصيةُ المستطيل لا تعريفٌ لمتوازي الأضلاع.', 1)
