  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bba882f2-8dc3-5547-99b4-d31f1418cfc0', '6db33607-2209-5b90-a3e1-4a58c78d9e9d', 'في متوازي الأضلاع ABCD كان AB = 8 cm. ما طولُ الضلع DC؟', '[{"id":"a","text":"8 cm"},{"id":"b","text":"4 cm"},{"id":"c","text":"16 cm"},{"id":"d","text":"لا يمكن معرفتُه"}]'::jsonb, 'a', 'AB وDC ضلعان متقابلان، والأضلاعُ المتقابلة في متوازي الأضلاع متقايسة، فـ DC = AB = 8 cm ✓. الخطأُ الشائع: قسمةُ الطول على 2 (4 cm) بالخلط مع خاصية الأقطار المتناصفة، أو مضاعفتُه (16 cm).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
