INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0995a445-ae92-5304-94ff-6336806d7863', '6db33607-2209-5b90-a3e1-4a58c78d9e9d', 'في متوازي الأضلاع ABCD كانت الزاويةُ Â = 65°. ما قيسُ الزاوية B̂ المجاورةِ لها؟', '[{"id":"a","text":"65°"},{"id":"b","text":"25°"},{"id":"c","text":"115°"},{"id":"d","text":"130°"}]'::jsonb, 'c', 'Â وB̂ زاويتان متتاليتان، ومجموعُ المتتاليتين 180°، فـ B̂ = 180° − 65° = 115° ✓. الخطأُ الشائع: اعتبارُها متقابلةً فتساوي 65°، أو استعمالُ التكامل إلى 90° فيُكتب 25°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('382b2aca-186b-5c79-a288-5366973f5930', '6db33607-2209-5b90-a3e1-4a58c78d9e9d', 'ما الخاصيةُ الصحيحةُ لقطرَي متوازي الأضلاع في الحالة العامة؟', '[{"id":"a","text":"متقايسان"},{"id":"b","text":"متعامدان"},{"id":"c","text":"متوازيان"},{"id":"d","text":"متناصفان"}]'::jsonb, 'd', 'قطرا متوازي الأضلاع **متناصفان**: يتقاطعان في منتصفهما المشترك ✓. التقايسُ خاصيةُ المستطيل وحدَه، والتعامدُ خاصيةُ المعيّن وحدَه؛ أمّا التوازي فمستحيلٌ لأنّ القطرَين يتقاطعان في O.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3450a81e-b337-5214-9b7a-bdad30cf7d88', '6db33607-2209-5b90-a3e1-4a58c78d9e9d', 'متوازي أضلاعٍ قطراه متقايسان. ما نوعُه بالضرورة؟', '[{"id":"a","text":"معيّن"},{"id":"b","text":"مستطيل"},{"id":"c","text":"شبه منحرف"},{"id":"d","text":"لا شيء إضافيّ؛ يبقى متوازيَ أضلاع عاديًّا"}]'::jsonb, 'b', 'متوازي أضلاعٍ قطراه متقايسان هو مستطيلٌ ✓ (تقايسُ الأقطار يميّز المستطيل). المعيّنُ يُميَّز بتعامد الأقطار لا تقايسِها؛ وشبهُ المنحرف ليس متوازيَ أضلاع أصلًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

