INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6bcb9123-00f6-50cb-9f31-426a403b9a12', 'a412a117-80eb-5bc8-b792-3d7a9f107b30', 'في متوازي الأضلاع MNPQ كان MN = 6 cm. ما طولُ الضلع المقابل QP؟', '[{"id":"a","text":"3 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"12 cm"},{"id":"d","text":"لا يمكن تحديدُه"}]'::jsonb, 'b', 'MN وQP ضلعان متقابلان، والأضلاعُ المتقابلة متقايسة، فـ QP = MN = 6 cm ✓. الخطأُ الشائع: قسمةُ الطول على 2 (3 cm) بالخلط مع خاصية الأقطار المتناصفة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03102d56-8853-573f-99f5-32216ebbd37d', 'a412a117-80eb-5bc8-b792-3d7a9f107b30', 'قطرا متوازي الأضلاع ABCD يتقاطعان في O. أيُّ العبارات صحيحة؟', '[{"id":"a","text":"O منتصفُ [AC] ومنتصفُ [BD]"},{"id":"b","text":"O منتصفُ [AC] فقط"},{"id":"c","text":"AC = BD دائمًا"},{"id":"d","text":"O هو الرأس A"}]'::jsonb, 'a', 'قطرا متوازي الأضلاع متناصفان، أي يتقاطعان في منتصفهما المشترك، فـ O منتصفُ [AC] و[BD] معًا ✓. تناصفُ القطرَين لا يعني تقايسَهما (AC = BD) الذي يخصّ المستطيلَ وحدَه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a784ee78-7509-5c45-9d18-5b7728bc6c7a', 'a412a117-80eb-5bc8-b792-3d7a9f107b30', 'في متوازي الأضلاع ABCD كانت الزاويةُ Â = 70°. ما قيسُ الزاوية المقابلة Ĉ؟', '[{"id":"a","text":"110°"},{"id":"b","text":"20°"},{"id":"c","text":"70°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'Â وĈ زاويتان متقابلتان، والمتقابلتان متقايستان، فـ Ĉ = 70° ✓. الخطأُ الشائع: تطبيقُ التكامل (180° − 70° = 110°) الخاصِّ بالزاويتين المتتاليتين لا المتقابلتين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b3e2497-af15-5e4a-bd9e-8ac3d9e6432c', 'a412a117-80eb-5bc8-b792-3d7a9f107b30', 'في متوازي الأضلاع ABCD كان AB = 5 cm وBC = 3 cm. ما محيطُه؟', '[{"id":"a","text":"8 cm"},{"id":"b","text":"15 cm"},{"id":"c","text":"11 cm"},{"id":"d","text":"16 cm"}]'::jsonb, 'd', 'الأضلاعُ المتقابلة متقايسة، فالمحيطُ P = 2×(AB + BC) = 2×(5 + 3) = 16 cm ✓. الخطأُ الشائع: جمعُ ضلعَين فقط دون مضاعفة (8 cm)، أو ضربُ الطولَين (15).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5aa00963-eb52-5dc7-abd2-03d835580c80', 'a412a117-80eb-5bc8-b792-3d7a9f107b30', 'في متوازي الأضلاع ABCD كان القطرُ AC = 12 cm ويتقاطع مع BD في O. ما طولُ OA؟', '[{"id":"a","text":"12 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"24 cm"},{"id":"d","text":"يساوي OB"}]'::jsonb, 'b', 'O منتصفُ [AC] لأنّ القطرَين متناصفان، فـ OA = AC ÷ 2 = 12 ÷ 2 = 6 cm ✓. القولُ إنّ OA = OB خطأ: تناصفُ القطرَين لا يجعلهما متقايسَين إلّا في المستطيل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f12e7575-4949-5e03-b596-9762edeee48f', 'a412a117-80eb-5bc8-b792-3d7a9f107b30', 'أيُّ الحالات الخاصة هي متوازي أضلاعٍ له أربعُ زوايا قائمة؟', '[{"id":"a","text":"المستطيل"},{"id":"b","text":"المعيّن"},{"id":"c","text":"شبه المنحرف"},{"id":"d","text":"أيُّ متوازي أضلاع"}]'::jsonb, 'a', 'المستطيلُ هو متوازي الأضلاع الذي له زاويةٌ قائمة (ومنه تصير الأربعُ قائمة) ✓. المعيّنُ يُميَّز بتقايس أضلاعه لا بزواياه؛ وشبهُ المنحرف ليس متوازيَ أضلاع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

