INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('908bb92c-b002-560b-9e5d-e7d7fd59ffea', '75223a47-b7d6-5f70-8200-4cb01800df20', 'في متوازي الأضلاع ABCD كانت الزاويةُ B̂ = 108°. ما قيسُ الزاوية Â؟', '[{"id":"a","text":"108°"},{"id":"b","text":"72°"},{"id":"c","text":"82°"},{"id":"d","text":"36°"}]'::jsonb, 'b', 'Â وB̂ متتاليتان فمجموعهما 180°، إذن Â = 180° − 108° = 72° ✓. الخطأُ الشائع: اعتبارُها متقابلةً لـ B̂ فتساوي 108°، أو الخطأُ في طرح 180 − 108 فيُكتب 82° بدل 72°.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('740a1a4c-9480-51f1-b6ae-9d52d7030f28', '75223a47-b7d6-5f70-8200-4cb01800df20', 'في متوازي الأضلاع ABCD كان AB = 2x + 1 وDC = x + 5 (بالـ cm). ما قيمةُ x؟', '[{"id":"a","text":"4"},{"id":"b","text":"6"},{"id":"c","text":"2"},{"id":"d","text":"5"}]'::jsonb, 'a', 'AB وDC ضلعان متقابلان فهما متقايسان: 2x + 1 = x + 5، ومنه 2x − x = 5 − 1، أي x = 4 ✓. الخطأُ الشائع: جمعُ الطرفين بدل حلّ المعادلة، أو نسيانُ نقل x.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0c0f2040-8b2f-583c-b8b5-12005f0d4244', '75223a47-b7d6-5f70-8200-4cb01800df20', 'متوازي أضلاعٍ محيطُه 30 cm وأحدُ أضلاعه يساوي 8 cm. ما طولُ الضلع المجاور له؟', '[{"id":"a","text":"22 cm"},{"id":"b","text":"11 cm"},{"id":"c","text":"7 cm"},{"id":"d","text":"15 cm"}]'::jsonb, 'c', 'P = 2×(a + b)، فـ 30 = 2×(8 + b)، ومنه 8 + b = 15، أي b = 7 cm ✓. الخطأُ الشائع: طرحُ 8 من 30 مباشرةً (22) بنسيان القسمة على 2، أو قسمةُ المحيط على 2 فقط دون طرح (15).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0df64a7-aa94-587a-ad12-fcb52b201beb', '75223a47-b7d6-5f70-8200-4cb01800df20', 'قطرا رباعيّ ABCD متناصفان (يتقاطعان في منتصفهما المشترك). ما نوعُه؟', '[{"id":"a","text":"مستطيل بالضرورة"},{"id":"b","text":"معيّن بالضرورة"},{"id":"c","text":"لا يمكن استنتاجُ شيء"},{"id":"d","text":"متوازي أضلاع"}]'::jsonb, 'd', 'تناصفُ القطرَين شرطٌ **كافٍ** لكون الرباعيّ متوازيَ أضلاع ✓. لا نستنتج مستطيلًا (يلزم تقايسُ القطرَين) ولا معيّنًا (يلزم تعامدُهما)؛ التناصفُ وحدَه يعطي متوازيَ الأضلاع العامّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac97e38d-fb76-5e89-b37f-8eebf3ffaa96', '75223a47-b7d6-5f70-8200-4cb01800df20', 'متوازي أضلاعٍ قطراه متعامدان لكنّهما غيرُ متقايسَين. ما نوعُه بالضبط؟', '[{"id":"a","text":"مربّع"},{"id":"b","text":"مستطيل"},{"id":"c","text":"معيّن"},{"id":"d","text":"متوازي أضلاع عاديّ"}]'::jsonb, 'c', 'تعامدُ القطرَين في متوازي أضلاعٍ يميّز المعيّن ✓. لو كانا متقايسَين أيضًا لكان مربّعًا؛ التقايسُ وحدَه (دون تعامد) يعطي مستطيلًا. غيرُ متقايسَين يستبعد المربّعَ والمستطيل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b12ea9ad-554a-5fbf-ad24-1e518a18a9ea', '75223a47-b7d6-5f70-8200-4cb01800df20', 'في متوازي الأضلاع ABCD كان مجموعُ الزاويتين المتقابلتين Â + Ĉ = 140°. ما قيسُ كلٍّ منهما؟', '[{"id":"a","text":"كلٌّ منهما 140°"},{"id":"b","text":"كلٌّ منهما 70°"},{"id":"c","text":"Â = 40° وĈ = 100°"},{"id":"d","text":"كلٌّ منهما 90°"}]'::jsonb, 'b', 'Â وĈ متقابلتان فهما متقايستان، ومجموعهما 140°، إذن كلٌّ منهما 140° ÷ 2 = 70° ✓. الخطأُ الشائع: توزيعُ المجموع بقيمتين مختلفتين (كـ 40° و100°) رغم أنّ المتقابلتين لا بدّ متساويتان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
