INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('598fd29e-4ac7-5834-acbe-5826f71e0d11', '4006fc58-0a2e-56b3-95df-db1dbe8bef45', 'أيُّ زوجٍ من الأضلاع متقابلٌ في متوازي الأضلاع ABCD؟', '[{"id":"a","text":"[AB] و[DC]"},{"id":"b","text":"[AB] و[BC]"},{"id":"c","text":"[AB] و[AD]"},{"id":"d","text":"[AC] و[BD]"}]'::jsonb, 'a', 'في الرباعيّ ABCD الأضلاعُ المتقابلة هي [AB] و[DC] من جهة، و[AD] و[BC] من جهة أخرى ✓. [AB] و[BC] متتاليان؛ و[AC] و[BD] هما القطران لا ضلعان.', 1)
