INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('670ef2a5-2a6f-51f7-b729-4cc2a335747f', '4006fc58-0a2e-56b3-95df-db1dbe8bef45', 'في متوازي الأضلاع ABCD كان OB = 4 cm حيث O مركزُ التقاطع. ما طولُ القطر BD؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"2 cm"},{"id":"c","text":"8 cm"},{"id":"d","text":"يساوي AC"}]'::jsonb, 'c', 'O منتصفُ [BD] لأنّ القطرَين متناصفان، فـ BD = 2×OB = 2×4 = 8 cm ✓. الخطأُ الشائع: اعتبارُ OB هو القطرَ كلَّه (4 cm)، أو نصفَه (2 cm). القولُ إنّ BD = AC خطأ إلّا في المستطيل.', 2)
ON CONFLICT (id) DO UPDATE SET
