INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9fe9f08-3e62-54e0-aa77-1e13f8f655e9', '4006fc58-0a2e-56b3-95df-db1dbe8bef45', 'متوازي أضلاعٍ كلُّ أضلاعه الأربعةُ متقايسة. ما نوعُه؟', '[{"id":"a","text":"مستطيل"},{"id":"b","text":"شبه منحرف"},{"id":"c","text":"متوازي أضلاع عاديّ فقط"},{"id":"d","text":"معيّن"}]'::jsonb, 'd', 'متوازي أضلاعٍ ضلعاه المتتاليان (ومن ثمّ أضلاعُه الأربع) متقايسة هو معيّن ✓. المستطيلُ يُميَّز بزواياه القائمة لا بتقايس أضلاعه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('70e99023-7c36-5711-bf14-5414d22dc1ab', '4006fc58-0a2e-56b3-95df-db1dbe8bef45', 'في متوازي الأضلاع ABCD كانت Â = 55°. ما قيسُ الزاوية D̂؟', '[{"id":"a","text":"55°"},{"id":"b","text":"125°"},{"id":"c","text":"35°"},{"id":"d","text":"145°"}]'::jsonb, 'b', 'Â وD̂ زاويتان متتاليتان (متجاورتان على الضلع [AD])، فمجموعهما 180°: D̂ = 180° − 55° = 125° ✓. الخطأُ الشائع: اعتبارُهما متقابلتين فتساويان 55°، أو التكاملُ إلى 90° (35°).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2f05a0c-a130-5fda-8478-deb3c37b9e3a', '4006fc58-0a2e-56b3-95df-db1dbe8bef45', 'ما الشرطُ الكافي وحدَه ليكون رباعيُّ ABCD متوازيَ أضلاع؟', '[{"id":"a","text":"ضلعان متقابلان متقايسان فقط"},{"id":"b","text":"قطران متقايسان فقط"},{"id":"c","text":"ضلعان متقابلان متوازيان ومتقايسان معًا"},{"id":"d","text":"زاويةٌ واحدةٌ قائمة"}]'::jsonb, 'c', 'زوجُ أضلاعٍ متقابلٍ متوازٍ **ومتقايسٍ معًا** يكفي لإثبات متوازي الأضلاع ✓. تقايسُ ضلعَين فقط أو تقايسُ قطرَين فقط لا يكفي (قد يكون شبهَ منحرفٍ متساويَ الساقين)؛ وزاويةٌ قائمةٌ وحدَها لا تعني توازيَ الأضلاع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('536e32e7-442a-5c83-9440-80b21680f529', '4006fc58-0a2e-56b3-95df-db1dbe8bef45', 'أيُّ العبارات التالية خاطئةٌ حول متوازي الأضلاع في الحالة العامة؟', '[{"id":"a","text":"أضلاعُه المتقابلة متقايسة"},{"id":"b","text":"قطراه متناصفان"},{"id":"c","text":"زاويتاه المتقابلتان متقايستان"},{"id":"d","text":"قطراه متعامدان"}]'::jsonb, 'd', 'تعامدُ القطرَين ليس خاصيةً عامةً لمتوازي الأضلاع؛ إنّه صفةُ المعيّن وحدَه، فالعبارةُ خاطئة ✓. أمّا تقايسُ الأضلاع المتقابلة وتناصفُ القطرَين وتقايسُ الزاويتين المتقابلتين فكلُّها خاصياتٌ صحيحةٌ لكلّ متوازي أضلاع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

