  ('09042276-5a6b-5c9d-8dc6-dc1c0222fa86', '2ebee8d0-e505-5df8-b6ec-451f668d7838', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: شروطُ التعرّف والحالات الخاصة', 4, 300, 60, 'challenge', 'admin', 4)
