INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f58bf9eb-9037-5cdc-b9c7-41ae0d20567a', '09042276-5a6b-5c9d-8dc6-dc1c0222fa86', 'متوازي أضلاعٍ قطراه متقايسان ومتعامدان في آنٍ واحد. ما نوعُه بالضبط؟', '[{"id":"a","text":"مستطيل"},{"id":"b","text":"معيّن"},{"id":"c","text":"متوازي أضلاع عاديّ"},{"id":"d","text":"مربّع"}]'::jsonb, 'd', 'تقايسُ الأقطار يعطي مستطيلًا، وتعامدُها يعطي معيّنًا؛ اجتماعُهما معًا يعطي المربّعَ (مستطيلٌ ومعيّنٌ في آن) ✓. أخذُ خاصيةٍ واحدةٍ فقط يعطي المستطيلَ أو المعيّنَ لا المربّع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b0f5fd50-80ef-5ef6-a551-f11a4fe54d59', '09042276-5a6b-5c9d-8dc6-dc1c0222fa86', 'قال تلميذٌ: «في الرباعيّ ABCD كان AB = DC، إذن ABCD متوازي أضلاع.» أين الخطأ؟', '[{"id":"a","text":"لا خطأ؛ الاستنتاج صحيح"},{"id":"b","text":"تقايسُ ضلعَين متقابلَين وحدَه لا يكفي؛ يلزم أيضًا توازيهما (أو تقايسُ الزوج الآخر)"},{"id":"c","text":"الشرطُ الصحيح هو AB = AD"},{"id":"d","text":"يجب أن يكون القطران متعامدَين"}]'::jsonb, 'b', 'تقايسُ زوجٍ واحدٍ من الأضلاع المتقابلة **لا يكفي** وحدَه؛ قد يكون الشكلُ شبهَ منحرفٍ متساويَ الساقَين. الشرطُ الكافي: أن يتقايسا **ويتوازيا** معًا، أو أن يتقايس الزوجان المتقابلان ✓. (سؤالُ اكتشاف خطأ: نصف موضعَ الخطأ لا حلًّا بديلًا.)', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9277006f-60a5-59b5-b454-79c32b02c549', '09042276-5a6b-5c9d-8dc6-dc1c0222fa86', 'في متوازي الأضلاع ABCD المتقاطعِ قطراه في O، كان OA = 3x − 1 وOC = x + 5 (بالـ cm). ما طولُ القطر AC؟', '[{"id":"a","text":"16 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"3 cm"},{"id":"d","text":"11 cm"}]'::jsonb, 'a', 'O منتصفُ [AC] فـ OA = OC: 3x − 1 = x + 5، ومنه 2x = 6 أي x = 3. إذن OA = 3×3 − 1 = 8 cm، والقطرُ AC = 2×OA = 16 cm ✓. الخطأُ الشائع: التوقّفُ عند OA = 8 cm دون مضاعفة، أو إعطاءُ قيمة x بدل القطر (3).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba12e55a-74d6-51f0-a97b-95c6bcdd6706', '09042276-5a6b-5c9d-8dc6-dc1c0222fa86', 'ما الشرطُ الذي يجعل متوازيَ الأضلاع مستطيلًا (لا معيّنًا)؟', '[{"id":"a","text":"قطراه متعامدان"},{"id":"b","text":"ضلعان متتاليان متقايسان"},{"id":"c","text":"قطراه متقايسان"},{"id":"d","text":"أضلاعُه المتقابلة متقايسة"}]'::jsonb, 'c', 'متوازي أضلاعٍ قطراه متقايسان هو مستطيل ✓. تعامدُ الأقطار وتقايسُ ضلعَين متتاليَين يميّزان المعيّنَ لا المستطيل؛ وتقايسُ الأضلاع المتقابلة خاصيةٌ عامةٌ لكلّ متوازي أضلاع فلا تميّز شيئًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82205923-b4c5-5b6a-8ee4-f0cb242adc1e', '09042276-5a6b-5c9d-8dc6-dc1c0222fa86', 'متوازي أضلاعٍ هو مستطيلٌ ومعيّنٌ في آنٍ واحد. ما نوعُه وما خاصيةُ قطرَيه؟', '[{"id":"a","text":"مستطيل؛ قطراه متقايسان فقط"},{"id":"b","text":"مربّع؛ قطراه متقايسان ومتعامدان ويتناصفان"},{"id":"c","text":"معيّن؛ قطراه متعامدان فقط"},{"id":"d","text":"متوازي أضلاع عاديّ؛ قطراه متناصفان فقط"}]'::jsonb, 'b', 'ما هو مستطيلٌ ومعيّنٌ معًا هو المربّع ✓. يرث تقايسَ الأقطار من المستطيل، وتعامدَها من المعيّن، ويبقى التناصفُ لأنّه متوازي أضلاع: فقطراه متقايسان ومتعامدان ويتناصفان.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9bb8eeea-7080-57d0-8f38-4d7e387e724b', '09042276-5a6b-5c9d-8dc6-dc1c0222fa86', 'في متوازي الأضلاع ABCD كانت الزاويةُ Â تزيد عن الزاوية المتتاليةِ B̂ بمقدار 40°. ما قيسُ Â؟', '[{"id":"a","text":"110°"},{"id":"b","text":"70°"},{"id":"c","text":"140°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'Â وB̂ متتاليتان فـ Â + B̂ = 180°، ومع Â − B̂ = 40° نجمع المعادلتين: 2×Â = 220°، إذن Â = 110° (وB̂ = 70°) ✓. الخطأُ الشائع: إعطاءُ قيمة B̂ = 70° بدل Â.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

