  ('45232de4-c65f-5c37-ae63-dd506e5d1800', '2ebee8d0-e505-5df8-b6ec-451f668d7838', 'math-8eme', '⭐⭐⭐ زعيم: تدرّبٌ على البراهين والحالات الخاصة', 3, 120, 30, 'boss', 'admin', 5)
