INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c91c4e1a-6f4d-5791-b773-9b27e4e2bed7', '45232de4-c65f-5c37-ae63-dd506e5d1800', 'في متوازي الأضلاع ABCD كانت الزاويةُ Ĉ = 95°. ما قيسُ الزاوية المتتاليةِ D̂؟', '[{"id":"a","text":"95°"},{"id":"b","text":"85°"},{"id":"c","text":"5°"},{"id":"d","text":"185°"}]'::jsonb, 'b', 'Ĉ وD̂ متتاليتان فمجموعهما 180°: D̂ = 180° − 95° = 85° ✓. الخطأُ الشائع: اعتبارُهما متقابلتين فتساويان 95°، أو التكاملُ إلى 90° (5°).', 1)
