INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afca41c2-10bb-53c8-9377-fdd4cbb9969e', '45232de4-c65f-5c37-ae63-dd506e5d1800', 'في متوازي الأضلاع ABCD كانت Â = 3x وB̂ = 2x (متتاليتان). ما قيسُ Â؟', '[{"id":"a","text":"108°"},{"id":"b","text":"72°"},{"id":"c","text":"36°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'المتتاليتان مجموعهما 180°: 3x + 2x = 180°، فـ 5x = 180° أي x = 36°. إذن Â = 3×36° = 108° ✓. الخطأُ الشائع: التوقّفُ عند x = 36°، أو حسابُ B̂ = 2×36° = 72° بدل Â.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
