INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7227339e-a931-5a50-91e3-665168cb2995', '45232de4-c65f-5c37-ae63-dd506e5d1800', 'متوازي أضلاعٍ له زاويةٌ قائمةٌ وضلعان متتاليان متقايسان في آنٍ واحد. ما نوعُه؟', '[{"id":"a","text":"مستطيل فقط"},{"id":"b","text":"معيّن فقط"},{"id":"c","text":"متوازي أضلاع عاديّ"},{"id":"d","text":"مربّع"}]'::jsonb, 'd', 'الزاويةُ القائمة تجعله مستطيلًا، والضلعان المتتاليان المتقايسان يجعلانه معيّنًا؛ ما هو مستطيلٌ ومعيّنٌ معًا هو المربّع ✓. أخذُ شرطٍ واحدٍ فقط يعطي المستطيلَ أو المعيّنَ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56953f22-d112-56e4-ae91-ea88a13a3d5b', '45232de4-c65f-5c37-ae63-dd506e5d1800', 'أيٌّ من الشروط التالية لا يكفي وحدَه لإثبات أنّ رباعيًّا متوازي أضلاع؟', '[{"id":"a","text":"القطران متناصفان"},{"id":"b","text":"الأضلاعُ المتقابلة متقايسة مثنى مثنى"},{"id":"c","text":"زوجٌ واحدٌ فقط من الأضلاع متوازٍ"},{"id":"d","text":"الزاويتان المتقابلتان متقايستان مثنى مثنى"}]'::jsonb, 'c', 'توازي زوجٍ واحدٍ فقط من الأضلاع يعطي شبهَ منحرفٍ لا متوازيَ أضلاع؛ فهو لا يكفي وحدَه ✓. أمّا تناصفُ القطرَين وتقايسُ الأضلاع المتقابلة وتقايسُ الزاويتين المتقابلتين فكلٌّ منها شرطٌ كافٍ.', 4)
