INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83854956-2bc4-5bb3-8fd2-d71b8e0033c3', '45232de4-c65f-5c37-ae63-dd506e5d1800', 'في المستطيل ABCD كان القطرُ AC = 10 cm. ما طولُ القطر BD؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"10 cm"},{"id":"c","text":"20 cm"},{"id":"d","text":"لا يمكن تحديدُه"}]'::jsonb, 'b', 'في المستطيل القطران متقايسان، فـ BD = AC = 10 cm ✓. الخطأُ الشائع: أخذُ نصف القطر (5 cm) بالخلط مع تناصف الأقطار، أو مضاعفتُه (20 cm). المستطيلُ يميّزه تقايسُ الأقطار.', 5)
