INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2f69a7e-64f8-595f-b54b-97225a61860a', '45232de4-c65f-5c37-ae63-dd506e5d1800', 'معيّنٌ محيطُه 20 cm. ما طولُ ضلعه الواحد؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"10 cm"},{"id":"c","text":"4 cm"},{"id":"d","text":"80 cm"}]'::jsonb, 'a', 'أضلاعُ المعيّن الأربعةُ متقايسة، فطولُ الضلع = المحيط ÷ 4 = 20 ÷ 4 = 5 cm ✓. الخطأُ الشائع: القسمةُ على 2 (10 cm) بمعاملة المعيّن معاملةَ متوازي أضلاعٍ بضلعَين مختلفَين، أو ضربُ المحيط في 4 (80 cm).', 6)
