INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('694c0085-c8a4-5266-9b55-52daa7267ee8', '310837f0-97dc-5683-8c7e-625ff55ff507', 'متوازي أضلاعٍ قطراه متعامدان ومتناصفان لكنّهما غيرُ متقايسَين. ما نوعُه بالضبط؟', '[{"id":"a","text":"مربّع"},{"id":"b","text":"مستطيل"},{"id":"c","text":"متوازي أضلاع عاديّ"},{"id":"d","text":"معيّن"}]'::jsonb, 'd', 'التناصفُ خاصيةٌ لكلّ متوازي أضلاع، والتعامدُ يميّز المعيّن ✓. لو كان القطران متقايسَين أيضًا لصار مربّعًا؛ لكنّهما غيرُ متقايسَين فهو معيّنٌ لا مربّع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('079f825f-ce2d-5b37-a6cc-296e94c44e3f', '310837f0-97dc-5683-8c7e-625ff55ff507', 'قال تلميذٌ: «المستطيلُ قطراه متعامدان.» ما تصحيحُ العبارة؟', '[{"id":"a","text":"العبارةُ صحيحة"},{"id":"b","text":"قطرا المستطيل متقايسان لا متعامدَين؛ التعامدُ صفةُ المعيّن"},{"id":"c","text":"قطرا المستطيل غيرُ متناصفَين"},{"id":"d","text":"المستطيلُ ليس متوازيَ أضلاع"}]'::jsonb, 'b', 'الصحيح: قطرا المستطيل **متقايسان** (ويتناصفان)، أمّا التعامدُ فهو صفةُ المعيّن ✓. قطرا المستطيل متناصفان لأنّه متوازي أضلاع، والمستطيلُ حالةٌ خاصةٌ من متوازي الأضلاع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9f5bafe1-cf4b-5246-934c-02f6b8ec03ca', '310837f0-97dc-5683-8c7e-625ff55ff507', 'متوازي الأضلاع ABCD معيّنٌ، وكان AB = 2x وBC = x + 4 (بالـ cm). ما طولُ ضلعه؟', '[{"id":"a","text":"8 cm"},{"id":"b","text":"4 cm"},{"id":"c","text":"12 cm"},{"id":"d","text":"6 cm"}]'::jsonb, 'a', 'في المعيّن كلُّ الأضلاع متقايسة، والضلعان المتتاليان AB وBC متساويان: 2x = x + 4، ومنه x = 4. فطولُ الضلع = 2×4 = 8 cm ✓. الخطأُ الشائع: التوقّفُ عند x = 4، أو جمعُ الطولَين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba1b733b-cb31-580e-b58c-08ad410c0c73', '310837f0-97dc-5683-8c7e-625ff55ff507', 'رباعيٌّ قطراه متناصفان ومتقايسان لكنّهما غيرُ متعامدَين. ما نوعُه؟', '[{"id":"a","text":"معيّن"},{"id":"b","text":"مربّع"},{"id":"c","text":"مستطيل"},{"id":"d","text":"شبه منحرف"}]'::jsonb, 'c', 'التناصفُ يجعله متوازيَ أضلاع، والتقايسُ يجعله مستطيلًا ✓. لو كان القطران متعامدَين أيضًا لصار مربّعًا؛ التعامدُ وحدَه (دون تقايس) يعطي معيّنًا. غيرُ متعامدَين يستبعد المربّعَ والمعيّن.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af786eab-e136-53f4-bc88-93185f13c2b5', '310837f0-97dc-5683-8c7e-625ff55ff507', 'في متوازي الأضلاع ABCD نسبةُ الزاوية Â إلى الزاوية المتتاليةِ B̂ هي 4 إلى 5. ما قيسُ B̂؟', '[{"id":"a","text":"80°"},{"id":"b","text":"45°"},{"id":"c","text":"90°"},{"id":"d","text":"100°"}]'::jsonb, 'd', 'نضع Â = 4k وB̂ = 5k؛ المتتاليتان مجموعهما 180°: 4k + 5k = 180°، فـ 9k = 180° أي k = 20°. إذن B̂ = 5×20° = 100° (وÂ = 80°) ✓. الخطأُ الشائع: إعطاءُ قيمة Â = 80° بدل B̂.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89d6985c-4e41-5722-a01f-44273c7668f8', '310837f0-97dc-5683-8c7e-625ff55ff507', 'أيُّ العبارات التالية صحيحةٌ دائمًا؟', '[{"id":"a","text":"كلُّ مستطيلٍ معيّن"},{"id":"b","text":"كلُّ مربّعٍ مستطيلٌ ومعيّنٌ في آن"},{"id":"c","text":"كلُّ متوازي أضلاعٍ مستطيل"},{"id":"d","text":"كلُّ معيّنٍ مربّع"}]'::jsonb, 'b', 'المربّعُ يجمع صفتَي المستطيل (زوايا قائمة) والمعيّن (أضلاع متقايسة)، فكلُّ مربّعٍ مستطيلٌ ومعيّنٌ معًا ✓. أمّا العكسُ فليس صحيحًا: مستطيلٌ غيرُ مربّعٍ ليس معيّنًا، ومعيّنٌ غيرُ مربّعٍ ليس مربّعًا، ومتوازي الأضلاع العامُّ ليس مستطيلًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

