INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d5230d15-220b-51f5-aee8-3473168c2008', '8f2fc61b-3316-5190-bd65-c1ad8d5ebc96', 'تقاطع مستقيمان، فكانت إحدى الزوايا المتكوّنة قيسها 50°. ما قيس الزاوية المقابلة لها بالرأس؟', '[{"id":"a","text":"40°"},{"id":"b","text":"130°"},{"id":"c","text":"50°"},{"id":"d","text":"100°"}]'::jsonb, 'c', 'الزاويتان المتقابلتان بالرأس متساويتان دائمًا، فالأخرى 50° ✓. الخطأُ الشائع: أخذُ المتمّمة إلى 90° (40°) أو المكمّلة إلى 180° (130°)؛ التقابلُ بالرأس يعني التساوي لا التكامل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('980862ec-7785-536d-a1e2-708f4a607f25', '8f2fc61b-3316-5190-bd65-c1ad8d5ebc96', 'زاويتان متكاملتان (متجاورتان على استقامة واحدة)، إحداهما قيسها 110°. ما قيس الأخرى؟', '[{"id":"a","text":"70°"},{"id":"b","text":"110°"},{"id":"c","text":"90°"},{"id":"d","text":"250°"}]'::jsonb, 'a', 'المتكاملتان مجموعهما 180°، فالأخرى 180° − 110° = 70° ✓. الخطأُ الشائع: اعتبارُهما متساويتَين (110°)، أو الخلطُ بالتتام إلى 90°.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd9db75c-08c1-5985-b2d1-5aa3074063ab', '8f2fc61b-3316-5190-bd65-c1ad8d5ebc96', 'مستقيمان متوازيان (d)//(d'') يقطعهما قاطع. زاويتان متبادلتان داخليًّا، إحداهما قيسها 65°. ما قيس الأخرى؟', '[{"id":"a","text":"115°"},{"id":"b","text":"65°"},{"id":"c","text":"25°"},{"id":"d","text":"130°"}]'::jsonb, 'b', 'عند التوازي تكون الزاويتان المتبادلتان داخليًّا متساويتَين، فالأخرى 65° ✓. الخطأُ الأخطر: معاملتُها كأنّها متحالفة داخليًّا فتُطرح من 180° (115°)؛ المتبادلتان متساويتان لا متكاملتان.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f46f1a4-7887-5a58-8e5a-46b903263d3f', '8f2fc61b-3316-5190-bd65-c1ad8d5ebc96', 'في مثلّث، زاويتان قيسهما 40° و75°. ما قيس الزاوية الثالثة؟', '[{"id":"a","text":"65°"},{"id":"b","text":"115°"},{"id":"c","text":"75°"},{"id":"d","text":"245°"}]'::jsonb, 'a', 'مجموع زوايا المثلّث 180°، فالثالثة = 180° − (40° + 75°) = 180° − 115° = 65° ✓. الخطأُ الشائع: إعطاءُ مجموع الزاويتَين 115° بدل الفرق، أو نسيانُ أنّ المجموع 180°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33dd83a9-7dcd-5023-991b-6979fb04b290', '8f2fc61b-3316-5190-bd65-c1ad8d5ebc96', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متحالفتان داخليًّا (على نفس الجهة)، إحداهما قيسها 70°. ما قيس الأخرى؟', '[{"id":"a","text":"70°"},{"id":"b","text":"110°"},{"id":"c","text":"20°"},{"id":"d","text":"130°"}]'::jsonb, 'b', 'عند التوازي تكون الزاويتان المتحالفتان داخليًّا متكاملتَين، فالأخرى 180° − 70° = 110° ✓. الخطأُ الأشهر: اعتبارُهما متساويتَين (70°) بالخلط مع المتبادلتَين داخليًّا؛ المتحالفتان مجموعهما 180°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

