INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c421fd3b-0805-57fb-8d79-ead50f372a25', 'e37c0da8-3def-543d-a774-34f96607f45d', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متناظرتان، إحداهما قيسها 45°. ما قيس الأخرى؟', '[{"id":"a","text":"135°"},{"id":"b","text":"55°"},{"id":"c","text":"90°"},{"id":"d","text":"45°"}]'::jsonb, 'd', 'عند التوازي تكون الزاويتان المتناظرتان متساويتَين، فالأخرى 45° ✓. الخطأُ الشائع: طرحُها من 180° (135°) كأنّها متكاملة؛ المتناظرتان عند التوازي متساويتان.', 3)
