INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('797d3677-24d2-5a22-a349-a527311b7a7e', '4234ec21-6cc2-5ad3-8c8e-bb6e0d64e18d', 'زاويتان متقابلتان بالرأس، إحداهما قيسها 125°. ما قيس الأخرى؟', '[{"id":"a","text":"55°"},{"id":"b","text":"125°"},{"id":"c","text":"35°"},{"id":"d","text":"65°"}]'::jsonb, 'b', 'المتقابلتان بالرأس متساويتان، فالأخرى 125° ✓. الخطأُ الشائع: أخذُ المكمّلة إلى 180° (55°) بالخلط بين التقابل بالرأس والتكامل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ceb366b-7824-5ae1-b69d-569990e1cba1', '4234ec21-6cc2-5ad3-8c8e-bb6e0d64e18d', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متحالفتان داخليًّا (على نفس الجهة)، إحداهما قيسها 130°. ما قيس الأخرى؟', '[{"id":"a","text":"130°"},{"id":"b","text":"40°"},{"id":"c","text":"230°"},{"id":"d","text":"50°"}]'::jsonb, 'd', 'المتحالفتان داخليًّا عند التوازي متكاملتان، فالأخرى 180° − 130° = 50° ✓. الخطأُ الأشهر: اعتبارُهما متساويتَين (130°) بالخلط مع المتبادلتَين داخليًّا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('244a7997-5637-542a-ac41-f2e4864ea489', '4234ec21-6cc2-5ad3-8c8e-bb6e0d64e18d', 'رباعي زواياه الثلاث قيسها 100° و80° و90°. ما قيس الزاوية الرابعة؟', '[{"id":"a","text":"80°"},{"id":"b","text":"180°"},{"id":"c","text":"90°"},{"id":"d","text":"100°"}]'::jsonb, 'c', 'مجموع زوايا الرباعي (4 − 2)×180° = 360°، فالرابعة = 360° − (100° + 80° + 90°) = 360° − 270° = 90° ✓. الخطأُ الشائع: استعمالُ 180° كمجموع (فتظهر نتيجة سالبة) أو 540° بدل 360°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92278053-3f8a-5ad0-9aa7-93874f7a3173', '4234ec21-6cc2-5ad3-8c8e-bb6e0d64e18d', 'في مثلّث ABC، الزاوية Â قيسها 50°، والزاوية الخارجية عند الرأس C قيسها 120°. ما قيس الزاوية B̂؟', '[{"id":"a","text":"70°"},{"id":"b","text":"60°"},{"id":"c","text":"130°"},{"id":"d","text":"10°"}]'::jsonb, 'a', 'الزاوية الخارجية تساوي مجموع الزاويتَين الداخليّتَين غير المجاورتَين لها: 120° = Â + B̂ = 50° + B̂، فـ B̂ = 70° ✓. الخطأُ الشائع: طرحُ 120° من 180° ثمّ من Â، أو معاملةُ الخارجية كأنّها داخلية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f87aa9fe-5034-5b36-9607-ebd5349eea9d', '4234ec21-6cc2-5ad3-8c8e-bb6e0d64e18d', 'قاطعٌ يقطع مستقيمَين (d) و(d'') فيكوّن زاويتَين متناظرتَين قيسهما 3x و(x + 40) بالدرجات. إذا كان (d)//(d'')، فما قيس كلّ زاوية؟', '[{"id":"a","text":"20°"},{"id":"b","text":"60°"},{"id":"c","text":"70°"},{"id":"d","text":"40°"}]'::jsonb, 'b', 'المتناظرتان عند التوازي متساويتان: 3x = x + 40، فـ 2x = 40 و x = 20، وقيس كلّ زاوية 3×20 = 60° (أو 20 + 40 = 60°) ✓. الخطأُ الشائع: التوقّفُ عند x = 20 وتقديمُه كقيس الزاوية بدل حسابها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d36304e6-e782-5640-933a-6e84ede88533', '4234ec21-6cc2-5ad3-8c8e-bb6e0d64e18d', 'ما مجموع الزوايا الداخلية لمضلّع خماسي (5 أضلاع)؟', '[{"id":"a","text":"360°"},{"id":"b","text":"900°"},{"id":"c","text":"720°"},{"id":"d","text":"540°"}]'::jsonb, 'd', 'المجموع = (n − 2)×180° = (5 − 2)×180° = 3×180° = 540° ✓. الخطأُ الأشهر: استعمالُ n×180° = 900° بنسيان طرح 2، أو الخلطُ بالرباعي 360° أو السداسي 720°.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

