  ('cebf2d16-f13c-54f4-9b91-210fdb7e0384', 'd22ae00e-755d-5e63-8c0d-a3ff8a2e4b04', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متناظرتان، إحداهما قيسها 72°. ما قيس الأخرى؟', '[{"id":"a","text":"72°"},{"id":"b","text":"108°"},{"id":"c","text":"18°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'المتناظرتان عند التوازي متساويتان، فالأخرى 72° ✓. الخطأُ الشائع: طرحُها من 180° (108°) كأنّها متكاملة، أو من 90° (18°).', 2)
ON CONFLICT (id) DO UPDATE SET
