INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f23f4db5-f6f3-5461-8b9c-0db420c34de1', 'd22ae00e-755d-5e63-8c0d-a3ff8a2e4b04', 'مثلّث متساوي الساقَين، زاوية رأسه قيسها 40°. ما قيس كلّ زاوية من زاويتي القاعدة؟', '[{"id":"a","text":"140°"},{"id":"b","text":"40°"},{"id":"c","text":"70°"},{"id":"d","text":"100°"}]'::jsonb, 'c', 'زاويتا القاعدة متساويتان ومجموعهما 180° − 40° = 140°، فكلٌّ منهما 140° ÷ 2 = 70° ✓. الخطأُ الشائع: نسيانُ القسمة على 2 (140°) أو استعمالُ زاوية الرأس نفسها (40°).', 3)
ON CONFLICT (id) DO UPDATE SET
