  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b66d556-12a3-5043-a4fb-784b2abf6558', 'd22ae00e-755d-5e63-8c0d-a3ff8a2e4b04', 'ما مجموع الزوايا الداخلية لمضلّع سداسي (6 أضلاع)؟', '[{"id":"a","text":"540°"},{"id":"b","text":"720°"},{"id":"c","text":"1080°"},{"id":"d","text":"360°"}]'::jsonb, 'b', 'المجموع = (6 − 2)×180° = 4×180° = 720° ✓. الخطأُ الأشهر: استعمالُ 6×180° = 1080° بنسيان طرح 2، أو الخلطُ بالخماسي 540°.', 4)
ON CONFLICT (id) DO UPDATE SET
