INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29dcf472-398e-54ba-a0ca-806b3b270af3', 'd22ae00e-755d-5e63-8c0d-a3ff8a2e4b04', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متبادلتان داخليًّا، قيس إحداهما 3x وقيس الأخرى 66°. ما قيمة x؟', '[{"id":"a","text":"66"},{"id":"b","text":"33"},{"id":"c","text":"198"},{"id":"d","text":"22"}]'::jsonb, 'd', 'المتبادلتان داخليًّا عند التوازي متساويتان: 3x = 66، فـ x = 66 ÷ 3 = 22 ✓. الخطأُ الشائع: أخذُ x = 66 دون قسمة، أو ضربُ 3×66 = 198 بدل القسمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
