  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46474ae1-6cc0-5baf-9050-55a6c5859769', 'd22ae00e-755d-5e63-8c0d-a3ff8a2e4b04', 'زاويتان متتامّتان، إحداهما قيسها 30°. ما قيس الأخرى؟', '[{"id":"a","text":"60°"},{"id":"b","text":"150°"},{"id":"c","text":"70°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'المتتامّتان مجموعهما 90°، فالأخرى 90° − 30° = 60° ✓. الخطأُ الأشهر: الخلطُ بالمتكاملتَين والطرحُ من 180° (150°)؛ التتامّ إلى 90° لا 180°.', 6)
