INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92082649-95a6-581f-bb1e-3d170282103b', 'd2883264-6d36-5d98-a586-01ec33362bd5', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متحالفتان داخليًّا قيسهما (2x + 10) و(x + 20) بالدرجات. ما قيمة x؟', '[{"id":"a","text":"10"},{"id":"b","text":"50"},{"id":"c","text":"150"},{"id":"d","text":"30"}]'::jsonb, 'b', 'المتحالفتان داخليًّا عند التوازي متكاملتان: (2x + 10) + (x + 20) = 180، فـ 3x + 30 = 180 و 3x = 150 و x = 50 ✓ (الزاويتان 110° و70°، مجموعهما 180°). الخطأُ الأخطر: مساواةُ الزاويتَين 2x + 10 = x + 20 → x = 10 بالخلط مع المتبادلتَين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4650f1ce-b41f-5080-9f44-9f620880eab5', 'd2883264-6d36-5d98-a586-01ec33362bd5', 'في مثلّث ABC، الزاوية Â تساوي ضعف الزاوية B̂، والزاوية Ĉ قيسها 60°. ما قيس الزاوية Â؟', '[{"id":"a","text":"40°"},{"id":"b","text":"120°"},{"id":"c","text":"80°"},{"id":"d","text":"60°"}]'::jsonb, 'c', 'المجموع 180°: 2B̂ + B̂ + 60° = 180°، فـ 3B̂ = 120° و B̂ = 40°، ومنه Â = 2×40° = 80° ✓. الخطأُ الشائع: التوقّفُ عند B̂ = 40° وتقديمُه كجواب بدل حساب Â.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9e82ff49-40f4-57b7-9b33-e5e7a016f9ad', 'd2883264-6d36-5d98-a586-01ec33362bd5', 'مضلّع منتظم مجموع زواياه الداخلية 1080°. كم عدد أضلاعه؟', '[{"id":"a","text":"8"},{"id":"b","text":"6"},{"id":"c","text":"10"},{"id":"d","text":"7"}]'::jsonb, 'a', '(n − 2)×180° = 1080°، فـ n − 2 = 1080 ÷ 180 = 6، ومنه n = 8 ✓. الخطأُ الشائع: قسمةُ 1080 ÷ 180 = 6 وتقديمُ 6 كجواب بنسيان إضافة 2.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7cf4a250-0bcd-5e7f-8380-5d8193cb1b75', 'd2883264-6d36-5d98-a586-01ec33362bd5', 'ما قيس كلّ زاوية داخلية في مضلّع سداسي منتظم (6 أضلاع)؟', '[{"id":"a","text":"720°"},{"id":"b","text":"108°"},{"id":"c","text":"60°"},{"id":"d","text":"120°"}]'::jsonb, 'd', 'الزاوية الواحدة = (n − 2)×180° ÷ n = 720° ÷ 6 = 120° ✓. الخطأُ الأشهر: تقديمُ المجموع 720° كزاوية واحدة، أو استعمالُ صيغة الخماسي 108°.', 4)
