INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb40751b-7f91-5029-a51f-0e9aa865cb58', 'd2883264-6d36-5d98-a586-01ec33362bd5', 'كتب تلميذٌ: «مجموع الزوايا الداخلية لمضلّع خماسي = 5×180° = 900°». أين الخطأ؟', '[{"id":"a","text":"لا خطأ، الحساب صحيح"},{"id":"b","text":"الخطأ في القاعدة: المجموع = (n − 2)×180° = 3×180° = 540°، لا n×180°"},{"id":"c","text":"الخطأ في الضرب: 5×180 = 850"},{"id":"d","text":"المجموع الصحيح 360°"}]'::jsonb, 'b', 'القاعدةُ الصحيحة (n − 2)×180°، فالمجموع = (5 − 2)×180° = 3×180° = 540° لا 900° ✓. الخطأُ هو استعمالُ n×180° بنسيان طرح 2. (سؤالُ اكتشاف خطأ: الخيارُ الصحيح يصف موضعَ الخطأ.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e796157-b7f8-5822-b466-086e2a50afdf', 'd2883264-6d36-5d98-a586-01ec33362bd5', 'المستقيمان (d) و(d'') متوازيان ويقطعهما قاطع. زاويةٌ على (d) قيسها 110°؛ نأخذ الزاوية المتناظرة معها على (d'') ثمّ الزاوية المجاورة لها المتكاملة معها على (d''). ما قيس هذه الأخيرة؟', '[{"id":"a","text":"110°"},{"id":"b","text":"35°"},{"id":"c","text":"70°"},{"id":"d","text":"55°"}]'::jsonb, 'c', 'المتناظرة عند التوازي تساوي 110°، ثمّ المجاورة لها المتكاملة معها = 180° − 110° = 70° ✓. الخطأُ الشائع: التوقّفُ عند 110° (نسيانُ خطوة التكامل)، أو خلطُ التكامل بالتتام.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
