INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec04c6d8-584e-5a45-a65f-128997223500', '8faba87a-8ce2-597c-9538-467a84f65d1b', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متناظرتان، إحداهما قيسها 88°. ما قيس الأخرى؟', '[{"id":"a","text":"92°"},{"id":"b","text":"88°"},{"id":"c","text":"2°"},{"id":"d","text":"178°"}]'::jsonb, 'b', 'المتناظرتان عند التوازي متساويتان، فالأخرى 88° ✓. الخطأُ الشائع: طرحُها من 180° (92°) كأنّها متكاملة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e82a3ccc-6805-5517-85c6-12f404f6b9e5', '8faba87a-8ce2-597c-9538-467a84f65d1b', 'زاويتان متقابلتان بالرأس قيسهما (x + 30) و(2x) بالدرجات. ما قيمة x؟', '[{"id":"a","text":"10"},{"id":"b","text":"15"},{"id":"c","text":"60"},{"id":"d","text":"30"}]'::jsonb, 'd', 'المتقابلتان بالرأس متساويتان: x + 30 = 2x، فـ x = 30 ✓ (كلٌّ منهما 60°). الخطأُ الشائع: مساواةُ مجموعهما بـ 180° (كأنّهما متكاملتان) بدل تساويهما.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('376f7a97-7863-56bf-849a-48f9311991af', '8faba87a-8ce2-597c-9538-467a84f65d1b', 'رباعي زواياه قيسها 3x و2x و4x و3x بالدرجات. ما قيمة x؟', '[{"id":"a","text":"30"},{"id":"b","text":"45"},{"id":"c","text":"36"},{"id":"d","text":"90"}]'::jsonb, 'a', 'مجموع زوايا الرباعي 360°: 3x + 2x + 4x + 3x = 12x = 360، فـ x = 30 ✓. الخطأُ الشائع: استعمالُ 180° كمجموع (12x = 180 → x = 15) بالخلط مع المثلّث.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('94944f6e-623f-5759-ade9-869bb23926aa', '8faba87a-8ce2-597c-9538-467a84f65d1b', 'قاطعٌ يقطع مستقيمَين (d) و(d'') فيكوّن زاويتَين متبادلتَين داخليًّا قيسهما (4x − 10) و(2x + 30) بالدرجات. إذا كان (d)//(d'')، فما قيمة x؟', '[{"id":"a","text":"10"},{"id":"b","text":"40"},{"id":"c","text":"20"},{"id":"d","text":"5"}]'::jsonb, 'c', 'المتبادلتان داخليًّا عند التوازي متساويتان: 4x − 10 = 2x + 30، فـ 2x = 40 و x = 20 ✓ (كلّ زاوية 70°). الخطأُ الشائع: جعلُ مجموعهما 180° (كأنّهما متحالفتان) بدل تساويهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44132f8c-4030-527d-ad30-3815df50a20a', '8faba87a-8ce2-597c-9538-467a84f65d1b', 'مثلّث زواياه بالنسبة 1 : 2 : 3. ما قيس الزاوية الكبرى؟', '[{"id":"a","text":"60°"},{"id":"b","text":"90°"},{"id":"c","text":"30°"},{"id":"d","text":"120°"}]'::jsonb, 'b', 'مجموع الأجزاء 1 + 2 + 3 = 6، والمجموع 180°، فقيمة الجزء الواحد 180° ÷ 6 = 30°؛ الكبرى = 3×30° = 90° ✓. الخطأُ الشائع: أخذُ الجزء الأوسط 60° كأكبر، أو تجاوزُ 180° بجمع خاطئ (120°).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3eba17e3-cca2-51cb-8ba4-203d66109a81', '8faba87a-8ce2-597c-9538-467a84f65d1b', 'ما قيس كلّ زاوية داخلية في مضلّع منتظم ثُماني (8 أضلاع)؟', '[{"id":"a","text":"135°"},{"id":"b","text":"1080°"},{"id":"c","text":"45°"},{"id":"d","text":"120°"}]'::jsonb, 'a', 'الزاوية الواحدة = (n − 2)×180° ÷ n = (8 − 2)×180° ÷ 8 = 1080° ÷ 8 = 135° ✓. الخطأُ الأشهر: تقديمُ المجموع 1080° كزاوية واحدة، أو استعمالُ صيغة السداسي 120°.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('414d836a-8afb-526a-bb45-25d32a990874', 'dc069921-eb84-505a-94b2-025b1413186e', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مضلّعات ومثلّثات متقدّمة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e0426af-2ec2-53be-baeb-2ab34bd35c87', '414d836a-8afb-526a-bb45-25d32a990874', 'مستقيمان متوازيان يقطعهما قاطع. زاويتان متحالفتان داخليًّا، الصغرى قيسها x والكبرى (x + 40) بالدرجات. ما قيس الكبرى؟', '[{"id":"a","text":"70°"},{"id":"b","text":"110°"},{"id":"c","text":"90°"},{"id":"d","text":"140°"}]'::jsonb, 'b', 'المتحالفتان داخليًّا عند التوازي متكاملتان: x + (x + 40) = 180، فـ 2x = 140 و x = 70؛ الكبرى = 70 + 40 = 110° ✓. الخطأُ الشائع: تقديمُ الصغرى 70° كجواب، أو مساواةُ الزاويتَين بالخلط مع المتبادلتَين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c2de966-f89b-53f2-8ca1-49b0a9a4192c', '414d836a-8afb-526a-bb45-25d32a990874', 'مثلّث ABC قائم في A. الزاوية الخارجية عند الرأس B قيسها 145°. ما قيس الزاوية Ĉ؟', '[{"id":"a","text":"55°"},{"id":"b","text":"35°"},{"id":"c","text":"90°"},{"id":"d","text":"145°"}]'::jsonb, 'a', 'الزاوية الخارجية عند B تساوي مجموع الزاويتَين غير المجاورتَين: 145° = Â + Ĉ = 90° + Ĉ، فـ Ĉ = 55° ✓ (أو: الزاوية الداخلية B̂ = 180° − 145° = 35°، ثمّ Ĉ = 180° − 90° − 35° = 55°). الخطأُ الشائع: أخذُ B̂ = 35° كجواب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85b7efff-2eeb-55b6-b721-5b65b380092d', '414d836a-8afb-526a-bb45-25d32a990874', 'مضلّع منتظم مجموع زواياه الداخلية 1440°. كم عدد أضلاعه؟', '[{"id":"a","text":"8"},{"id":"b","text":"10"},{"id":"c","text":"12"},{"id":"d","text":"9"}]'::jsonb, 'b', '(n − 2)×180° = 1440°، فـ n − 2 = 1440 ÷ 180 = 8، ومنه n = 10 ✓. الخطأُ الشائع: تقديمُ 8 (ناتج القسمة) كجواب بنسيان إضافة 2.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47557eff-85a9-5c21-83ec-d2e52d3069cd', '414d836a-8afb-526a-bb45-25d32a990874', 'مضلّع منتظم قيس كلّ زاوية داخلية فيه 150°. كم عدد أضلاعه؟', '[{"id":"a","text":"6"},{"id":"b","text":"10"},{"id":"c","text":"12"},{"id":"d","text":"8"}]'::jsonb, 'c', 'كلّ زاوية خارجية = 180° − 150° = 30°، ومجموع الزوايا الخارجية 360°، فعدد الأضلاع = 360° ÷ 30° = 12 ✓ (أو حلّ (n − 2)×180° ÷ n = 150 يعطي n = 12). الخطأُ الشائع: قسمةُ 360 ÷ 150 أو خلطُ الداخلية بالخارجية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cb839d84-06b4-5682-a675-f250d053055a', '414d836a-8afb-526a-bb45-25d32a990874', 'كتب تلميذٌ: «كلّ زاوية في مضلّع منتظم خماسي تساوي 540°». أين الخطأ؟', '[{"id":"a","text":"لا خطأ، القيمة صحيحة"},{"id":"b","text":"المجموع الصحيح 360°"},{"id":"c","text":"540° هو مجموع الزوايا كلِّها؛ الزاوية الواحدة = 540° ÷ 5 = 108°"},{"id":"d","text":"كلّ زاوية تساوي 90°"}]'::jsonb, 'c', '540° هو مجموعُ زوايا الخماسي كلِّها ((5 − 2)×180°)، أمّا الزاوية الواحدة في المنتظم فهي 540° ÷ 5 = 108° ✓. الخطأُ هو الخلطُ بين المجموع الكلّي والزاوية الواحدة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('00063780-71fc-56d5-8785-f2c0791fdaef', '414d836a-8afb-526a-bb45-25d32a990874', 'مثلّث زواياه قيسها 2x و3x و4x بالدرجات. ما نوع هذا المثلّث حسب زواياه؟', '[{"id":"a","text":"حادّ الزوايا"},{"id":"b","text":"قائم الزاوية"},{"id":"c","text":"منفرج الزاوية"},{"id":"d","text":"متساوي الأضلاع"}]'::jsonb, 'a', 'المجموع 180°: 2x + 3x + 4x = 9x = 180، فـ x = 20؛ الزوايا 40° و60° و80° كلُّها أصغر من 90°، فالمثلّث حادّ الزوايا ✓. الخطأُ الشائع: عدمُ حساب الزوايا والحكمُ من الأعداد 2 و3 و4 مباشرةً.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('950c4d0c-c544-56e2-b5d7-3d52044d6b50', 'c8c10e2d-2106-59cb-b4a1-05920b7c30c6', 'math-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
