INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af778635-cbb6-5c02-8b92-493b46838719', '950c4d0c-c544-56e2-b5d7-3d52044d6b50', 'مثلثان متقايسان (isométriques) هما مثلثان:', '[{"id":"a","text":"لهما نفس الشكل ونفس الحجم، وينطبق أحدهما تمامًا على الآخر"},{"id":"b","text":"لهما نفس الشكل مع إمكان اختلاف الحجم"},{"id":"c","text":"لهما نفس المحيط فقط دون شرطٍ على الزوايا"},{"id":"d","text":"لهما ضلعٌ واحدٌ مشترك على الأقلّ"}]'::jsonb, 'a', 'التقايسُ هو الانطباقُ التامّ: الأضلاعُ المتناظرة متقايسة والزوايا المتناظرة متقايسة ✓. نفسُ الشكل مع اختلاف الحجم هو التشابهُ لا التقايس؛ وتساوي المحيط أو وجودُ ضلعٍ مشترك لا يكفيان.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('539b962f-9200-5937-b404-ca50c1b4134b', '950c4d0c-c544-56e2-b5d7-3d52044d6b50', 'في المثلث ABC، ما هي الزاوية المحصورة بين الضلعين [AB] و[BC]؟', '[{"id":"a","text":"الزاوية A"},{"id":"b","text":"الزاوية B"},{"id":"c","text":"الزاوية C"},{"id":"d","text":"لا توجد زاوية محصورة"}]'::jsonb, 'b', 'الزاويةُ المحصورةُ بين ضلعين رأسُها هو الرأسُ المشترك بينهما؛ والرأسُ المشترك بين [AB] و[BC] هو B، فالزاويةُ المحصورةُ هي B ✓ (الحرفُ المتكرّر في اسمَي الضلعين).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('873a4b86-32ad-5b55-9c68-e1dfbbba6bff', '950c4d0c-c544-56e2-b5d7-3d52044d6b50', 'في مثلثين ABC و A''B''C'' لدينا: AB = A''B'' ; BC = B''C''، والزاوية B = الزاوية B''. بأيّة حالةٍ نستنتج تقايسهما؟', '[{"id":"a","text":"الحالة الأولى: ضلعان والزاوية المحصورة بينهما (ض ـ ز ـ ض)"},{"id":"b","text":"الحالة الثانية: ضلعٌ والزاويتان المجاورتان له (ز ـ ض ـ ز)"},{"id":"c","text":"الحالة الثالثة: الأضلاع الثلاثة (ض ـ ض ـ ض)"},{"id":"d","text":"لا تنطبق أيّ حالة"}]'::jsonb, 'a', 'الزاوية B محصورةٌ بين الضلعين [AB] و[BC] (رأسُها B المشترك بينهما)، ولدينا هذان الضلعان متقايسان، فتنطبق الحالةُ الأولى (ضلعان والزاوية المحصورة بينهما) ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('76738366-f347-5ab8-913e-b4612e55a164', '950c4d0c-c544-56e2-b5d7-3d52044d6b50', 'المثلثان MNP و M''N''P'' متقايسان بالتناظر M↔M'' ; N↔N'' ; P↔P''. إذا كان MN = 8 cm فما طول [M''N'']؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"لا يمكن معرفته"},{"id":"c","text":"8 cm"},{"id":"d","text":"16 cm"}]'::jsonb, 'c', '[MN] و[M''N''] ضلعان متناظران (M↔M'' و N↔N'')، وفي المثلثين المتقايسين تتساوى الأضلاعُ المتناظرة، فـ M''N'' = MN = 8 cm ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d8c10d8-72c3-5e7b-b561-43e57145bc0a', '950c4d0c-c544-56e2-b5d7-3d52044d6b50', 'قال تلميذ: «إذا تساوت زوايا مثلثٍ مع زوايا مثلثٍ آخر مثنى مثنى فالمثلثان متقايسان.» هل قولُه صحيح؟', '[{"id":"a","text":"صحيح، تساوي الزوايا يكفي للتقايس"},{"id":"b","text":"خطأ، تساوي الزوايا يعطي التشابهَ فقط؛ قد يكون لأحدهما حجمٌ أكبر"},{"id":"c","text":"صحيح فقط إذا كان المثلثان قائمين"},{"id":"d","text":"خطأ، لأنّ مجموع الزوايا لا يساوي 180°"}]'::jsonb, 'b', 'الزوايا المتقايسة مثنى مثنى تعطي مثلثين متشابهين (نفسُ الشكل) لكنْ قد يختلف حجمُهما، فليسا بالضرورة متقايسين ✓. يلزم معطًى واحدٌ على الأقلّ عن طول ضلع. (مجموعُ الزوايا يبقى 180° في كليهما.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('07b610bf-6b0e-59b6-9ffa-1eff69efacc4', 'c8c10e2d-2106-59cb-b4a1-05920b7c30c6', 'math-8eme', '⭐ تمرين: أساسيات تقايس المثلثات', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
