INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99a4e938-c722-5b37-8f5c-3d90b4174669', '07b610bf-6b0e-59b6-9ffa-1eff69efacc4', 'المثلثان ABC و A''B''C'' متقايسان بالتناظر A↔A'' ; B↔B'' ; C↔C''. أيّ العبارات صحيحة؟', '[{"id":"a","text":"الأضلاع المتناظرة متقايسة والزوايا المتناظرة متقايسة"},{"id":"b","text":"الأضلاع فقط متقايسة أمّا الزوايا فقد تختلف"},{"id":"c","text":"الزوايا فقط متقايسة أمّا الأضلاع فقد تختلف"},{"id":"d","text":"المحيطان مختلفان بالضرورة"}]'::jsonb, 'a', 'في مثلثين متقايسين ينطبق أحدهما على الآخر تمامًا، فتتقايس الأضلاعُ المتناظرة **و** الزوايا المتناظرة معًا ✓ (ويكون المحيطان متساويين).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdf2eff1-b0c2-5bd7-aa08-363af6c216ad', '07b610bf-6b0e-59b6-9ffa-1eff69efacc4', 'الزاوية المحصورة بين الضلعين [CA] و[CB] في المثلث ABC هي:', '[{"id":"a","text":"الزاوية A"},{"id":"b","text":"الزاوية B"},{"id":"c","text":"الزاوية C"},{"id":"d","text":"لا يمكن تحديدها دون معرفة أطوال الأضلاع"}]'::jsonb, 'c', 'رأسُ الزاوية المحصورة هو الرأسُ المشترك بين الضلعين؛ والحرفُ المتكرّر في [CA] و[CB] هو C، فالزاويةُ المحصورةُ هي C ✓. وتُحدَّد من الرأس المشترك وحده، دون حاجةٍ إلى أطوال الأضلاع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('544452fc-d3f0-5e93-97ad-dcf470f8b676', '07b610bf-6b0e-59b6-9ffa-1eff69efacc4', 'مثلثان ABC و A''B''C'': AB = A''B'' ; BC = B''C'' ; CA = C''A''. الحالة التي تُثبت تقايسهما هي:', '[{"id":"a","text":"الحالة الأولى (ض ـ ز ـ ض)"},{"id":"b","text":"الحالة الثانية (ز ـ ض ـ ز)"},{"id":"c","text":"لا تنطبق أيّ حالة"},{"id":"d","text":"الحالة الثالثة: الأضلاع الثلاثة (ض ـ ض ـ ض)"}]'::jsonb, 'd', 'الأضلاعُ الثلاثة متقايسةٌ مثنى مثنى، فهذه هي الحالةُ الثالثة (ض ـ ض ـ ض) ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a566812-0d5f-5538-bd22-8a789de3c2ad', '07b610bf-6b0e-59b6-9ffa-1eff69efacc4', 'المثلثان RST و R''S''T'' متقايسان (R↔R'' ; S↔S'' ; T↔T''). إذا كانت الزاوية S = 55° فما قياس الزاوية S''؟', '[{"id":"a","text":"35°"},{"id":"b","text":"55°"},{"id":"c","text":"125°"},{"id":"d","text":"لا يمكن معرفته"}]'::jsonb, 'b', 'الزاويتان S و S'' متناظرتان، وفي المثلثين المتقايسين تتقايس الزوايا المتناظرة، فـ S'' = S = 55° ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d5e3172-6aff-5b41-a365-fcc131bbcad2', '07b610bf-6b0e-59b6-9ffa-1eff69efacc4', 'مثلثان ABC و A''B''C'': الزاوية B = الزاوية B'' ; BC = B''C''، الزاوية C = الزاوية C''. أيّ حالةٍ تنطبق؟', '[{"id":"a","text":"الحالة الأولى (ض ـ ز ـ ض)"},{"id":"b","text":"الحالة الثانية: ضلعٌ محصورٌ بين زاويتين (ز ـ ض ـ ز)"},{"id":"c","text":"الحالة الثالثة (ض ـ ض ـ ض)"},{"id":"d","text":"لا تنطبق أيّ حالة"}]'::jsonb, 'b', 'الضلع [BC] محصورٌ بين الزاويتين B و C (هما على طرفيه)، ولدينا الضلعُ والزاويتان متقايسة، فتنطبق الحالةُ الثانية (ز ـ ض ـ ز) ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f84df874-0cce-57da-9464-837d43d7bf6a', '07b610bf-6b0e-59b6-9ffa-1eff69efacc4', 'مثلثان لهما ضلعان متقايسان طولاهما 5 cm و7 cm، والزاوية المحصورة بينهما متقايسة وقياسها 60°. المثلثان:', '[{"id":"a","text":"متشابهان لا متقايسان"},{"id":"b","text":"لا يمكن الحكم عليهما"},{"id":"c","text":"متقايسان بالحالة الأولى (ض ـ ز ـ ض)"},{"id":"d","text":"متقايسان بالحالة الثالثة (ض ـ ض ـ ض)"}]'::jsonb, 'c', 'لدينا ضلعان متقايسان (5 cm و7 cm) والزاويةُ المحصورةُ بينهما متقايسة (60°)، وهذا بالضبط شرطُ الحالة الأولى (ض ـ ز ـ ض)، فالمثلثان متقايسان ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('899ced15-50c9-52b5-a8fe-9702a7411439', 'c8c10e2d-2106-59cb-b4a1-05920b7c30c6', 'math-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: الحالات والتطبيقات', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
