INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9c08adf-135f-59c5-9e14-d05c01ace01c', '899ced15-50c9-52b5-a8fe-9702a7411439', 'لاستعمال الحالة الأولى (ضلع ـ زاوية ـ ضلع) يجب أن تكون الزاوية المتقايسة:', '[{"id":"a","text":"محصورةً بين الضلعين المتقايسين"},{"id":"b","text":"مقابلةً لأكبر ضلع"},{"id":"c","text":"قائمةً دائمًا"},{"id":"d","text":"أيّ زاويةٍ في المثلث"}]'::jsonb, 'a', 'شرطُ الحالة الأولى أن تكون الزاويةُ المتقايسةُ **محصورةً** بين الضلعين المتقايسين (رأسُها هو الرأسُ المشترك بينهما) ✓. إن كانت غيرَ محصورةٍ فالحالةُ لا تنطبق.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4251c806-eb9f-5eac-9712-0b95418108da', '899ced15-50c9-52b5-a8fe-9702a7411439', 'مثلثان ABC و A''B''C'': AB = A''B'' ; AC = A''C''، والزاوية B = الزاوية B''. هل تنطبق الحالة الأولى (ض ـ ز ـ ض)؟', '[{"id":"a","text":"نعم، يكفي وجود ضلعين وزاوية"},{"id":"b","text":"لا، لأنّ الزاوية B ليست محصورةً بين الضلعين [AB] و[AC] (المحصورة بينهما هي A)"},{"id":"c","text":"نعم، بالحالة الثانية (ز ـ ض ـ ز)"},{"id":"d","text":"لا، لأنّ الضلعين غير متقايسين"}]'::jsonb, 'b', 'الضلعان المتقايسان هما [AB] و[AC]، والزاويةُ المحصورةُ بينهما هي A لا B. المعطاةُ هي B، فهذه حالةُ «ضلعان وزاويةٌ غيرُ محصورة» وهي لا تضمن التقايس ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('edd7dc55-bc3b-5ff7-aaf2-7727d1737f0a', '899ced15-50c9-52b5-a8fe-9702a7411439', 'المثلثان ABC و A''B''C'' متقايسان (A↔A'' ; B↔B'' ; C↔C''). علمنا AB = 6 cm ; BC = 9 cm ; CA = 7 cm. ما محيط المثلث A''B''C''؟', '[{"id":"a","text":"11 cm"},{"id":"b","text":"21 cm"},{"id":"c","text":"22 cm"},{"id":"d","text":"لا يمكن معرفته"}]'::jsonb, 'c', 'الأضلاعُ المتناظرة متقايسة، فأضلاعُ A''B''C'' هي أيضًا 6 و9 و7؛ ومحيطُه = 6 + 9 + 7 = 22 cm ✓ (المثلثان المتقايسان لهما نفسُ المحيط).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f862d945-e506-5c3f-b06a-a4a4bf37d20d', '899ced15-50c9-52b5-a8fe-9702a7411439', 'مثلثان لهما ضلعٌ متقايس طولُه 8 cm والزاويتان الواقعتان على طرفيه متقايستان. الحالة المستعملة هي:', '[{"id":"a","text":"الأولى (ض ـ ز ـ ض)"},{"id":"b","text":"الثالثة (ض ـ ض ـ ض)"},{"id":"c","text":"لا تنطبق أيّ حالة"},{"id":"d","text":"الثانية (ز ـ ض ـ ز): ضلعٌ محصورٌ بين زاويتين متقايستين"}]'::jsonb, 'd', 'لدينا ضلعٌ متقايس والزاويتان الواقعتان على طرفيه (المجاورتان له) متقايستان، وهذا شرطُ الحالة الثانية (ز ـ ض ـ ز) ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f1d27b3-2c8e-5e10-90b0-857946a35645', '899ced15-50c9-52b5-a8fe-9702a7411439', 'في مثلثٍ ABC حيث AB = AC، لتكن M منتصف [BC]. نقارن المثلثين ABM و ACM. أيّ المعطيات تُثبت تقايسهما بالحالة الثالثة (ض ـ ض ـ ض)؟', '[{"id":"a","text":"AB = AC ; BM = CM، والضلع [AM] مشترك"},{"id":"b","text":"الزاوية A مشتركة فقط"},{"id":"c","text":"BM = CM فقط"},{"id":"d","text":"لا يمكن إثبات التقايس"}]'::jsonb, 'a', 'AB = AC (الساقان) ; BM = CM (لأنّ M منتصفُ [BC])، و[AM] ضلعٌ مشترك بين المثلثين: ثلاثةُ أضلاعٍ متقايسة مثنى مثنى ⇐ الحالة الثالثة (ض ـ ض ـ ض) ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('823b55ff-fc42-5650-b2b9-4a741d46f8eb', '899ced15-50c9-52b5-a8fe-9702a7411439', 'من تقايس المثلثين ABM و ACM في السؤال السابق (A↔A ; B↔C ; M↔M)، ماذا نستنتج؟', '[{"id":"a","text":"الزاوية B = الزاوية A"},{"id":"b","text":"AB = BC"},{"id":"c","text":"الزاوية B = الزاوية C، و[AM] عموديٌّ على [BC]"},{"id":"d","text":"لا نستنتج شيئًا عن الزوايا"}]'::jsonb, 'c', 'من تناظر الزوايا: B ↔ C فـ الزاوية B = الزاوية C (زاويتا القاعدة في المثلث المتساوي الساقين). والزاويتان AMB و AMC متناظرتان ومتقايستان ومجموعُهما 180°، فكلٌّ منهما 90° ⇐ [AM] عموديٌّ على [BC] ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

