INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('748d2ff7-0748-5788-bbf7-dbd8a6863634', 'a6640f80-8754-5c9a-9d2a-4b8f1db750c0', 'مثلثان لهما نفس الشكل لكنّ حجم أحدهما ضعف الآخر. هما:', '[{"id":"a","text":"متشابهان لا متقايسان"},{"id":"b","text":"متقايسان"},{"id":"c","text":"متقايسان ومتشابهان معًا"},{"id":"d","text":"لا علاقة بينهما"}]'::jsonb, 'a', 'نفسُ الشكل مع اختلاف الحجم = تشابهٌ فقط. التقايسُ يشترط نفسَ الحجم أيضًا (انطباقٌ تامّ)، وهو غيرُ متحقّقٍ هنا ✓.', 1)
