INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0b0bc81b-278f-571f-8050-03436336bce7', 'a6640f80-8754-5c9a-9d2a-4b8f1db750c0', 'في المثلث DEF، الزاوية المحصورة بين الضلعين [ED] و[EF] هي:', '[{"id":"a","text":"الزاوية D"},{"id":"b","text":"الزاوية F"},{"id":"c","text":"الزاوية E"},{"id":"d","text":"لا توجد زاوية محصورة"}]'::jsonb, 'c', 'الحرفُ المتكرّر في [ED] و[EF] هو E، وهو الرأسُ المشترك، فالزاويةُ المحصورةُ بينهما هي E ✓.', 2)
