INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('065d1bc6-39e7-5dfc-a28d-12ac418cb31c', 'a6640f80-8754-5c9a-9d2a-4b8f1db750c0', 'مثلثان ABC و A''B''C'': AB = A''B'' = 5 cm ; BC = B''C'' = 6 cm ; AC = A''C'' = 4 cm. المثلثان متقايسان بالحالة:', '[{"id":"a","text":"الأولى (ض ـ ز ـ ض)"},{"id":"b","text":"الثانية (ز ـ ض ـ ز)"},{"id":"c","text":"غير متقايسين"},{"id":"d","text":"الثالثة: الأضلاع الثلاثة (ض ـ ض ـ ض)"}]'::jsonb, 'd', 'المعطياتُ الثلاث كلُّها أطوالُ أضلاعٍ متقايسة مثنى مثنى (5 ; 6 ; 4)، فهي الحالةُ الثالثة (ض ـ ض ـ ض) ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
