  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4db58d30-bc41-5d9f-9361-047bb2f3c913', 'a6640f80-8754-5c9a-9d2a-4b8f1db750c0', 'مثلثان GHI و G''H''I'': GH = G''H'' ; HI = H''I''، والزاوية H = الزاوية H''. الحالة المستعملة هي:', '[{"id":"a","text":"الثانية (ز ـ ض ـ ز)"},{"id":"b","text":"الأولى (ض ـ ز ـ ض): ضلعان والزاوية المحصورة بينهما"},{"id":"c","text":"الثالثة (ض ـ ض ـ ض)"},{"id":"d","text":"لا تنطبق أيّ حالة"}]'::jsonb, 'b', 'الزاوية H محصورةٌ بين الضلعين [GH] و[HI] (رأسُها H المشترك بينهما)، وهذان الضلعان متقايسان، فتنطبق الحالةُ الأولى (ض ـ ز ـ ض) ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2432cfd-6c18-5546-95ad-a8e33d4bb988', 'a6640f80-8754-5c9a-9d2a-4b8f1db750c0', 'المثلثان KLM و K''L''M'' متقايسان (K↔K'' ; L↔L'' ; M↔M''). الزاوية K = 70° والزاوية L = 60°. ما قياس الزاوية M''؟', '[{"id":"a","text":"130°"},{"id":"b","text":"70°"},{"id":"c","text":"50°"},{"id":"d","text":"60°"}]'::jsonb, 'c', 'في المثلث KLM: الزاوية M = 180° − 70° − 60° = 50°. والزاويتان M و M'' متناظرتان في مثلثين متقايسين، فـ M'' = M = 50° ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2b18d04-4286-5b85-b26c-63490f715837', 'a6640f80-8754-5c9a-9d2a-4b8f1db750c0', 'مثلثان زواياهما متقايسة مثنى مثنى (60° ; 60° ; 60°) لكنّنا لا نعرف أضلاعهما. هل هما بالضرورة متقايسان؟', '[{"id":"a","text":"لا، فقد يختلف الحجم؛ هما متشابهان وليسا بالضرورة متقايسين"},{"id":"b","text":"نعم، تساوي الزوايا كافٍ"},{"id":"c","text":"نعم، لأنّهما متساويا الأضلاع"},{"id":"d","text":"لا يمكن الجزم بأيّ شيء إطلاقًا"}]'::jsonb, 'a', 'تساوي الزوايا مثنى مثنى يعطي التشابهَ فقط؛ يمكن أن يكون أحدُ المثلثين المتساويي الأضلاع أكبرَ من الآخر. بلا معطًى عن طولٍ لا نضمن التقايس ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2734d311-f733-522b-9ce5-776f6a462d64', 'c8c10e2d-2106-59cb-b4a1-05920b7c30c6', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: تمييز الحالات والبراهين', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a3ab840-09e1-5cb4-9fa4-0032de40bdd7', '2734d311-f733-522b-9ce5-776f6a462d64', 'مثلثان ABC و A''B''C'': AB = A''B'' = 5 cm ; AC = A''C'' = 7 cm، والزاوية C = الزاوية C'' = 30°. هل نستطيع الجزم بتقايسهما بالحالة الأولى؟', '[{"id":"a","text":"نعم، لدينا ضلعان وزاوية فتنطبق الحالة الأولى"},{"id":"b","text":"لا، لأنّ الزاوية C ليست محصورةً بين الضلعين [AB] و[AC]؛ فهذه حالةُ «ضلعان وزاوية غير محصورة» ولا تضمن التقايس"},{"id":"c","text":"نعم، بالحالة الثالثة (ض ـ ض ـ ض)"},{"id":"d","text":"لا، لأنّ الأطوال مختلفة"}]'::jsonb, 'b', 'الضلعان المتقايسان هما [AB] و[AC]، والزاويةُ المحصورةُ بينهما هي A لا C. الزاويةُ المعطاة C غيرُ محصورةٍ بينهما، فالحالةُ الأولى لا تنطبق ولا تُضمن النتيجة ✓ (الأطوالُ المختلفة لا علاقة لها بالسبب).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7aa06ed-aded-5bfa-b6c6-608325a7f2f3', '2734d311-f733-522b-9ce5-776f6a462d64', 'كُتِب أنّ المثلث ABC يقايس المثلث A''B''C'' (بهذا الترتيب). أيّ تساوٍ صحيح؟', '[{"id":"a","text":"AB = B''C''"},{"id":"b","text":"الزاوية A = الزاوية B''"},{"id":"c","text":"AB = A''B'' والزاوية A = الزاوية A''"},{"id":"d","text":"AC = B''C''"}]'::jsonb, 'c', 'ترتيبُ الرؤوس يعطي التناظر A↔A'' ; B↔B'' ; C↔C''؛ ومنه [AB] يناظر [A''B''] والزاوية A تناظر A''، فـ AB = A''B'' والزاوية A = الزاوية A'' ✓. المطابقاتُ الأخرى تخلط بين رؤوسٍ غير متناظرة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82313c76-a678-5da6-993d-30cea0c3a209', '2734d311-f733-522b-9ce5-776f6a462d64', 'تتقاطع القطعتان [AC] و[BD] في نقطة O منتصفٍ لكلٍّ منهما. نقارن المثلثين OAB و OCD. ما الحالة، وماذا نستنتج؟', '[{"id":"a","text":"الحالة الأولى (ض ـ ز ـ ض) بزاويتين متقابلتين بالرأس، ونستنتج AB = CD"},{"id":"b","text":"الحالة الثالثة (ض ـ ض ـ ض)، ونستنتج AB = CD"},{"id":"c","text":"لا تنطبق أيّ حالة لأنّ الزاويتين مجهولتان"},{"id":"d","text":"الحالة الثانية (ز ـ ض ـ ز)، ونستنتج AB = AC"}]'::jsonb, 'a', 'OA = OC (O منتصفُ [AC]) و OB = OD (O منتصفُ [BD])، والزاويتان AOB و COD متقابلتان بالرأس فمتقايستان، وهي محصورةٌ بين الضلعين في كلّ مثلث ⇐ الحالة الأولى (ض ـ ز ـ ض) ⇐ الضلعان المتناظران AB و CD متقايسان ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fdab0d13-8000-5cb8-9fb5-ad7fb8d1ca5b', '2734d311-f733-522b-9ce5-776f6a462d64', 'قال تلميذ: «المثلثان متساويا الزوايا (45° ; 60° ; 75° لكليهما) إذن هما متقايسان.» أين الخطأ في استدلاله؟', '[{"id":"a","text":"لا خطأ، الاستدلال صحيح"},{"id":"b","text":"الخطأ: تساوي الزوايا يعطي التشابهَ فقط؛ يلزم تساوي طول ضلعٍ متناظرٍ على الأقلّ للتقايس"},{"id":"c","text":"الخطأ: مجموع الزوايا ليس 180°"},{"id":"d","text":"الخطأ: يجب أن تكون إحدى الزوايا قائمة"}]'::jsonb, 'b', 'مجموعُ الزوايا صحيحٌ (45 + 60 + 75 = 180)، لكنّ تساوي الزوايا وحده يعطي التشابهَ لا التقايس؛ قد يختلف الحجمُ ما لم يُعطَ طولُ ضلعٍ متناظر ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dba93b5e-c230-5fb0-b39a-4d998e4c78b1', '2734d311-f733-522b-9ce5-776f6a462d64', 'المثلثان ABC و A''B''C'' متقايسان (A↔A'' ; B↔B'' ; C↔C''). في ABC: الزاوية A = 40°، الزاوية B = 75°. ما قياس الزاوية C''؟', '[{"id":"a","text":"115°"},{"id":"b","text":"40°"},{"id":"c","text":"75°"},{"id":"d","text":"65°"}]'::jsonb, 'd', 'في المثلث ABC: الزاوية C = 180° − 40° − 75° = 65°. وبالتناظر C ↔ C'' فـ C'' = C = 65° ✓ (لا نجمع 40 و75 معًا لنحصل على 115).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5de96052-ceb2-5fad-b8fa-ed714c5b8cc9', '2734d311-f733-522b-9ce5-776f6a462d64', 'نريد إثبات تقايس مثلثين بالحالة الثانية (ز ـ ض ـ ز). لدينا الزاوية B = الزاوية B'' والزاوية C = الزاوية C''. أيّ ضلعٍ يجب أن يكون متقايسًا لتطبيق الحالة مباشرةً؟', '[{"id":"a","text":"[AB]"},{"id":"b","text":"[AC]"},{"id":"c","text":"[BC] المحصور بين الزاويتين B و C"},{"id":"d","text":"أيّ ضلعٍ لا يهمّ الموضع"}]'::jsonb, 'c', 'الحالةُ الثانية تشترط ضلعًا محصورًا **بين** الزاويتين المتقايستين؛ والضلعُ الواقع بين B و C هو [BC]، فيجب أن يكون BC = B''C'' ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('825acbaa-afd1-535d-9888-eeb275ce7829', 'c8c10e2d-2106-59cb-b4a1-05920b7c30c6', 'math-8eme', '📝 تدريب ⭐⭐⭐: مراجعةٌ شاملة للحالات الثلاث', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
