INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('42add603-7c40-5ee4-95da-3a40fe6c5277', '825acbaa-afd1-535d-9888-eeb275ce7829', 'حالات تقايس المثلثات الثلاث هي:', '[{"id":"a","text":"(ض ـ ز ـ ض)، (ز ـ ض ـ ز)، (ض ـ ض ـ ض)"},{"id":"b","text":"(ز ـ ز ـ ز)، (ض ـ ض ـ ض)، (ض ـ ز ـ ض)"},{"id":"c","text":"(ض ـ ز ـ ض) فقط"},{"id":"d","text":"(ز ـ ز ـ ز) و(ض ـ ض ـ ض)"}]'::jsonb, 'a', 'الحالاتُ الثلاث هي: ضلعان والزاوية المحصورة (ض ـ ز ـ ض)، ضلعٌ وزاويتاه المجاورتان (ز ـ ض ـ ز)، والأضلاع الثلاثة (ض ـ ض ـ ض) ✓. أمّا (ز ـ ز ـ ز) أي الزوايا الثلاث فليست حالةَ تقايس (تعطي تشابهًا فقط).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1481373e-d936-5ea9-9aec-dda0900fcb92', '825acbaa-afd1-535d-9888-eeb275ce7829', 'في أيّ الحالتين نضمن التقايس؟ (1) ضلعان متقايسان والزاوية المحصورة بينهما متقايسة. (2) ضلعان متقايسان وزاويةٌ غير محصورة بينهما متقايسة.', '[{"id":"a","text":"(2) فقط"},{"id":"b","text":"(1) فقط"},{"id":"c","text":"كلتاهما"},{"id":"d","text":"لا شيء منهما"}]'::jsonb, 'b', 'الحالةُ (1) هي بالضبط الحالة الأولى (ض ـ ز ـ ض) وتضمن التقايس. أمّا (2) فالزاويةُ غيرُ محصورة، وهذه المعطياتُ لا تضمن التقايس، فالجوابُ (1) فقط ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f02747c-2324-5529-85e8-cc25a2bb63d2', '825acbaa-afd1-535d-9888-eeb275ce7829', 'مثلثان ABC و A''B''C'': الزاوية A = الزاوية A'' = 50° ; AB = A''B'' = 6 cm، الزاوية B = الزاوية B'' = 60°. الحالة المستعملة:', '[{"id":"a","text":"الأولى (ض ـ ز ـ ض)"},{"id":"b","text":"الثانية (ز ـ ض ـ ز): الضلع [AB] محصورٌ بين الزاويتين A و B"},{"id":"c","text":"الثالثة (ض ـ ض ـ ض)"},{"id":"d","text":"لا تنطبق أيّ حالة"}]'::jsonb, 'b', 'الضلع [AB] محصورٌ بين الزاويتين A و B، والزاويتان والضلعُ متقايسة، فتنطبق الحالةُ الثانية (ز ـ ض ـ ز) ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ee7e385-bf74-52b7-acf9-3a573bba5b87', '825acbaa-afd1-535d-9888-eeb275ce7829', 'المثلثان PQR و P''Q''R'' متقايسان (P↔P'' ; Q↔Q'' ; R↔R''). إذا كان PQ = 4 cm ; QR = 5 cm ; RP = 6 cm، فما طول [Q''R'']؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"5 cm"},{"id":"d","text":"15 cm"}]'::jsonb, 'c', '[QR] يناظر [Q''R''] (Q↔Q'' ; R↔R'')، وفي المثلثين المتقايسين تتقايس الأضلاعُ المتناظرة، فـ Q''R'' = QR = 5 cm ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f291ce2-059e-544b-a772-4dfb985721a2', '825acbaa-afd1-535d-9888-eeb275ce7829', '[AM] منصّف الزاوية A في مثلثٍ ABC، وعلمنا AB = AC. نقارن ABM و ACM. ما المعطيات التي تعطي الحالة الأولى (ض ـ ز ـ ض)؟', '[{"id":"a","text":"BM = CM فقط"},{"id":"b","text":"الزاويتان B و C متقايستان فقط"},{"id":"c","text":"AB = AC، الزاوية BAM = الزاوية CAM، والضلع [AM] مشترك"},{"id":"d","text":"لا يمكن إثبات التقايس"}]'::jsonb, 'c', 'الضلعان [AB] و[AC] متقايسان (معطى)، والزاويةُ المحصورةُ بينهما عند A منصّفةٌ فـ الزاوية BAM = الزاوية CAM، و[AM] مشترك ⇐ ضلعان والزاوية المحصورة بينهما = الحالة الأولى (ض ـ ز ـ ض) ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35994069-1bfc-5513-a276-3c26fecab177', '825acbaa-afd1-535d-9888-eeb275ce7829', 'من تقايس ABM و ACM في السؤال السابق، ماذا نستنتج مباشرةً؟', '[{"id":"a","text":"AB = BM"},{"id":"b","text":"الزاوية B = الزاوية A"},{"id":"c","text":"لا نستنتج شيئًا"},{"id":"d","text":"BM = CM والزاوية AMB = الزاوية AMC = 90°"}]'::jsonb, 'd', 'من تناظر الأضلاع: [BM] يناظر [CM] فـ BM = CM (المنصّفُ من الرأس متوسّطٌ أيضًا). والزاويتان AMB و AMC متناظرتان ومتقايستان ومجموعُهما 180°، فكلٌّ منهما 90° ⇐ [AM] عموديٌّ على [BC] ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

