  ('3e50939b-8769-5875-ac6c-cbf624313670', 'c8c10e2d-2106-59cb-b4a1-05920b7c30c6', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: البراهين المركّبة والحالات المزيّفة', 4, 300, 60, 'challenge', 'admin', 6)
