INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a014eac-a463-563c-987d-b5cecddbe103', '3e50939b-8769-5875-ac6c-cbf624313670', 'يتقاطع المستقيمان (AB) و(CD) في نقطة I منتصفٍ لكلٍّ من [AB] و[CD]. لإثبات تقايس المثلثين IAC و IBD نستعمل:', '[{"id":"a","text":"الحالة الأولى (ض ـ ز ـ ض) بزاويتين متقابلتين بالرأس"},{"id":"b","text":"الحالة الثانية (ز ـ ض ـ ز)"},{"id":"c","text":"الحالة الثالثة (ض ـ ض ـ ض)"},{"id":"d","text":"لا تنطبق أيّ حالة"}]'::jsonb, 'a', 'IA = IB (I منتصفُ [AB]) و IC = ID (I منتصفُ [CD])، والزاويتان AIC و BID متقابلتان بالرأس فمتقايستان ومحصورتان بين الضلعين ⇐ الحالة الأولى (ض ـ ز ـ ض) ✓ (ومنه AC = BD).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dc3dd5ae-b896-507c-ad9e-6a819c31b0eb', '3e50939b-8769-5875-ac6c-cbf624313670', 'أيُّ مجموعةٍ من المعطيات لا تكفي وحدها لإثبات تقايس مثلثين؟', '[{"id":"a","text":"الأضلاع الثلاثة متقايسة مثنى مثنى"},{"id":"b","text":"ضلعان والزاوية المحصورة بينهما"},{"id":"c","text":"ثلاث زوايا متقايسة مثنى مثنى (فقط)"},{"id":"d","text":"ضلعٌ والزاويتان المجاورتان له"}]'::jsonb, 'c', 'الخيارات (a) و(b) و(d) هي الحالاتُ الثلاث المعتمدة وتضمن التقايس. أمّا الزوايا الثلاث وحدها (c) فتعطي التشابهَ لا التقايس، فهي لا تكفي ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('257edf76-ed85-56c3-bbeb-1863515a2189', '3e50939b-8769-5875-ac6c-cbf624313670', 'في مثلثٍ متساوي الساقين ABC (AB = AC)، أُخِذت E على [AB] و F على [AC] بحيث AE = AF. نقارن AEC و AFB. ما الحالة، وماذا نستنتج عن [EC] و[FB]؟', '[{"id":"a","text":"الحالة الثالثة (ض ـ ض ـ ض)، ونستنتج EC = FB"},{"id":"b","text":"لا تنطبق أيّ حالة"},{"id":"c","text":"الحالة الثانية (ز ـ ض ـ ز)، ونستنتج AE = AC"},{"id":"d","text":"الحالة الأولى (ض ـ ز ـ ض) بالزاوية A المشتركة، ونستنتج EC = FB"}]'::jsonb, 'd', 'في المثلثين AEC و AFB: AE = AF (معطى) ; AC = AB (معطى)، والزاوية A مشتركةٌ ومحصورةٌ بين هذين الضلعين في كلٍّ منهما ⇐ الحالة الأولى (ض ـ ز ـ ض)؛ ومنه الضلعان المتناظران EC و FB متقايسان: EC = FB ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36997480-95ac-5e22-bb52-108b8ce5e462', '3e50939b-8769-5875-ac6c-cbf624313670', '«مثلثان لهما ضلعان متقايسان (6 cm و9 cm) وزاويةٌ متقايسة (40°) مقابلةٌ للضلع 6 cm، إذن هما متقايسان.» قيّم العبارة.', '[{"id":"a","text":"صحيحة، فلدينا ضلعان وزاوية"},{"id":"b","text":"خاطئة، لأنّ الزاوية غير محصورةٍ بين الضلعين؛ فحالةُ «ضلعان وزاوية غير محصورة» لا تضمن التقايس"},{"id":"c","text":"خاطئة، لأنّ الزاوية 40° صغيرةٌ جدًّا"},{"id":"d","text":"صحيحة بالحالة الثالثة (ض ـ ض ـ ض)"}]'::jsonb, 'b', 'الزاويةُ 40° مقابلةٌ لأحد الضلعين، أي **غيرُ محصورةٍ** بين الضلعين المتقايسين؛ ومعطياتُ «ضلعان وزاوية غير محصورة» لا تضمن التقايس ✓ (قياسُ الزاوية بحدّ ذاته ليس هو السبب).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c16547d-a5ea-5dc1-b274-da7eaf7a47c4', '3e50939b-8769-5875-ac6c-cbf624313670', 'لدينا مثلثان ABC و A''B''C'' مع AB = A''B'' = 5 cm والزاوية A = الزاوية A'' = 60°. ما المعطى الإضافي الذي يجعلهما متقايسين بالحالة الأولى (ض ـ ز ـ ض) مباشرةً؟', '[{"id":"a","text":"BC = B''C''"},{"id":"b","text":"الزاوية B = الزاوية B''"},{"id":"c","text":"AC = A''C'' (الضلع الثاني المحصور مع [AB] حول الزاوية A)"},{"id":"d","text":"المحيطان متساويان"}]'::jsonb, 'c', 'الزاوية A محصورةٌ بين الضلعين [AB] و[AC]؛ ولدينا AB = A''B'' والزاوية A = الزاوية A''، فيكفي أن يتقايس الضلعُ الثاني المحيطُ بالزاوية أي AC = A''C'' لتكتمل الحالةُ الأولى (ض ـ ز ـ ض) ✓. (BC غيرُ محصورٍ مع [AB] حول A، والزاوية B تقود لحالةٍ أخرى.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a50906c-011a-56be-a32d-30f37dba144a', '3e50939b-8769-5875-ac6c-cbf624313670', 'أيُّ العبارات التالية صحيحةٌ دائمًا؟', '[{"id":"a","text":"المثلثان المتشابهان متقايسان دائمًا"},{"id":"b","text":"المثلثان المتقايسان متشابهان (نفس الشكل) وبنفس الحجم"},{"id":"c","text":"تساوي زاويتين يكفي للتقايس"},{"id":"d","text":"حالةُ «ضلعان وزاوية غير محصورة» تضمن التقايس"}]'::jsonb, 'b', 'كلُّ مثلثين متقايسين هما متشابهان أيضًا (نفسُ الشكل) وبنفس الحجم ✓. أمّا العكسُ فخطأ (المتشابهان قد يختلفان حجمًا)، وتساوي زاويتين أو «ضلعان وزاوية غير محصورة» لا يضمنان التقايس.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b0586565-2a16-5b5d-9364-740536276dc2', 'b98c1b4f-93c6-5efb-a388-9841b4c25226', 'math-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0ac336c4-d858-5437-9bac-79ee96307e65', 'b0586565-2a16-5b5d-9364-740536276dc2', 'المثلثُ ABC قائمُ الزاوية في A. ما هو الوتر؟', '[{"id":"a","text":"الضلع [BC]"},{"id":"b","text":"الضلع [AB]"},{"id":"c","text":"الضلع [AC]"},{"id":"d","text":"الرأس A"}]'::jsonb, 'a', 'الوترُ هو الضلعُ الذي يقابل الزاوية القائمة وهو أطولُ الأضلاع. الزاويةُ القائمة في A فالوترُ هو الضلعُ المقابلُ له [BC] ✓. الضلعان [AB] و[AC] هما الضلعان القائمان اللذان يكوّنان الزاوية القائمة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6aa48013-6828-5cf3-9221-e59ac2a0c1ba', 'b0586565-2a16-5b5d-9364-740536276dc2', 'مثلثٌ ABC قائمٌ في A، حيث AB = 3 وAC = 4. احسب طول الوتر BC.', '[{"id":"a","text":"7"},{"id":"b","text":"5"},{"id":"c","text":"25"},{"id":"d","text":"12"}]'::jsonb, 'b', 'بالنصّ المباشر: BC² = AB² + AC² = 3² + 4² = 9 + 16 = 25، فـ BC = √25 = 5 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 3 + 4 = 7، أو نسيانُ الجذر (BC = 25)، أو ضربُ الطولين 3 × 4 = 12.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a48e4fee-2805-5adc-959c-eebc829239ab', 'b0586565-2a16-5b5d-9364-740536276dc2', 'مثلثٌ ABC قائمٌ في A، وترُه BC = 13 وأحدُ ضلعيه القائمين AB = 5. احسب AC.', '[{"id":"a","text":"8"},{"id":"b","text":"144"},{"id":"c","text":"12"},{"id":"d","text":"18"}]'::jsonb, 'c', 'المجهولُ ضلعٌ قائم فنطرح: AC² = BC² − AB² = 13² − 5² = 169 − 25 = 144، فـ AC = √144 = 12 ✓. الأخطاءُ الشائعة: طرحُ الأطوال مباشرةً 13 − 5 = 8، أو نسيانُ الجذر (144)، أو الجمعُ بدل الطرح ثمّ جمعُ الأطوال 13 + 5 = 18.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('67c47c3a-066e-571b-8fe0-56407279a9e8', 'b0586565-2a16-5b5d-9364-740536276dc2', 'أيُّ ثلاثيّةِ أطوالٍ (بالـ cm) تكوّنُ مثلثًا قائمَ الزاوية؟', '[{"id":"a","text":"6, 8, 10"},{"id":"b","text":"4, 5, 6"},{"id":"c","text":"5, 6, 7"},{"id":"d","text":"2, 3, 4"}]'::jsonb, 'a', 'بالنصّ العكسي نقارن مربّعَ أطولِ ضلعٍ بمجموع مربّعَي الآخرين: 10² = 100 و6² + 8² = 36 + 64 = 100، متساويان ⇒ قائم ✓. أمّا 6² = 36 ≠ 4² + 5² = 41، و7² = 49 ≠ 5² + 6² = 61، و4² = 16 ≠ 2² + 3² = 13، فليست قائمة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5db9d27a-faca-5e12-9047-8de6bdb42b42', 'b0586565-2a16-5b5d-9364-740536276dc2', 'مثلثٌ ABC قائمٌ في A، حيث AB = 6 وAC = 8. احسب الوتر BC.', '[{"id":"a","text":"14"},{"id":"b","text":"100"},{"id":"c","text":"48"},{"id":"d","text":"10"}]'::jsonb, 'd', 'BC² = 6² + 8² = 36 + 64 = 100، فـ BC = √100 = 10 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 6 + 8 = 14، أو نسيانُ الجذر (100)، أو ضربُ الطولين 6 × 8 = 48.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('62106dd1-bc9d-5609-9142-1cd0d7fa6d00', 'b98c1b4f-93c6-5efb-a388-9841b4c25226', 'math-8eme', '⭐ تمرين: أساسيات مبرهنة فيثاغور', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
