  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7350f25c-8073-555e-a82a-582fe8683f34', '62106dd1-bc9d-5609-9142-1cd0d7fa6d00', 'في مثلثٍ قائم الزاوية، ما هو الوتر؟', '[{"id":"a","text":"أقصرُ ضلعٍ في المثلث"},{"id":"b","text":"الضلعُ المقابلُ للزاوية القائمة، وهو أطولُ الأضلاع"},{"id":"c","text":"أحدُ الضلعين المكوّنين للزاوية القائمة"},{"id":"d","text":"الضلعُ الأفقيّ دائمًا"}]'::jsonb, 'b', 'الوترُ يُعرَّف بأنّه الضلعُ المقابلُ للزاوية القائمة، وهو أطولُ الأضلاع الثلاثة ✓. الضلعان المكوّنان للزاوية القائمة هما الضلعان القائمان، وموضعُ الوتر لا علاقةَ له باتجاه الرسم (أفقيّ أو غيره).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dfa1eeb2-3ab6-5e81-83c2-f9e175b9fd9f', '62106dd1-bc9d-5609-9142-1cd0d7fa6d00', 'مثلثٌ ABC قائمٌ في A، AB = 5 وAC = 12. احسب الوتر BC.', '[{"id":"a","text":"13"},{"id":"b","text":"17"},{"id":"c","text":"169"},{"id":"d","text":"60"}]'::jsonb, 'a', 'BC² = AB² + AC² = 5² + 12² = 25 + 144 = 169، فـ BC = √169 = 13 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 5 + 12 = 17، أو نسيانُ الجذر (169)، أو ضربُ الطولين 5 × 12 = 60.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d559d4c-341d-5c94-b71a-10b428e5e634', '62106dd1-bc9d-5609-9142-1cd0d7fa6d00', 'مثلثٌ MNP قائمُ الزاوية في N. أيُّ ضلعٍ هو الوتر؟', '[{"id":"a","text":"الضلع [MN]"},{"id":"b","text":"الضلع [NP]"},{"id":"c","text":"الضلعان [MN] و[NP] معًا"},{"id":"d","text":"الضلع [MP]"}]'::jsonb, 'd', 'الوترُ يقابل الزاوية القائمة. الزاويةُ القائمة في N، فالوترُ هو الضلعُ المقابلُ للرأس N، أي [MP] ✓. الضلعان [MN] و[NP] يكوّنان الزاوية القائمة فهما الضلعان القائمان لا الوتر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('60d19ffd-0720-5351-93c3-51c990dde334', '62106dd1-bc9d-5609-9142-1cd0d7fa6d00', 'مثلثٌ ABC قائمٌ في A. أيُّ علاقةٍ صحيحةٌ حسب مبرهنة فيثاغور؟', '[{"id":"a","text":"AB² = BC² + AC²"},{"id":"b","text":"BC = AB + AC"},{"id":"c","text":"BC² = AB² + AC²"},{"id":"d","text":"BC² = AB² − AC²"}]'::jsonb, 'c', 'الزاويةُ القائمة في A فالوترُ [BC]، والنصُّ المباشر يقول مربّعُ الوتر = مجموعُ مربّعَي الضلعين القائمين: BC² = AB² + AC² ✓. العلاقةُ BC = AB + AC خطأٌ (الأطوالُ لا تُجمع بل مربّعاتُها)، وBC² = AB² − AC² قلبٌ للعملية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fb75cd8-d923-54a8-920c-d1689ff721d5', '62106dd1-bc9d-5609-9142-1cd0d7fa6d00', 'مثلثٌ ABC قائمٌ في A، الوتر BC = 5 والضلع AB = 3. احسب AC.', '[{"id":"a","text":"8"},{"id":"b","text":"4"},{"id":"c","text":"16"},{"id":"d","text":"2"}]'::jsonb, 'b', 'المجهولُ ضلعٌ قائم فنطرح: AC² = BC² − AB² = 5² − 3² = 25 − 9 = 16، فـ AC = √16 = 4 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 5 + 3 = 8، أو نسيانُ الجذر (16)، أو طرحُ الأطوال مباشرةً 5 − 3 = 2.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('12aa80c6-6405-5437-b768-8dbc267ecc26', '62106dd1-bc9d-5609-9142-1cd0d7fa6d00', 'أطوالُ أضلاعِ مثلثٍ هي 3 cm و4 cm و5 cm. هل هو قائمُ الزاوية؟', '[{"id":"a","text":"نعم، لأنّ 5² = 3² + 4² أي 25 = 9 + 16"},{"id":"b","text":"لا، لأنّ 5 ≠ 3 + 4"},{"id":"c","text":"نعم، لأنّ 3 + 4 = 7 أكبر من 5"},{"id":"d","text":"لا يمكن معرفةُ ذلك دون رسم المثلث"}]'::jsonb, 'a', 'بالنصّ العكسي نقارن مربّعَ أطولِ ضلعٍ (5) بمجموع مربّعَي الآخرين: 5² = 25 و3² + 4² = 9 + 16 = 25، متساويان ⇒ المثلثُ قائمُ الزاوية ✓. المقارنةُ يجب أن تكون على المربّعات لا على الأطوال، والنصُّ العكسي يُغني عن الرسم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f8a20b88-ee46-5389-bbd1-9f450e0a862f', 'b98c1b4f-93c6-5efb-a388-9841b4c25226', 'math-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: حسابُ الأطوال والنصّ العكسي', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b6422d36-244a-52ae-9d9a-3973b68cb68c', 'f8a20b88-ee46-5389-bbd1-9f450e0a862f', 'مثلثٌ ABC قائمٌ في A، AB = 8 وAC = 15. احسب الوتر BC.', '[{"id":"a","text":"23"},{"id":"b","text":"17"},{"id":"c","text":"289"},{"id":"d","text":"120"}]'::jsonb, 'b', 'BC² = 8² + 15² = 64 + 225 = 289، فـ BC = √289 = 17 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 8 + 15 = 23، أو نسيانُ الجذر (289)، أو ضربُ الطولين 8 × 15 = 120.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8941f387-766d-5d51-999a-8b85d9511650', 'f8a20b88-ee46-5389-bbd1-9f450e0a862f', 'مثلثٌ ABC قائمٌ في A، BC = 17 وAB = 8. احسب AC.', '[{"id":"a","text":"25"},{"id":"b","text":"225"},{"id":"c","text":"9"},{"id":"d","text":"15"}]'::jsonb, 'd', 'المجهولُ ضلعٌ قائم فنطرح: AC² = BC² − AB² = 17² − 8² = 289 − 64 = 225، فـ AC = √225 = 15 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 17 + 8 = 25، أو نسيانُ الجذر (225)، أو طرحُ الأطوال مباشرةً 17 − 8 = 9.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d392b77f-a9f2-5ef3-8f31-8fb5f58d0710', 'f8a20b88-ee46-5389-bbd1-9f450e0a862f', 'مثلثٌ ABC أطوالُ أضلاعه AB = 9، AC = 12، BC = 15. بيّن نوعَه ومكانَ الزاوية القائمة إن وُجدت.', '[{"id":"a","text":"قائمُ الزاوية في A"},{"id":"b","text":"قائمُ الزاوية في B"},{"id":"c","text":"قائمُ الزاوية في C"},{"id":"d","text":"ليس قائمَ الزاوية"}]'::jsonb, 'a', 'أطولُ ضلعٍ هو BC = 15: نقارن 15² = 225 بمجموع مربّعَي الآخرين 9² + 12² = 81 + 144 = 225، متساويان ⇒ المثلثُ قائم، وزاويتُه القائمة تقابل أطولَ ضلعٍ [BC] أي عند الرأس A ✓. الخطأُ الشائع: وضعُ الزاوية القائمة عند رأسٍ يقابل ضلعًا أقصر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35a2ff4b-8310-54a5-b4ed-5992880661e4', 'f8a20b88-ee46-5389-bbd1-9f450e0a862f', 'مثلثٌ ABC قائمٌ في A، AB = 2 وAC = 3. احسب الوتر BC.', '[{"id":"a","text":"√5"},{"id":"b","text":"√13"},{"id":"c","text":"13"},{"id":"d","text":"5"}]'::jsonb, 'b', 'BC² = 2² + 3² = 4 + 9 = 13، فـ BC = √13 (العددُ 13 ليس مربّعًا كاملًا فنترك الجواب بالصورة الجذرية) ✓. الأخطاءُ الشائعة: الطرحُ بدل الجمع 9 − 4 = 5 فيُكتب √5، أو نسيانُ الجذر (13)، أو جمعُ الأطوال 2 + 3 = 5.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc6f882f-9507-57a7-bbab-75d46512bb62', 'f8a20b88-ee46-5389-bbd1-9f450e0a862f', 'مستطيلٌ طولُه 12 cm وعرضُه 5 cm. احسب طولَ قُطره.', '[{"id":"a","text":"17"},{"id":"b","text":"169"},{"id":"c","text":"13"},{"id":"d","text":"60"}]'::jsonb, 'c', 'القُطرُ وترُ مثلثٍ قائمٍ ضِلعاه القائمان هما الطول والعرض: d² = 12² + 5² = 144 + 25 = 169، فـ d = √169 = 13 ✓. الأخطاءُ الشائعة: جمعُ البُعدين 12 + 5 = 17، أو نسيانُ الجذر (169)، أو ضربُ البُعدين 12 × 5 = 60 (وهي المساحةُ لا القُطر).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a8f5d2a-2ec7-59eb-94c1-3d70e838e2ed', 'f8a20b88-ee46-5389-bbd1-9f450e0a862f', 'مثلثٌ ABC قائمٌ في A، الوتر BC = 6 والضلع AB = 4. احسب AC.', '[{"id":"a","text":"2"},{"id":"b","text":"20"},{"id":"c","text":"√20"},{"id":"d","text":"√52"}]'::jsonb, 'c', 'المجهولُ ضلعٌ قائم فنطرح: AC² = BC² − AB² = 6² − 4² = 36 − 16 = 20، فـ AC = √20 ✓. الأخطاءُ الشائعة: طرحُ الأطوال مباشرةً 6 − 4 = 2، أو نسيانُ الجذر (20)، أو الجمعُ بدل الطرح 36 + 16 = 52 فيُكتب √52.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('77f3a946-050c-5172-a282-a67923c9d7ba', 'b98c1b4f-93c6-5efb-a388-9841b4c25226', 'math-8eme', '⭐⭐ تمرين مراجعة (نمط امتحان): المباشر والعكسي والأطوال', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
