INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99483ba7-8644-5a4b-b174-a63c6e958005', '77f3a946-050c-5172-a282-a67923c9d7ba', 'مثلثٌ ABC قائمٌ في A، AB = 6 وAC = 8. احسب BC.', '[{"id":"a","text":"14"},{"id":"b","text":"10"},{"id":"c","text":"100"},{"id":"d","text":"48"}]'::jsonb, 'b', 'BC² = 6² + 8² = 36 + 64 = 100، فـ BC = √100 = 10 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 6 + 8 = 14، أو نسيانُ الجذر (100)، أو ضربُ الطولين 6 × 8 = 48.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac12e6e2-36d5-570d-bbff-898bcc3de310', '77f3a946-050c-5172-a282-a67923c9d7ba', 'ما نصُّ المبرهنة العكسية لفيثاغور؟', '[{"id":"a","text":"إذا كان مربّعُ أطولِ ضلعٍ يساوي مجموعَ مربّعَي الضلعين الآخرين، فالمثلثُ قائمُ الزاوية"},{"id":"b","text":"إذا كان المثلثُ قائمًا، فمربّعُ الوتر يساوي مجموعَ مربّعَي الضلعين القائمين"},{"id":"c","text":"إذا تساوت أضلاعُ المثلث، فهو قائمُ الزاوية"},{"id":"d","text":"إذا كان أطولُ ضلعٍ يساوي مجموعَ الضلعين الآخرين، فالمثلثُ قائمُ الزاوية"}]'::jsonb, 'a', 'النصُّ العكسي ينطلق من الأطوال ليُثبت الزاوية القائمة: إن كان مربّعُ أطولِ ضلعٍ = مجموعَ مربّعَي الآخرين فالمثلثُ قائم ✓. الخيار (b) هو النصُّ المباشر (العكس)، والمقارنةُ تكون على المربّعات لا على الأطوال كما في (d)، وتساوي الأضلاع لا يدلّ على زاويةٍ قائمة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8d230b5-dc93-5aac-af7e-2b11a9ebbdd0', '77f3a946-050c-5172-a282-a67923c9d7ba', 'مثلثٌ ABC قائمٌ في A، BC = 17 وAC = 15. احسب AB.', '[{"id":"a","text":"2"},{"id":"b","text":"64"},{"id":"c","text":"8"},{"id":"d","text":"32"}]'::jsonb, 'c', 'المجهولُ ضلعٌ قائم فنطرح: AB² = BC² − AC² = 17² − 15² = 289 − 225 = 64، فـ AB = √64 = 8 ✓. الأخطاءُ الشائعة: طرحُ الأطوال مباشرةً 17 − 15 = 2، أو نسيانُ الجذر (64)، أو جمعُ الأطوال 17 + 15 = 32.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf182abd-0845-591c-87ba-139b6b7e020c', '77f3a946-050c-5172-a282-a67923c9d7ba', 'أطوالُ مثلثٍ هي 4 cm و6 cm و8 cm. هل هو قائمُ الزاوية؟', '[{"id":"a","text":"نعم، لأنّ 8² = 4² + 6²"},{"id":"b","text":"لا، لأنّ 8² = 64 لا يساوي 4² + 6² = 52"},{"id":"c","text":"نعم، لأنّ 4 + 6 = 10 أكبر من 8"},{"id":"d","text":"لا، لأنّ 8 ≠ 4 + 6"}]'::jsonb, 'b', 'بالنصّ العكسي نقارن مربّعَ أطولِ ضلعٍ (8) بمجموع مربّعَي الآخرين: 8² = 64 و4² + 6² = 16 + 36 = 52، وبما أنّ 64 ≠ 52 فالمثلثُ ليس قائمَ الزاوية ✓. المقارنةُ تكون على المربّعات لا على الأطوال، وكونُ مجموعِ ضلعين أكبرَ من الثالث شرطُ وجودِ المثلث لا شرطَ كونِه قائمًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c471a4e-7dbb-516b-9de5-7d6d19390937', '77f3a946-050c-5172-a282-a67923c9d7ba', 'سُلّمٌ طولُه 10 m مُسنَدٌ إلى جدارٍ عموديّ، وتبعُد قاعدتُه عن الجدار بـ 6 m. ما ارتفاعُ نقطةِ ملامسته للجدار؟', '[{"id":"a","text":"8"},{"id":"b","text":"4"},{"id":"c","text":"64"},{"id":"d","text":"16"}]'::jsonb, 'a', 'السُّلّمُ هو الوتر، والأرضُ والجدارُ ضلعان قائمان. الارتفاع h يحقّق h² = 10² − 6² = 100 − 36 = 64، فـ h = √64 = 8 ✓. الأخطاءُ الشائعة: طرحُ الأطوال 10 − 6 = 4، أو نسيانُ الجذر (64)، أو جمعُ الأطوال 10 + 6 = 16.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('928ae4c9-2088-5470-bab2-917028dd1c37', '77f3a946-050c-5172-a282-a67923c9d7ba', 'مثلثٌ ABC قائمٌ في A، AB = 7 وAC = 24. احسب الوتر BC.', '[{"id":"a","text":"31"},{"id":"b","text":"625"},{"id":"c","text":"168"},{"id":"d","text":"25"}]'::jsonb, 'd', 'BC² = 7² + 24² = 49 + 576 = 625، فـ BC = √625 = 25 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 7 + 24 = 31، أو نسيانُ الجذر (625)، أو ضربُ الطولين 7 × 24 = 168.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0ce28329-9601-5e43-877a-4dd5d5f91dae', 'b98c1b4f-93c6-5efb-a388-9841b4c25226', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: فيثاغور في وضعيّاتٍ مركّبة', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
