INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('00689d2a-1b78-52a1-952d-a563b7fe8f7f', '0ce28329-9601-5e43-877a-4dd5d5f91dae', 'مثلثٌ ABC أطوالُ أضلاعه AB = 20، BC = 29، AC = 21، وهو قائمُ الزاوية. في أيّ رأسٍ توجد الزاوية القائمة؟', '[{"id":"a","text":"في B"},{"id":"b","text":"في C"},{"id":"c","text":"ليس قائمَ الزاوية"},{"id":"d","text":"في A"}]'::jsonb, 'd', 'أطولُ ضلعٍ هو BC = 29 (الوتر): نتحقّق 29² = 841 و20² + 21² = 400 + 441 = 841، متساويان ⇒ قائم. الزاويةُ القائمة تقابل الوترَ [BC] فهي عند الرأس A ✓. الخطأُ الشائع: وضعُ الزاوية القائمة عند رأسٍ يقابل ضلعًا أقصر (B أو C).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6bf5a53-c2e8-51d5-b8b6-b194f174a9e1', '0ce28329-9601-5e43-877a-4dd5d5f91dae', 'مثلثٌ ABC قائمٌ في A، AB = 3 وAC = 5. احسب الوتر BC.', '[{"id":"a","text":"√34"},{"id":"b","text":"4"},{"id":"c","text":"34"},{"id":"d","text":"8"}]'::jsonb, 'a', 'BC² = 3² + 5² = 9 + 25 = 34، فـ BC = √34 (34 ليس مربّعًا كاملًا فنترك الصورة الجذرية) ✓. الأخطاءُ الشائعة: الطرحُ بدل الجمع 25 − 9 = 16 فيُكتب √16 = 4، أو نسيانُ الجذر (34)، أو جمعُ الأطوال 3 + 5 = 8.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('833d24fd-d7bf-5852-b390-82696322fcd7', '0ce28329-9601-5e43-877a-4dd5d5f91dae', 'مثلثٌ ABC قائمٌ في A، الوتر BC = 7 والضلع AB = 5. احسب AC.', '[{"id":"a","text":"√74"},{"id":"b","text":"√24"},{"id":"c","text":"2"},{"id":"d","text":"24"}]'::jsonb, 'b', 'المجهولُ ضلعٌ قائم فنطرح: AC² = BC² − AB² = 7² − 5² = 49 − 25 = 24، فـ AC = √24 ✓. الأخطاءُ الشائعة: الجمعُ بدل الطرح 49 + 25 = 74 فيُكتب √74، أو طرحُ الأطوال مباشرةً 7 − 5 = 2، أو نسيانُ الجذر (24).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4eb40591-7251-5ba4-851c-3f87eef2a0e9', '0ce28329-9601-5e43-877a-4dd5d5f91dae', 'مثلثٌ ABC قائمُ الزاوية في A، AB = 9 والوتر BC = 15. احسب مساحةَ المثلث.', '[{"id":"a","text":"108"},{"id":"b","text":"90"},{"id":"c","text":"54"},{"id":"d","text":"67.5"}]'::jsonb, 'c', 'نحسب الضلعَ القائم الثاني أوّلًا: AC² = BC² − AB² = 15² − 9² = 225 − 81 = 144، فـ AC = 12. المساحةُ = (AB × AC) ÷ 2 = (9 × 12) ÷ 2 = 108 ÷ 2 = 54 ✓. الأخطاءُ الشائعة: نسيانُ القسمة على 2 (108)، أو استعمالُ الوتر في المساحة (12 × 15) ÷ 2 = 90 أو (9 × 15) ÷ 2 = 67.5؛ المساحةُ تعتمد الضلعين القائمين فقط.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e4be6ca-b0f4-53e5-8177-88294e05bc5b', '0ce28329-9601-5e43-877a-4dd5d5f91dae', 'لحساب الوتر BC في مثلثٍ قائمٍ في A حيث AB = 9 وAC = 12، كتب تلميذٌ: BC = 9 + 12 = 21. أين الخطأ؟', '[{"id":"a","text":"جمعَ الأطوال مباشرةً؛ الصحيح BC² = 9² + 12² = 225 فـ BC = 15"},{"id":"b","text":"لا خطأ، BC = 21 صحيح"},{"id":"c","text":"كان عليه طرحُ الطولين: BC = 12 − 9 = 3"},{"id":"d","text":"الصحيح BC² = 225 فـ BC = 225"}]'::jsonb, 'a', 'مبرهنةُ فيثاغور تجمع **المربّعات** لا الأطوال: BC² = 9² + 12² = 81 + 144 = 225، ثمّ BC = √225 = 15 ✓. الخيار (c) طرحٌ خاطئ (الوترُ أكبرُ لا نطرح لحسابه)، والخيار (d) نسيانُ الجذر. (سؤالُ اكتشاف خطأ: الخيارُ الصحيح يصف موضعَ الخطأ والتصحيح.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('69c12e94-53f3-5a52-8d66-28fe99fad239', '0ce28329-9601-5e43-877a-4dd5d5f91dae', 'مثلثٌ أطوالُ أضلاعه 12 cm و16 cm و20 cm. تحقّقْ أنّه قائمُ الزاوية ثمّ احسب مساحتَه.', '[{"id":"a","text":"192"},{"id":"b","text":"120"},{"id":"c","text":"96"},{"id":"d","text":"160"}]'::jsonb, 'c', 'أطولُ ضلعٍ 20: نتحقّق 20² = 400 و12² + 16² = 144 + 256 = 400، متساويان ⇒ قائم، والضلعان القائمان هما 12 و16 (الوترُ 20). المساحةُ = (12 × 16) ÷ 2 = 192 ÷ 2 = 96 ✓. الأخطاءُ الشائعة: نسيانُ القسمة على 2 (192)، أو إشراكُ الوتر في المساحة (12 × 20) ÷ 2 = 120 أو (16 × 20) ÷ 2 = 160.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d2aa3cdd-19ba-5c4e-9180-d31ed661a408', 'b98c1b4f-93c6-5efb-a388-9841b4c25226', 'math-8eme', '📝 تدريب ⭐⭐⭐: مراجعةٌ شاملة (مباشر، عكسي، جذور)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
