  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cb3bd9bf-5cd3-5edb-8ecf-0d83ee093c98', 'd2aa3cdd-19ba-5c4e-9180-d31ed661a408', 'مثلثٌ ABC قائمٌ في A، AB = 9 وAC = 12. احسب BC.', '[{"id":"a","text":"21"},{"id":"b","text":"15"},{"id":"c","text":"225"},{"id":"d","text":"108"}]'::jsonb, 'b', 'BC² = 9² + 12² = 81 + 144 = 225، فـ BC = √225 = 15 ✓. الأخطاءُ الشائعة: جمعُ الأطوال 9 + 12 = 21، أو نسيانُ الجذر (225)، أو ضربُ الطولين 9 × 12 = 108.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a41a552e-1cb0-5c50-9902-c5f6ed0aba9a', 'd2aa3cdd-19ba-5c4e-9180-d31ed661a408', 'مثلثٌ ABC قائمٌ في A، BC = 10 وAB = 6. احسب AC.', '[{"id":"a","text":"8"},{"id":"b","text":"4"},{"id":"c","text":"64"},{"id":"d","text":"16"}]'::jsonb, 'a', 'المجهولُ ضلعٌ قائم فنطرح: AC² = BC² − AB² = 10² − 6² = 100 − 36 = 64، فـ AC = √64 = 8 ✓. الأخطاءُ الشائعة: طرحُ الأطوال 10 − 6 = 4، أو نسيانُ الجذر (64)، أو جمعُ الأطوال 10 + 6 = 16.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e1d0380-d97f-585d-b0d3-bcc873df3829', 'd2aa3cdd-19ba-5c4e-9180-d31ed661a408', 'أطوالُ مثلثٍ هي 7 cm و24 cm و25 cm. هل هو قائمُ الزاوية؟ وإن كان، فما الضلعُ الذي يمثّل الوتر؟', '[{"id":"a","text":"نعم، ووترُه الضلعُ الذي طولُه 25"},{"id":"b","text":"نعم، ووترُه الضلعُ الذي طولُه 24"},{"id":"c","text":"نعم، ووترُه الضلعُ الذي طولُه 7"},{"id":"d","text":"لا، ليس قائمَ الزاوية"}]'::jsonb, 'a', 'أطولُ ضلعٍ 25: نقارن 25² = 625 و7² + 24² = 49 + 576 = 625، متساويان ⇒ قائم. الوترُ هو أطولُ ضلعٍ ويقابل الزاوية القائمة، أي الضلعُ 25 ✓. الوترُ لا يكون أبدًا أحدَ الضلعين الأقصرين (24 أو 7).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('504abdcb-96d0-5234-8fd7-4e49ab6afcc8', 'd2aa3cdd-19ba-5c4e-9180-d31ed661a408', 'مثلثٌ ABC قائمٌ في A، AB = 2 وAC = 5. احسب BC.', '[{"id":"a","text":"√21"},{"id":"b","text":"√29"},{"id":"c","text":"29"},{"id":"d","text":"7"}]'::jsonb, 'b', 'BC² = 2² + 5² = 4 + 25 = 29، فـ BC = √29 (29 عددٌ أوّليّ فالجذرُ يُترك بصورته) ✓. الأخطاءُ الشائعة: الطرحُ بدل الجمع 25 − 4 = 21 فيُكتب √21، أو نسيانُ الجذر (29)، أو جمعُ الأطوال 2 + 5 = 7.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f16d089-4385-5ca7-bf54-7a2bca0025b9', 'd2aa3cdd-19ba-5c4e-9180-d31ed661a408', 'شاشةٌ مستطيلةٌ قُطرُها 17 inch وارتفاعُها 8 inch. ما عرضُها (طولُها الأفقي)؟', '[{"id":"a","text":"9"},{"id":"b","text":"225"},{"id":"c","text":"15"},{"id":"d","text":"25"}]'::jsonb, 'c', 'القُطرُ وترُ مثلثٍ قائمٍ ضِلعاه العرضُ والارتفاع: العرض² = 17² − 8² = 289 − 64 = 225، فالعرضُ = √225 = 15 ✓. الأخطاءُ الشائعة: طرحُ الأطوال 17 − 8 = 9، أو نسيانُ الجذر (225)، أو جمعُ الأطوال 17 + 8 = 25.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c16b686-bd92-5118-b4cc-7cdb42eae9d5', 'd2aa3cdd-19ba-5c4e-9180-d31ed661a408', 'مثلثٌ ABC قائمٌ في A، AB = 5 وAC = 12. احسب محيطَ المثلث.', '[{"id":"a","text":"17"},{"id":"b","text":"34"},{"id":"c","text":"60"},{"id":"d","text":"30"}]'::jsonb, 'd', 'نحسب الوترَ أوّلًا: BC² = 5² + 12² = 25 + 144 = 169 فـ BC = √169 = 13. المحيطُ = AB + AC + BC = 5 + 12 + 13 = 30 ✓. الأخطاءُ الشائعة: نسيانُ إضافة الوتر (5 + 12 = 17)، أو حسابُ الوتر خطأً بجمع الطولين BC = 5 + 12 = 17 ثمّ 5 + 12 + 17 = 34، أو ضربُ الضلعين 5 × 12 = 60.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('247e5a09-4627-5b73-9884-71f33d01de10', 'b98c1b4f-93c6-5efb-a388-9841b4c25226', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: البرهنة والحساب المتقدّم', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
