INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('722e147b-c771-5a06-99b3-c88880f7d155', '247e5a09-4627-5b73-9884-71f33d01de10', 'مثلثٌ ABC: AB = 40، AC = 9، BC = 41. أثبتْ أنّه قائمُ الزاوية وحدّدِ الرأسَ الذي توجد فيه الزاوية القائمة.', '[{"id":"a","text":"قائمٌ في B"},{"id":"b","text":"ليس قائمَ الزاوية"},{"id":"c","text":"قائمٌ في A"},{"id":"d","text":"قائمٌ في C"}]'::jsonb, 'c', 'أطولُ ضلعٍ هو BC = 41: نتحقّق 41² = 1681 و40² + 9² = 1600 + 81 = 1681، متساويان ⇒ قائم بالنصّ العكسي. الزاويةُ القائمة تقابل الوترَ [BC] فهي عند الرأس A ✓. الخطأُ الشائع: وضعُها عند رأسٍ يقابل ضلعًا أقصر (B أو C).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d0b7b71-cd20-5ec2-be10-95490fa515d2', '247e5a09-4627-5b73-9884-71f33d01de10', 'مثلثٌ ABC قائمٌ في A، الوتر BC = 8 والضلع AB = 5. احسب AC.', '[{"id":"a","text":"√39"},{"id":"b","text":"√89"},{"id":"c","text":"3"},{"id":"d","text":"39"}]'::jsonb, 'a', 'المجهولُ ضلعٌ قائم فنطرح: AC² = BC² − AB² = 8² − 5² = 64 − 25 = 39، فـ AC = √39 (39 ليس مربّعًا كاملًا) ✓. الأخطاءُ الشائعة: الجمعُ بدل الطرح 64 + 25 = 89 فيُكتب √89، أو طرحُ الأطوال 8 − 5 = 3، أو نسيانُ الجذر (39).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd3ce125-9c9a-55b6-a075-a14e8ef64934', '247e5a09-4627-5b73-9884-71f33d01de10', 'مثلثٌ ABC قائمٌ في A، حيث AB = x، AC = 8 والوتر BC = 10. ما قيمة x؟', '[{"id":"a","text":"36"},{"id":"b","text":"2"},{"id":"c","text":"6"},{"id":"d","text":"√164"}]'::jsonb, 'c', 'AB ضلعٌ قائم فنطرح: x² = BC² − AC² = 10² − 8² = 100 − 64 = 36، فـ x = √36 = 6 ✓. الأخطاءُ الشائعة: نسيانُ الجذر (36)، أو طرحُ الأطوال 10 − 8 = 2، أو الجمعُ بدل الطرح 100 + 64 = 164 فيُكتب √164.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9425003-43a1-531b-a6a6-fcb8170d9abd', '247e5a09-4627-5b73-9884-71f33d01de10', 'لِيتحقّق تلميذٌ أنّ مثلثًا أطوالُه 6، 8، 11 قائمُ الزاوية، كتب: 6² + 8² = 36 + 64 = 100، إذن قائم. أين الخطأ في استدلاله؟', '[{"id":"a","text":"قارن مربّعَي الضلعين الأقصرين فقط؛ يجب مقارنةُ 100 بمربّع أطولِ ضلعٍ 11² = 121، وبما أنّ 121 ≠ 100 فالمثلثُ ليس قائمًا"},{"id":"b","text":"لا خطأ، المثلثُ قائمُ الزاوية"},{"id":"c","text":"كان عليه جمعُ الأطوال 6 + 8 = 14 ومقارنتُها بـ 11"},{"id":"d","text":"الخطأ حسابيّ فقط: 36 + 64 = 90 لا 100"}]'::jsonb, 'a', 'النصُّ العكسي يتطلّب مقارنةَ مربّع **أطولِ** ضلعٍ (11) بمجموع مربّعَي الآخرين: 11² = 121 و6² + 8² = 100؛ وبما أنّ 121 ≠ 100 فالمثلثُ ليس قائمَ الزاوية ✓. حسابُ 36 + 64 = 100 صحيحٌ لكنّه لا يكفي؛ المقارنةُ يجب أن تشمل مربّعَ أطولِ ضلع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('05c58752-e608-5381-9b42-2dd8986a0581', '247e5a09-4627-5b73-9884-71f33d01de10', 'مثلثٌ ABC قائمٌ في A، AB = 8 والوتر BC = 17. احسب مساحةَ المثلث ABC.', '[{"id":"a","text":"120"},{"id":"b","text":"60"},{"id":"c","text":"68"},{"id":"d","text":"127.5"}]'::jsonb, 'b', 'نحسب الضلعَ القائم الثاني: AC² = BC² − AB² = 17² − 8² = 289 − 64 = 225 فـ AC = 15. المساحةُ = (AB × AC) ÷ 2 = (8 × 15) ÷ 2 = 120 ÷ 2 = 60 ✓. الأخطاءُ الشائعة: نسيانُ القسمة على 2 (120)، أو إشراكُ الوتر في المساحة (8 × 17) ÷ 2 = 68 أو (15 × 17) ÷ 2 = 127.5.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('97566ee3-03c8-579b-aad7-7540c432ceec', '247e5a09-4627-5b73-9884-71f33d01de10', 'مربّعٌ ABCD طولُ ضلعِه 6 cm. احسب طولَ قُطره AC.', '[{"id":"a","text":"12"},{"id":"b","text":"72"},{"id":"c","text":"√36"},{"id":"d","text":"√72"}]'::jsonb, 'd', 'القُطرُ AC وترُ المثلث القائم ABC حيث AB = BC = 6: AC² = 6² + 6² = 36 + 36 = 72، فـ AC = √72 ✓. الأخطاءُ الشائعة: جمعُ الضلعين 6 + 6 = 12، أو نسيانُ الجذر (72)، أو الطرحُ بدل الجمع 36 − 36 = 0 أو خلطُ العدد فيُكتب √36 = 6 (طولُ الضلع لا القطر).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

