INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f218c7ae-4037-5653-8377-78a38ad411b8', 'f258229c-e96a-5bc7-b906-c17dce1c48ee', 'المثلث ABC قائم الزاوية في A ووترُه [BC]. أين يقع مركز الدائرة المحيطة به؟', '[{"id":"a","text":"منتصف الوتر [BC]"},{"id":"b","text":"الرأس A (رأس الزاوية القائمة)"},{"id":"c","text":"منتصف الضلع [AB]"},{"id":"d","text":"نقطة تقاطع ارتفاعات المثلث"}]'::jsonb, 'a', 'في المثلث القائم مركزُ الدائرة المحيطة هو منتصفُ الوتر [BC] ✓، لأنّه يبعد بنفس المسافة عن الرؤوس الثلاثة. الخطأُ الأشهر: اختيارُ رأس الزاوية القائمة A بدل منتصف الوتر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0538b53f-0c0f-5e0f-a32e-e291483e4aa6', 'f258229c-e96a-5bc7-b906-c17dce1c48ee', 'المثلث ABC قائم في A ووترُه BC = 10 cm. النقطة I منتصف [BC] هي مركز الدائرة المحيطة. ما نصف قطر هذه الدائرة؟', '[{"id":"a","text":"10 cm"},{"id":"b","text":"5 cm"},{"id":"c","text":"20 cm"},{"id":"d","text":"2.5 cm"}]'::jsonb, 'b', 'الوترُ قطرٌ للدائرة، فنصفُ القطر يساوي نصفَ الوتر: R = 10⁄2 = 5 cm ✓. الخطأُ الشائع: أخذُ نصف القطر مساويًا للوتر كاملًا (10)، أو قسمتُه على 4 (2.5).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d246437-7542-5551-9552-93c72a154fe1', 'f258229c-e96a-5bc7-b906-c17dce1c48ee', 'المثلث ABC قائم في A، وI منتصف الوتر [BC]. أيّ مساواةٍ صحيحة دائمًا؟', '[{"id":"a","text":"IA = AB"},{"id":"b","text":"IA = BC"},{"id":"c","text":"IA = IB = IC"},{"id":"d","text":"IB = AC"}]'::jsonb, 'c', 'مركزُ الدائرة المحيطة I يبعد بنفس المسافة عن الرؤوس الثلاثة، فـ IA = IB = IC (وكلُّها تساوي نصفَ الوتر) ✓. الخطأُ الشائع: مساواةُ المتوسّط IA بالوتر كاملًا (IA = BC) بدل نصفه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
