INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cb149b6c-c104-556e-8cef-65c4092ba06d', 'f258229c-e96a-5bc7-b906-c17dce1c48ee', 'النقطة M من دائرةٍ قطرُها [BC]، وM تخالف B وC. ما نوع المثلث MBC؟', '[{"id":"a","text":"قائم الزاوية في B"},{"id":"b","text":"متساوي الساقين حتمًا"},{"id":"c","text":"مثلث أيٌّ لا يمكن تحديد نوعه"},{"id":"d","text":"قائم الزاوية في M"}]'::jsonb, 'd', 'بالمبرهنة العكسية: كلُّ مثلثٍ مرسومٍ في نصف دائرةٍ ووترُه قطرُها يكون قائم الزاوية عند الرأس الموجود على القوس، أي في M ✓. الخطأُ الشائع: وضعُ الزاوية القائمة عند أحد طرفَي القطر (B) بدل النقطة M.', 4)
