INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d97c585-5732-56c0-a7bc-4a72a3295cd5', 'f258229c-e96a-5bc7-b906-c17dce1c48ee', 'المثلث ABC قائم في A وBC = 8 cm. ما طول المتوسّط AI الصادر من A نحو الوتر (I منتصف [BC])؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"4 cm"},{"id":"c","text":"8 cm"},{"id":"d","text":"16 cm"}]'::jsonb, 'b', 'متوسّطُ الوتر في مثلثٍ قائم يساوي نصفَ الوتر: AI = 8⁄2 = 4 cm ✓ (لأنّ IA = IB = IC = نصف القطر). الخطأُ الشائع: أخذُ المتوسّط مساويًا للوتر كاملًا (8) أو ضعفَه (16).', 5)
