INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34f96918-282a-5ec1-88e3-8b8434417c1d', '65c05831-3608-5507-8e81-4a14a84b6994', 'المثلث ABC قائم في A ووترُه [BC]. مركز الدائرة المحيطة به هو:', '[{"id":"a","text":"الرأس A"},{"id":"b","text":"منتصف الضلع [AC]"},{"id":"c","text":"منتصف الوتر [BC]"},{"id":"d","text":"منتصف الضلع [AB]"}]'::jsonb, 'c', 'مركزُ الدائرة المحيطة بمثلثٍ قائم هو منتصفُ الوتر [BC] ✓، لأنّه على مسافةٍ واحدة من الرؤوس الثلاثة. الخطأُ الأشهر: اختيارُ رأس الزاوية القائمة A.', 1)
