INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8587ac35-9a67-58ad-8059-cc2bbb8c1466', '65c05831-3608-5507-8e81-4a14a84b6994', 'مثلثٌ قائم وترُه BC = 6 cm. ما نصف قطر دائرته المحيطة؟', '[{"id":"a","text":"3 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"12 cm"},{"id":"d","text":"1.5 cm"}]'::jsonb, 'a', 'نصفُ القطر يساوي نصفَ الوتر لأنّ الوتر قطرٌ للدائرة: R = 6⁄2 = 3 cm ✓. الخطأُ الشائع: أخذُ R مساويًا للوتر (6) أو ضعفَه (12).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
