INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('179d8362-3503-5427-bae8-3efe9c39b070', '65c05831-3608-5507-8e81-4a14a84b6994', 'المثلث ABC قائم في A، وI منتصف [BC]. المسافات IA وIB وIC هي:', '[{"id":"a","text":"مختلفةٌ كلُّها"},{"id":"b","text":"متساوية"},{"id":"c","text":"IA أكبرُ من IB"},{"id":"d","text":"IA أصغرُ من IB"}]'::jsonb, 'b', 'النقطة I مركزُ الدائرة المحيطة، فهي تبعد بنفس المسافة عن الرؤوس الثلاثة: IA = IB = IC ✓. جميعُها تساوي نصفَ القطر.', 3)
ON CONFLICT (id) DO UPDATE SET
