  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d27cd0a-b8f9-58fa-9a05-a8ed732b1585', '65c05831-3608-5507-8e81-4a14a84b6994', 'دائرةٌ مركزها I ونصف قطرها 5 cm، والوتر [BC] قطرٌ فيها. ما طول BC؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"20 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"2.5 cm"}]'::jsonb, 'c', 'القطرُ يساوي ضعفَ نصف القطر: BC = 2 × 5 = 10 cm ✓. الخطأُ الشائع: أخذُ الوتر مساويًا لنصف القطر (5) بدل ضعفه.', 4)
