INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b89323ec-ce2c-5edd-a730-cd8d4b9a584d', '2e00fa20-a744-5c4a-b6e2-759d76890c59', 'المثلث ABC قائم في A وBC = 20 cm. ما نصف قطر دائرته المحيطة؟', '[{"id":"a","text":"10 cm"},{"id":"b","text":"20 cm"},{"id":"c","text":"40 cm"},{"id":"d","text":"5 cm"}]'::jsonb, 'a', 'الوترُ قطرٌ للدائرة، فنصفُ القطر يساوي نصفَه: R = 20⁄2 = 10 cm ✓. الخطأُ الشائع: أخذُ R مساويًا للوتر (20) أو ضعفَه (40).', 1)
