INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0600d321-493f-54e3-9b30-3bb202e94437', '2e00fa20-a744-5c4a-b6e2-759d76890c59', 'المثلث ABC قائم في A، AB = 8 cm وAC = 6 cm. احسب نصف قطر الدائرة المحيطة.', '[{"id":"a","text":"7 cm"},{"id":"b","text":"5 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"3 cm"}]'::jsonb, 'b', 'نحسب الوتر بفيثاغور: BC = √(8² + 6²) = √(64 + 36) = √100 = 10 cm، ثمّ R = BC⁄2 = 5 cm ✓. الخطأُ الشائع: نسيانُ القسمة على 2 فيبقى R = 10، أو حسابُ نصف مجموع الضلعين (8+6)⁄2 = 7.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a919c840-c83f-51eb-b127-5e656c2a0361', '2e00fa20-a744-5c4a-b6e2-759d76890c59', 'النقطة M من دائرةٍ مركزُها O ونصفُ قطرها 5 cm، و[AB] قطرٌ فيها. عُلم أنّ AM = 8 cm. احسب BM.', '[{"id":"a","text":"4 cm"},{"id":"b","text":"13 cm"},{"id":"c","text":"6 cm"},{"id":"d","text":"2 cm"}]'::jsonb, 'c', 'القطرُ AB = 2 × 5 = 10 cm، والمثلث AMB قائمٌ في M (مرسومٌ في نصف دائرة وترُه قطر). بفيثاغور: BM = √(AB² − AM²) = √(100 − 64) = √36 = 6 cm ✓. الخطأُ الشائع: أخذُ AB = 5 (نصف القطر) بدل 10، أو جمعُ AM ونصف القطر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7afe371a-79da-5bb0-9cb0-49f6a2a3f935', '2e00fa20-a744-5c4a-b6e2-759d76890c59', 'في المثلث ABC، I منتصف [BC]، ولوحظ أنّ المتوسّط AI يساوي نصفَ الوتر BC. ماذا نستنتج؟', '[{"id":"a","text":"المثلث قائم الزاوية في B"},{"id":"b","text":"المثلث متساوي الساقين فقط"},{"id":"c","text":"المثلث منفرج الزاوية"},{"id":"d","text":"المثلث قائم الزاوية في A"}]'::jsonb, 'd', 'بما أنّ I منتصف [BC] فإنّ IB = IC = BC⁄2 دائمًا؛ فإذا صار AI = BC⁄2 أيضًا فـ IA = IB = IC، أي A على الدائرة التي قطرُها [BC]، فالمثلث قائمٌ في A (المبرهنة العكسية) ✓. الخطأُ الشائع: الاكتفاءُ بالقول إنّه متساوي الساقين دون استنتاج القائمية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a80cbfe7-e762-5c9e-9dd1-afacfa1ad393', '2e00fa20-a744-5c4a-b6e2-759d76890c59', 'نصفُ دائرةٍ قطرُها [BC] = 13 cm، وM نقطةٌ منها مع BM = 5 cm. احسب مساحة المثلث MBC.', '[{"id":"a","text":"30 cm²"},{"id":"b","text":"60 cm²"},{"id":"c","text":"32.5 cm²"},{"id":"d","text":"78 cm²"}]'::jsonb, 'a', 'المثلث MBC قائمٌ في M (وترُه القطر). بفيثاغور: MC = √(13² − 5²) = √(169 − 25) = √144 = 12 cm. المساحة = (BM × MC)⁄2 = (5 × 12)⁄2 = 30 cm² ✓. الخطأُ الشائع: نسيانُ القسمة على 2 (60)، أو استعمالُ الوتر ضلعًا قائمًا (13 × 5)⁄2 = 32.5.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5b9dfcb-46a1-51af-a5d2-174b733c4400', '2e00fa20-a744-5c4a-b6e2-759d76890c59', 'المثلث ABC قائم في A، I منتصف [BC]، AB = 12 cm وAC = 5 cm. احسب طول المتوسّط AI.', '[{"id":"a","text":"13 cm"},{"id":"b","text":"6.5 cm"},{"id":"c","text":"8.5 cm"},{"id":"d","text":"5 cm"}]'::jsonb, 'b', 'الوتر BC = √(12² + 5²) = √(144 + 25) = √169 = 13 cm، والمتوسّط AI = BC⁄2 = 6.5 cm ✓. الخطأُ الشائع: نسيانُ القسمة على 2 (13)، أو حسابُ نصف مجموع الضلعين (12+5)⁄2 = 8.5.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

