INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2dd5c938-99e8-5b60-8022-69f0e637a30f', '9932d685-0faa-551f-8e9c-4d8bbc932a2a', 'المثلث ABC قائم في B. أين يقع مركز الدائرة المحيطة به؟', '[{"id":"a","text":"منتصف [AC] (الوتر)"},{"id":"b","text":"منتصف [AB]"},{"id":"c","text":"الرأس B"},{"id":"d","text":"منتصف [BC]"}]'::jsonb, 'a', 'المثلث قائمٌ في B، فوترُه هو الضلع المقابل للزاوية القائمة، أي [AC]، ومركزُ الدائرة المحيطة منتصفُه ✓. الخطأُ الشائع: أخذُ منتصف [BC] لمجرّد ظهور الحرفين، دون الانتباه إلى موضع الزاوية القائمة.', 1)
