INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d895fb1b-3ef2-5978-a606-0bf1ae1ca50e', '9932d685-0faa-551f-8e9c-4d8bbc932a2a', 'مثلثٌ قائم ضلعاه القائمان 3 cm و4 cm. احسب الوتر ثمّ نصف قطر دائرته المحيطة.', '[{"id":"a","text":"5 cm"},{"id":"b","text":"2.5 cm"},{"id":"c","text":"3.5 cm"},{"id":"d","text":"7 cm"}]'::jsonb, 'b', 'الوتر = √(3² + 4²) = √25 = 5 cm، ونصفُ القطر = 5⁄2 = 2.5 cm ✓. الخطأُ الشائع: التوقّفُ عند الوتر واعتبارُه نصفَ القطر (5)، أو حسابُ نصف مجموع الضلعين (3+4)⁄2 = 3.5.', 2)
