INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db54b40c-05cf-5bec-a43d-94bb6fa9c33f', '9932d685-0faa-551f-8e9c-4d8bbc932a2a', 'المثلث ABC قائم في A، I منتصف [BC]، والمتوسّط AI = 6 cm. ما طول الوتر BC؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"3 cm"},{"id":"c","text":"36 cm"},{"id":"d","text":"12 cm"}]'::jsonb, 'd', 'المتوسّط يساوي نصفَ الوتر، فالوتر ضعفُ المتوسّط: BC = 2 × 6 = 12 cm ✓. الخطأُ الشائع: أخذُ الوتر مساويًا للمتوسّط (6) أو نصفَه (3).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bad52343-3bd4-5b19-bd7e-f14041bd9a47', '9932d685-0faa-551f-8e9c-4d8bbc932a2a', 'في المثلث ABC، I منتصف [BC]، وتحقّق أنّ IA = IB = IC. ماذا نستنتج؟', '[{"id":"a","text":"المثلث قائم الزاوية في A"},{"id":"b","text":"المثلث قائم الزاوية في B"},{"id":"c","text":"المثلث متساوي الأضلاع"},{"id":"d","text":"لا يمكن استنتاج شيء"}]'::jsonb, 'a', 'IA = IB = IC يعني أنّ I تبعد بنفس المسافة عن الرؤوس الثلاثة، فهي مركزُ الدائرة المحيطة والوترُ [BC] قطرٌ لها، إذن المثلث قائمٌ في A ✓ (الزاوية المقابلة للقطر). الخطأُ الشائع: الخلطُ مع متساوي الأضلاع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56c186f8-18b3-5756-ba42-52896118282c', '9932d685-0faa-551f-8e9c-4d8bbc932a2a', 'نصفُ قطر الدائرة المحيطة بمثلثٍ قائم يساوي 6.5 cm، وأحدُ ضلعيه القائمين 5 cm. احسب الضلع القائم الآخر.', '[{"id":"a","text":"13 cm"},{"id":"b","text":"12 cm"},{"id":"c","text":"8 cm"},{"id":"d","text":"11.5 cm"}]'::jsonb, 'b', 'الوتر = 2 × 6.5 = 13 cm، والضلع الآخر = √(13² − 5²) = √(169 − 25) = √144 = 12 cm ✓. الخطأُ الشائع: نسيانُ مضاعفة نصف القطر واعتبارُ الوتر 6.5، أو طرحُ الطولين دون تربيع (13 − 5 = 8).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5c0f2ddd-1a9f-5fe9-aa8d-4f16ae1308e2', 'f74e1397-5bd0-5925-ba92-b6c5fad9d582', 'math-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مسائل المثلث القائم والدائرة', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35d7ed39-4b60-5e96-99de-ee8a31ec0efb', '5c0f2ddd-1a9f-5fe9-aa8d-4f16ae1308e2', 'المثلث ABC قائم في A. نصفُ قطر دائرته المحيطة 6.5 cm وAB = 5 cm. احسب مساحة المثلث ABC.', '[{"id":"a","text":"30 cm²"},{"id":"b","text":"32.5 cm²"},{"id":"c","text":"60 cm²"},{"id":"d","text":"39 cm²"}]'::jsonb, 'a', 'الوتر BC = 2 × 6.5 = 13 cm، والضلع الآخر AC = √(13² − 5²) = √144 = 12 cm. المساحة = (AB × AC)⁄2 = (5 × 12)⁄2 = 30 cm² ✓. الخطأُ الشائع: استعمالُ الوتر ضلعًا قائمًا (5 × 13)⁄2 = 32.5، أو نسيانُ القسمة على 2 (60).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8061b0fe-4f0c-52f6-847f-1e3e7d263245', '5c0f2ddd-1a9f-5fe9-aa8d-4f16ae1308e2', 'كتب تلميذٌ: «مثلثٌ قائم وترُه 10 cm، إذن نصفُ قطر دائرته المحيطة 10 cm». أين الخطأ؟', '[{"id":"a","text":"لا خطأ، الحلُّ صحيح"},{"id":"b","text":"نصفُ القطر يساوي نصفَ الوتر أي 5 cm، لا الوترَ كاملًا"},{"id":"c","text":"نصفُ القطر يساوي ضعفَ الوتر أي 20 cm"},{"id":"d","text":"الوترُ ليس قطرًا للدائرة المحيطة"}]'::jsonb, 'b', 'الوترُ هو **قطرُ** الدائرة المحيطة، ونصفُ القطر يساوي نصفَه: R = 10⁄2 = 5 cm ✓. التلميذُ خلط بين القطر ونصف القطر. (الوترُ فعلًا قطرٌ، لكنّ نصف القطر نصفُه.)', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b65ffdab-9f74-53f7-ba6a-cc0e1a3cc0cb', '5c0f2ddd-1a9f-5fe9-aa8d-4f16ae1308e2', 'المثلث ABC قائم في A، AB = 16 cm وAC = 12 cm، وI منتصف [BC]. احسب طول المتوسّط AI.', '[{"id":"a","text":"20 cm"},{"id":"b","text":"14 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"5 cm"}]'::jsonb, 'c', 'الوتر BC = √(16² + 12²) = √(256 + 144) = √400 = 20 cm، والمتوسّط AI = BC⁄2 = 10 cm ✓. الخطأُ الشائع: التوقّفُ عند الوتر 20 دون قسمة، أو حسابُ نصف مجموع الضلعين (16+12)⁄2 = 14.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4eb73ea-1497-50bc-98d0-a7a5ec80df17', '5c0f2ddd-1a9f-5fe9-aa8d-4f16ae1308e2', 'المثلث ABC، I منتصف [BC]، وعُلم أنّ المثلث AIB متساوي الأضلاع طولُ ضلعه 6 cm. احسب طول الوتر BC.', '[{"id":"a","text":"6 cm"},{"id":"b","text":"18 cm"},{"id":"c","text":"36 cm"},{"id":"d","text":"12 cm"}]'::jsonb, 'd', 'بما أنّ I منتصف [BC] فإنّ IB = BC⁄2. والمثلث AIB متساوي الأضلاع فـ IB = 6 cm، إذن BC = 2 × IB = 2 × 6 = 12 cm ✓. (وبما أنّ AI = IB = 6 = BC⁄2 يكون المثلث ABC أيضًا قائمًا في A.) الخطأُ الشائع: أخذُ BC = 6 (طول الضلع) أو 36.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34edfb36-e6ee-5bdd-a6b2-8ee61be6fd70', '5c0f2ddd-1a9f-5fe9-aa8d-4f16ae1308e2', 'أراد تلميذٌ أن يتحقّق أنّ المثلث ABC (حيث BC = 15، AB = 9، AC = 12) قائمُ الزاوية، مستعملًا فكرة الدائرة. ما الطريقة الصحيحة؟', '[{"id":"a","text":"يتحقّق أنّ منتصف [BC] يبعد 7.5 cm عن الرؤوس الثلاثة (نصفَ الوتر)"},{"id":"b","text":"يتحقّق أنّ منتصف [BC] يبعد 15 cm عن A"},{"id":"c","text":"يرسم دائرةً مركزُها A ويرى إن مرّت بـ B وC"},{"id":"d","text":"يقيس الزاوية B فقط بالمنقلة"}]'::jsonb, 'a', 'المثلث قائمٌ في A إذا كان منتصفُ الوتر I على مسافةٍ واحدة من الرؤوس الثلاثة تساوي نصفَ الوتر 15⁄2 = 7.5 cm ✓ (هنا 9، 12، 15 = 3×(3، 4، 5) فالمثلث قائمٌ فعلًا). الخطأُ الشائع: أخذُ المسافة مساويةً للوتر كاملًا (15)، أو جعلُ المركز عند الرأس A.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50fec117-d35b-512c-ac2c-6a035c33192f', '5c0f2ddd-1a9f-5fe9-aa8d-4f16ae1308e2', 'في المستطيل ABCD يتقاطع القطران [AC] و[BD] في O. لماذا تبعد O بنفس المسافة عن الرؤوس الأربعة (فتكون مركز الدائرة المحيطة بالمستطيل)؟', '[{"id":"a","text":"لأنّ المستطيل متساوي الأضلاع"},{"id":"b","text":"لأنّ قطرَي المستطيل متقايسان ويتناصفان، فـ O منتصفُ كلّ قطر، والمثلث ABC قائمٌ في B ووترُه [AC]، إذن OA = OB = OC = OD"},{"id":"c","text":"لأنّ O مركزُ ثقل المستطيل فقط"},{"id":"d","text":"لا تبعد O بنفس المسافة عن الرؤوس"}]'::jsonb, 'b', 'قطرا المستطيل متقايسان ويتناصفان، فـ O منتصفُ القطر [AC]. والزاوية في B قائمة ووترُها [AC]، فمنتصفُ الوتر O مركزُ الدائرة المحيطة بالمثلث ABC: OA = OB = OC = نصف القطر؛ ونفسُ الشيء للقطر الآخر يعطي OD مساويًا، فـ OA = OB = OC = OD ✓. الخطأُ الشائع: الخلطُ مع تساوي الأضلاع أو مع مركز الثقل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

