INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef0d819b-3cd1-5ca8-baaf-1eb2eebdfd7f', 'ba05c3d0-feda-5956-93ce-5d0c7cd2fca8', 'أكمل: «المثلث المرسوم داخل نصف دائرةٍ ووترُه قطرُها يكون ...».', '[{"id":"a","text":"قائم الزاوية"},{"id":"b","text":"متساوي الساقين"},{"id":"c","text":"متساوي الأضلاع"},{"id":"d","text":"منفرج الزاوية"}]'::jsonb, 'a', 'هذه هي المبرهنة العكسية: كلُّ مثلثٍ مرسومٍ في نصف دائرةٍ ووترُه قطرُ الدائرة يكون قائم الزاوية عند الرأس الموجود على القوس ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
