  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('960d4ba6-9ef8-5174-8d4a-e3ec45d76dc3', 'ba05c3d0-feda-5956-93ce-5d0c7cd2fca8', 'المثلث ABC قائم في C، وAB = 26 cm، وI منتصف [AB]. ما طول المتوسّط CI؟', '[{"id":"a","text":"26 cm"},{"id":"b","text":"13 cm"},{"id":"c","text":"6.5 cm"},{"id":"d","text":"52 cm"}]'::jsonb, 'b', 'المثلث قائمٌ في C فوترُه [AB]، ومتوسّطُ الوتر CI يساوي نصفَه: CI = 26⁄2 = 13 cm ✓. الخطأُ الشائع: أخذُ المتوسّط مساويًا للوتر (26) أو قسمتُه على 4 (6.5).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
