INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4a9446b1-e7a4-5c2f-9a49-3b3a7bb6c4d4', 'ba05c3d0-feda-5956-93ce-5d0c7cd2fca8', 'الضلع [BC] قطرٌ لدائرة، وA نقطةٌ منها، مع BC = 17 cm وAC = 15 cm. احسب AB.', '[{"id":"a","text":"2 cm"},{"id":"b","text":"32 cm"},{"id":"c","text":"8 cm"},{"id":"d","text":"4 cm"}]'::jsonb, 'c', 'المثلث ABC قائمٌ في A (وترُه القطر [BC]). بفيثاغور: AB = √(BC² − AC²) = √(17² − 15²) = √(289 − 225) = √64 = 8 cm ✓. الخطأُ الشائع: طرحُ الطولين دون تربيع (17 − 15 = 2)، أو جمعُهما (32).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d0871fd-1394-522b-ba1f-264c8edc4d3e', 'ba05c3d0-feda-5956-93ce-5d0c7cd2fca8', 'المثلث ABC، I منتصف [BC]. أيّ شرطٍ يجعله قائمَ الزاوية في A؟', '[{"id":"a","text":"IA = BC"},{"id":"b","text":"IA = AB"},{"id":"c","text":"IA = 2 × BC"},{"id":"d","text":"IA = نصف BC"}]'::jsonb, 'd', 'بما أنّ I منتصف [BC] فإنّ IB = IC = BC⁄2 دائمًا؛ فإذا صار IA = BC⁄2 (نصفَ الوتر) أصبح IA = IB = IC، فـ A على الدائرة التي قطرُها [BC] والمثلث قائمٌ في A ✓. الخطأُ الشائع: مساواةُ المتوسّط بالوتر كاملًا (IA = BC).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e564b474-b117-5e9a-b2a2-6e22a0fbd878', 'ba05c3d0-feda-5956-93ce-5d0c7cd2fca8', 'المثلث ABC قائم في A، AB = 9 cm وAC = 12 cm. احسب نصف قطر دائرته المحيطة.', '[{"id":"a","text":"7.5 cm"},{"id":"b","text":"15 cm"},{"id":"c","text":"6 cm"},{"id":"d","text":"30 cm"}]'::jsonb, 'a', 'الوتر BC = √(9² + 12²) = √(81 + 144) = √225 = 15 cm، ونصفُ القطر = 15⁄2 = 7.5 cm ✓. الخطأُ الشائع: نسيانُ القسمة على 2 فيبقى R = 15، أو حسابُ نصف مجموع الضلعين (9+12)⁄2 = 10.5.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46c6963c-0a81-555b-9526-0f3c81775b0c', 'ba05c3d0-feda-5956-93ce-5d0c7cd2fca8', 'دائرةٌ قطرُها [AB] = 10 cm، وM نقطةٌ منها مع AM = 6 cm. احسب محيط المثلث AMB.', '[{"id":"a","text":"14 cm"},{"id":"b","text":"20 cm"},{"id":"c","text":"24 cm"},{"id":"d","text":"30 cm"}]'::jsonb, 'c', 'المثلث AMB قائمٌ في M (وترُه القطر [AB]). MB = √(10² − 6²) = √(100 − 36) = √64 = 8 cm. المحيط = AM + MB + AB = 6 + 8 + 10 = 24 cm ✓. الخطأُ الشائع: نسيانُ إضافة الوتر AB (6 + 8 = 14)، أو أخطاءٌ في MB.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

