INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa50a83e-26c0-5d96-9208-8160496730a4', 'be1e4d13-1396-55cb-b432-f686b3cfdca3', 'نصفُ دائرةٍ قطرُها [BC] = 15 cm، وM نقطةٌ منها مع CM = 9 cm. احسب BM.', '[{"id":"a","text":"12 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"18 cm"},{"id":"d","text":"12.5 cm"}]'::jsonb, 'a', 'المثلث MBC قائمٌ في M (وترُه القطر [BC]). بفيثاغور: BM = √(BC² − CM²) = √(15² − 9²) = √(225 − 81) = √144 = 12 cm ✓. الخطأُ الشائع: طرحُ الطولين دون تربيع (15 − 9 = 6)، أو أخذُ نصف القطر بدل القطر.', 1)
ON CONFLICT (id) DO UPDATE SET
