  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d188a496-f814-5796-a89a-7ac8f8adc523', 'be1e4d13-1396-55cb-b432-f686b3cfdca3', 'المثلث ABC قائم في A، I منتصف [BC]، وعُلم IB = 7.5 cm. أيّ زوجٍ صحيح لطول الوتر BC وطول المتوسّط AI؟', '[{"id":"a","text":"BC = 7.5 cm وAI = 15 cm"},{"id":"b","text":"BC = 15 cm وAI = 7.5 cm"},{"id":"c","text":"BC = 15 cm وAI = 15 cm"},{"id":"d","text":"BC = 3.75 cm وAI = 7.5 cm"}]'::jsonb, 'b', 'I منتصف [BC] فـ IB = BC⁄2، إذن BC = 2 × 7.5 = 15 cm. والمتوسّط AI = IB = IC = BC⁄2 = 7.5 cm ✓. الخطأُ الشائع: قلبُ العلاقة (اعتبار BC = 7.5)، أو مساواةُ AI بالوتر (15).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d61ac020-8f13-55f9-8f7c-619f082a0734', 'be1e4d13-1396-55cb-b432-f686b3cfdca3', 'قال تلميذ: «بما أنّ IA = IB في المثلث ABC (I منتصف [BC])، فالمثلث متساوي الساقين في A فقط». صحّح الاستنتاج.', '[{"id":"a","text":"صحيح، مجرّدُ مثلثٍ متساوي الساقين"},{"id":"b","text":"يعني أنّ المثلث متساوي الأضلاع"},{"id":"c","text":"بما أنّ I منتصف [BC] فإنّ IB = IC دائمًا؛ وكون IA = IB يعني IA = IB = IC، فالمثلث قائمٌ في A"},{"id":"d","text":"لا يمكن استنتاج أيّ شيء"}]'::jsonb, 'c', 'المتوسّط الصادر إلى منتصف [BC] يعطي IB = IC تلقائيًّا. فإذا أُضيف IA = IB صار IA = IB = IC = نصف الوتر، وهو شرطُ المبرهنة العكسية: المثلث قائمٌ في A ✓. الخطأُ الشائع: الاكتفاءُ بوصفه متساوي الساقين دون استنتاج القائمية.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f5942f9-6208-5f74-a1fb-42727cfb9080', 'be1e4d13-1396-55cb-b432-f686b3cfdca3', 'المثلث ABC قائم في A، BC = 10 cm وAB = 6 cm، وI منتصف [BC]. احسب مساحة المثلث AIC.', '[{"id":"a","text":"24 cm²"},{"id":"b","text":"6 cm²"},{"id":"c","text":"48 cm²"},{"id":"d","text":"12 cm²"}]'::jsonb, 'd', 'AC = √(10² − 6²) = √64 = 8 cm، فمساحة ABC = (6 × 8)⁄2 = 24 cm². المتوسّط AI يقسم المثلث إلى مثلثين متساويي المساحة (BI = IC)، فمساحة AIC = 24⁄2 = 12 cm² ✓. الخطأُ الشائع: إعطاءُ مساحة المثلث كلِّه (24) بدل نصفه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc20d2c0-ad6f-5d20-8f60-a98f36954c97', 'be1e4d13-1396-55cb-b432-f686b3cfdca3', 'دائرةٌ قطرُها [AB] = 20 cm، وM وN نقطتان منها على جانبَي [AB]، مع AM = 12 cm وAN = 16 cm. احسب BM + BN.', '[{"id":"a","text":"28 cm"},{"id":"b","text":"32 cm"},{"id":"c","text":"24 cm"},{"id":"d","text":"20 cm"}]'::jsonb, 'a', 'المثلثان AMB وANB قائمان (وترُهما القطر [AB] = 20). BM = √(20² − 12²) = √(400 − 144) = √256 = 16 cm، وBN = √(20² − 16²) = √(400 − 256) = √144 = 12 cm. المجموع = 16 + 12 = 28 cm ✓. الخطأُ الشائع: نسيانُ تربيع الأطوال في فيثاغور.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c3ffae65-bb20-549d-8b12-70b82160c77f', 'be1e4d13-1396-55cb-b432-f686b3cfdca3', 'المثلث ABC قائم في A، ضلعاه القائمان AB = 15 cm وAC = 20 cm. احسب طول القطر [BC] لدائرته المحيطة ثمّ نصف قطرها.', '[{"id":"a","text":"BC = 25 cm وR = 25 cm"},{"id":"b","text":"BC = 25 cm وR = 12.5 cm"},{"id":"c","text":"BC = 35 cm وR = 17.5 cm"},{"id":"d","text":"BC = 25 cm وR = 6.25 cm"}]'::jsonb, 'b', 'الوتر BC = √(15² + 20²) = √(225 + 400) = √625 = 25 cm (وهو قطرُ الدائرة المحيطة)، ونصفُ القطر R = 25⁄2 = 12.5 cm ✓. الخطأُ الشائع: جمعُ الضلعين دون فيثاغور (15+20 = 35)، أو نسيانُ القسمة على 2 لنصف القطر (25).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

